// Field       : DUMMY
// Access      : RW
#define FTINT_EFIQDEB_BIT              0
#define FTINT_EFIQDEB_LEN              32
#define FTINT_EFIQDEB_MASK             0xffffffff


// ======================================================================
// Module      : Faraday SPI Flash Controller
// Base Address: 0x10010000
// The registers between offsets 0x10 and 0x54, 0x100 except 0x30, can be
// accessed as BYTE, HWORD, or WORD. The command queue (Offsets
// 0x00-0x0C, 0x30) input entry can only accept WORD accesses.
// ----------------------------------------------------------------------
// Register    : Command Register 0
// One command contains four words. One command will be executed when the
// fourth word of a command is written. The command must be executed
// before reading/writing the data into FIFO. For write commands, users
// must check and clear the command complete interrupt before writing the
// next command. For read status commands, users must check and clear the
// command complete interrupt before writing the next command. For read
// data commands, users must finish reading the data from RXFIFO; and
// check and clear the command complete interrupt before writing the next
// command.
#define FTSPI_CMD_W0_ADDR              0x10010000
// Field       : ADDR
// Access      : RW
// SPI Flash Address.
#define FTSPI_CMD_W0_ADDR_BIT          0
#define FTSPI_CMD_W0_ADDR_LEN          32
#define FTSPI_CMD_W0_ADDR_MASK         0xffffffff
// ----------------------------------------------------------------------
// Register    : Command Register 1
//
#define FTSPI_CMD_W1_ADDR              0x10010004
// Field       : ADDR_LEN
// Access      : RW
// Number of SPI address bytes from 0 to 4. For  XIP port access, the
// value is decided by the SPI_addr_cyc port. When the address length is
// 0, there will be no dummy cycle ([23:16]) and continuous read mode
// code (0x000C[23 :16]) will occur.
#define FTSPI_CMD_W1_ADDR_LEN_BIT      0
#define FTSPI_CMD_W1_ADDR_LEN_LEN      3
#define FTSPI_CMD_W1_ADDR_LEN_MASK     0x00000007
// Field       : DUM_2ND
// Access      : RW
// Number of Second Dummy Cycle States from 0 to 32. Second dummy state
// is located between the address and the data state that excludes the
// continuous read mode state. Users can check whether the dummy state
// exists between the address and the data state or not in the SPI Flash
// specification. The host controller will issue logic 1 in the dummy
// cycle.
#define FTSPI_CMD_W1_DUM_2ND_BIT       16
#define FTSPI_CMD_W1_DUM_2ND_LEN       8
#define FTSPI_CMD_W1_DUM_2ND_MASK      0x00ff0000
// Field       : ILEN
// Access      : RW
// Instruction code length from 0 to 2 bytes. When users want to execute
// a SPI Flash command, the instruction code must be included. Different
// SPI Flash vendors have different instruction lengths. Therefore, users
// can set this register to meet different behaviors. Instruction code is
// normally 1 byte. However, if users set the 2-byte instruction length,
// the host controller will issue this instruction code twice.
#define FTSPI_CMD_W1_ILEN_BIT          24
#define FTSPI_CMD_W1_ILEN_LEN          2
#define FTSPI_CMD_W1_ILEN_MASK         0x03000000
// Field       : CRM
// Access      : RW
// Continous Read Mode Enable. The continuous read mode state is located
// between the address and second dummy state. It can eliminate the
// instruction state after the second read command in the continuous read
// mode. Please do not enable this bit while data counter (Cmd_w2) is 0.
#define FTSPI_CMD_W1_CRM_BIT           28
#define FTSPI_CMD_W1_CRM_LEN           1
#define FTSPI_CMD_W1_CRM_MASK          0x10000000
// ----------------------------------------------------------------------
// Register    : Command Register 2
//
#define FTSPI_CMD_W2_ADDR              0x10010008
// Field       : DATA_COUNTER
// Access      : RW
// Read/Write data counter. Set this to the number of bytes to read or
// written. It must not be set to 0 except when the command is read
// status or write enable. This register must be set to 0 when performing
// the read status command.
#define FTSPI_CMD_W2_DATA_COUNTER_BIT  0
#define FTSPI_CMD_W2_DATA_COUNTER_LEN  32
#define FTSPI_CMD_W2_DATA_COUNTER_MASK 0xffffffff
// ----------------------------------------------------------------------
// Register    : Command Register 3
//
#define FTSPI_CMD_W3_ADDR              0x1001000c
// Field       : WREN
// Access      : RW
// Write enable. Enable the SPI write data, except for the read data or
// read status (Read the data return path); users must set the write
// enable = 1 for other SPI commands. Please note that in the write data
// or erase Flash command, write enable is set to 1. Only when in the
// read data or read status command, write enable must be set to 0.
#define FTSPI_CMD_W3_WREN_BIT          1
#define FTSPI_CMD_W3_WREN_LEN          1
#define FTSPI_CMD_W3_WREN_MASK         0x00000002
// Field       : RDSTEN
// Access      : RW
// Read status enable. To read the SPI status the wren bit must be 0 and
// users must issue the SPI read status command.
#define FTSPI_CMD_W3_RDSTEN_BIT        2
#define FTSPI_CMD_W3_RDSTEN_LEN        1
#define FTSPI_CMD_W3_RDSTEN_MASK       0x00000004
// Field       : RDST
// Access      : RW
// Disable reading of SPI status by the hardware. When cleared the
// controller will poll the status until the status is ready (Not busy)
// and write the status register. When set SW issues the read status
// command.
#define FTSPI_CMD_W3_RDST_BIT          3
#define FTSPI_CMD_W3_RDST_LEN          1
#define FTSPI_CMD_W3_RDST_MASK         0x00000008
// Field       : DTR
// Access      : RW
// Double Data Transfer Rate Mode. DTR mode should only bet set for read
// data commands.
#define FTSPI_CMD_W3_DTR_BIT           4
#define FTSPI_CMD_W3_DTR_LEN           1
#define FTSPI_CMD_W3_DTR_MASK          0x00000010
// Field       : SPIMODE
// Access      : RW
// SPI operate mode. 0: Serial Mode, 1: Dual Mode, 2: Quad Mode, 3: Dual
// I/O Mode, 4: Quad I/O Mode.
#define FTSPI_CMD_W3_SPIMODE_BIT       5
#define FTSPI_CMD_W3_SPIMODE_LEN       3
#define FTSPI_CMD_W3_SPIMODE_MASK      0x000000e0
// Field       : CRM_CODE
// Access      : RW
// Continuous read mode operate code. Users can fill this code to execute
// the continuous read mode. To do the continuous read mode with this
// Flash, users have to issue 0xA0 as the mode bit because it does not
// need the instruction code for the next read command.
#define FTSPI_CMD_W3_CRM_CODE_BIT      16
#define FTSPI_CMD_W3_CRM_CODE_LEN      8
#define FTSPI_CMD_W3_CRM_CODE_MASK     0x00ff0000
// Field       : INSTR
// Access      : RW
// SPI Flash Instruction Code.
#define FTSPI_CMD_W3_INSTR_BIT         24
#define FTSPI_CMD_W3_INSTR_LEN         8
#define FTSPI_CMD_W3_INSTR_MASK        0xff000000
// ----------------------------------------------------------------------
// Register    : Control Register
//
#define FTSPI_CR_ADDR                  0x10010010
// Field       : CLKDIV
// Access      : RW
// Divide the SPI input clock to derive the SPI output clock. Divisor = 2
// << clkdiv.
#define FTSPI_CR_CLKDIV_BIT            0
#define FTSPI_CR_CLKDIV_LEN            2
#define FTSPI_CR_CLKDIV_MASK           0x00000003
// Field       : CLKMODE
// Access      : RW
// SPI clock level at the IDLE state. 0: clock low, 1: clock high.
#define FTSPI_CR_CLKMODE_BIT           4
#define FTSPI_CR_CLKMODE_LEN           1
#define FTSPI_CR_CLKMODE_MASK          0x00000010
// Field       : XIP_IDLE
// Access      : RO
// XIP Idle Status. 0: busy, 1: idle.
#define FTSPI_CR_XIP_IDLE_BIT          7
#define FTSPI_CR_XIP_IDLE_LEN          1
#define FTSPI_CR_XIP_IDLE_MASK         0x00000080
// Field       : ABORT
// Access      : RW
// Flush all commands and FIFOS, and reset the state machine. his bit
// will be automatically cleared to zero.
#define FTSPI_CR_ABORT_BIT             8
#define FTSPI_CR_ABORT_LEN             1
#define FTSPI_CR_ABORT_MASK            0x00000100
// Field       : RDY_LOC
// Access      : RW
// Indicates which bit of the SPI status is the busy bit.
#define FTSPI_CR_RDY_LOC_BIT           16
#define FTSPI_CR_RDY_LOC_LEN           3
#define FTSPI_CR_RDY_LOC_MASK          0x00070000
// Field       : XIP_MODE
// Access      : RW
// XIP Mode Enable. 0: Command Slave Port, 1: XIP Port. When the bit is
// toggled, FTSPI020 will automatically issue the abort function. Users
// must wait until the abort function is finished to issue a command.
#define FTSPI_CR_XIP_MODE_BIT          20
#define FTSPI_CR_XIP_MODE_LEN          1
#define FTSPI_CR_XIP_MODE_MASK         0x00100000
// ----------------------------------------------------------------------
// Register    : AC Timing Register
//
#define FTSPI_ACTR_ADDR                0x10010014
// Field       : CS_DELAY
// Access      : RW
// cs delay is the number of SPI clocks-1 from inactive cs to active cs,
// which means that the timing is from high to low. Please follow the SPI
// flash specification for details. The unit is the sck_out period, and
// the default setting is 16 sck_out periods.
#define FTSPI_ACTR_CS_DELAY_BIT        0
#define FTSPI_ACTR_CS_DELAY_LEN        4
#define FTSPI_ACTR_CS_DELAY_MASK       0x0000000f
// ----------------------------------------------------------------------
// Register    : Status Register
//
#define FTSPI_SR_ADDR                  0x10010018
// Field       : TXF_RDY
// Access      : RO
// TxFIFO ready status. 1 when the FIFO is ready to accept data.
#define FTSPI_SR_TXF_RDY_BIT           0
#define FTSPI_SR_TXF_RDY_LEN           1
#define FTSPI_SR_TXF_RDY_MASK          0x00000001
// Field       : RXF_RDY
// Access      : RO
// RxFIFO ready status. 1 when the FIFO has data to read.
#define FTSPI_SR_RXF_RDY_BIT           1
#define FTSPI_SR_RXF_RDY_LEN           1
#define FTSPI_SR_RXF_RDY_MASK          0x00000002
// ----------------------------------------------------------------------
// Register    : Interrupt Control Register
//
#define FTSPI_ICR_ADDR                 0x10010020
// Field       : DMA_EN
// Access      : RW
// Enable DMA hardware handshake. disable this bit first before switching
// from the command-based slave port to the XIP port.
#define FTSPI_ICR_DMA_EN_BIT           0
#define FTSPI_ICR_DMA_EN_LEN           1
#define FTSPI_ICR_DMA_EN_MASK          0x00000001
// Field       : CCIE
// Access      : RW
// Command Complete Interrupt Enable.
#define FTSPI_ICR_CCIE_BIT             1
#define FTSPI_ICR_CCIE_LEN             1
#define FTSPI_ICR_CCIE_MASK            0x00000002
// Field       : TXF_THR
// Access      : RW
// Tx FIFO threshold for generating an interrupt. 0: 8, 1: 16, 2: 24.
#define FTSPI_ICR_TXF_THR_BIT          8
#define FTSPI_ICR_TXF_THR_LEN          2
#define FTSPI_ICR_TXF_THR_MASK         0x00000300
// Field       : RXF_THR
// Access      : RW
// Rx FIFO threshold for generating an interrupt. 0: 8, 1: 16, 2: 24.
#define FTSPI_ICR_RXF_THR_BIT          12
#define FTSPI_ICR_RXF_THR_LEN          2
#define FTSPI_ICR_RXF_THR_MASK         0x00003000
// ----------------------------------------------------------------------
// Register    : Interrupt Status Register
//
#define FTSPI_ISR_ADDR                 0x10010024
// Field       : CCS
// Access      : W1C
// Command Complete Status. This bit will be set when a command is
// completed.
#define FTSPI_ISR_CCS_BIT              0
#define FTSPI_ISR_CCS_LEN              1
#define FTSPI_ISR_CCS_MASK             0x00000001
// ----------------------------------------------------------------------
// Register    : SPI Read Status Register
//
#define FTSPI_SPISR_ADDR               0x10010028
// Field       : STATUS
// Access      : RO
// Host issues the read SPI Flash status command and stores the return
// data at this register. Users can read this register to check the SPI
// Flash status.
#define FTSPI_SPISR_STATUS_BIT         0
#define FTSPI_SPISR_STATUS_LEN         8
#define FTSPI_SPISR_STATUS_MASK        0x000000ff
// ----------------------------------------------------------------------
// Register    : SPI Flash Size Register
// For the direct address mapped function, the address of system is
// always larger than the address of the SPI Flash. Users need to mask
// the higher bits of the system address to fit the SPI Flash size.
#define FTSPI_SPIFSR_ADDR              0x1001002c
// Field       : DUMMY
// Access      : RW
#define FTSPI_SPIFSR_BIT               0
#define FTSPI_SPIFSR_LEN               32
#define FTSPI_SPIFSR_MASK              0xffffffff
// ----------------------------------------------------------------------
// Register    : XIP Command Word Register
//
#define FTSPI_XIPCMD_ADDR              0x10010030
// Field       : DUM_2ND
// Access      : RW
// Number of Second Dummy Cycle States from 0 to 32. Second dummy state
// is located between the address and the data state that excludes the
// continuous read mode state. Users can check whether the dummy state
// exists between the address and the data state or not in the SPI Flash
// specification. The host controller will issue logic 1 in the dummy
// cycle.
#define FTSPI_XIPCMD_DUM_2ND_BIT       0
#define FTSPI_XIPCMD_DUM_2ND_LEN       8
#define FTSPI_XIPCMD_DUM_2ND_MASK      0x000000ff
// Field       : SPIMODE
// Access      : RW
// SPI operate mode. 0: Serial Mode, 1: Dual Mode, 2: Quad Mode, 3: Dual
// I/O Mode, 4: Quad I/O Mode.
#define FTSPI_XIPCMD_SPIMODE_BIT       8
#define FTSPI_XIPCMD_SPIMODE_LEN       3
#define FTSPI_XIPCMD_SPIMODE_MASK      0x00000700
// Field       : ADDR_LEN
// Access      : RW
// Number of address bytes in XIP SPI commands. 0: 3 bytes, 1: 4 bytes.
#define FTSPI_XIPCMD_ADDR_LEN_BIT      11
#define FTSPI_XIPCMD_ADDR_LEN_LEN      1
#define FTSPI_XIPCMD_ADDR_LEN_MASK     0x00000800
// Field       : INSTR
// Access      : RW
// Instruction code. Users can set this code to execute the SPI Flash
// command for XIP read. If this byte set to 0, XIP will transfer in
// 1-bit mode.
#define FTSPI_XIPCMD_INSTR_BIT         12
#define FTSPI_XIPCMD_INSTR_LEN         8
#define FTSPI_XIPCMD_INSTR_MASK        0x000ff000
// Field       : INSTR_DQ
// Access      : RW
// Instruction code for dual/quad mode I/O. Users have to issue the code,
// for example, 0xB0, as the mode bit because every command needs
// instruction code while the XIP port is reading.
#define FTSPI_XIPCMD_INSTR_DQ_BIT      20
#define FTSPI_XIPCMD_INSTR_DQ_LEN      8
#define FTSPI_XIPCMD_INSTR_DQ_MASK     0x0ff00000
// Field       : DQ_EN
// Access      : RW
// Dual/Quad Mode I/O enable.
#define FTSPI_XIPCMD_DQ_EN_BIT         28
#define FTSPI_XIPCMD_DQ_EN_LEN         1
#define FTSPI_XIPCMD_DQ_EN_MASK        0x10000000
// ----------------------------------------------------------------------
// Register    : XIP Prefetch Function Option Register
//
#define FTSPI_XIPPFO_ADDR              0x10010034
// Field       : BYPASS_CACHE
// Access      : RW
// Bypass the prefetch cache. When this bit is set the SPI controller
// will invalidate cache entries and reads will go straight to the SPI
// flash.
#define FTSPI_XIPPFO_BYPASS_CACHE_BIT  0
#define FTSPI_XIPPFO_BYPASS_CACHE_LEN  1
#define FTSPI_XIPPFO_BYPASS_CACHE_MASK 0x00000001
// Field       : SRAM_RD_LAT
// Access      : RW
// Cache SRAM read latency in clock cycles.
#define FTSPI_XIPPFO_SRAM_RD_LAT_BIT   1
#define FTSPI_XIPPFO_SRAM_RD_LAT_LEN   2
#define FTSPI_XIPPFO_SRAM_RD_LAT_MASK  0x00000006
// ----------------------------------------------------------------------
// Register    : Revision Register
//
#define FTSPI_RR_ADDR                  0x10010050
// Field       : REV_VER
// Access      : RO
// Revision number
#define FTSPI_RR_REV_VER_BIT           0
#define FTSPI_RR_REV_VER_LEN           8
#define FTSPI_RR_REV_VER_MASK          0x000000ff
// Field       : MINOR_VER
// Access      : RO
// Minor version number
#define FTSPI_RR_MINOR_VER_BIT         8
#define FTSPI_RR_MINOR_VER_LEN         8
#define FTSPI_RR_MINOR_VER_MASK        0x0000ff00
// Field       : MAJOR_VER
// Access      : RO
// Major version number
#define FTSPI_RR_MAJOR_VER_BIT         16
#define FTSPI_RR_MAJOR_VER_LEN         8
#define FTSPI_RR_MAJOR_VER_MASK        0x00ff0000
// ----------------------------------------------------------------------
// Register    : Feature Register
//
#define FTSPI_FR_ADDR                  0x10010054
// Field       : TXFIFO_DEPTH
// Access      : RO
// Tx FIFO Depth in Words.
#define FTSPI_FR_TXFIFO_DEPTH_BIT      0
#define FTSPI_FR_TXFIFO_DEPTH_LEN      8
#define FTSPI_FR_TXFIFO_DEPTH_MASK     0x000000ff
// Field       : RXFIFO_DEPTH
// Access      : RO
// Rx FIFO Depth in Words.
#define FTSPI_FR_RXFIFO_DEPTH_BIT      8
#define FTSPI_FR_RXFIFO_DEPTH_LEN      8
#define FTSPI_FR_RXFIFO_DEPTH_MASK     0x0000ff00
// Field       : IDW
// Access      : RO
// AXI Bus ID Width. Not meaningful since the SPI is on the AHB bus.
#define FTSPI_FR_IDW_BIT               19
#define FTSPI_FR_IDW_LEN               5
#define FTSPI_FR_IDW_MASK              0x00f80000
// Field       : DTR
// Access      : RO
// DTR mode available.
#define FTSPI_FR_DTR_BIT               24
#define FTSPI_FR_DTR_LEN               1
#define FTSPI_FR_DTR_MASK              0x01000000
// Field       : CLK
// Access      : RO
// System and SPI clocks are asynchronous.
#define FTSPI_FR_CLK_BIT               25
#define FTSPI_FR_CLK_LEN               1
#define FTSPI_FR_CLK_MASK              0x02000000
// Field       : XIP
// Access      : RO
// XIP mode available.
#define FTSPI_FR_XIP_BIT               29
#define FTSPI_FR_XIP_LEN               1
#define FTSPI_FR_XIP_MASK              0x20000000
// Field       : DW
// Access      : RO
// Data bus width is 32 bits.
#define FTSPI_FR_DW_BIT                30
#define FTSPI_FR_DW_LEN                1
#define FTSPI_FR_DW_MASK               0x40000000
// Field       : AHB
// Access      : RO
// The bus interface is AHB.
#define FTSPI_FR_AHB_BIT               31
#define FTSPI_FR_AHB_LEN               1
#define FTSPI_FR_AHB_MASK              0x80000000
// ----------------------------------------------------------------------
// Register    : Data Port Register
// Data written goes into the TxFIFO for writing to SPI flash. Data read
// comes from the RxFIFO that was read from the SPI flash or cache in the
// case of prefetching.
#define FTSPI_DR_ADDR                  0x10010100
// Field       : DUMMY
// Access      : RW
#define FTSPI_DR_BIT                   0
#define FTSPI_DR_LEN                   32
#define FTSPI_DR_MASK                  0xffffffff


// ======================================================================
// Module      : Interal ROM High Range
// Base Address: 0x10020000
//
// ----------------------------------------------------------------------
// Memory      : Interal ROM
//
#define IROM_MEM_START_ADDR            0x10020000
#define IROM_MEM_WORDS                 0x00000400
#define IROM_MEM_WIDTH                 0x00000020


// ======================================================================
// Module      : Faraday FTDMAC020 DMA Controller
// Base Address: 0x10030000
// The DMA controller supports two channels. The channels are serviced in
// round-robin fashion. Refer to the Ax Architecture document for more
// information about the DMA controller.
// ----------------------------------------------------------------------
// Register    : Interrupt Status Register
// This registers it the 'or' of INT_ABT[n], INT_ERR[n] and INT_TC[n].
#define FTDMA_INT_ADDR                 0x10030000
// Field       : INT0
// Access      : RO
// Set when the corresponding channel has an interrupt pending.
#define FTDMA_INT_INT0_BIT             0
#define FTDMA_INT_INT0_LEN             2
#define FTDMA_INT_INT0_MASK            0x00000003
// ----------------------------------------------------------------------
// Register    : Interrupt Terminal Count Status Register
// This register shows the status of the DMA terminal count interrupts
// after masking. The mask bit of these interrupts is bit 0 (INT_TC_MSK)
// of the Channel Configuration register (Cn_CFG). If this mask bit is
// set, the content of this register is always ?0? regardless of the
// presence of a pending DMA terminal count interrupt.
#define FTDMA_INT_TC_ST_ADDR           0x10030004
// Field       : INT0
// Access      : RO
// Set when bit corresponding to channel has a terminal count interrupt
// pending.
#define FTDMA_INT_TC_ST_INT0_BIT       0
#define FTDMA_INT_TC_ST_INT0_LEN       2
#define FTDMA_INT_TC_ST_INT0_MASK      0x00000003
// ----------------------------------------------------------------------
// Register    : Interrupt Terminal Count Clear Register
// Writing 1 to bit n of this register clears both INT_TC[n] and TC[n].
#define FTDMA_INT_TC_CLR_ADDR          0x10030008
// Field       : INT0
// Access      : W1C
// Clear terminal count interrupt corresponding to bit set to 1.
#define FTDMA_INT_TC_CLR_INT0_BIT      0
#define FTDMA_INT_TC_CLR_INT0_LEN      2
#define FTDMA_INT_TC_CLR_INT0_MASK     0x00000003
// ----------------------------------------------------------------------
// Register    : Interrupt Error/Abort Status Register
// INT_ERR is the status of the DMA error interrupts after masking. The
// mask bit of these interrupts is bit 1 (INT_ERR_MSK) of the channel
// configuration register (Cn_CFG). If this mask bit is set, the content
// of INT_ERR[n] of this register will always be ?0? regardless of the
// presence of a pending DMA error interrupt. If an AHB ERROR response
// happens during the DMA transfer, the DMA controller will stop the
// current DMA transfer and will set ERR[n] to 1. Then, if INT_ERR_MSK is
// not set, the DMA controller will set INT_ERR[n] to 1 and assert the
// dmaint_err and dmaint interrupts. INT_ABT is the status of the DMA
// abort interrupts after masking. The mask bit of these interrupts is
// bit 2 (INT_ABT_MSK) of the channel configuration register (Cn_CFG). If
// this mask bit is set, the content of INT_ABT[n] of this register will
// always be 0, regardless of the presence of a pending DMA abort
// interrupt. If the ABT bit (Bit 15 of the channel control register
// (Cn_CSR)) is set, the DMA controller will stop the current DMA
// transfer and set ABT[n] to 1. Then, if INT_ABT_MSK is not set, the DMA
// controller will set INT_ABT[n] to 1 and assert the dmaint interrupt.
#define FTDMA_INT_ERRABT_ST_ADDR       0x1003000c
// Field       : INT_ERR
// Access      : RO
// Set when the corresponding channel has an error interrupt pending.
#define FTDMA_INT_ERRABT_ST_INT_ERR_BIT 0
#define FTDMA_INT_ERRABT_ST_INT_ERR_LEN 2
#define FTDMA_INT_ERRABT_ST_INT_ERR_MASK 0x00000003
// Field       : INT_ABT
// Access      : RO
// Set when the corresponding channel has an abort interrupt pending.
#define FTDMA_INT_ERRABT_ST_INT_ABT_BIT 16
#define FTDMA_INT_ERRABT_ST_INT_ABT_LEN 2
#define FTDMA_INT_ERRABT_ST_INT_ABT_MASK 0x00030000
// ----------------------------------------------------------------------
// Register    : Interrupt Error/Abort Clear Register
//
#define FTDMA_INT_ERRABT_CLR_ADDR      0x10030010
// Field       : INT_ERR_CLR
// Access      : W1C
// Write 1 to clear the corresponding bit.
#define FTDMA_INT_ERRABT_CLR_INT_ERR_CLR_BIT 0
#define FTDMA_INT_ERRABT_CLR_INT_ERR_CLR_LEN 2
#define FTDMA_INT_ERRABT_CLR_INT_ERR_CLR_MASK 0x00000003
// Field       : INT_ABT_CLR
// Access      : W1C
// Write 1 to clear the corresponding bit.
#define FTDMA_INT_ERRABT_CLR_INT_ABT_CLR_BIT 16
#define FTDMA_INT_ERRABT_CLR_INT_ABT_CLR_LEN 2
#define FTDMA_INT_ERRABT_CLR_INT_ABT_CLR_MASK 0x00030000
// ----------------------------------------------------------------------
// Register    : Terminal Count Register
// This register shows the status of the DMA terminal count after
// masking. The mask bit for the DMA terminal count is bit 31 (TC_MSK) of
// the channel control register (Cn_CSR). If this mask bit of the Cn_CSR
// register is set, TC[n] of this register will always be 0 regardless of
// the presence of a DMA terminal count.
#define FTDMA_TC_ADDR                  0x10030014
// Field       : TC
// Access      : RO
// Bit is set when the corresponding channel has reached its terminal
// count.
#define FTDMA_TC_TC_BIT                0
#define FTDMA_TC_TC_LEN                2
#define FTDMA_TC_TC_MASK               0x00000003
// ----------------------------------------------------------------------
// Register    : Error/Abort Status Register Register
// ERR is the status of the DMA error. If an AHB ERROR response happens
// during a DMA transfer, the DMA controller will stop the current DMA
// transfer and set ERR[n] to 1. If INT_ERR_MSK is not set, the DMA
// controller will set INT_ERR[n] to 1 and assert both the dmaint_err and
// dmaint interrupts. ABT is the status of the DMA abort. If the ABT bit
// (Bit 15 of the Channel Control register (Cn_CSR)) is set, the DMA
// controller will stop the current DMA transfer and set ABT[n] to 1. If
// INT_ABT_MSK is not set, the DMA controller will set INT_ABT[n] to 1
// and assert the dmaint interrupt.
#define FTDMA_ERRABT_ST_ADDR           0x10030018
// Field       : ERR
// Access      : RO
// Set when the corresponding channel has an error.
#define FTDMA_ERRABT_ST_ERR_BIT        0
#define FTDMA_ERRABT_ST_ERR_LEN        2
#define FTDMA_ERRABT_ST_ERR_MASK       0x00000003
// Field       : ABT
// Access      : RO
// Set when the corresponding channel was aborted.
#define FTDMA_ERRABT_ST_ABT_BIT        16
#define FTDMA_ERRABT_ST_ABT_LEN        2
#define FTDMA_ERRABT_ST_ABT_MASK       0x00030000
// ----------------------------------------------------------------------
// Register    : Channel Enable Status Register
//
#define FTDMA_CH_EN_ADDR               0x1003001c
// Field       : CH_EN
// Access      : RO
// Set when the corresponding channel is enabled.
#define FTDMA_CH_EN_CH_EN_BIT          0
#define FTDMA_CH_EN_CH_EN_LEN          2
#define FTDMA_CH_EN_CH_EN_MASK         0x00000003
// ----------------------------------------------------------------------
// Register    : Channel Busy Status  Register
// Care should be exercised when using the busy bit to determine if the
// DMA controller is finished. It is possible that the CPU will read the
// DMA busy bit as not active, before the DMA controller has started and
// actually set the bit. It is recommended to use the Terminal Count
// status instead.
#define FTDMA_CH_BUSY_ADDR             0x10030020
// Field       : CH_EN
// Access      : RO
// Set when the corresponding channel is busy.
#define FTDMA_CH_BUSY_CH_EN_BIT        0
#define FTDMA_CH_BUSY_CH_EN_LEN        2
#define FTDMA_CH_BUSY_CH_EN_MASK       0x00000003
// ----------------------------------------------------------------------
// Register    : Configuration Status  Register
//
#define FTDMA_CSR_ADDR                 0x10030024
// Field       : DMACEN
// Access      : RW
// Set to enable the DMA controller.
#define FTDMA_CSR_DMACEN_BIT           0
#define FTDMA_CSR_DMACEN_LEN           1
#define FTDMA_CSR_DMACEN_MASK          0x00000001
// Field       : M0ENDIAN
// Access      : RW
// Write 0 for Little Endian bus format. Only Little Endian is supported.
#define FTDMA_CSR_M0ENDIAN_BIT         1
#define FTDMA_CSR_M0ENDIAN_LEN         1
#define FTDMA_CSR_M0ENDIAN_MASK        0x00000002
// ----------------------------------------------------------------------
// Register    : Sync Register
// The synchronization register is used to control the internal
// synchronization logic of the DMA controller for the hardware DMA
// request. To use HW Handshake Mode this bit must set, because the UART
// and SPI Flash run at different speeds.
#define FTDMA_SYNC_ADDR                0x10030028
// Field       : SYNC
// Access      : RW
// Set to enable sync logic.
#define FTDMA_SYNC_SYNC_BIT            0
#define FTDMA_SYNC_SYNC_LEN            1
#define FTDMA_SYNC_SYNC_MASK           0x00000001
// ----------------------------------------------------------------------
// Register    : DMA Controller Revision Register
//
#define FTDMA_REVISION_ADDR            0x10030030
// Field       : REL_REV
// Access      : RO
// Release revision number.
#define FTDMA_REVISION_REL_REV_BIT     0
#define FTDMA_REVISION_REL_REV_LEN     8
#define FTDMA_REVISION_REL_REV_MASK    0x000000ff
// Field       : MIN_REV
// Access      : RO
// Minor revision number.
#define FTDMA_REVISION_MIN_REV_BIT     8
#define FTDMA_REVISION_MIN_REV_LEN     8
#define FTDMA_REVISION_MIN_REV_MASK    0x0000ff00
// Field       : MAJ_REV
// Access      : RO
// Major revision number.
#define FTDMA_REVISION_MAJ_REV_BIT     16
#define FTDMA_REVISION_MAJ_REV_LEN     8
#define FTDMA_REVISION_MAJ_REV_MASK    0x00ff0000
// ----------------------------------------------------------------------
// Register    : DMA Controller Feature Register
// Since the DMA controller is highly configurable, the individual
// function of the DMA controller can be enabled or disabled before
// synthesizing a real design. This register reflects the actual
// configuration of the HW.
#define FTDMA_FEATURE_ADDR             0x10030034
// Field       : FF_ADD_WIDTH
// Access      : RO
// FIFO RAM address width.
#define FTDMA_FEATURE_FF_ADD_WIDTH_BIT 0
#define FTDMA_FEATURE_FF_ADD_WIDTH_LEN 4
#define FTDMA_FEATURE_FF_ADD_WIDTH_MASK 0x0000000f
// Field       : LINKLIST_YES
// Access      : RO
// Design supports chained DMA mode.
#define FTDMA_FEATURE_LINKLIST_YES_BIT 8
#define FTDMA_FEATURE_LINKLIST_YES_LEN 1
#define FTDMA_FEATURE_LINKLIST_YES_MASK 0x00000100
// Field       : AHB1_YES
// Access      : RO
// Design does not support second AHB.
#define FTDMA_FEATURE_AHB1_YES_BIT     9
#define FTDMA_FEATURE_AHB1_YES_LEN     1
#define FTDMA_FEATURE_AHB1_YES_MASK    0x00000200
// Field       : MAX_CHNO_N
// Access      : RO
// Design supports two channels.
#define FTDMA_FEATURE_MAX_CHNO_N_BIT   12
#define FTDMA_FEATURE_MAX_CHNO_N_LEN   4
#define FTDMA_FEATURE_MAX_CHNO_N_MASK  0x0000f000
// ----------------------------------------------------------------------
// Register    : Channel 0 Control Register
//
#define FTDMA_C0_CSR_ADDR              0x10030100
// Field       : CH_EN
// Access      : RW
// Set to enable this channel.
#define FTDMA_C0_CSR_CH_EN_BIT         0
#define FTDMA_C0_CSR_CH_EN_LEN         1
#define FTDMA_C0_CSR_CH_EN_MASK        0x00000001
// Field       : DST_SEL
// Access      : RW
// Always set to 0, because a second AHB is not enabled for this design.
#define FTDMA_C0_CSR_DST_SEL_BIT       1
#define FTDMA_C0_CSR_DST_SEL_LEN       1
#define FTDMA_C0_CSR_DST_SEL_MASK      0x00000002
// Field       : SRC_SEL
// Access      : RW
// Always set to 0, because a second AHB is not enabled for this design.
#define FTDMA_C0_CSR_SRC_SEL_BIT       2
#define FTDMA_C0_CSR_SRC_SEL_LEN       1
#define FTDMA_C0_CSR_SRC_SEL_MASK      0x00000004
// Field       : DSTAD_CTL
// Access      : RW
// Destination Address Control. 00: Increment, 01: Decrement, 10: Fixed,
// 11: Reserved.
#define FTDMA_C0_CSR_DSTAD_CTL_BIT     3
#define FTDMA_C0_CSR_DSTAD_CTL_LEN     2
#define FTDMA_C0_CSR_DSTAD_CTL_MASK    0x00000018
// Field       : SRCAD_CTL
// Access      : RW
// Destination Address Control. 00: Increment, 01: Decrement, 10: Fixed,
// 11: Reserved.
#define FTDMA_C0_CSR_SRCAD_CTL_BIT     5
#define FTDMA_C0_CSR_SRCAD_CTL_LEN     2
#define FTDMA_C0_CSR_SRCAD_CTL_MASK    0x00000060
// Field       : MODE
// Access      : RW
// 0: Normal DMA Mode, 1: HW Handshake Mode.
#define FTDMA_C0_CSR_MODE_BIT          7
#define FTDMA_C0_CSR_MODE_LEN          1
#define FTDMA_C0_CSR_MODE_MASK         0x00000080
// Field       : DST_WIDTH
// Access      : RW
// Destination transfer bit width. 000: 8, 001: 16, 010: 32, Others:
// Reserved. Hardware will automatically pack and unpack data as
// required. Notes: 1. If source transfer width < destination transfer
// width, DMA will pack the source input data. For example, if the source
// transfer width equals to 8 bits and the destination transfer width
// equals to 32 bits, then DMA will pack four sets of 8-bit source data
// and transfer one set of 32-bit data to destination. Limitation: Do not
// set DSTAD_CTL to '01'? (Decrement source address) when the pack
// function works; otherwise DMA will have a wrong action. 2. If source
// transfer width > destination transfer width, DMA will unpack the
// source input data. For example, if the source transfer width equals to
// 32 bits and the destination transfer width equals to 8 bits, then DMA
// will unpack the source of 32-bit data and transfer four sets of 8-bit
// data to destination.
#define FTDMA_C0_CSR_DST_WIDTH_BIT     8
#define FTDMA_C0_CSR_DST_WIDTH_LEN     3
#define FTDMA_C0_CSR_DST_WIDTH_MASK    0x00000700
// Field       : SRC_WIDTH
// Access      : RW
// Source transfer bit width. Handle the same as dst_width.
#define FTDMA_C0_CSR_SRC_WIDTH_BIT     11
#define FTDMA_C0_CSR_SRC_WIDTH_LEN     3
#define FTDMA_C0_CSR_SRC_WIDTH_MASK    0x00003800
// Field       : ABT
// Access      : W1C
// Transaction Abort. Writing 1 to this bit causes DMA to stop the
// current transfer, then set the ABT[n] bit of the Error/Abort Status
// register and assert the dmaint interrupt if INT_ABT_MSK = 0. Note:
// When writing 1 to bit 15 (ABT), all other bits of this register will
// remain the same. That is, users cannot program bit 15 to bit 1 and
// other bits of this register simultaneously.
#define FTDMA_C0_CSR_ABT_BIT           15
#define FTDMA_C0_CSR_ABT_LEN           1
#define FTDMA_C0_CSR_ABT_MASK          0x00008000
// Field       : SRC_SIZE
// Access      : RW
// Source burst size is the number of transfers the DMA controller should
// move before re-arbitrating. 0: 1, 1: 4, 2: 8, 3: 16, 4: 32, 5: 64, 6:
// 128, 7: 256. Burst size * SRC_WIDTH) must be equal to or larger than
// DST_WIDTH.
#define FTDMA_C0_CSR_SRC_SIZE_BIT      16
#define FTDMA_C0_CSR_SRC_SIZE_LEN      3
#define FTDMA_C0_CSR_SRC_SIZE_MASK     0x00070000
// Field       : PROT1
// Access      : RW
// Memory Protection Settings. 0: User Mode, 1: Privileged Mode.
#define FTDMA_C0_CSR_PROT1_BIT         19
#define FTDMA_C0_CSR_PROT1_LEN         1
#define FTDMA_C0_CSR_PROT1_MASK        0x00080000
// Field       : PROT2
// Access      : RW
// Memory Protection Settings. 0: Not bufferable, 1: Bufferable.
#define FTDMA_C0_CSR_PROT2_BIT         20
#define FTDMA_C0_CSR_PROT2_LEN         1
#define FTDMA_C0_CSR_PROT2_MASK        0x00100000
// Field       : PROT3
// Access      : RW
// Memory Protection Settings. 0: Not cacheable, 1: Cacheable.
#define FTDMA_C0_CSR_PROT3_BIT         21
#define FTDMA_C0_CSR_PROT3_LEN         1
#define FTDMA_C0_CSR_PROT3_MASK        0x00200000
// Field       : DMA_FF_TH
// Access      : RW
// DMA FIFO Threshold Value. DMAC waits until there is at least this much
// space in FIFO before fetching and waits until there are at least this
// many words in the FIFO before beginning a write to the destination.
// Threshold = 1 << DMA_FF_TH.
#define FTDMA_C0_CSR_DMA_FF_TH_BIT     24
#define FTDMA_C0_CSR_DMA_FF_TH_LEN     3
#define FTDMA_C0_CSR_DMA_FF_TH_MASK    0x07000000
// Field       : TC_MSK
// Access      : RW
// Terminal Count Status Mask. 0: When the terminal count is reached, the
// TC status register will be set, 1: When the terminal count is reached
// the TC status register is not set.
#define FTDMA_C0_CSR_TC_MSK_BIT        31
#define FTDMA_C0_CSR_TC_MSK_LEN        1
#define FTDMA_C0_CSR_TC_MSK_MASK       0x80000000
// ----------------------------------------------------------------------
// Register    : Channel 0 Configuration Register
//
#define FTDMA_C0_CFG_ADDR              0x10030104
// Field       : INT_TC_MSK
// Access      : RW
// Set to mask terminal count interrupt.
#define FTDMA_C0_CFG_INT_TC_MSK_BIT    0
#define FTDMA_C0_CFG_INT_TC_MSK_LEN    1
#define FTDMA_C0_CFG_INT_TC_MSK_MASK   0x00000001
// Field       : INT_ERR_MSK
// Access      : RW
// Set to mask error interrupt.
#define FTDMA_C0_CFG_INT_ERR_MSK_BIT   1
#define FTDMA_C0_CFG_INT_ERR_MSK_LEN   1
#define FTDMA_C0_CFG_INT_ERR_MSK_MASK  0x00000002
// Field       : INT_ABT_MSK
// Access      : RW
// Set to mask abort interrupt.
#define FTDMA_C0_CFG_INT_ABT_MSK_BIT   2
#define FTDMA_C0_CFG_INT_ABT_MSK_LEN   1
#define FTDMA_C0_CFG_INT_ABT_MSK_MASK  0x00000004
// Field       : SRC_RS
// Access      : RW
// Source DMA request select. It specifies the dma_req source and can
// only be used when the DMA hardware handshake mode is enabled. 0: SPI
// Flash, 1: UART Tx, 2: UART Rx.
#define FTDMA_C0_CFG_SRC_RS_BIT        3
#define FTDMA_C0_CFG_SRC_RS_LEN        4
#define FTDMA_C0_CFG_SRC_RS_MASK       0x00000078
// Field       : SRC_HE
// Access      : RW
// Source HW Handshake Mode enable. When users disable the destination
// hardware handshake, DMA will start transferring data without waiting
// for the destination request. This bit will be only valid when DMAC is
// in the hardware handshake mode.
#define FTDMA_C0_CFG_SRC_HE_BIT        7
#define FTDMA_C0_CFG_SRC_HE_LEN        1
#define FTDMA_C0_CFG_SRC_HE_MASK       0x00000080
// Field       : BUSY
// Access      : RO
// The DMA channel is busy. Care should be exercised when using the busy
// bit to determine if the DMA controller is finished. It is possible
// that the CPU will read the DMA busy bit as not active, before the DMA
// controller has started and actually set the bit. It is recommended to
// use the Terminal Count status instead.
#define FTDMA_C0_CFG_BUSY_BIT          8
#define FTDMA_C0_CFG_BUSY_LEN          1
#define FTDMA_C0_CFG_BUSY_MASK         0x00000100
// Field       : DST_RS
// Access      : RW
// Destination DMA request select.  It specifies the dma_req destination
// and can only be used when the DMA hardware handshake mode is enabled.
// 0: SPI Flash, 1: UART Tx, 2: UART Rx.
#define FTDMA_C0_CFG_DST_RS_BIT        9
#define FTDMA_C0_CFG_DST_RS_LEN        4
#define FTDMA_C0_CFG_DST_RS_MASK       0x00001e00
// Field       : DST_HE
// Access      : RW
// Destination HW Handshake Mode enable. When users disable the source
// hardware handshake, DMA will start transferring data without waiting
// for the source request. This bit will be only valid when DMAC is in
// the hardware handshake mode.
#define FTDMA_C0_CFG_DST_HE_BIT        13
#define FTDMA_C0_CFG_DST_HE_LEN        1
#define FTDMA_C0_CFG_DST_HE_MASK       0x00002000
// Field       : LLP_CNT
// Access      : RO
// Chain transfer counter. This counter is reset to 0 when CH_EN changes
// from 0 to 1. If the chain transfer is enabled after each block data
// transfer is finished, LLP_CNT will be increased by 1.
#define FTDMA_C0_CFG_LLP_CNT_BIT       16
#define FTDMA_C0_CFG_LLP_CNT_LEN       4
#define FTDMA_C0_CFG_LLP_CNT_MASK      0x000f0000
// ----------------------------------------------------------------------
// Register    : Channel 0 Source Address Register
// Source starting address. Note that when the DMA transaction is
// complete, its value will reflect the DMA source ending address.
#define FTDMA_C0_SRCADDR_ADDR          0x10030108
// Field       : DUMMY
// Access      : RW
#define FTDMA_C0_SRCADDR_BIT           0
#define FTDMA_C0_SRCADDR_LEN           32
#define FTDMA_C0_SRCADDR_MASK          0xffffffff
// ----------------------------------------------------------------------
// Register    : Channel 0 Destination Address Register
// Destination starting address. Note that when the DMA transaction is
// complete, its value will reflect the DMA destination ending address.
#define FTDMA_C0_DSTADDR_ADDR          0x1003010c
// Field       : DUMMY
// Access      : RW
#define FTDMA_C0_DSTADDR_BIT           0
#define FTDMA_C0_DSTADDR_LEN           32
#define FTDMA_C0_DSTADDR_MASK          0xffffffff
// ----------------------------------------------------------------------
// Register    : Channel 0 Link List Pointer Register
//
#define FTDMA_C0_LLP_ADDR              0x10030110
// Field       : LLP_MASTER
// Access      : RW
// Master for loading the next LLP. Always 0 for the Ax design.
#define FTDMA_C0_LLP_LLP_MASTER_BIT    0
#define FTDMA_C0_LLP_LLP_MASTER_LEN    1
#define FTDMA_C0_LLP_LLP_MASTER_MASK   0x00000001
// Field       : LLP_ADDR
// Access      : RW
// Linked list pointer address. This field specifies the upper 30 bits of
// the address. The lower 2 bits are assumed to be 0.
#define FTDMA_C0_LLP_LLP_ADDR_BIT      2
#define FTDMA_C0_LLP_LLP_ADDR_LEN      30
#define FTDMA_C0_LLP_LLP_ADDR_MASK     0xfffffffc
// ----------------------------------------------------------------------
// Register    : Channel 0 Transfer Size Register
//
#define FTDMA_C0_SIZE_ADDR             0x10030114
// Field       : TOT_SIZE
// Access      : RW
// Total transfer beats of the bus size. When the transfer is complete
// this register should read as 0.
#define FTDMA_C0_SIZE_TOT_SIZE_BIT     0
#define FTDMA_C0_SIZE_TOT_SIZE_LEN     22
#define FTDMA_C0_SIZE_TOT_SIZE_MASK    0x003fffff
// ----------------------------------------------------------------------
// Register    : Channel 1 Control Register
//
#define FTDMA_C1_CSR_ADDR              0x10030120
// Field       : CH_EN
// Access      : RW
// Set to enable this channel.
#define FTDMA_C1_CSR_CH_EN_BIT         0
#define FTDMA_C1_CSR_CH_EN_LEN         1
#define FTDMA_C1_CSR_CH_EN_MASK        0x00000001
// Field       : DST_SEL
// Access      : RW
// Always set to 0, because a second AHB is not enabled for this design.
#define FTDMA_C1_CSR_DST_SEL_BIT       1
#define FTDMA_C1_CSR_DST_SEL_LEN       1
#define FTDMA_C1_CSR_DST_SEL_MASK      0x00000002
// Field       : SRC_SEL
// Access      : RW
// Always set to 0, because a second AHB is not enabled for this design.
#define FTDMA_C1_CSR_SRC_SEL_BIT       2
#define FTDMA_C1_CSR_SRC_SEL_LEN       1
#define FTDMA_C1_CSR_SRC_SEL_MASK      0x00000004
// Field       : DSTAD_CTL
// Access      : RW
// Destination Address Control. 00: Increment, 01: Decrement, 10: Fixed,
// 11: Reserved.
#define FTDMA_C1_CSR_DSTAD_CTL_BIT     3
#define FTDMA_C1_CSR_DSTAD_CTL_LEN     2
#define FTDMA_C1_CSR_DSTAD_CTL_MASK    0x00000018
// Field       : SRCAD_CTL
// Access      : RW
// Destination Address Control. 00: Increment, 01: Decrement, 10: Fixed,
// 11: Reserved.
#define FTDMA_C1_CSR_SRCAD_CTL_BIT     5
#define FTDMA_C1_CSR_SRCAD_CTL_LEN     2
#define FTDMA_C1_CSR_SRCAD_CTL_MASK    0x00000060
// Field       : MODE
// Access      : RW
// 0: Normal DMA Mode, 1: HW Handshake Mode.
#define FTDMA_C1_CSR_MODE_BIT          7
#define FTDMA_C1_CSR_MODE_LEN          1
#define FTDMA_C1_CSR_MODE_MASK         0x00000080
// Field       : DST_WIDTH
// Access      : RW
// Destination transfer bit width. 000: 8, 001: 16, 010: 32, Others:
// Reserved. Hardware will automatically pack and unpack data as
// required. Notes: 1. If source transfer width < destination transfer
// width, DMA will pack the source input data. For example, if the source
// transfer width equals to 8 bits and the destination transfer width
// equals to 32 bits, then DMA will pack four sets of 8-bit source data
// and transfer one set of 32-bit data to destination. Limitation: Do not
// set DSTAD_CTL to '01'? (Decrement source address) when the pack
// function works; otherwise DMA will have a wrong action. 2. If source
// transfer width > destination transfer width, DMA will unpack the
// source input data. For example, if the source transfer width equals to
// 32 bits and the destination transfer width equals to 8 bits, then DMA
// will unpack the source of 32-bit data and transfer four sets of 8-bit
// data to destination.
#define FTDMA_C1_CSR_DST_WIDTH_BIT     8
#define FTDMA_C1_CSR_DST_WIDTH_LEN     3
#define FTDMA_C1_CSR_DST_WIDTH_MASK    0x00000700
// Field       : SRC_WIDTH
// Access      : RW
// Source transfer bit width. Handle the same as dst_width.
#define FTDMA_C1_CSR_SRC_WIDTH_BIT     11
#define FTDMA_C1_CSR_SRC_WIDTH_LEN     3
#define FTDMA_C1_CSR_SRC_WIDTH_MASK    0x00003800
// Field       : ABT
// Access      : W1C
// Transaction Abort. Writing 1 to this bit causes DMA to stop the
// current transfer, then set the ABT[n] bit of the Error/Abort Status
// register and assert the dmaint interrupt if INT_ABT_MSK = 0. Note:
// When writing 1 to bit 15 (ABT), all other bits of this register will
// remain the same. That is, users cannot program bit 15 to bit 1 and
// other bits of this register simultaneously.
#define FTDMA_C1_CSR_ABT_BIT           15
#define FTDMA_C1_CSR_ABT_LEN           1
#define FTDMA_C1_CSR_ABT_MASK          0x00008000
// Field       : SRC_SIZE
// Access      : RW
// Source burst size is the number of transfers the DMA controller should
// move before re-arbitrating. 0: 1, 1: 4, 2: 8, 3: 16, 4: 32, 5: 64, 6:
// 128, 7: 256. Burst size * SRC_WIDTH) must be equal to or larger than
// DST_WIDTH.
#define FTDMA_C1_CSR_SRC_SIZE_BIT      16
#define FTDMA_C1_CSR_SRC_SIZE_LEN      3
#define FTDMA_C1_CSR_SRC_SIZE_MASK     0x00070000
// Field       : PROT1
// Access      : RW
// Memory Protection Settings. 0: User Mode, 1: Privileged Mode.
#define FTDMA_C1_CSR_PROT1_BIT         19
#define FTDMA_C1_CSR_PROT1_LEN         1
#define FTDMA_C1_CSR_PROT1_MASK        0x00080000
// Field       : PROT2
// Access      : RW
// Memory Protection Settings. 0: Not bufferable, 1: Bufferable.
#define FTDMA_C1_CSR_PROT2_BIT         20
#define FTDMA_C1_CSR_PROT2_LEN         1
#define FTDMA_C1_CSR_PROT2_MASK        0x00100000
// Field       : PROT3
// Access      : RW
// Memory Protection Settings. 0: Not cacheable, 1: Cacheable.
#define FTDMA_C1_CSR_PROT3_BIT         21
#define FTDMA_C1_CSR_PROT3_LEN         1
#define FTDMA_C1_CSR_PROT3_MASK        0x00200000
// Field       : DMA_FF_TH
// Access      : RW
// DMA FIFO Threshold Value. DMAC waits until there is at least this much
// space in FIFO before fetching and waits until there are at least this
// many words in the FIFO before beginning a write to the destination.
// Threshold = 1 << DMA_FF_TH.
#define FTDMA_C1_CSR_DMA_FF_TH_BIT     24
#define FTDMA_C1_CSR_DMA_FF_TH_LEN     3
#define FTDMA_C1_CSR_DMA_FF_TH_MASK    0x07000000
// Field       : TC_MSK
// Access      : RW
// Terminal Count Status Mask. 0: When the terminal count is reached, the
// TC status register will be set, 1: When the terminal count is reached
// the TC status register is not set.
#define FTDMA_C1_CSR_TC_MSK_BIT        31
#define FTDMA_C1_CSR_TC_MSK_LEN        1
#define FTDMA_C1_CSR_TC_MSK_MASK       0x80000000
// ----------------------------------------------------------------------
// Register    : Channel 1 Configuration Register
//
#define FTDMA_C1_CFG_ADDR              0x10030124
// Field       : INT_TC_MSK
// Access      : RW
// Set to mask terminal count interrupt.
#define FTDMA_C1_CFG_INT_TC_MSK_BIT    0
#define FTDMA_C1_CFG_INT_TC_MSK_LEN    1
#define FTDMA_C1_CFG_INT_TC_MSK_MASK   0x00000001
// Field       : INT_ERR_MSK
// Access      : RW
// Set to mask error interrupt.
#define FTDMA_C1_CFG_INT_ERR_MSK_BIT   1
#define FTDMA_C1_CFG_INT_ERR_MSK_LEN   1
#define FTDMA_C1_CFG_INT_ERR_MSK_MASK  0x00000002
// Field       : INT_ABT_MSK
// Access      : RW
// Set to mask abort interrupt.
#define FTDMA_C1_CFG_INT_ABT_MSK_BIT   2
#define FTDMA_C1_CFG_INT_ABT_MSK_LEN   1
#define FTDMA_C1_CFG_INT_ABT_MSK_MASK  0x00000004
// Field       : SRC_RS
// Access      : RW
// Source DMA request select. It specifies the dma_req source and can
// only be used when the DMA hardware handshake mode is enabled. 0: SPI
// Flash, 1: UART Tx, 2: UART Rx.
#define FTDMA_C1_CFG_SRC_RS_BIT        3
#define FTDMA_C1_CFG_SRC_RS_LEN        4
#define FTDMA_C1_CFG_SRC_RS_MASK       0x00000078
// Field       : SRC_HE
// Access      : RW
// Source HW Handshake Mode enable. When users disable the destination
// hardware handshake, DMA will start transferring data without waiting
// for the destination request. This bit will be only valid when DMAC is
// in the hardware handshake mode.
#define FTDMA_C1_CFG_SRC_HE_BIT        7
#define FTDMA_C1_CFG_SRC_HE_LEN        1
#define FTDMA_C1_CFG_SRC_HE_MASK       0x00000080
// Field       : BUSY
// Access      : RO
// The DMA channel is busy. Care should be exercised when using the busy
// bit to determine if the DMA controller is finished. It is possible
// that the CPU will read the DMA busy bit as not active, before the DMA
// controller has started and actually set the bit. It is recommended to
// use the Terminal Count status instead.
#define FTDMA_C1_CFG_BUSY_BIT          8
#define FTDMA_C1_CFG_BUSY_LEN          1
#define FTDMA_C1_CFG_BUSY_MASK         0x00000100
// Field       : DST_RS
// Access      : RW
// Destination DMA request select.  It specifies the dma_req destination
// and can only be used when the DMA hardware handshake mode is enabled.
// 0: SPI Flash, 1: UART Tx, 2: UART Rx.
#define FTDMA_C1_CFG_DST_RS_BIT        9
#define FTDMA_C1_CFG_DST_RS_LEN        4
#define FTDMA_C1_CFG_DST_RS_MASK       0x00001e00
// Field       : DST_HE
// Access      : RW
// Destination HW Handshake Mode enable. When users disable the source
// hardware handshake, DMA will start transferring data without waiting
// for the source request. This bit will be only valid when DMAC is in
// the hardware handshake mode.
#define FTDMA_C1_CFG_DST_HE_BIT        13
#define FTDMA_C1_CFG_DST_HE_LEN        1
#define FTDMA_C1_CFG_DST_HE_MASK       0x00002000
// Field       : LLP_CNT
// Access      : RO
// Chain transfer counter. This counter is reset to 0 when CH_EN changes
// from 0 to 1. If the chain transfer is enabled after each block data
// transfer is finished, LLP_CNT will be increased by 1.
#define FTDMA_C1_CFG_LLP_CNT_BIT       16
#define FTDMA_C1_CFG_LLP_CNT_LEN       4
#define FTDMA_C1_CFG_LLP_CNT_MASK      0x000f0000
// ----------------------------------------------------------------------
// Register    : Channel 1 Source Address Register
// Source starting address. Note that when the DMA transaction is
// complete, its value will reflect the DMA source ending address.
#define FTDMA_C1_SRCADDR_ADDR          0x10030128
// Field       : DUMMY
// Access      : RW
#define FTDMA_C1_SRCADDR_BIT           0
#define FTDMA_C1_SRCADDR_LEN           32
#define FTDMA_C1_SRCADDR_MASK          0xffffffff
// ----------------------------------------------------------------------
// Register    : Channel 1 Destination Address Register
// Destination starting address. Note that when the DMA transaction is
// complete, its value will reflect the DMA destination ending address.
#define FTDMA_C1_DSTADDR_ADDR          0x1003012c
// Field       : DUMMY
// Access      : RW
#define FTDMA_C1_DSTADDR_BIT           0
#define FTDMA_C1_DSTADDR_LEN           32
#define FTDMA_C1_DSTADDR_MASK          0xffffffff
// ----------------------------------------------------------------------
// Register    : Channel 1 Link List Pointer Register
//
#define FTDMA_C1_LLP_ADDR              0x10030130
// Field       : LLP_MASTER
// Access      : RW
// Master for loading the next LLP. Always 0 for the Ax design.
#define FTDMA_C1_LLP_LLP_MASTER_BIT    0
#define FTDMA_C1_LLP_LLP_MASTER_LEN    1
#define FTDMA_C1_LLP_LLP_MASTER_MASK   0x00000001
// Field       : LLP_ADDR
// Access      : RW
// Linked list pointer address. This field specifies the upper 30 bits of
// the address. The lower 2 bits are assumed to be 0.
#define FTDMA_C1_LLP_LLP_ADDR_BIT      2
#define FTDMA_C1_LLP_LLP_ADDR_LEN      30
#define FTDMA_C1_LLP_LLP_ADDR_MASK     0xfffffffc
// ----------------------------------------------------------------------
// Register    : Channel 1 Transfer Size Register
//
#define FTDMA_C1_SIZE_ADDR             0x10030134
// Field       : TOT_SIZE
// Access      : RW
// Total transfer beats of the bus size. When the transfer is complete
// this register should read as 0.
#define FTDMA_C1_SIZE_TOT_SIZE_BIT     0
#define FTDMA_C1_SIZE_TOT_SIZE_LEN     22
#define FTDMA_C1_SIZE_TOT_SIZE_MASK    0x003fffff


