// ======================================================================
// Module      : Faraday FTTMR010 Timer
// Base Address: 0x10100000
// The Faraday timer provides three independent sets of sub-timers. Each
// sub-timer can use the internal system clock (PCLK) or external clock
// (EXTCLK) to increase or decrease counting. Two match registers are
// provided for each sub-timer. When the values of the match registers
// equal to any value of the sub-timers, the timer interrupt will be
// immediately triggered. Issuing a timer interrupt is decided by the
// register setting when an overflow occurs.
// ----------------------------------------------------------------------
// Register    : Timer 1 Count Register
// Holds the count value for timer 1. If the timer is not enabled the
// count will be held.
#define FTTMR_TM1COUNTER_ADDR          0x10100000
// Field       : DUMMY
// Access      : RW
#define FTTMR_TM1COUNTER_BIT           0
#define FTTMR_TM1COUNTER_LEN           32
#define FTTMR_TM1COUNTER_MASK          0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 1 Load Register
// When the counter underflows/overflows the TmLoad value will be loaded
// into the TmCounter register. This value can be used to set the period
// between two overflows or underflows.
#define FTTMR_TM1LOAD_ADDR             0x10100004
// Field       : DUMMY
// Access      : RW
#define FTTMR_TM1LOAD_BIT              0
#define FTTMR_TM1LOAD_LEN              32
#define FTTMR_TM1LOAD_MASK             0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 1 Match 1 Register
// When the values of TmCounter equals TmMatch an interrupt will be
// triggered if one is enabled.
#define FTTMR_TM1MATCH1_ADDR           0x10100008
// Field       : DUMMY
// Access      : RW
#define FTTMR_TM1MATCH1_BIT            0
#define FTTMR_TM1MATCH1_LEN            32
#define FTTMR_TM1MATCH1_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 1 Match 2 Register
// When the values of TmCounter equals TmMatch an interrupt will be
// triggered if one is enabled.
#define FTTMR_TM1MATCH2_ADDR           0x1010000c
// Field       : DUMMY
// Access      : RW
#define FTTMR_TM1MATCH2_BIT            0
#define FTTMR_TM1MATCH2_LEN            32
#define FTTMR_TM1MATCH2_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 2 Count Register
// Holds the count value for timer 2. If the timer is not enabled the
// count will be held.
#define FTTMR_TM2COUNTER_ADDR          0x10100010
// Field       : DUMMY
// Access      : RW
#define FTTMR_TM2COUNTER_BIT           0
#define FTTMR_TM2COUNTER_LEN           32
#define FTTMR_TM2COUNTER_MASK          0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 2 Load Register
// When the counter underflows/overflows the TmLoad value will be loaded
// into the TmCounter register. This value can be used to set the period
// between two overflows or underflows.
#define FTTMR_TM2LOAD_ADDR             0x10100014
// Field       : DUMMY
// Access      : RW
#define FTTMR_TM2LOAD_BIT              0
#define FTTMR_TM2LOAD_LEN              32
#define FTTMR_TM2LOAD_MASK             0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 2 Match 1 Register
