// Field       : DUMMY
// Access      : RW
#define FTTMR_TM2MATCH1_BIT            0
#define FTTMR_TM2MATCH1_LEN            32
#define FTTMR_TM2MATCH1_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 2 Match 2 Register
// When the values of TmCounter equals TmMatch an interrupt will be
