#define FTTMR_TM2MATCH2_ADDR           0x1010001c
// Field       : DUMMY
// Access      : RW
#define FTTMR_TM2MATCH2_BIT            0
#define FTTMR_TM2MATCH2_LEN            32
#define FTTMR_TM2MATCH2_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 3 Count Register
// Holds the count value for timer 3. If the timer is not enabled the
