#define FTTMR_TM3COUNTER_ADDR          0x10100020
// Field       : DUMMY
// Access      : RW
#define FTTMR_TM3COUNTER_BIT           0
#define FTTMR_TM3COUNTER_LEN           32
#define FTTMR_TM3COUNTER_MASK          0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 3 Load Register
// When the counter underflows/overflows the TmLoad value will be loaded
