// Field       : DUMMY
// Access      : RW
#define FTTMR_TM3LOAD_BIT              0
#define FTTMR_TM3LOAD_LEN              32
#define FTTMR_TM3LOAD_MASK             0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 3 Match 1 Register
// When the values of TmCounter equals TmMatch an interrupt will be
