// Field       : DUMMY
// Access      : RW
#define FTTMR_TM3MATCH1_BIT            0
#define FTTMR_TM3MATCH1_LEN            32
#define FTTMR_TM3MATCH1_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Timer 3 Match 2 Register
