// Field       : TM3ENABLE
// Access      : RW
// Enable timer.
#define FTTMR_TMCR_TM3ENABLE_BIT       6
#define FTTMR_TMCR_TM3ENABLE_LEN       1
#define FTTMR_TMCR_TM3ENABLE_MASK      0x00000040
// Field       : TM3CLOCK
// Access      : RW
// Clock tick source for timer. 0: PCLK, 1: EXTCLK
#define FTTMR_TMCR_TM3CLOCK_BIT        7
#define FTTMR_TMCR_TM3CLOCK_LEN        1
#define FTTMR_TMCR_TM3CLOCK_MASK       0x00000080
// Field       : TM3OFENABLE
// Access      : RW
// Enable overflow interrupt.
#define FTTMR_TMCR_TM3OFENABLE_BIT     8
#define FTTMR_TMCR_TM3OFENABLE_LEN     1
#define FTTMR_TMCR_TM3OFENABLE_MASK    0x00000100
// Field       : TM1UPDOWN
// Access      : RW
// 0: Timer counts down, 1: Timer counts up.
#define FTTMR_TMCR_TM1UPDOWN_BIT       9
#define FTTMR_TMCR_TM1UPDOWN_LEN       1
#define FTTMR_TMCR_TM1UPDOWN_MASK      0x00000200
// Field       : TM2UPDOWN
// Access      : RW
// 0: Timer counts down, 1: Timer counts up.
#define FTTMR_TMCR_TM2UPDOWN_BIT       10
#define FTTMR_TMCR_TM2UPDOWN_LEN       1
#define FTTMR_TMCR_TM2UPDOWN_MASK      0x00000400
// Field       : TM3UPDOWN
// Access      : RW
// 0: Timer counts down, 1: Timer counts up.
#define FTTMR_TMCR_TM3UPDOWN_BIT       11
#define FTTMR_TMCR_TM3UPDOWN_LEN       1
#define FTTMR_TMCR_TM3UPDOWN_MASK      0x00000800
// ----------------------------------------------------------------------
// Register    : Interrupt Status Register
// The IntrState register is the interrupt state register of FTTMR010.
// When the assertion of tmr_intr is detected, CPU must check which
// interrupt has occurred by reading the IntrState register. Each bit of
// the IntrState register must indicate that a corresponding interrupt
// has occurred. All bits of IntrState must be cleared by firmware. If
// some bits of pwdata are set, the related bits of IntrState will be
// cleared when users write to the IntrState address.
#define FTTMR_INTST_ADDR               0x10100034
// Field       : TM1MATCH1
// Access      : W1C
// The count value matched the match register.
#define FTTMR_INTST_TM1MATCH1_BIT      0
#define FTTMR_INTST_TM1MATCH1_LEN      1
#define FTTMR_INTST_TM1MATCH1_MASK     0x00000001
// Field       : TM1MATCH2
// Access      : W1C
// The count value matched the match register.
#define FTTMR_INTST_TM1MATCH2_BIT      1
#define FTTMR_INTST_TM1MATCH2_LEN      1
#define FTTMR_INTST_TM1MATCH2_MASK     0x00000002
// Field       : TM1OVERFLOW
// Access      : W1C
