#define FTTMR_INTST_TM2OVERFLOW_BIT    5
#define FTTMR_INTST_TM2OVERFLOW_LEN    1
#define FTTMR_INTST_TM2OVERFLOW_MASK   0x00000020
// Field       : TM3MATCH1
// Access      : W1C
// The count value matched the match register.
#define FTTMR_INTST_TM3MATCH1_BIT      6
#define FTTMR_INTST_TM3MATCH1_LEN      1
