// ======================================================================
// Module      : Watch Dog Timer
// Base Address: 0x10110000
// The Faraday WatchDog Timer (WDT) is used to prevent system from
// infinite loop if software gets trapped in the deadlock. Under normal
// operation, users will restart WDT at the regular intervals before
// counter counts down to 0. If the counter does reach 0, WDT will
// generate one or a combination of signals, system reset, system
// interrupt, and external interrupt to reset the system, interrupt the
// system, or interrupt an external device correspondingly. After the
// programmer turns on the enable bit of WDT in the WatchDog timer
// control register, the WDT counter starts to reduce the counting. If
// the Watch Dog timer reaches 0, the wd_rst signal, wd_intr signal, or
// wd_ext signal will be triggered. As long as the signal is set in the
// WdInstlen register, the assertion of this signal will depend on the
// WdRst, WdIntr, and WdExt bits in the WatchDog timer control register,
// the signal will keep asserted for a period of time. The WdStatus bit
// is used to check if the counter reaches 0 or not. The programmer can
// clear the WdStatus bit by writing 1 to the WdClear bit. To prevent the
// unexpected reset, the programmer needs to write 0x5AB9 to the
// WdRestart register as the password to activate the down counting
// function. If the WdRestart register equals 0x5AB9, the value of the
// WdLoad register will be loaded into the counter of the WatchDog timer.
// The default reset value of the WdRestart register is 0, and the
// WdRestart register will automatically return to 0 after each write.
// The default value of the WdLoad register is set to 0x3EF1480. The
// programmer can write this register to customize the operation of the
// WatchDog timer reset.
// ----------------------------------------------------------------------
// Register    : Watch Dog Count Register
// WdCounter contains the current counter value. When it is reset, the
// WdCounter register will be set to 0x3EF1480. After programmers write
// 0x5AB9 to WdRestart, the value of WdLoad will be loaded into
// WdCounter. WdCounter will start to decrease once WdCR[0], and the
// WatchDog timer enable bit is set. If the WatchDog timer is disabled,
// WdCounter will hold the value. If WdCR [4] is set, the register will
// be driven by an external clock, and WdCounter will decrease at the
// EXTCLK frequency.
#define FTWDT_WDCOUNTER_ADDR           0x10110000
// Field       : DUMMY
// Access      : RO
#define FTWDT_WDCOUNTER_BIT            0
#define FTWDT_WDCOUNTER_LEN            32
#define FTWDT_WDCOUNTER_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Watch Dog Load Register
// WdLoad contains the value which will be loaded into WdCounter. When it
// is reset or restarted, the value of WdLoad will be automatically
// loaded into the WdCounter register.
#define FTWDT_WDLOAD_ADDR              0x10110004
// Field       : DUMMY
// Access      : RW
#define FTWDT_WDLOAD_BIT               0
#define FTWDT_WDLOAD_LEN               32
#define FTWDT_WDLOAD_MASK              0xffffffff
// ----------------------------------------------------------------------
// Register    : Watch Dog Restart Register
// Writing 0x5AB9 to this register causes the WatchDog timer counter to
// load WdLoad into the WdCounter register and the WatchDog timer counter
// will begin to count down. After finishing the write cycle, WdRestart
// will automatically be reset to 0.
#define FTWDT_WDRESTART_ADDR           0x10110008
// Field       : DUMMY
// Access      : WO
#define FTWDT_WDRESTART_BIT            0
#define FTWDT_WDRESTART_LEN            32
#define FTWDT_WDRESTART_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Watch Dog Control Register
//
#define FTWDT_WDCR_ADDR                0x1011000c
// Field       : ENABLE
// Access      : RW
// {0: Disabled, 1: Enabled}
#define FTWDT_WDCR_ENABLE_BIT          0
#define FTWDT_WDCR_ENABLE_LEN          1
#define FTWDT_WDCR_ENABLE_MASK         0x00000001
// Field       : RESET
// Access      : RW
// {0: normal, 1: reset}
#define FTWDT_WDCR_RESET_BIT           1
#define FTWDT_WDCR_RESET_LEN           1
#define FTWDT_WDCR_RESET_MASK          0x00000002
// Field       : INTR
// Access      : RW
// {0: Interrupt disabled, 1: Interrupt enabled}
#define FTWDT_WDCR_INTR_BIT            2
#define FTWDT_WDCR_INTR_LEN            1
#define FTWDT_WDCR_INTR_MASK           0x00000004
// Field       : CLOCK
// Access      : RW
// Clock source {0: 104/125 MHz, 1: 10 MHz}
#define FTWDT_WDCR_CLOCK_BIT           4
#define FTWDT_WDCR_CLOCK_LEN           1
#define FTWDT_WDCR_CLOCK_MASK          0x00000010
// ----------------------------------------------------------------------
// Register    : Watch Dog Status Register
//
#define FTWDT_WDSTATUS_ADDR            0x10110010
// Field       : EXPIRED
// Access      : RO
// Reads 1 when the counter has counted down to 0.
#define FTWDT_WDSTATUS_EXPIRED_BIT     0
#define FTWDT_WDSTATUS_EXPIRED_LEN     1
#define FTWDT_WDSTATUS_EXPIRED_MASK    0x00000001
// ----------------------------------------------------------------------
// Register    : Watch Dog Status Clear Register
//
#define FTWDT_WDCLEAR_ADDR             0x10110014
// Field       : EXPIRED
// Access      : W1C
// Write a 1 to clear the WD Status Register.
#define FTWDT_WDCLEAR_EXPIRED_BIT      0
#define FTWDT_WDCLEAR_EXPIRED_LEN      1
#define FTWDT_WDCLEAR_EXPIRED_MASK     0x00000001
// ----------------------------------------------------------------------
// Register    : Watch Dog Interrupt Length Register
//
#define FTWDT_WDINTRLEN_ADDR           0x10110018
// Field       : LENGTH
// Access      : RW
// Number of clocks the interrupt signal will be asserted when it fires.
#define FTWDT_WDINTRLEN_LENGTH_BIT     0
#define FTWDT_WDINTRLEN_LENGTH_LEN     8
#define FTWDT_WDINTRLEN_LENGTH_MASK    0x000000ff
// ----------------------------------------------------------------------
// Register    : Watch Dog Revision Register
//
#define FTWDT_REV_ADDR                 0x1011001c
// Field       : DUMMY
// Access      : RO
#define FTWDT_REV_BIT                  0
#define FTWDT_REV_LEN                  32
#define FTWDT_REV_MASK                 0xffffffff


// ======================================================================
// Module      : Faraday AXI to AHB Bridge
// Base Address: 0x10120000
// FTX2H030 is a bridge connecting the AXI fabric to the AHB bus.
// ----------------------------------------------------------------------
// Register    : Data FIFO Threshold Register
// The data FIFO threshold register includes the write data and read data
// FIFO thresholds. The thresholds should not exceed the FIFO depth of
// the write data or read data, which is hardware configurable.
#define FTX2H_DFIFO_THR_ADDR           0x10120004
// Field       : WRTHR
// Access      : RW
// Data FIFO Write Threshold Level. 1 << wrthr. Maximum value is 4.
#define FTX2H_DFIFO_THR_WRTHR_BIT      0
#define FTX2H_DFIFO_THR_WRTHR_LEN      3
#define FTX2H_DFIFO_THR_WRTHR_MASK     0x00000007
// Field       : RDTHR
// Access      : RW
// Data FIFO Read Threshold Level. 1 << rdthr. Maximum value is 4.
#define FTX2H_DFIFO_THR_RDTHR_BIT      4
#define FTX2H_DFIFO_THR_RDTHR_LEN      3
#define FTX2H_DFIFO_THR_RDTHR_MASK     0x00000070
// ----------------------------------------------------------------------
// Register    : APB Slave Error Mask Register
// When users access the register offset over the legal range (Offset:
// 0x18), FTX2H030 will respond Slave Error from the APB port. The APB
// slave error mask register can mask the response and will always
// respond Slave Okay from the APB port.
#define FTX2H_ERR_MASK_ADDR            0x10120008
// Field       : APB_ERR
// Access      : RW
// When set the response will always be Slave OK.
#define FTX2H_ERR_MASK_APB_ERR_BIT     0
#define FTX2H_ERR_MASK_APB_ERR_LEN     1
#define FTX2H_ERR_MASK_APB_ERR_MASK    0x00000001
// ----------------------------------------------------------------------
// Register    : Feature Register 1
//
#define FTX2H_FR1_ADDR                 0x10120010
// Field       : AHB_DW
// Access      : RO
// AHB Bus is 32 bits.
#define FTX2H_FR1_AHB_DW_BIT           0
#define FTX2H_FR1_AHB_DW_LEN           8
#define FTX2H_FR1_AHB_DW_MASK          0x000000ff
// Field       : AXI_DW
// Access      : RO
// AXI Bus is 64 bits.
#define FTX2H_FR1_AXI_DW_BIT           8
#define FTX2H_FR1_AXI_DW_LEN           8
#define FTX2H_FR1_AXI_DW_MASK          0x0000ff00
// Field       : EXEN
// Access      : RO
// One monitor.
#define FTX2H_FR1_EXEN_BIT             16
#define FTX2H_FR1_EXEN_LEN             4
#define FTX2H_FR1_EXEN_MASK            0x000f0000
// Field       : AHB_IF
// Access      : RO
// AHB Master Interface.
#define FTX2H_FR1_AHB_IF_BIT           20
#define FTX2H_FR1_AHB_IF_LEN           1
#define FTX2H_FR1_AHB_IF_MASK          0x00100000
// Field       : AHB_PR
// Access      : RO
// Lite AHB Protocol.
#define FTX2H_FR1_AHB_PR_BIT           21
#define FTX2H_FR1_AHB_PR_LEN           1
#define FTX2H_FR1_AHB_PR_MASK          0x00200000
// Field       : CLOCK_MODE
// Access      : RO
// The AHB bus is asynchronous to the AXI bus.
#define FTX2H_FR1_CLOCK_MODE_BIT       22
#define FTX2H_FR1_CLOCK_MODE_LEN       2
#define FTX2H_FR1_CLOCK_MODE_MASK      0x00c00000
// Field       : IDW
// Access      : RO
// AXI ID Width is 8 bits.
#define FTX2H_FR1_IDW_BIT              24
#define FTX2H_FR1_IDW_LEN              4
#define FTX2H_FR1_IDW_MASK             0x0f000000
// Field       : AXI4
// Access      : RO
// AXI-3 Protocol.
#define FTX2H_FR1_AXI4_BIT             31
#define FTX2H_FR1_AXI4_LEN             1
#define FTX2H_FR1_AXI4_MASK            0x80000000
// ----------------------------------------------------------------------
// Register    : Feature Register 2
//
#define FTX2H_FR2_ADDR                 0x10120014
// Field       : RD_DEPTH
// Access      : RO
// Read data queue depth is 4.
#define FTX2H_FR2_RD_DEPTH_BIT         0
#define FTX2H_FR2_RD_DEPTH_LEN         8
#define FTX2H_FR2_RD_DEPTH_MASK        0x000000ff
// Field       : WR_DEPTH
// Access      : RO
// Write response queue depth is 4.
#define FTX2H_FR2_WR_DEPTH_BIT         8
#define FTX2H_FR2_WR_DEPTH_LEN         8
#define FTX2H_FR2_WR_DEPTH_MASK        0x0000ff00
// Field       : WD_DEPTH
// Access      : RO
// Write data queue depth is 4.
#define FTX2H_FR2_WD_DEPTH_BIT         16
#define FTX2H_FR2_WD_DEPTH_LEN         8
#define FTX2H_FR2_WD_DEPTH_MASK        0x00ff0000
// Field       : CMDQ_DEPTH
// Access      : RO
// Command queue depth is 4.
#define FTX2H_FR2_CMDQ_DEPTH_BIT       24
#define FTX2H_FR2_CMDQ_DEPTH_LEN       8
#define FTX2H_FR2_CMDQ_DEPTH_MASK      0xff000000
// ----------------------------------------------------------------------
// Register    : Revision Register
//
#define FTX2H_RR_ADDR                  0x10120018
// Field       : REV_VER
// Access      : RO
// Revision number
#define FTX2H_RR_REV_VER_BIT           0
#define FTX2H_RR_REV_VER_LEN           8
#define FTX2H_RR_REV_VER_MASK          0x000000ff
// Field       : MINOR_VER
// Access      : RO
// Minor version number
#define FTX2H_RR_MINOR_VER_BIT         8
#define FTX2H_RR_MINOR_VER_LEN         8
#define FTX2H_RR_MINOR_VER_MASK        0x0000ff00
// Field       : MAJOR_VER
// Access      : RO
// Major version number
#define FTX2H_RR_MAJOR_VER_BIT         16
#define FTX2H_RR_MAJOR_VER_LEN         8
#define FTX2H_RR_MAJOR_VER_MASK        0x00ff0000


// ======================================================================
// Module      : Faraday AHB to AXI Bridge
// Base Address: 0x10130000
// FTH2X030 provides a bridge between the AHB bus and the AXI bus. It
// converts an AHB command of the AHB bus into an AXI command of the AXI
// bus.
// ----------------------------------------------------------------------
// Register    : Control Registers
//
#define FTH2X_CR_ADDR                  0x10130000
// Field       : INTEN
// Access      : RW
// Interrupt Enable. Enable an interrupt signal to CPU when H2X receives
// an AXI error response for a bufferable AHB write command.
#define FTH2X_CR_INTEN_BIT             0
#define FTH2X_CR_INTEN_LEN             1
#define FTH2X_CR_INTEN_MASK            0x00000001
// Field       : DISAPBSLVERR
// Access      : RW
// Disable APB Error Respons. The output signal, PSlvErr, will always be
// 0 even when this blocks APB interface receives a non-existing address.
#define FTH2X_CR_DISAPBSLVERR_BIT      1
#define FTH2X_CR_DISAPBSLVERR_LEN      1
#define FTH2X_CR_DISAPBSLVERR_MASK     0x00000002
// Field       : HPROTTYPE_W
// Access      : RW
// Write data queue control. 00: AHB write data will be buffered if HProt
// in received request is bufferable. 01: AHB write data will always be
// buffered regardless of input request HProt value. 10: AHB write data
// will never be buffered regardless of received request HProt value.
#define FTH2X_CR_HPROTTYPE_W_BIT       2
#define FTH2X_CR_HPROTTYPE_W_LEN       2
#define FTH2X_CR_HPROTTYPE_W_MASK      0x0000000c
// Field       : HPROTTYPE_R
// Access      : RW
// Read data queue control. 00: AHB read data will be cached if HProt in
// received request is cached. 01: AHB read data will always be buffered
// regardless of input request HProt value. 10: AHB read data will never
// be cached regardless of received request HProt value.
#define FTH2X_CR_HPROTTYPE_R_BIT       4
#define FTH2X_CR_HPROTTYPE_R_LEN       2
#define FTH2X_CR_HPROTTYPE_R_MASK      0x00000030
// ----------------------------------------------------------------------
// Register    : Status Register
//
#define FTH2X_SR_ADDR                  0x10130004
// Field       : AXIERR
// Access      : W1C
// This bit is set when AXI interface receives an AXI error response for
// an AHB bufferable write command.
#define FTH2X_SR_AXIERR_BIT            0
#define FTH2X_SR_AXIERR_LEN            1
#define FTH2X_SR_AXIERR_MASK           0x00000001
// Field       : H2XIDLE
// Access      : RO
// Set when the H2X bridge has no commands to process.
#define FTH2X_SR_H2XIDLE_BIT           1
#define FTH2X_SR_H2XIDLE_LEN           1
#define FTH2X_SR_H2XIDLE_MASK          0x00000002
// ----------------------------------------------------------------------
// Register    : Feature Register
//
#define FTH2X_FR_ADDR                  0x10130008
// Field       : AHB_DW
// Access      : RO
// AHB Bus is 32 bits.
#define FTH2X_FR_AHB_DW_BIT            0
#define FTH2X_FR_AHB_DW_LEN            1
#define FTH2X_FR_AHB_DW_MASK           0x00000001
// Field       : AXI_DW
// Access      : RO
// AXI Bus is 64 bits.
#define FTH2X_FR_AXI_DW_BIT            1
#define FTH2X_FR_AXI_DW_LEN            1
#define FTH2X_FR_AXI_DW_MASK           0x00000002
// Field       : CMDQ_DEPTH
// Access      : RO
// Command queue depth is 2.
#define FTH2X_FR_CMDQ_DEPTH_BIT        2
#define FTH2X_FR_CMDQ_DEPTH_LEN        3
#define FTH2X_FR_CMDQ_DEPTH_MASK       0x0000001c
// Field       : WDQ_DEPTH
// Access      : RO
// Write data queue depth is 4.
#define FTH2X_FR_WDQ_DEPTH_BIT         5
#define FTH2X_FR_WDQ_DEPTH_LEN         4
#define FTH2X_FR_WDQ_DEPTH_MASK        0x000001e0
// Field       : RDQ_DEPTH
// Access      : RO
// Read data queue depth is 4.
#define FTH2X_FR_RDQ_DEPTH_BIT         9
#define FTH2X_FR_RDQ_DEPTH_LEN         4
#define FTH2X_FR_RDQ_DEPTH_MASK        0x00001e00
// Field       : AHB_BUS
// Access      : RO
// The H2X bridge is connected to the AHB bus.
#define FTH2X_FR_AHB_BUS_BIT           13
#define FTH2X_FR_AHB_BUS_LEN           1
#define FTH2X_FR_AHB_BUS_MASK          0x00002000
// Field       : CLOCK_MODE
// Access      : RO
// The AHB bus is asynchronous to the AXI bus.
#define FTH2X_FR_CLOCK_MODE_BIT        14
#define FTH2X_FR_CLOCK_MODE_LEN        2
#define FTH2X_FR_CLOCK_MODE_MASK       0x0000c000
// ----------------------------------------------------------------------
// Register    : Revision Register
//
#define FTH2X_RR_ADDR                  0x1013000c
// Field       : REV_VER
// Access      : RO
// Revision number
#define FTH2X_RR_REV_VER_BIT           0
#define FTH2X_RR_REV_VER_LEN           8
#define FTH2X_RR_REV_VER_MASK          0x000000ff
// Field       : MINOR_VER
// Access      : RO
// Minor version number
#define FTH2X_RR_MINOR_VER_BIT         8
#define FTH2X_RR_MINOR_VER_LEN         8
#define FTH2X_RR_MINOR_VER_MASK        0x0000ff00
// Field       : MAJOR_VER
// Access      : RO
// Major version number
#define FTH2X_RR_MAJOR_VER_BIT         16
#define FTH2X_RR_MAJOR_VER_LEN         8
#define FTH2X_RR_MAJOR_VER_MASK        0x00ff0000


// ======================================================================
