// Address bus width is 32 bits.
#define FTX2X_PCIE_FR1_AW_BIT          26
#define FTX2X_PCIE_FR1_AW_LEN          6
#define FTX2X_PCIE_FR1_AW_MASK         0xfc000000
// ----------------------------------------------------------------------
// Register    : Feature Register 2
//
#define FTX2X_PCIE_FR2_ADDR            0x10140014
// Field       : WR_DEPTH
// Access      : RO
// Write response queue depth.
#define FTX2X_PCIE_FR2_WR_DEPTH_BIT    0
#define FTX2X_PCIE_FR2_WR_DEPTH_LEN    3
#define FTX2X_PCIE_FR2_WR_DEPTH_MASK   0x00000007
// Field       : RD_DEPTH
// Access      : RO
// Read data queue depth.
#define FTX2X_PCIE_FR2_RD_DEPTH_BIT    3
#define FTX2X_PCIE_FR2_RD_DEPTH_LEN    4
#define FTX2X_PCIE_FR2_RD_DEPTH_MASK   0x00000078
// Field       : WD_DEPTH
// Access      : RO
// Write data queue depth.
#define FTX2X_PCIE_FR2_WD_DEPTH_BIT    7
#define FTX2X_PCIE_FR2_WD_DEPTH_LEN    4
#define FTX2X_PCIE_FR2_WD_DEPTH_MASK   0x00000780
// Field       : RCMDQ_DEPTH
// Access      : RO
// Command queue depth.
#define FTX2X_PCIE_FR2_RCMDQ_DEPTH_BIT 11
#define FTX2X_PCIE_FR2_RCMDQ_DEPTH_LEN 3
#define FTX2X_PCIE_FR2_RCMDQ_DEPTH_MASK 0x00003800
// Field       : WCMDQ_DEPTH
