//
#define FTX2X_PCIE_FR3_ADDR            0x10140018
// Field       : WR_UW
// Access      : RO
// WR User Width.
#define FTX2X_PCIE_FR3_WR_UW_BIT       0
#define FTX2X_PCIE_FR3_WR_UW_LEN       6
#define FTX2X_PCIE_FR3_WR_UW_MASK      0x0000003f
// Field       : RD_UW
// Access      : RO
// RD User Width.
#define FTX2X_PCIE_FR3_RD_UW_BIT       6
#define FTX2X_PCIE_FR3_RD_UW_LEN       6
#define FTX2X_PCIE_FR3_RD_UW_MASK      0x00000fc0
// Field       : WD_UW
