// ======================================================================
// Module      : System Control Unit
// Base Address: 0x10180000
//
// ----------------------------------------------------------------------
// Register    : Boot-up Status Register
// This register contains the boot-up status bits that can be read by the
// system software to determine which wakeup event (External, Internal)
// caused the system to come out of the dormant mode. FTSCU100 can be
// booted up from several events. These boot-up events are recorded in
// the boot-up status register when the system receives them in the
// dormant mode. EXT_BOOTUP_STS is used to record the events that are
// triggered from the external pins of 'btup_event'. The peripherals that
// are partitioned in the PCU power domain can issue the boot-up events
// through these external pins and they should be connected during
// implementation.
#define FTSCU_BTUP_STS_ADDR            0x10180000
// Field       : HWR
// Access      : W1C
// Reboot triggered by hardware reset.
#define FTSCU_BTUP_STS_HWR_BIT         8
#define FTSCU_BTUP_STS_HWR_LEN         1
#define FTSCU_BTUP_STS_HWR_MASK        0x00000100
// Field       : WDR
// Access      : W1C
// Reboot triggered by watchdog reset.
#define FTSCU_BTUP_STS_WDR_BIT         9
#define FTSCU_BTUP_STS_WDR_LEN         1
#define FTSCU_BTUP_STS_WDR_MASK        0x00000200
// ----------------------------------------------------------------------
// Register    : Power Control Register
// The PWRDN_CTRL bits of the power control register are set to be the
// expected power control pins when the system enters the soft-off mode.
// The PWRUP_CTRL bits are able to directly set the current power control
// pins. Users can program these bits and then set the PWRCTRL_UPDATE
// bit. An additional function sets the power control pins in advance
// when the system is re-booted from the soft-off mode. Users can also
// program the PWRUP_CTRL bits without setting PWRCTRL_UPDATE before
// entering the soft-off mode. The power control pins are not immediately
// changed, and will be updated when the system comes back to the working
// state from the dormant mode. EchoNous logic reset may be required when
// power off and on the logic.
#define FTSCU_PWR_CTRL_ADDR            0x10180008
// Field       : MAIN_PWRDN_CTRL
// Access      : RW
// Main power control when in soft off state. DONT USE
#define FTSCU_PWR_CTRL_MAIN_PWRDN_CTRL_BIT 0
#define FTSCU_PWR_CTRL_MAIN_PWRDN_CTRL_LEN 1
#define FTSCU_PWR_CTRL_MAIN_PWRDN_CTRL_MASK 0x00000001
// Field       : BF_PWRDN_CTRL
// Access      : RW
// EchoNous logic power control when in soft off state.
#define FTSCU_PWR_CTRL_BF_PWRDN_CTRL_BIT 1
#define FTSCU_PWR_CTRL_BF_PWRDN_CTRL_LEN 1
#define FTSCU_PWR_CTRL_BF_PWRDN_CTRL_MASK 0x00000002
// Field       : MAIN_PWRUP_CTRL
// Access      : RW
// Main power control when in working state. DONT USE
#define FTSCU_PWR_CTRL_MAIN_PWRUP_CTRL_BIT 8
#define FTSCU_PWR_CTRL_MAIN_PWRUP_CTRL_LEN 1
#define FTSCU_PWR_CTRL_MAIN_PWRUP_CTRL_MASK 0x00000100
// Field       : BF_PWRUP_CTRL
// Access      : RW
// EchoNous logic power control when in working state.
#define FTSCU_PWR_CTRL_BF_PWRUP_CTRL_BIT 9
#define FTSCU_PWR_CTRL_BF_PWRUP_CTRL_LEN 1
#define FTSCU_PWR_CTRL_BF_PWRUP_CTRL_MASK 0x00000200
// Field       : PWR_CTRL_UPDATE
// Access      : RW
// Initiate power change.
#define FTSCU_PWR_CTRL_PWR_CTRL_UPDATE_BIT 24
#define FTSCU_PWR_CTRL_PWR_CTRL_UPDATE_LEN 1
#define FTSCU_PWR_CTRL_PWR_CTRL_UPDATE_MASK 0x01000000
// ----------------------------------------------------------------------
// Register    : Chip ID Register
// This register is configured by the SoC integrator to provide the chip
// ID. The register can be programmed by software though a unlock
// sequence. The CHIPID register is protected to avoid unexpected
// programming. The unlock ID is the same CHIPID, and writes the value to
// the version tag register (0x14). It will unlock the write protected
// and allow one write operation to the chip ID register (Offset 0x10),
// and the register will resume the lock state after the write operation.
// When CHPID is programmed, the unlock key will also be updated to new
// CHIPID. Users should use new CHIPID to unlock the protected register
// in the next write procedure.
#define FTSCU_CHIPID_ADDR              0x10180010
// Field       : DUMMY
// Access      : RO
#define FTSCU_CHIPID_BIT               0
#define FTSCU_CHIPID_LEN               32
#define FTSCU_CHIPID_MASK              0xffffffff
// ----------------------------------------------------------------------
// Register    : System Control Unit Version Register
// This register identifies the version of this IP.
#define FTSCU_VERID_ADDR               0x10180014
// Field       : DUMMY
// Access      : RO
#define FTSCU_VERID_BIT                0
#define FTSCU_VERID_LEN                32
#define FTSCU_VERID_MASK               0xffffffff
// ----------------------------------------------------------------------
// Register    : Strap Value Register
// The strappings pins are used to decide the initial value through the
// external pull-up/pull-down resister at the reset interval. These pins
// generally should be selected for the pure output function in the
// normal operation during SoC integration. FTSCU100 will be directly set
// to latch the input values of the I/O pins and keep data after de-
// asserting the reset signal these strap values can be read through the
// strap value register.
#define FTSCU_SVR_ADDR                 0x10180018
// Field       : X_BOOT_SELECT
// Access      : RO
// Boot Select Pins. {0: ISP, 1: Normal, 2: SPI, 3: Debug}
#define FTSCU_SVR_X_BOOT_SELECT_BIT    8
#define FTSCU_SVR_X_BOOT_SELECT_LEN    2
#define FTSCU_SVR_X_BOOT_SELECT_MASK   0x00000300
// Field       : X_CPU_EN
// Access      : RO
// If in ISP mode and X_CPU_EN is tied low the CPU will put itself to
// sleep. If this pin is tied hi the CPU will boot normally and the PCIe
// core will be prevented from initiating link training until the
// app_ltssm_enable register bit is set to 1.
#define FTSCU_SVR_X_CPU_EN_BIT         10
#define FTSCU_SVR_X_CPU_EN_LEN         1
#define FTSCU_SVR_X_CPU_EN_MASK        0x00000400
// Field       : X_PCIE_EP_RC
// Access      : RO
// {0: PCIe in EP mode, 1: PCIe in RC mode}
#define FTSCU_SVR_X_PCIE_EP_RC_BIT     11
#define FTSCU_SVR_X_PCIE_EP_RC_LEN     1
#define FTSCU_SVR_X_PCIE_EP_RC_MASK    0x00000800
// ----------------------------------------------------------------------
// Register    : Power Mode Register
// The power mode register (PWR_MOD) provides the power management
// commands and parameters of the operation sequence. It can issue the
// power state transaction command to enter the sleep, dormant, or power-
// off state from the working state, and can dynamically change the CPU
// and BUS running speeds, and can use to manage the PLL clock. FTSCU100
// allows the combination of several commands for transition in one
// operation mode.
#define FTSCU_PWRMOD_ADDR              0x10180020
// Field       : RES0
// Access      : RW
// Reserved R/W. Bits have no effect.
#define FTSCU_PWRMOD_RES0_BIT          0
#define FTSCU_PWRMOD_RES0_LEN          6
#define FTSCU_PWRMOD_RES0_MASK         0x0000003f
// Field       : FCS
// Access      : RW
// Frequency Change Sequence (FCS) The bit is set to enter the frequency
// change sequence, and will be automatically cleared after finishing
// FCS. The PLL setting will be changed to the programmed values after
// the next boot up from the power-off mode.
#define FTSCU_PWRMOD_FCS_BIT           6
#define FTSCU_PWRMOD_FCS_LEN           1
#define FTSCU_PWRMOD_FCS_MASK          0x00000040
// Field       : REBOOT
// Access      : RW
// Reboot command The bit is set to issue a reset to initiate the CPU and
// bus state. In the combined command, the reset will be de-asserted
// after another operation sequence is done. However, it is prohibited to
// perform the sleep command.
#define FTSCU_PWRMOD_REBOOT_BIT        7
#define FTSCU_PWRMOD_REBOOT_LEN        1
#define FTSCU_PWRMOD_REBOOT_MASK       0x00000080
// Field       : PLL_UPDATE
// Access      : RW
// PLL update command. PLL setting value is directly updated by the PLL
// programming register.
#define FTSCU_PWRMOD_PLL_UPDATE_BIT    8
#define FTSCU_PWRMOD_PLL_UPDATE_LEN    1
#define FTSCU_PWRMOD_PLL_UPDATE_MASK   0x00000100
// Field       : CURR_RESTORE
// Access      : RW
// Restore current setting frequency in programming register. All PLL
// setting values, including the power mode setting values, and REMAP
// will be restored to the PLL control (PLL_CTRL) and power mode
// (PWR_MOD) registers.
#define FTSCU_PWRMOD_CURR_RESTORE_BIT  9
#define FTSCU_PWRMOD_CURR_RESTORE_LEN  1
#define FTSCU_PWRMOD_CURR_RESTORE_MASK 0x00000200
// Field       : SW_RST
// Access      : RW
// Software reset command The bit is set to issue a reset signal that the
// interval can be adjusted by programming SWRST_CTRL (offset 0x02C), and
// be cleared by hardware after the reset is done.
#define FTSCU_PWRMOD_SW_RST_BIT        10
#define FTSCU_PWRMOD_SW_RST_LEN        1
#define FTSCU_PWRMOD_SW_RST_MASK       0x00000400
// Field       : REMAP_CHG
// Access      : RW
// REMAP directly change without reboot. The bit is to directly change
// the remapping value without CPU reboot, but CPU still needs to issue
// idle instruction that makes sure CPU will not access before finishing
// changing the memory map.
#define FTSCU_PWRMOD_REMAP_CHG_BIT     11
#define FTSCU_PWRMOD_REMAP_CHG_LEN     1
#define FTSCU_PWRMOD_REMAP_CHG_MASK    0x00000800
// Field       : RES1
// Access      : RW
// Reserved R/W. Bits have no effect.
#define FTSCU_PWRMOD_RES1_BIT          12
#define FTSCU_PWRMOD_RES1_LEN          12
#define FTSCU_PWRMOD_RES1_MASK         0x00fff000
// Field       : REMAP
// Access      : RW
// After reset is de-asserted the default value of remap will be the
// values of the X_BOOT_SELECT strap pins. Remap is used to set the AHB
// bus memory map. Refer to the Ax architecture specification for more
// information.
#define FTSCU_PWRMOD_REMAP_BIT         24
#define FTSCU_PWRMOD_REMAP_LEN         4
#define FTSCU_PWRMOD_REMAP_MASK        0x0f000000
// Field       : FCS_PLL_RSTN
// Access      : RW
// PLL resets in the frequency change sequence. If the PLL output
// frequency is not satisfied, PLL should be reset in the FCS mode. 0:
// Reset PLL 1: Keep PLL active in FCS.
#define FTSCU_PWRMOD_FCS_PLL_RSTN_BIT  28
#define FTSCU_PWRMOD_FCS_PLL_RSTN_LEN  1
#define FTSCU_PWRMOD_FCS_PLL_RSTN_MASK 0x10000000
// Field       : RES2
// Access      : RW
// Reserved R/W. Bits have no effect.
#define FTSCU_PWRMOD_RES2_BIT          29
#define FTSCU_PWRMOD_RES2_LEN          2
#define FTSCU_PWRMOD_RES2_MASK         0x60000000
// Field       : SELFR_CMD_OFF
// Access      : RW
// Turn off DDR self-refresh command. Even though DDR is not present in
// the Ax ASIC this bit must be set to 1 to trigger a FCS.
#define FTSCU_PWRMOD_SELFR_CMD_OFF_BIT 31
#define FTSCU_PWRMOD_SELFR_CMD_OFF_LEN 1
#define FTSCU_PWRMOD_SELFR_CMD_OFF_MASK 0x80000000
// ----------------------------------------------------------------------
// Register    : Interrupt Status Register
// SCU Generated Interrupts.
#define FTSCU_INT_STS_ADDR             0x10180024
// Field       : INT_WAKEUP
// Access      : W1C
// Wake up event status in the sleep mode.
#define FTSCU_INT_STS_INT_WAKEUP_BIT   3
#define FTSCU_INT_STS_INT_WAKEUP_LEN   1
#define FTSCU_INT_STS_INT_WAKEUP_MASK  0x00000008
// Field       : INT_FCS
// Access      : W1C
// FCS command finish interrupt status.
#define FTSCU_INT_STS_INT_FCS_BIT      6
#define FTSCU_INT_STS_INT_FCS_LEN      1
#define FTSCU_INT_STS_INT_FCS_MASK     0x00000040
// Field       : REBOOT_STS
// Access      : W1C
// Reboot issued status from reboot command.
#define FTSCU_INT_STS_REBOOT_STS_BIT   7
#define FTSCU_INT_STS_REBOOT_STS_LEN   1
#define FTSCU_INT_STS_REBOOT_STS_MASK  0x00000080
// Field       : INT_PLL_UPDATE
// Access      : W1C
// PLL update finish interrupt status.
#define FTSCU_INT_STS_INT_PLL_UPDATE_BIT 8
#define FTSCU_INT_STS_INT_PLL_UPDATE_LEN 1
#define FTSCU_INT_STS_INT_PLL_UPDATE_MASK 0x00000100
// Field       : INT_REMAP_CHG
// Access      : W1C
// Remap complete status.
#define FTSCU_INT_STS_INT_REMAP_CHG_BIT 11
#define FTSCU_INT_STS_INT_REMAP_CHG_LEN 1
#define FTSCU_INT_STS_INT_REMAP_CHG_MASK 0x00000800
// Field       : ICE_REBOOT_STS
// Access      : W1C
// Reboot issued from ICE.
#define FTSCU_INT_STS_ICE_REBOOT_STS_BIT 15
#define FTSCU_INT_STS_ICE_REBOOT_STS_LEN 1
#define FTSCU_INT_STS_ICE_REBOOT_STS_MASK 0x00008000
// Field       : INT_PWRSTATE_CHG
// Access      : W1C
// Power domain state change status The status indicates that one power
// state has been changed, and it can be used to check if the power is
// turned on.
#define FTSCU_INT_STS_INT_PWRSTATE_CHG_BIT 28
#define FTSCU_INT_STS_INT_PWRSTATE_CHG_LEN 1
#define FTSCU_INT_STS_INT_PWRSTATE_CHG_MASK 0x10000000
// ----------------------------------------------------------------------
// Register    : Interrupt Enable Register
// SCU Interrupt Enables.
#define FTSCU_INT_EN_ADDR              0x10180028
// Field       : INT_WAKEUP
// Access      : RW
// Wake up event interrupt enable in the sleep mode.
#define FTSCU_INT_EN_INT_WAKEUP_BIT    3
#define FTSCU_INT_EN_INT_WAKEUP_LEN    1
#define FTSCU_INT_EN_INT_WAKEUP_MASK   0x00000008
// Field       : INT_FCS
// Access      : RW
// FCS command finish interrupt enable.
#define FTSCU_INT_EN_INT_FCS_BIT       6
#define FTSCU_INT_EN_INT_FCS_LEN       1
#define FTSCU_INT_EN_INT_FCS_MASK      0x00000040
// Field       : REBOOT_STS
// Access      : RW
// Reboot issued interrupt enable from reboot command.
#define FTSCU_INT_EN_REBOOT_STS_BIT    7
#define FTSCU_INT_EN_REBOOT_STS_LEN    1
#define FTSCU_INT_EN_REBOOT_STS_MASK   0x00000080
// Field       : INT_PLL_UPDATE
// Access      : RW
// PLL update finish interrupt enable.
#define FTSCU_INT_EN_INT_PLL_UPDATE_BIT 8
#define FTSCU_INT_EN_INT_PLL_UPDATE_LEN 1
#define FTSCU_INT_EN_INT_PLL_UPDATE_MASK 0x00000100
// Field       : INT_REMAP_CHG
// Access      : RW
// Remap complete interrupt enable.
#define FTSCU_INT_EN_INT_REMAP_CHG_BIT 11
#define FTSCU_INT_EN_INT_REMAP_CHG_LEN 1
#define FTSCU_INT_EN_INT_REMAP_CHG_MASK 0x00000800
// Field       : ICE_REBOOT_STS
// Access      : RW
// Reboot issued from ICE.
#define FTSCU_INT_EN_ICE_REBOOT_STS_BIT 15
#define FTSCU_INT_EN_ICE_REBOOT_STS_LEN 1
#define FTSCU_INT_EN_ICE_REBOOT_STS_MASK 0x00008000
// Field       : INT_PWRSTATE_CHG
// Access      : RW
// Power domain state change interrupt enable.
#define FTSCU_INT_EN_INT_PWRSTATE_CHG_BIT 28
#define FTSCU_INT_EN_INT_PWRSTATE_CHG_LEN 1
#define FTSCU_INT_EN_INT_PWRSTATE_CHG_MASK 0x10000000
// ----------------------------------------------------------------------
// Register    : PLL Control Register
// The register contains the PLL programmable setting values, the loop
// divider (PLLNS), pre-divider (MS), and frequency range (PLLFRANG).
// PLLEN controls the power-down modesetting signal of PLL, and PLLSTABLE
// refers that the PLL clock is at the locking state.
#define FTSCU_PLLCTRL_ADDR             0x10180030
// Field       : PLLEN
// Access      : RW
// PLL enable control, the PLL cannot directly be turned ON/OFF when the
// bit is set. The procedure should accompany a FCS command to stop or
// enable PLL.
#define FTSCU_PLLCTRL_PLLEN_BIT        0
#define FTSCU_PLLCTRL_PLLEN_LEN        1
#define FTSCU_PLLCTRL_PLLEN_MASK       0x00000001
// Field       : PLLSTABLE
// Access      : RO
// 0: PLL is not stable. 1: PLL is stable.
#define FTSCU_PLLCTRL_PLLSTABLE_BIT    1
#define FTSCU_PLLCTRL_PLLSTABLE_LEN    1
#define FTSCU_PLLCTRL_PLLSTABLE_MASK   0x00000002
