// Register    : PCIe Control Register
//
#define FTSCU_PCIEC_ADDR               0x10180840
// Field       : APP_LTSSM_ENABLE
// Access      : RW
// app_ltssm_enable controls when the PCIe core is allowed to begin link
// training and establish the link. When X_SYS_RESET is de-asserted the
// app_ltssm_enable bit latches in the inverse of X_CPU_ENABLE. When
// X_CPU_ENABLE is asserted, app_ltssm_enable is low preventing the PCIe
// core from entering link training. This allows the CPU to configure the
// PCIe core before the link is established. The CPU then enables the
// PCIe core by writing a 1 to this bit.
#define FTSCU_PCIEC_APP_LTSSM_ENABLE_BIT 0
#define FTSCU_PCIEC_APP_LTSSM_ENABLE_LEN 1
#define FTSCU_PCIEC_APP_LTSSM_ENABLE_MASK 0x00000001
// Field       : AXI_SLV_CSYSREQ
// Access      : RW
// {0: Power down AXI bus, 1: AXI bus active.}
#define FTSCU_PCIEC_AXI_SLV_CSYSREQ_BIT 8
#define FTSCU_PCIEC_AXI_SLV_CSYSREQ_LEN 1
#define FTSCU_PCIEC_AXI_SLV_CSYSREQ_MASK 0x00000100
// Field       : AXI_MSTR_CSYSREQ
// Access      : RW
// {0: Power down AXI bus, 1: AXI bus active.}
#define FTSCU_PCIEC_AXI_MSTR_CSYSREQ_BIT 9
#define FTSCU_PCIEC_AXI_MSTR_CSYSREQ_LEN 1
#define FTSCU_PCIEC_AXI_MSTR_CSYSREQ_MASK 0x00000200
