// Access      : RW
// {0: Power down AXI bus, 1: AXI bus active.}
#define FTSCU_PCIEC_AXI_DBI_CSYSREQ_BIT 10
#define FTSCU_PCIEC_AXI_DBI_CSYSREQ_LEN 1
#define FTSCU_PCIEC_AXI_DBI_CSYSREQ_MASK 0x00000400
// Field       : PHY_APB_EN
// Access      : RW
// Enable APB access to VSemi PHY.
#define FTSCU_PCIEC_PHY_APB_EN_BIT     16
#define FTSCU_PCIEC_PHY_APB_EN_LEN     1
#define FTSCU_PCIEC_PHY_APB_EN_MASK    0x00010000
// Field       : TXONESZEROS
// Access      : RW
// Enable transmit of ones/zeros pattern on PHY.
#define FTSCU_PCIEC_TXONESZEROS_BIT    17
#define FTSCU_PCIEC_TXONESZEROS_LEN    1
#define FTSCU_PCIEC_TXONESZEROS_MASK   0x00020000
// Field       : RXTERM
// Access      : RW
// Enable receiver termination on PHY.
#define FTSCU_PCIEC_RXTERM_BIT         18
#define FTSCU_PCIEC_RXTERM_LEN         1
#define FTSCU_PCIEC_RXTERM_MASK        0x00040000
