// Access      : RW
// Clear Rx Equalizer on PHY. PCIe Gen 3 feature.
#define FTSCU_PCIEC_RXEQ_CLR_BIT       19
#define FTSCU_PCIEC_RXEQ_CLR_LEN       1
#define FTSCU_PCIEC_RXEQ_CLR_MASK      0x00080000
// ----------------------------------------------------------------------
// Register    : USB Control Register
//
#define FTSCU_USBC_ADDR                0x10180844
// Field       : LPMEN
// Access      : RW
// CLKLPM control 1: Enable CLKLPM in the L1 mode 0: Disable CLKLPM in
// the L1 mode
#define FTSCU_USBC_LPMEN_BIT           0
#define FTSCU_USBC_LPMEN_LEN           1
#define FTSCU_USBC_LPMEN_MASK          0x00000001
// Field       : HWRSTN
// Access      : RW
// USB Core Reset. Active Low. USB in reset by default after power up.
#define FTSCU_USBC_HWRSTN_BIT          3
#define FTSCU_USBC_HWRSTN_LEN          1
#define FTSCU_USBC_HWRSTN_MASK         0x00000008
// Field       : CLKSEL
// Access      : RW
// Reference clock source selection This static control signal cannot be
// changed within one operation. This signal selects the source of the
// reference clock to be the crystal or external source. 0: Select the
// crystal as the reference clock source (XSCI/XSCO) 1: Select the
// external reference clock source (CORECLKIN). Should always be 1 in
// EchoNous design.
#define FTSCU_USBC_CLKSEL_BIT          4
#define FTSCU_USBC_CLKSEL_LEN          1
#define FTSCU_USBC_CLKSEL_MASK         0x00000010
// Field       : CRYSTALSEL
// Access      : RW
// Reference clock speed selection This static control signal cannot be
// changed within one operation. This signal is used to specify the
// frequency of the reference clock. 00: 12-MHz reference clock from the
// XSCI or CORECLKIN pin 01: 30-MHz reference clock from the XSCI or
// CORECLKIN pin 11: 48-MHz reference clock from the CORECLKIN input pin.
// Should always be 01 for EchoNous design.
#define FTSCU_USBC_CRYSTALSEL_BIT      8
#define FTSCU_USBC_CRYSTALSEL_LEN      2
#define FTSCU_USBC_CRYSTALSEL_MASK     0x00000300
// Field       : PLLALIV
// Access      : RW
// PLL active control This static control signal cannot be changed within
// one operation. When PLLALIV is set to 1, the embedded PLL is alive and
// SUSCLK120, SUSCLK480, and CLK48M will generate clocks. Otherwise,
// these clocks will be gated and kept as logic low.
#define FTSCU_USBC_PLLALIV_BIT         12
#define FTSCU_USBC_PLLALIV_LEN         1
#define FTSCU_USBC_PLLALIV_MASK        0x00001000
// Field       : OSCOUTEN
// Access      : RW
// CLKOSCO clock output enable for High-Speed/Full-Speed PHYs This static
// control signal cannot be changed within one operation. 1: Enable
// CLKOSCO 0: Disable CLKOSCO
#define FTSCU_USBC_OSCOUTEN_BIT        16
#define FTSCU_USBC_OSCOUTEN_LEN        1
#define FTSCU_USBC_OSCOUTEN_MASK       0x00010000
// Field       : DEVPHY
// Access      : RW
// USB 3.0 differential pin selection. If DEVICE_PHY is set to 1'b0
// (Host), SSTXA will be the positive pin (SSTXP) and SSTXB will be the
// negative pin (SSTXM); SSRXA will be the positive pin (SSRXP) and SSRXB
// will be the negative pin (SSRXM). If DEVICE_PHY is set to 1?b1
// (Device), SSTXA will be the negative pin (SSTXM) and SSTXB will be the
// positive pin (SSTXP); SSRXA will be the negative pin (SSRXM) and SSRXB
// will be the positive pin (SSRXP).
#define FTSCU_USBC_DEVPHY_BIT          20
#define FTSCU_USBC_DEVPHY_LEN          1
#define FTSCU_USBC_DEVPHY_MASK         0x00100000
// Field       : SSCG_BYPASS
// Access      : RW
// If the control signals are set by using the I2C registers inside PHY,
