// Disable SSCG in the TX output 0: Enable SSCG in the TX output
#define FTSCU_USBC_SSCG_BYPASS_BIT     24
#define FTSCU_USBC_SSCG_BYPASS_LEN     1
#define FTSCU_USBC_SSCG_BYPASS_MASK    0x01000000
// Field       : REXT_EN
// Access      : RW
// RREF current source selection. 1: Enable RREF 0: Disable RREF
#define FTSCU_USBC_REXT_EN_BIT         28
