#define FTAXI_S5FEATURE_READISSUCAP_LEN 5
#define FTAXI_S5FEATURE_READISSUCAP_MASK 0x00001f00
// Field       : WRINTERDEPTH
// Access      : RO
// Write command interleave depth.
#define FTAXI_S5FEATURE_WRINTERDEPTH_BIT 16
#define FTAXI_S5FEATURE_WRINTERDEPTH_LEN 4
#define FTAXI_S5FEATURE_WRINTERDEPTH_MASK 0x000f0000
// Field       : WR_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S5FEATURE_WR_TMO_BIT     22
#define FTAXI_S5FEATURE_WR_TMO_LEN     2
#define FTAXI_S5FEATURE_WR_TMO_MASK    0x00c00000
// Field       : RD_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S5FEATURE_RD_TMO_BIT     24
#define FTAXI_S5FEATURE_RD_TMO_LEN     2
#define FTAXI_S5FEATURE_RD_TMO_MASK    0x03000000
// Field       : WD_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S5FEATURE_WD_TMO_BIT     26
#define FTAXI_S5FEATURE_WD_TMO_LEN     2
#define FTAXI_S5FEATURE_WD_TMO_MASK    0x0c000000
// Field       : AR_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S5FEATURE_AR_TMO_BIT     28
#define FTAXI_S5FEATURE_AR_TMO_LEN     2
#define FTAXI_S5FEATURE_AR_TMO_MASK    0x30000000
// Field       : AW_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S5FEATURE_AW_TMO_BIT     30
#define FTAXI_S5FEATURE_AW_TMO_LEN     2
#define FTAXI_S5FEATURE_AW_TMO_MASK    0xc0000000
// ----------------------------------------------------------------------
// Register    : AXI Slave 31 Feature Register
//
#define FTAXI_S31FEATURE_ADDR          0x10190248
// Field       : WRITEISSUCAP
// Access      : RO
// This many write command commands can be issued.
#define FTAXI_S31FEATURE_WRITEISSUCAP_BIT 0
#define FTAXI_S31FEATURE_WRITEISSUCAP_LEN 5
#define FTAXI_S31FEATURE_WRITEISSUCAP_MASK 0x0000001f
// Field       : BS_REG
// Access      : RO
// Design includes register for base address and region size.
#define FTAXI_S31FEATURE_BS_REG_BIT    5
#define FTAXI_S31FEATURE_BS_REG_LEN    1
#define FTAXI_S31FEATURE_BS_REG_MASK   0x00000020
// Field       : READISSUCAP
// Access      : RO
// This many read command commands can be issued.
#define FTAXI_S31FEATURE_READISSUCAP_BIT 8
#define FTAXI_S31FEATURE_READISSUCAP_LEN 5
#define FTAXI_S31FEATURE_READISSUCAP_MASK 0x00001f00
// Field       : WRINTERDEPTH
// Access      : RO
// Write command interleave depth.
#define FTAXI_S31FEATURE_WRINTERDEPTH_BIT 16
#define FTAXI_S31FEATURE_WRINTERDEPTH_LEN 4
#define FTAXI_S31FEATURE_WRINTERDEPTH_MASK 0x000f0000
// Field       : WR_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S31FEATURE_WR_TMO_BIT    22
#define FTAXI_S31FEATURE_WR_TMO_LEN    2
#define FTAXI_S31FEATURE_WR_TMO_MASK   0x00c00000
// Field       : RD_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S31FEATURE_RD_TMO_BIT    24
#define FTAXI_S31FEATURE_RD_TMO_LEN    2
#define FTAXI_S31FEATURE_RD_TMO_MASK   0x03000000
// Field       : WD_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S31FEATURE_WD_TMO_BIT    26
#define FTAXI_S31FEATURE_WD_TMO_LEN    2
#define FTAXI_S31FEATURE_WD_TMO_MASK   0x0c000000
// Field       : AR_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S31FEATURE_AR_TMO_BIT    28
#define FTAXI_S31FEATURE_AR_TMO_LEN    2
#define FTAXI_S31FEATURE_AR_TMO_MASK   0x30000000
// Field       : AW_TMO
// Access      : RO
// Timing mode. 0: Bypass.
#define FTAXI_S31FEATURE_AW_TMO_BIT    30
#define FTAXI_S31FEATURE_AW_TMO_LEN    2
#define FTAXI_S31FEATURE_AW_TMO_MASK   0xc0000000
// ----------------------------------------------------------------------
// Register    : AXI IC Revision Register
//
#define FTAXI_REVISION_ADDR            0x10190250
// Field       : REV_VER
// Access      : RO
// Revision number.
#define FTAXI_REVISION_REV_VER_BIT     0
#define FTAXI_REVISION_REV_VER_LEN     8
#define FTAXI_REVISION_REV_VER_MASK    0x000000ff
// Field       : MINOR_VER
// Access      : RO
// Revision number.
#define FTAXI_REVISION_MINOR_VER_BIT   8
#define FTAXI_REVISION_MINOR_VER_LEN   8
#define FTAXI_REVISION_MINOR_VER_MASK  0x0000ff00
// Field       : MAJOR_VER
// Access      : RO
// Revision number.
#define FTAXI_REVISION_MAJOR_VER_BIT   16
#define FTAXI_REVISION_MAJOR_VER_LEN   8
#define FTAXI_REVISION_MAJOR_VER_MASK  0x00ff0000
// ----------------------------------------------------------------------
// Register    : AXI Master Port Write Grant Count Register
// The grant count registers define the maximum AW command count that a
// granted AXI master can issues before arbiter changes the grant to
// other AXI master. The AR arbiter at AXI slave port will re-arbitrate
// the requests at the following two conditions: The granted master de-
// asserts its request, the granted master runs out of its grant count.
#define FTAXI_MAWGNTCNT_ADDR           0x10190390
// Field       : M0_AWGNTCNT
// Access      : RO
// Master 0 AW grant count.
#define FTAXI_MAWGNTCNT_M0_AWGNTCNT_BIT 0
#define FTAXI_MAWGNTCNT_M0_AWGNTCNT_LEN 3
#define FTAXI_MAWGNTCNT_M0_AWGNTCNT_MASK 0x00000007
// Field       : M1_AWGNTCNT
// Access      : RO
// Master 1 AW grant count.
#define FTAXI_MAWGNTCNT_M1_AWGNTCNT_BIT 4
#define FTAXI_MAWGNTCNT_M1_AWGNTCNT_LEN 3
#define FTAXI_MAWGNTCNT_M1_AWGNTCNT_MASK 0x00000070
// Field       : M2_AWGNTCNT
// Access      : RO
// Master 2 AW grant count.
#define FTAXI_MAWGNTCNT_M2_AWGNTCNT_BIT 8
#define FTAXI_MAWGNTCNT_M2_AWGNTCNT_LEN 3
#define FTAXI_MAWGNTCNT_M2_AWGNTCNT_MASK 0x00000700
// Field       : M3_AWGNTCNT
// Access      : RO
// Master 3 AW grant count.
#define FTAXI_MAWGNTCNT_M3_AWGNTCNT_BIT 12
#define FTAXI_MAWGNTCNT_M3_AWGNTCNT_LEN 3
#define FTAXI_MAWGNTCNT_M3_AWGNTCNT_MASK 0x00007000
// ----------------------------------------------------------------------
// Register    : AXI Master Port Read Grant Count Register
// The grant count registers define the maximum AR command count that a
// granted AXI master can issues before arbiter changes the grant to
// other AXI master. The AR arbiter at AXI slave port will re-arbitrate
// the requests at the following two conditions: The granted master de-
// asserts its request, the granted master runs out of its grant count.
#define FTAXI_MARGNTCNT_ADDR           0x10190398
// Field       : M0_ARGNTCNT
// Access      : RO
// Master 0 AW grant count.
#define FTAXI_MARGNTCNT_M0_ARGNTCNT_BIT 0
#define FTAXI_MARGNTCNT_M0_ARGNTCNT_LEN 3
#define FTAXI_MARGNTCNT_M0_ARGNTCNT_MASK 0x00000007
// Field       : M1_ARGNTCNT
// Access      : RO
// Master 1 AW grant count.
#define FTAXI_MARGNTCNT_M1_ARGNTCNT_BIT 4
#define FTAXI_MARGNTCNT_M1_ARGNTCNT_LEN 3
#define FTAXI_MARGNTCNT_M1_ARGNTCNT_MASK 0x00000070
// Field       : M2_ARGNTCNT
// Access      : RO
// Master 2 AW grant count.
#define FTAXI_MARGNTCNT_M2_ARGNTCNT_BIT 8
#define FTAXI_MARGNTCNT_M2_ARGNTCNT_LEN 3
#define FTAXI_MARGNTCNT_M2_ARGNTCNT_MASK 0x00000700
// Field       : M3_ARGNTCNT
// Access      : RO
// Master 3 AW grant count.
#define FTAXI_MARGNTCNT_M3_ARGNTCNT_BIT 12
#define FTAXI_MARGNTCNT_M3_ARGNTCNT_LEN 3
#define FTAXI_MARGNTCNT_M3_ARGNTCNT_MASK 0x00007000


// ======================================================================
// Module      : Faraday UART
// Base Address: 0x101a0000
// The Faraday UART controller is a serial communication element that
// implements the most common serial communication protocols. This device
// also provides a UART mode of the operation that is backward compatible
// to 16450 and 16550 devices to support existing the communication
// software. NOTE: The odd register memory map of the UART is because it
// conforms to hardware designed in the 1980's when digitals circuits
// were designed by hand with schematic capture. The weird modes of the
// UART registers propose a challenge for the autogenerated UVM code and
// the model won't work predictively without changes.
// ----------------------------------------------------------------------
// Register    : Receive Buffer Register - Data Transmit Register
// When read this receive data is retrieved from this location. To read
// received data continue reading this location until the Data Ready bit
// in LSR is 0. Data received is right justified. The Rx FIFO is 16
// characters deep. When written transmit data is sent from this
// location. Data transmitted is right justified. Before writing this
// register, the user must ensure that UART is ready to accept data for
// transmission by checking if the THR Empty flag is set in LSR. The Tx
// FIFO is 16 characters deep. When the DLAB bit in LCR is se this
// address accesses the low 8 bits of the BAUD rate divisor (DLL).
#define FTUART_RBR_THR_ADDR            0x101a0000
// Field       : DATA
// Access      : RW
// If FIFOs are enabled received characters are written to the RX FIFO.
// If FIFOs are not enabled then received data is always written to
// location 0 of the FIFO. In either case read this field to retrieve the
// data. If FIFOs are enabled transmit data is written to the TX FIFO. If
// FIFOs are not enabled then transmitted data is always written to
// location 0 of the FIFO. In either case write to this field to send
// data.
#define FTUART_RBR_THR_DATA_BIT        0
#define FTUART_RBR_THR_DATA_LEN        8
#define FTUART_RBR_THR_DATA_MASK       0x000000ff
// ----------------------------------------------------------------------
// Register    : Interrupt Enable Register
// When the DLAB bit in LCR is se this address accesses the upper 8 bits
// of the BAUD rate divisor (DLM).
#define FTUART_IER_ADDR                0x101a0004
// Field       : DR
// Access      : RW
// Enable received data available interrupt and character reception
// timeouts when in FIFO mode.
#define FTUART_IER_DR_BIT              0
#define FTUART_IER_DR_LEN              1
#define FTUART_IER_DR_MASK             0x00000001
// Field       : THR
// Access      : RW
// Enable THR empty interrupt.
#define FTUART_IER_THR_BIT             1
#define FTUART_IER_THR_LEN             1
#define FTUART_IER_THR_MASK            0x00000002
// Field       : RLS
// Access      : RW
// Enable receiver line status interrupt.
#define FTUART_IER_RLS_BIT             2
#define FTUART_IER_RLS_LEN             1
#define FTUART_IER_RLS_MASK            0x00000004
// Field       : MODEM
// Access      : RW
// Enable modem status interrupt. Always set to 0 in EchoNous design.
#define FTUART_IER_MODEM_BIT           3
#define FTUART_IER_MODEM_LEN           1
#define FTUART_IER_MODEM_MASK          0x00000008
// ----------------------------------------------------------------------
// Register    : Interrupt ID Register - FIFO Control Register
// Reading identifies the interrupt with the highest priority that is
// currently pending. FTUART010 implements a four-level priority encoder
// from the highest priority to the lowest priority. Writing this
// register is used to enable and clear FIFOs, and set the RX FIFO
// trigger level. If users reset FIFO, the status of FIFO will not clear.
// Users must clear these registers by reading the corresponding
// registers. When the DLAB bit in LCR is set this register is the
// Prescale Register.
#define FTUART_IIR_ADDR                0x101a0008
// Field       : INT_FIFOEN
// Access      : RW
// Interrupt pending. Active low. Enable both the transmit and receive
// FIFOs (As well as the Status FIFO). Changing this bit will
// automatically reset both FIFOs.
#define FTUART_IIR_INT_FIFOEN_BIT      0
#define FTUART_IIR_INT_FIFOEN_LEN      1
#define FTUART_IIR_INT_FIFOEN_MASK     0x00000001
// Field       : ID_RXF_RST
// Access      : RW
// Interrupt ID Code. 3: Receive Line Status (Highest priority) 2:
// Receive Data Ready and Character Reception Timeout (Second priority)
// 1: Transmitter Holding Register Empty (Third priority) 0: Modem Status
// (Lowest priority). Set this bit to logic 1 clears all bytes in Rx FIFO
// and resets the counter logic to 0. The shift register is not cleared,
// so any reception active will continue.Set this bit also clears the
// Status FIFO.This bit will automatically return to zero.
#define FTUART_IIR_ID_RXF_RST_BIT      1
#define FTUART_IIR_ID_RXF_RST_LEN      2
#define FTUART_IIR_ID_RXF_RST_MASK     0x00000006
// Field       : TX_FIFO_RESET
// Access      : WO
// Set this bit to logic 1 clears all bytes in TX FIFO and resets the
// counter logic to 0. The shift register is not cleared, so any
// reception active will continue.This bit will automatically return to
// zero.
#define FTUART_IIR_TX_FIFO_RESET_BIT   3
#define FTUART_IIR_TX_FIFO_RESET_LEN   1
#define FTUART_IIR_TX_FIFO_RESET_MASK  0x00000008
// Field       : FIFO_TMO_DMA_MODE2
// Access      : RW
// On read bit 4 is the Tx FIFO full interrupt bit and bit 5 is reserved.
// In 16450 mode this bit is always 0. In 16550 FIFO mode this bit is set
// when timeout interrupt is pending. This bit selects the UART DMA
// mode.The DMA mode affects the way in which the DMA signaling outputs
// pins(irda_nrxrdy and irda_ntxrdy) behave. On a write these two btis
// are the Tx FIFO interrupt trigger level. 0: 1, 1: 4, 2: 8, 3: 14
// characters.
#define FTUART_IIR_FIFO_TMO_DMA_MODE2_BIT 4
#define FTUART_IIR_FIFO_TMO_DMA_MODE2_LEN 2
#define FTUART_IIR_FIFO_TMO_DMA_MODE2_MASK 0x00000030
// Field       : FIFO_MODE_RXF_TRGL
// Access      : RW
// On read these bits are the FCR FIFO Enable bits. Both bits are set
// when FCR FIFO Enable (bit 0) is set. On a write these bits are the RX
// FIFO interrupt trigger level. Set the trigger level of the RX FIFO
// interrupt.0: 1, 1: 3, 2: 9, 3: 13 characters.
#define FTUART_IIR_FIFO_MODE_RXF_TRGL_BIT 7
#define FTUART_IIR_FIFO_MODE_RXF_TRGL_LEN 2
#define FTUART_IIR_FIFO_MODE_RXF_TRGL_MASK 0x00000180
// ----------------------------------------------------------------------
// Register    : Line Control Register
// This register controls the way in which the transmitted characters are
// serialized and received characters are assembled and checked.
#define FTUART_LCR_ADDR                0x101a000c
// Field       : WL
// Access      : RW
// Word Length.0: 5, 1: 6, 2: 7, 3: 8 bits.
#define FTUART_LCR_WL_BIT              0
#define FTUART_LCR_WL_LEN              2
#define FTUART_LCR_WL_MASK             0x00000003
// Field       : STOP
// Access      : RW
// Number of stop bits.0: 1 stop bit, 1: 1.5 stop bits for WL = 5 else 2
// stop bits.
#define FTUART_LCR_STOP_BIT            2
#define FTUART_LCR_STOP_LEN            1
#define FTUART_LCR_STOP_MASK           0x00000004
// Field       : PARITY_EN
// Access      : RW
// Set to 1 to enable parity generation and checking.
#define FTUART_LCR_PARITY_EN_BIT       3
#define FTUART_LCR_PARITY_EN_LEN       1
#define FTUART_LCR_PARITY_EN_MASK      0x00000008
// Field       : PARITY
// Access      : RW
// 0: Odd Parity, 1: Even Parity, 2: 1 Parity, 3: 0 Parity.
#define FTUART_LCR_PARITY_BIT          4
#define FTUART_LCR_PARITY_LEN          2
#define FTUART_LCR_PARITY_MASK         0x00000030
// Field       : BREAK
// Access      : RW
// This bit causes a break condition to be transmitted to the receiving
// UART.When it is set to logic 1, the serial output(io_irda_sout)is
// forced to the Spacing (Logic 0) state.The break is disabled by setting
// bit 6 to 0. The Break Control bit acts only on io_irda_sout and has no
// effect on the transmitter logic, so if several characters are stored
// in the transmit FIFO, they will be removed from this FIFO and passed
// sequentially to the Transmitter Shift Register which serializes them,
// even if Set Break is set.This fact can be useful to establish the
// break time making use of the THR Empty and Transmitter Empty flags of
// the LSR.Firmware can follow the sequence below to assure no erroneous
// or extraneous characters will be transmitted because of the break: Set
// break when transmitter is idle(LSR bit 6).Write a character with any
// value to THR.Wait for the transmitter to become idle(LSR bit 6), and
// clear break when normal transmission has to be restored.
#define FTUART_LCR_BREAK_BIT           6
#define FTUART_LCR_BREAK_LEN           1
#define FTUART_LCR_BREAK_MASK          0x00000040
// Field       : DLAB
// Access      : RW
// Divisor Latch Access Bit(DLAB)This bit must be set in order to access
// the DLL, DLM and PSR registers which program the division constants
// for the baud rate divider and the prescaler.
#define FTUART_LCR_DLAB_BIT            7
#define FTUART_LCR_DLAB_LEN            1
#define FTUART_LCR_DLAB_MASK           0x00000080
// ----------------------------------------------------------------------
// Register    : Mode Control Register
//
#define FTUART_MCR_ADDR                0x101a0010
// Field       : LOOPBACK
// Access      : RW
// Enable near end loopback with tx looped back to rx.
#define FTUART_MCR_LOOPBACK_BIT        4
#define FTUART_MCR_LOOPBACK_LEN        1
#define FTUART_MCR_LOOPBACK_MASK       0x00000010
// Field       : DMA_MODE2
// Access      : RW
// .
#define FTUART_MCR_DMA_MODE2_BIT       5
#define FTUART_MCR_DMA_MODE2_LEN       1
#define FTUART_MCR_DMA_MODE2_MASK      0x00000020
// ----------------------------------------------------------------------
// Register    : Line Status Register
// When this address is read it has the following functions.
#define FTUART_LSR_ADDR                0x101a0014
// Field       : DR
// Access      : RO
// This bit is set if one or more characters have been received and are
// waiting in the receiver FIFO for users to read.It is cleared to logic
// 0 by reading all of the data in the Receiver Buffer Register or FIFO.
#define FTUART_LSR_DR_BIT              0
#define FTUART_LSR_DR_LEN              1
#define FTUART_LSR_DR_MASK             0x00000001
// Field       : OVERRUN_ERR
// Access      : RO
// When this bit is set, a character will be completely assembled in the
// Receiver Shift Register without having free space to put it in the
// receive FIFO or buffer register.When an overrun condition appears, the
// result is different depending on whether the 16-byte FIFO is active or
// not.If FIFO is inactive, only a 1 - character Receiver Buffer Register
// will be available, and the unread data in this RBR will not be
// overwritten with the new character just received.If FIFO is active,
// the character just received in the Receiver Shift Register will be
// overwritten, but the data already present in FIFO will not be
// changed.The Overrun Error flag is set as soon as the overrun condition
// appears.This bit will not be queued in FIFO if it is active.This bit
// will be cleared as soon as LSR is read.
#define FTUART_LSR_OVERRUN_ERR_BIT     1
#define FTUART_LSR_OVERRUN_ERR_LEN     1
#define FTUART_LSR_OVERRUN_ERR_MASK    0x00000002
// Field       : PARITY_ERR
// Access      : RO
// When this bit is set, it indicates that the parity of the received
// character is wrong according to the current setting in LCR.This bit is
// queued in the receive FIFO; therefore, it is associated with the
// particular character that had the error.LSR must be read before RBR:
// Each time a character is read from RBR, the next character passes to
// the top of FIFO and LSR is loaded with the queued error flags
// corresponding to this top - of - the - FIFO character.This bit is
// cleared as soon as LSR is read.
#define FTUART_LSR_PARITY_ERR_BIT      2
#define FTUART_LSR_PARITY_ERR_LEN      1
#define FTUART_LSR_PARITY_ERR_MASK     0x00000004
// Field       : FRAMING_ERR
// Access      : RO
// This bit indicates that the received character did not have a valid
// stop bit (i.e., a 0 is detected in the(First)stop bit position instead
// of a 1) .This bit is queued in the receiver FIFO in the same way as
// the Parity Error bit.When a framing error is detected, the receiver
// tries to resynchronize; if the next sample is again a zero, it will be
// taken as the beginning of a possible new start bit.This bit is cleared
// as soon as LSR is read.
#define FTUART_LSR_FRAMING_ERR_BIT     3
#define FTUART_LSR_FRAMING_ERR_LEN     1
#define FTUART_LSR_FRAMING_ERR_MASK    0x00000008
// Field       : BREAK_INT
// Access      : RO
// This bit is set to 1 if the receiver line input, io_irda_sin, is held
// at zero for a complete character time.This indicates that the
// positions correspond to the start bit, data, parity bit(If any),
// and(First)stop bit are all detected as zeroes.Please note that a
// Framing Error flag always accompanies this flag.This bit is queued in
// the receiver FIFO in the same way as the Parity Error bit.When the
// break occurs, only one zero character is loaded into FIFO.The next
// character transfer is enabled after io_irda_sin goes to the marking
// state and receives the next valid start bit.This bit is cleared as
// soon as LSR is read.
#define FTUART_LSR_BREAK_INT_BIT       4
#define FTUART_LSR_BREAK_INT_LEN       1
#define FTUART_LSR_BREAK_INT_MASK      0x00000010
// Field       : THR
// Access      : RO
// This bit indicates that UART is ready to accept a new character for
// transmission.In addition, this bit will cause UART to issue an
// interrupt to CPU when the Transmit Holding Register Empty Interrupt
// enable bit(IER[1])is set high.In the non - FIFO mode, this bit is set
// whenever the 1-byte THR is empty.If THR holds data to be transmitted,
// this bit will be immediately set when this data is passed to TSR.In
// the FIFO mode, this bit is set when the transmitter FIFO is completely
// empty, being 0 if there is at least one byte in FIFO waiting to be
// passed to the TSR for transmission.
#define FTUART_LSR_THR_BIT             5
#define FTUART_LSR_THR_LEN             1
#define FTUART_LSR_THR_MASK            0x00000020
// Field       : TX_MT
// Access      : RO
// This bit will be 1 when both THR(Or TX FIFO)and TSR(Transmitter Shift
// Register)are empty.Reading this bit as 1 indicates that no
// transmission will currently occur in the io_irda_sout output pin, and
// that the transmission line is idle.As soon as new data is written in
// THR, this bit will be cleared.
#define FTUART_LSR_TX_MT_BIT           6
#define FTUART_LSR_TX_MT_LEN           1
#define FTUART_LSR_TX_MT_MASK          0x00000040
// Field       : FIFO_DERR
// Access      : RO
// If FIFO is disabled (16450 mode) , this bit will always be zero.If
// FIFO is active, this bit will be set as soon as any data character in
// the receive FIFO has parity or framing error or the break indication
// is active.This bit will be cleared when CPU reads LSR and the rest of
// the data in the receive FIFO do not have any of these three associated
// flags on.
#define FTUART_LSR_FIFO_DERR_BIT       7
#define FTUART_LSR_FIFO_DERR_LEN       1
#define FTUART_LSR_FIFO_DERR_MASK      0x00000080
// ----------------------------------------------------------------------
// Register    : Scratch Pad Register
//
#define FTUART_SPR_ADDR                0x101a001c
// Field       : USER
// Access      : RW
// This 8-bit read/write register has no effect on the operation of the
// Serial Port. It is intended as a scratchpad register to be temporarily
// used by the programmer to hold data.
#define FTUART_SPR_USER_BIT            0
#define FTUART_SPR_USER_LEN            8
#define FTUART_SPR_USER_MASK           0x000000ff
// ----------------------------------------------------------------------
// Register    : Mode Definition Register
//
#define FTUART_MDR_ADDR                0x101a0020
// Field       : DMA_EN
// Access      : RW
// DMA Enable. When data transfers are performed by a DMA controller
// transmit and/or receive data, interrupts in the PIO mode should be
// disabled to avoid the spurious interrupts.
#define FTUART_MDR_DMA_EN_BIT          4
#define FTUART_MDR_DMA_EN_LEN          1
#define FTUART_MDR_DMA_EN_MASK         0x00000010
// ----------------------------------------------------------------------
// Register    : RX FIFO Count Register
// The RX FIFO Count register represents the number of data bytes in RX
// FIFO. This register is useful when the number of remaining bytes of a
// frame received in RX FIFO is below the set trigger level. When FIFO is
// full, RXFF_CNTR is 0x10 for FIFO with the size of 16-byte. This
// register is for the FIFO mode only. When the FIFO mode is disabled,
// the returned value is unexpected.
#define FTUART_RXFF_CNTR_ADDR          0x101a005c
// Field       : CNT
// Access      : RO
// Number of bytes in the RX FIFO.
#define FTUART_RXFF_CNTR_CNT_BIT       0
#define FTUART_RXFF_CNTR_CNT_LEN       5
#define FTUART_RXFF_CNTR_CNT_MASK      0x0000001f
// ----------------------------------------------------------------------
// Register    : Feature Register
//
#define FTUART_FEATURE_ADDR            0x101a0068
// Field       : FIFO_DEPTH
// Access      : RO
// FIFO Depth is 16 bytes.
#define FTUART_FEATURE_FIFO_DEPTH_BIT  0
#define FTUART_FEATURE_FIFO_DEPTH_LEN  4
#define FTUART_FEATURE_FIFO_DEPTH_MASK 0x0000000f
// Field       : IRDA
// Access      : RO
// IRDA is not supported.
#define FTUART_FEATURE_IRDA_BIT        4
#define FTUART_FEATURE_IRDA_LEN        1
#define FTUART_FEATURE_IRDA_MASK       0x00000010
// ----------------------------------------------------------------------
// Register    : Revision ID Register 1
//
#define FTUART_REVD1_ADDR              0x101a006c
// Field       : ID
// Access      : RO
// First digit of revision number.
#define FTUART_REVD1_ID_BIT            0
#define FTUART_REVD1_ID_LEN            8
#define FTUART_REVD1_ID_MASK           0x000000ff
// ----------------------------------------------------------------------
// Register    : Revision ID Register 2
//
#define FTUART_REVD2_ADDR              0x101a0070
// Field       : ID
// Access      : RO
// Second digit of revision number.
#define FTUART_REVD2_ID_BIT            0
#define FTUART_REVD2_ID_LEN            8
#define FTUART_REVD2_ID_MASK           0x000000ff
// ----------------------------------------------------------------------
// Register    : Revision ID Register 3
//
#define FTUART_REVD3_ADDR              0x101a0074
// Field       : ID
// Access      : RO
// Third digit of revision number.
#define FTUART_REVD3_ID_BIT            0
#define FTUART_REVD3_ID_LEN            8
#define FTUART_REVD3_ID_MASK           0x000000ff


// ======================================================================
// Module      : Faraday AXI to AXI Bridge for USB Controller
// Base Address: 0x101b0000
// FTX2X030 is a bridge connecting the 64 bit AXI fabric to the 32 bit
// USB AXI slave interface.
// ----------------------------------------------------------------------
// Register    : APB Slave Error Mask Register
// When users access the register offset over the legal range, FTX2X will
// respond Slave Error from the APB port. The APB slave error mask
// register can mask the response and will always respond Slave Okay from
// the APB port.
#define FTX2X_USB_ERR_MASK_ADDR        0x101b0000
// Field       : APB_ERR
// Access      : RW
// When this bit is 0 the response will always be Slave OK.
#define FTX2X_USB_ERR_MASK_APB_ERR_BIT 0
#define FTX2X_USB_ERR_MASK_APB_ERR_LEN 1
#define FTX2X_USB_ERR_MASK_APB_ERR_MASK 0x00000001
// ----------------------------------------------------------------------
// Register    : Feature Register 1
//
#define FTX2X_USB_FR1_ADDR             0x101b0010
// Field       : AXIM_DW
// Access      : RO
// AXI Master Bus is 64 bits.
#define FTX2X_USB_FR1_AXIM_DW_BIT      0
#define FTX2X_USB_FR1_AXIM_DW_LEN      8
#define FTX2X_USB_FR1_AXIM_DW_MASK     0x000000ff
// Field       : AXIS_DW
// Access      : RO
// AXI Slave Bus is 64 bits.
#define FTX2X_USB_FR1_AXIS_DW_BIT      8
#define FTX2X_USB_FR1_AXIS_DW_LEN      8
#define FTX2X_USB_FR1_AXIS_DW_MASK     0x0000ff00
// Field       : IDW
// Access      : RO
// AXI ID Width is 8 bits.
#define FTX2X_USB_FR1_IDW_BIT          16
#define FTX2X_USB_FR1_IDW_LEN          5
#define FTX2X_USB_FR1_IDW_MASK         0x001f0000
// Field       : CLOCK_MODE
// Access      : RO
// The AXI master bus is synchronous to the AXI slave bus.
#define FTX2X_USB_FR1_CLOCK_MODE_BIT   21
#define FTX2X_USB_FR1_CLOCK_MODE_LEN   2
#define FTX2X_USB_FR1_CLOCK_MODE_MASK  0x00600000
// Field       : AXI_PR
// Access      : RO
// AXI-3 Protocol.
#define FTX2X_USB_FR1_AXI_PR_BIT       23
#define FTX2X_USB_FR1_AXI_PR_LEN       3
#define FTX2X_USB_FR1_AXI_PR_MASK      0x03800000
// Field       : AW
// Access      : RO
// Address bus width is 32 bits.
#define FTX2X_USB_FR1_AW_BIT           26
#define FTX2X_USB_FR1_AW_LEN           6
#define FTX2X_USB_FR1_AW_MASK          0xfc000000
// ----------------------------------------------------------------------
// Register    : Feature Register 2
//
#define FTX2X_USB_FR2_ADDR             0x101b0014
// Field       : WR_DEPTH
// Access      : RO
// Write response queue depth.
#define FTX2X_USB_FR2_WR_DEPTH_BIT     0
#define FTX2X_USB_FR2_WR_DEPTH_LEN     3
#define FTX2X_USB_FR2_WR_DEPTH_MASK    0x00000007
// Field       : RD_DEPTH
// Access      : RO
// Read data queue depth.
#define FTX2X_USB_FR2_RD_DEPTH_BIT     3
#define FTX2X_USB_FR2_RD_DEPTH_LEN     4
#define FTX2X_USB_FR2_RD_DEPTH_MASK    0x00000078
// Field       : WD_DEPTH
// Access      : RO
// Write data queue depth.
#define FTX2X_USB_FR2_WD_DEPTH_BIT     7
#define FTX2X_USB_FR2_WD_DEPTH_LEN     4
#define FTX2X_USB_FR2_WD_DEPTH_MASK    0x00000780
// Field       : RCMDQ_DEPTH
// Access      : RO
// Command queue depth.
#define FTX2X_USB_FR2_RCMDQ_DEPTH_BIT  11
#define FTX2X_USB_FR2_RCMDQ_DEPTH_LEN  3
#define FTX2X_USB_FR2_RCMDQ_DEPTH_MASK 0x00003800
// Field       : WCMDQ_DEPTH
// Access      : RO
// Command queue depth.
#define FTX2X_USB_FR2_WCMDQ_DEPTH_BIT  14
#define FTX2X_USB_FR2_WCMDQ_DEPTH_LEN  3
#define FTX2X_USB_FR2_WCMDQ_DEPTH_MASK 0x0001c000
// ----------------------------------------------------------------------
// Register    : Feature Register 3
//
#define FTX2X_USB_FR3_ADDR             0x101b0018
// Field       : WR_UW
// Access      : RO
// WR User Width.
#define FTX2X_USB_FR3_WR_UW_BIT        0
#define FTX2X_USB_FR3_WR_UW_LEN        6
#define FTX2X_USB_FR3_WR_UW_MASK       0x0000003f
// Field       : RD_UW
// Access      : RO
// RD User Width.
#define FTX2X_USB_FR3_RD_UW_BIT        6
#define FTX2X_USB_FR3_RD_UW_LEN        6
#define FTX2X_USB_FR3_RD_UW_MASK       0x00000fc0
// Field       : WD_UW
// Access      : RO
// WD User Width.
#define FTX2X_USB_FR3_WD_UW_BIT        12
#define FTX2X_USB_FR3_WD_UW_LEN        6
#define FTX2X_USB_FR3_WD_UW_MASK       0x0003f000
// Field       : AR_UW
// Access      : RO
// AR User Width.
#define FTX2X_USB_FR3_AR_UW_BIT        18
#define FTX2X_USB_FR3_AR_UW_LEN        6
#define FTX2X_USB_FR3_AR_UW_MASK       0x00fc0000
// Field       : AW_UW
// Access      : RO
// AW User Width.
#define FTX2X_USB_FR3_AW_UW_BIT        24
#define FTX2X_USB_FR3_AW_UW_LEN        6
#define FTX2X_USB_FR3_AW_UW_MASK       0x3f000000
// ----------------------------------------------------------------------
// Register    : Revision Register
//
#define FTX2X_USB_RR_ADDR              0x101b001c
// Field       : REV_VER
// Access      : RO
// Revision number
#define FTX2X_USB_RR_REV_VER_BIT       0
#define FTX2X_USB_RR_REV_VER_LEN       8
#define FTX2X_USB_RR_REV_VER_MASK      0x000000ff
// Field       : MINOR_VER
// Access      : RO
// Minor version number
#define FTX2X_USB_RR_MINOR_VER_BIT     8
#define FTX2X_USB_RR_MINOR_VER_LEN     8
#define FTX2X_USB_RR_MINOR_VER_MASK    0x0000ff00
// Field       : MAJOR_VER
// Access      : RO
// Major version number
#define FTX2X_USB_RR_MAJOR_VER_BIT     16
#define FTX2X_USB_RR_MAJOR_VER_LEN     8
#define FTX2X_USB_RR_MAJOR_VER_MASK    0x00ff0000


// ======================================================================
// Module      : Faraday USB Controller
// Base Address: 0x10300000
// Registers with offsets < 0x1800 are Host Mode registers. Registers
// with offsets >= 0x1800 and < 0x2000 are OTG and Global registers.
// Registers with offsets >= 0x2000 are Device Mode registers.
// ----------------------------------------------------------------------
// Register    : Capability Registers Length Register
// This register is part of the Host Controller Capability Register set.
#define FTUSB_CAPLENGTH_ADDR           0x10300000
// Field       : CL
// Access      : RO
// This register is used as an offset to add to register base to find the
// beginning of the Operational Register Space.
#define FTUSB_CAPLENGTH_CL_BIT         0
#define FTUSB_CAPLENGTH_CL_LEN         8
#define FTUSB_CAPLENGTH_CL_MASK        0x000000ff
// ----------------------------------------------------------------------
// Register    : Host Controller Interface Version Number Register
// This register is part of the Host Controller Capability Register set.
#define FTUSB_HCIVERSION_ADDR          0x10300002
// Field       : VERSION
// Access      : RO
// This is a two byte register containing a BCD encoding of the revision
// number of the XHCI specification supported by this host controller.
// The MSB represents a major revision and the LSB is the minor revision.
// This IP currently implements XHCI specification version 1.0.
#define FTUSB_HCIVERSION_VERSION_BIT   0
#define FTUSB_HCIVERSION_VERSION_LEN   16
#define FTUSB_HCIVERSION_VERSION_MASK  0x0000ffff
// ----------------------------------------------------------------------
// Register    : Host Controller Structural Parameters Register 1
// This register is part of the Host Controller Capability Register set.
#define FTUSB_HCSPARAMS1_ADDR          0x10300004
// Field       : MAXSLOTS
// Access      : RO
// Number of device slots.  Maximum number of Device Context Structures
// and Doorbell Array entries that this host controller supports.
#define FTUSB_HCSPARAMS1_MAXSLOTS_BIT  0
#define FTUSB_HCSPARAMS1_MAXSLOTS_LEN  8
#define FTUSB_HCSPARAMS1_MAXSLOTS_MASK 0x000000ff
// Field       : MAXINTRS
// Access      : RO
// Number of interrupters. This field indicates how many interrupt
// register sets are addressable in the Runtime Registers Space.
#define FTUSB_HCSPARAMS1_MAXINTRS_BIT  8
#define FTUSB_HCSPARAMS1_MAXINTRS_LEN  11
#define FTUSB_HCSPARAMS1_MAXINTRS_MASK 0x0007ff00
// Field       : MAXPORTS
// Access      : RO
// This field specifies the maximum number of Port Register Sets that are
// addressable in the Operational Register Space.
#define FTUSB_HCSPARAMS1_MAXPORTS_BIT  24
#define FTUSB_HCSPARAMS1_MAXPORTS_LEN  8
#define FTUSB_HCSPARAMS1_MAXPORTS_MASK 0xff000000
// ----------------------------------------------------------------------
// Register    : Host Controller Structural Parameters Register 2
// This register is part of the Host Controller Capability Register set.
#define FTUSB_HCSPARAMS2_ADDR          0x10300008
// Field       : IST
// Access      : RO
// Isochronous Scheduling Threshold.  Minimum time required to stay ahead
// of the host controller while adding TRBs so that the host controller
// can process them at the correct time. The valuer is specified in
// number of frames/microframes. SW can add a TRB no later than 1
// microframe before that TRB is scheduled to be executed.
#define FTUSB_HCSPARAMS2_IST_BIT       0
#define FTUSB_HCSPARAMS2_IST_LEN       4
#define FTUSB_HCSPARAMS2_IST_MASK      0x0000000f
// Field       : ERST
// Access      : RO
// Event Ring Segment Table Max. Maximum value supported by the Event
// Ring Segment Table base size register. Max entries = 1 << erst.
#define FTUSB_HCSPARAMS2_ERST_BIT      4
#define FTUSB_HCSPARAMS2_ERST_LEN      4
#define FTUSB_HCSPARAMS2_ERST_MASK     0x000000f0
// Field       : SPR
// Access      : RO
// Scratchpad restore. The IP does not support this feature.
#define FTUSB_HCSPARAMS2_SPR_BIT       26
#define FTUSB_HCSPARAMS2_SPR_LEN       1
#define FTUSB_HCSPARAMS2_SPR_MASK      0x04000000
// Field       : SCRBUFS
// Access      : RO
// Max scratchpad buffers. The IP does not support this feature.
#define FTUSB_HCSPARAMS2_SCRBUFS_BIT   27
#define FTUSB_HCSPARAMS2_SCRBUFS_LEN   4
#define FTUSB_HCSPARAMS2_SCRBUFS_MASK  0x78000000
// ----------------------------------------------------------------------
// Register    : Host Controller Structural Parameters Register 3
// This register is part of the Host Controller Capability Register set.
#define FTUSB_HCSPARAMS3_ADDR          0x1030000c
// Field       : U1_EXIT_LATENCY
// Access      : RO
// U1 Device Exit Latency from U1 to U0 expressed in microseconds.
#define FTUSB_HCSPARAMS3_U1_EXIT_LATENCY_BIT 0
#define FTUSB_HCSPARAMS3_U1_EXIT_LATENCY_LEN 8
#define FTUSB_HCSPARAMS3_U1_EXIT_LATENCY_MASK 0x000000ff
// Field       : U2_EXIT_LATENCY
// Access      : RO
// U2 Device Exit Latency from U2 to U0 expressed in microseconds.
#define FTUSB_HCSPARAMS3_U2_EXIT_LATENCY_BIT 16
#define FTUSB_HCSPARAMS3_U2_EXIT_LATENCY_LEN 16
#define FTUSB_HCSPARAMS3_U2_EXIT_LATENCY_MASK 0xffff0000
// ----------------------------------------------------------------------
// Register    : Host Controller Capability Parameters Register
// This register is part of the Host Controller Capability Register set.
#define FTUSB_HCCPARAMS_ADDR           0x10300010
// Field       : AC64
// Access      : RO
// 64 Bit Address Capability. 32 bit memory pointers are implemented for
// XHCI.
#define FTUSB_HCCPARAMS_AC64_BIT       0
#define FTUSB_HCCPARAMS_AC64_LEN       1
#define FTUSB_HCCPARAMS_AC64_MASK      0x00000001
// Field       : BZC
// Access      : RO
// BW Negotiation Capability.  The design does not support this
// capability.
#define FTUSB_HCCPARAMS_BZC_BIT        1
#define FTUSB_HCCPARAMS_BZC_LEN        1
#define FTUSB_HCCPARAMS_BZC_MASK       0x00000002
// Field       : CSZ
// Access      : RO
// Context Size. The context size is 32 bytes.
#define FTUSB_HCCPARAMS_CSZ_BIT        2
#define FTUSB_HCCPARAMS_CSZ_LEN        1
#define FTUSB_HCCPARAMS_CSZ_MASK       0x00000004
// Field       : PPC
// Access      : RO
// Port Power Control. The host controller has port power controls.
#define FTUSB_HCCPARAMS_PPC_BIT        3
#define FTUSB_HCCPARAMS_PPC_LEN        1
#define FTUSB_HCCPARAMS_PPC_MASK       0x00000008
// Field       : PIND
// Access      : RO
// Port Indicators. The host controller has port indicator controls.
#define FTUSB_HCCPARAMS_PIND_BIT       4
#define FTUSB_HCCPARAMS_PIND_LEN       1
#define FTUSB_HCCPARAMS_PIND_MASK      0x00000010
// Field       : LHRC
// Access      : RO
// Light HC Reset Capability. The design does not support this feature.
#define FTUSB_HCCPARAMS_LHRC_BIT       5
#define FTUSB_HCCPARAMS_LHRC_LEN       1
#define FTUSB_HCCPARAMS_LHRC_MASK      0x00000020
// Field       : LTC
// Access      : RO
// Latency Tolerance Messaging Capability. The design does not support
// this feature.
#define FTUSB_HCCPARAMS_LTC_BIT        6
#define FTUSB_HCCPARAMS_LTC_LEN        1
#define FTUSB_HCCPARAMS_LTC_MASK       0x00000040
// Field       : NSS
// Access      : RO
// No Secondary SID Support. The design does not support this feature.
#define FTUSB_HCCPARAMS_NSS_BIT        7
#define FTUSB_HCCPARAMS_NSS_LEN        1
#define FTUSB_HCCPARAMS_NSS_MASK       0x00000080
// Field       : MAXPSASIZE
// Access      : RO
// Maximum Primary Stream Array Size. PSA size = 2^maxpsasize + 1.
#define FTUSB_HCCPARAMS_MAXPSASIZE_BIT 12
#define FTUSB_HCCPARAMS_MAXPSASIZE_LEN 4
#define FTUSB_HCCPARAMS_MAXPSASIZE_MASK 0x0000f000
// Field       : XECP
// Access      : RO
// XHCI Extended Capabilities Pointer. The design has extended
// capabilities at offset 0x500.
#define FTUSB_HCCPARAMS_XECP_BIT       16
#define FTUSB_HCCPARAMS_XECP_LEN       16
#define FTUSB_HCCPARAMS_XECP_MASK      0xffff0000
// ----------------------------------------------------------------------
// Register    : Doorbell Offset Register
// This register is part of the Host Controller Capability Register set.
#define FTUSB_DBOFF_ADDR               0x10300014
// Field       : OFF
// Access      : RW
// DWord offset of the doorbell array base address from block address.
#define FTUSB_DBOFF_OFF_BIT            2
#define FTUSB_DBOFF_OFF_LEN            30
#define FTUSB_DBOFF_OFF_MASK           0xfffffffc
// ----------------------------------------------------------------------
// Register    : Runtime Register Space Offset Register
// This register is part of the Host Controller Capability Register set.
#define FTUSB_RTSOFF_ADDR              0x10300018
// Field       : OFF
// Access      : RW
// 32 byte offset to XHCI Runtime Registers from block address.
#define FTUSB_RTSOFF_OFF_BIT           5
#define FTUSB_RTSOFF_OFF_LEN           27
#define FTUSB_RTSOFF_OFF_MASK          0xffffffe0
// ----------------------------------------------------------------------
// Register    : USB Command Register
// This register is part of the Host Controller Operational Register set.
#define FTUSB_USBCMD_ADDR              0x10300020
// Field       : RS
// Access      : RW
// Run/Stop. When set the XCHI begins scheduling transactions, if any.
// When this bit is cleared the XHCI will complete any queued commands,
// or TDs and transactions associated with them.
#define FTUSB_USBCMD_RS_BIT            0
#define FTUSB_USBCMD_RS_LEN            1
#define FTUSB_USBCMD_RS_MASK           0x00000001
// Field       : HCRST
// Access      : RW
// Host Controller Reset.
#define FTUSB_USBCMD_HCRST_BIT         1
#define FTUSB_USBCMD_HCRST_LEN         1
#define FTUSB_USBCMD_HCRST_MASK        0x00000002
// Field       : INTE
// Access      : RW
// Interrut Enable. Set to enable host system interrupts.
#define FTUSB_USBCMD_INTE_BIT          2
#define FTUSB_USBCMD_INTE_LEN          1
#define FTUSB_USBCMD_INTE_MASK         0x00000004
// Field       : HSEE
// Access      : RW
// Host System Error Enable. When set and the HSE bit in the USBSTS
// register is 1 the XHCI controller signals an out of band error to the
// host.
#define FTUSB_USBCMD_HSEE_BIT          3
#define FTUSB_USBCMD_HSEE_LEN          1
#define FTUSB_USBCMD_HSEE_MASK         0x00000008
// Field       : LHCRST
// Access      : RO
// Light Host Controller Reset. The design does not support this feature.
#define FTUSB_USBCMD_LHCRST_BIT        7
#define FTUSB_USBCMD_LHCRST_LEN        1
#define FTUSB_USBCMD_LHCRST_MASK       0x00000080
// Field       : CSS
// Access      : RW
// Controller Save State. The design does not support this feature.
#define FTUSB_USBCMD_CSS_BIT           8
#define FTUSB_USBCMD_CSS_LEN           1
#define FTUSB_USBCMD_CSS_MASK          0x00000100
// Field       : CRS
// Access      : RW
// Controller Restore State. The design does not support this feature.
#define FTUSB_USBCMD_CRS_BIT           9
#define FTUSB_USBCMD_CRS_LEN           1
#define FTUSB_USBCMD_CRS_MASK          0x00000200
// Field       : EWE
// Access      : RW
// Enable Wrap Event. When set XHCI gnerates a MFINDEX wrap event each
// time the MFINDEX register transitions from 0x3FFF to 0.
#define FTUSB_USBCMD_EWE_BIT           10
#define FTUSB_USBCMD_EWE_LEN           1
#define FTUSB_USBCMD_EWE_MASK          0x00000400
// Field       : EU3S
// Access      : RW
// Enable U3 MFINDEX Stop. The design does not support this feature.
#define FTUSB_USBCMD_EU3S_BIT          11
#define FTUSB_USBCMD_EU3S_LEN          1
#define FTUSB_USBCMD_EU3S_MASK         0x00000800
// ----------------------------------------------------------------------
// Register    : USB Status Register
// This register is part of the Host Controller Operational Register set.
#define FTUSB_USBSTS_ADDR              0x10300024
// Field       : HCH
// Access      : RO
// Host Controller Halted. Set when the Run/Stop bit is cleared either by
// HW or SW.
#define FTUSB_USBSTS_HCH_BIT           0
#define FTUSB_USBSTS_HCH_LEN           1
#define FTUSB_USBSTS_HCH_MASK          0x00000001
// Field       : HSE
// Access      : W1C
// Host System Error. When this error occurs the XHCI clears the Run/Stop
// bit in the USBCMD register.
#define FTUSB_USBSTS_HSE_BIT           2
#define FTUSB_USBSTS_HSE_LEN           1
#define FTUSB_USBSTS_HSE_MASK          0x00000004
// Field       : EINT
// Access      : W1C
// Event Interrupt. Set when there is an interrupt pending.
#define FTUSB_USBSTS_EINT_BIT          3
#define FTUSB_USBSTS_EINT_LEN          1
#define FTUSB_USBSTS_EINT_MASK         0x00000008
// Field       : PCD
// Access      : W1C
// Port Change Detect. Set when any port change has been detected.
#define FTUSB_USBSTS_PCD_BIT           4
#define FTUSB_USBSTS_PCD_LEN           1
#define FTUSB_USBSTS_PCD_MASK          0x00000010
// Field       : SSS
// Access      : RO
// Save State Status. The design does not support save or restore.
#define FTUSB_USBSTS_SSS_BIT           8
#define FTUSB_USBSTS_SSS_LEN           1
#define FTUSB_USBSTS_SSS_MASK          0x00000100
// Field       : RSS
// Access      : RO
// Restore Stale Status. The design does not support save or restore.
#define FTUSB_USBSTS_RSS_BIT           9
#define FTUSB_USBSTS_RSS_LEN           1
#define FTUSB_USBSTS_RSS_MASK          0x00000200
// Field       : SRE
// Access      : W1C
// Save/Restore Error. The design does not support save or restore.
#define FTUSB_USBSTS_SRE_BIT           10
#define FTUSB_USBSTS_SRE_LEN           1
#define FTUSB_USBSTS_SRE_MASK          0x00000400
// Field       : CNR
// Access      : RO
// Controller Not Ready. If CNR bit is set SW should write doorbells or
// any operational register other than the USBSTS register.
#define FTUSB_USBSTS_CNR_BIT           11
#define FTUSB_USBSTS_CNR_LEN           1
#define FTUSB_USBSTS_CNR_MASK          0x00000800
// Field       : HCE
// Access      : RO
// Host Controller Error.
#define FTUSB_USBSTS_HCE_BIT           12
#define FTUSB_USBSTS_HCE_LEN           1
#define FTUSB_USBSTS_HCE_MASK          0x00001000
// ----------------------------------------------------------------------
// Register    : Page Size Register
// This register is part of the Host Controller Operational Register set.
#define FTUSB_PAGESIZE_ADDR            0x10300028
// Field       : PGS
// Access      : RO
// Size of pages supported by the design. Page Size = 1 << (pgs +12). For
// this design that means the page size is 8192 bytes.
#define FTUSB_PAGESIZE_PGS_BIT         0
#define FTUSB_PAGESIZE_PGS_LEN         16
#define FTUSB_PAGESIZE_PGS_MASK        0x0000ffff
// ----------------------------------------------------------------------
// Register    : Device Notification Control Register
// This register is part of the Host Controller Operational Register set.
#define FTUSB_DNCTRL_ADDR              0x10300034
// Field       : NE
// Access      : RW
// Notification Enable.  When set a Device Notification Event will be
// generated when a transaction packet is received matching the value in
// the Notification Type field.
#define FTUSB_DNCTRL_NE_BIT            0
#define FTUSB_DNCTRL_NE_LEN            16
#define FTUSB_DNCTRL_NE_MASK           0x0000ffff
// ----------------------------------------------------------------------
// Register    : Command Ring Control Register
// This register is part of the Host Controller Operational Register set.
#define FTUSB_CRCR_ADDR                0x10300038
// Field       : RCS
// Access      : RW
// Ring Cycle State. This bit identifies the XHCI Consumer Cycle State
// (CCS) flag for the current TRB. Writing this flags is ignored if CRR
// is set. If CRCR is written when Command Ring is stopped (CRR = 0),
// this flag shall be used to fetch first Command TRB after next time
// that the Host Controller Doorbell register is written with setting the
// DB Reason field to Host Controller Command.  If CRCR is not written
// when Command Ring is stopped (CRR = 0), Command Ring will begin
// fetching Command TRBs by using the current value of the internal
// Command Ring CCS flag. Reading this flag always returns to 0.
#define FTUSB_CRCR_RCS_BIT             0
#define FTUSB_CRCR_RCS_LEN             1
#define FTUSB_CRCR_RCS_MASK            0x00000001
// Field       : CS
// Access      : W1S
// Command Stop. Writing 1 to this bit shall stop the operation of
// Command Ring after the completion of the currently executed command
// and generate a Command Completion Event with setting Completion Code
// to Command Ring Stopped and setting Command TRB Pointer to the current
// value of Command Ring Dequeue Pointer. The next write to the Host
// Controller Doorbell with setting the DB Reason field to Host
// Controller Command shall restart the Command Ring operation. Writing
// to this flag will be ignored by XHCI if Command Ring Running (CRR) =
// 0. Reading this flag always returns 0.
#define FTUSB_CRCR_CS_BIT              1
#define FTUSB_CRCR_CS_LEN              1
#define FTUSB_CRCR_CS_MASK             0x00000002
// Field       : CA
// Access      : W1S
// Command Abort. When set the XHCI terminates the currently executed
// command, stop Command Ring, and generate Command Completion Event with
// setting Completion Code to Command Ring Stopped.
#define FTUSB_CRCR_CA_BIT              2
#define FTUSB_CRCR_CA_LEN              1
#define FTUSB_CRCR_CA_MASK             0x00000004
// Field       : CRR
// Access      : RO
// Command Ring Running. Set to when when Run/Stop bis is 1, or if the HC
// Doorbell register is written and DB Reason field is set to HC command.
// Cleared when the command ging is stopped after writing a 1 to the CS
// or CA fields or the Run/Stop bit is clear.
#define FTUSB_CRCR_CRR_BIT             3
#define FTUSB_CRCR_CRR_LEN             1
#define FTUSB_CRCR_CRR_MASK            0x00000008
// Field       : CRPTR
// Access      : RW
// Command Ring Pointer. Upper 26 bits of the base address of the command
// ring in host memory. Writing to this field is ignored when CRR is 1.
#define FTUSB_CRCR_CRPTR_BIT           6
#define FTUSB_CRCR_CRPTR_LEN           26
#define FTUSB_CRCR_CRPTR_MASK          0xffffffc0
// ----------------------------------------------------------------------
// Register    : Device Context Base Array Pointer Register
// This register is part of the Host Controller Operational Register set.
#define FTUSB_DCBAAPL_ADDR             0x10300050
// Field       : PTR
// Access      : RW
// Device Context Base Address Array Pointer. This field defines bits
// 31:6 of the base address of Device Context Pointer Array. A table of
// address pointers refers to Device Context structures for the devices
// attached to the host.
#define FTUSB_DCBAAPL_PTR_BIT          6
#define FTUSB_DCBAAPL_PTR_LEN          26
#define FTUSB_DCBAAPL_PTR_MASK         0xffffffc0
// ----------------------------------------------------------------------
// Register    : Device Context Base Array Pointer Register
// This register is part of the Host Controller Operational Register set.
#define FTUSB_DCBAAPU_ADDR             0x10300054
// Field       : PTR
// Access      : RW
// Device Context Base Address Array Pointer. Upper 32 bits of 64 bit
// address.
#define FTUSB_DCBAAPU_PTR_BIT          0
#define FTUSB_DCBAAPU_PTR_LEN          32
#define FTUSB_DCBAAPU_PTR_MASK         0xffffffff
// ----------------------------------------------------------------------
// Register    : Configure Register
// This register is part of the Host Controller Operational Register set.
#define FTUSB_CONFIG_ADDR              0x10300058
// Field       : MAXSLOTSEN
// Access      : RW
// Max Device Slots Enabled. This field specifies the maximum enabled
// device slots. Valid values are in a range from 0 to MaxSlots. Enabled
// devices slots are contiguously allocated. A value of 16 specifies that
// device slots 1 to 16 are active. A value of 0 disables all device
// slots. A disabled device slot shall not respond to Doorbell Register.
// This field shall not be modified by software if XHCI is running
// (Run/Stop(R/S) = 1).
#define FTUSB_CONFIG_MAXSLOTSEN_BIT    0
#define FTUSB_CONFIG_MAXSLOTSEN_LEN    8
#define FTUSB_CONFIG_MAXSLOTSEN_MASK   0x000000ff
// ----------------------------------------------------------------------
// Register    : Port Status and Control Register 0
// This register is part of the Host Controller Operational Register set.
// There is one PORTSC register for every port attached to the root hub.
// The addresses are determined as 0x420 + (0x10 * (n-1) where n is the
// Root Hub Port Index.
#define FTUSB_PORTSC0_ADDR             0x10300420
// Field       : CCS
// Access      : RO
// Current Connect Status. This value reflects the current state of the
// port, and may not directly correspond to the event that caused the
// Connect Status Change (CSC) bit to be set to 1. 1 = Device is
// presented on port. 0 = Device is not presented on port.
#define FTUSB_PORTSC0_CCS_BIT          0
#define FTUSB_PORTSC0_CCS_LEN          1
#define FTUSB_PORTSC0_CCS_MASK         0x00000001
// Field       : PED
// Access      : W1C
// Port Enabled/Disabled 1 = Enable 0 = Disable Ports may only be enabled
// by XHC. Software cannot enable a port by writing 1 to this flag. A
// port may be disabled when software writes 1 to this flag. This flag
// shall be automatically cleared to 0 by a disconnect event or other
// fault conditions. PED shall be automatically cleared to 0 when PR is
// set to 1, and set to 1 when PR transitions from 1 to 0 after a
// successful reset. This flag is 0 if PP is 0. The port may only be
// enabled (Set PED to 1) by XHC as the following conditions: For USB2
// protocol ports: When the port is at the Disabled state, software shall
// reset the port (PR = 1) to transition PED to 1 and the port to the
// Enabled state. For USB3 protocol ports: When the port is at the
// Polling state (After detecting an device attach), the port shall
// automatically transition to the Enabled state to set PED to 1 when
// completing successful link training. Note: When software writes this
// bit to 1, it shall also write 0 to the PR bit.
#define FTUSB_PORTSC0_PED_BIT          1
#define FTUSB_PORTSC0_PED_LEN          1
#define FTUSB_PORTSC0_PED_MASK         0x00000002
// Field       : OCA
// Access      : RO
// Over-current Active. Set when the port detects an over current
// condition.
#define FTUSB_PORTSC0_OCA_BIT          3
#define FTUSB_PORTSC0_OCA_LEN          1
#define FTUSB_PORTSC0_OCA_MASK         0x00000008
// Field       : PR
// Access      : W1S
// Port Reset. When software writes 1 to this bit (from 0) the bus reset
// sequence is initiated. This flag is 0 if PP is 0.
#define FTUSB_PORTSC0_PR_BIT           4
#define FTUSB_PORTSC0_PR_LEN           1
#define FTUSB_PORTSC0_PR_MASK          0x00000010
// Field       : PLS
// Access      : RW
// Port Link State. This field is used for power management of the port
// and reflects the current link state. When the port is in the Enabled
// state, system software may set the port to the link U state by writing
// to this field. System software may also write this field to force a
// Disabled to Disconnected state transition of the port. The Port Link
// State Write Strobe (LWS) is also set by a write to this field. 0: The
// link shall transition to the U0 state from the U state. 2: USB2
// protocol ports only. The link should transition to the U2 state. 3:
// The link shall transition to the U3 state from the U state. This
// action selectively suspends the device connected to this port. 5: USB3
// protocol ports only. If the port is at the Disabled state (PLS =
// Disabled, PP = 1), the link shall transition to the RxDetect state and
// the port shall transition to the Disconnected state. 15: USB2 protocol
// ports only. If the port is at the U3 state (PLS = U3), the link shall
// remain at the U3 state and the port shall transition to the U3 Exit
// state. For USB2 protocol ports: Writing a value of 2 to this field
// requests LPM by asserting L1 signaling on the USB2 bus. Software may
// read this field to determine if the transition successfully enters the
// U2 state. Writing 0 shall de-assert L1 signaling on the USB2 bus.
// Writing 1 shall have no effect. The U1 state shall never be reported
// by a USB2 protocol port. When reading this field the value has the
// following meaning: 0: Link is in the U0 State 1: Link is in the U1
// State 2: Link is in the U2 State 3: Link is in the U3 State 4: Link is
// in the Disable State 5: Link is in the RxDetect State 6: Link is in
// the Inactive State 7: Link is in the Polling State 8: Link is in the
// Recovery State 9: Link is in the Hot Reset State 10: Link is in the
// Compliance Mode State 11: Link is in the Test Mode State 15: Link is
// in the Resume State This field is undefined if PP =0.
#define FTUSB_PORTSC0_PLS_BIT          5
#define FTUSB_PORTSC0_PLS_LEN          4
#define FTUSB_PORTSC0_PLS_MASK         0x000001e0
// Field       : PP
// Access      : RW
// Port Power. This flag reflects a port logical and power control state.
// Because the host controllers can implement different methods for port
// power switching, this flag may or may not represent whether (VBUS)
// power is actually applied to the port. When PP equals 0, the port will
// be non-functional and shall not report attaches, detaches, or Port
// Link State (PLS) changes. However, the port shall report over-current
// conditions when PP = 0 if PPC = 0. After modifying PP, software shall
// read PP and confirm that it is not followed. 0 = This port is at the
// power-off state. 1 = This port is not at the power-off state. If the
// Port Power Control (PPC) flag in the HCCPARAMS register is 1, XHCI has
// port power switching and this bit represents the current setting of
// the switch (0 = Off, 1 = On). When an over-current condition is
// detected on a powered port, XHC shall transition the PP bit in each
// affected port from 1 to 0.
#define FTUSB_PORTSC0_PP_BIT           9
#define FTUSB_PORTSC0_PP_LEN           1
#define FTUSB_PORTSC0_PP_MASK          0x00000200
// Field       : PS
// Access      : RO
// Port Speed. This field identifies the speed of the attached USB
// device. This field is only relevant if a device is attached (CCS = 1).
// In all other cases, this field shall indicate undefined speed. This
// field is invalid on a USB2 protocol port until after the port is
// reset. 0: Undefined 1: Full-speed 2: Low-speed 3: High-speed 4: Super-
// speed
#define FTUSB_PORTSC0_PS_BIT           10
#define FTUSB_PORTSC0_PS_LEN           4
#define FTUSB_PORTSC0_PS_MASK          0x00003c00
// Field       : PIC
// Access      : RW
// Port Indicator Control. This field is 0 if PP is 0. Writing to these
// bits has no effect if the Port Indicators (PIND) bit in the HCCPARAMS
// register is 0. If PIND bit is 1, the bit encodings are: 0: Port
// indicators are off 1: Amber 2: Green
#define FTUSB_PORTSC0_PIC_BIT          14
#define FTUSB_PORTSC0_PIC_LEN          2
#define FTUSB_PORTSC0_PIC_MASK         0x0000c000
// Field       : LWS
// Access      : RW
// Port Link State Write Strobe. When this bit is set to 1 on a write
// reference to this register, this flag enables writes to the PLS field.
// When 0, write data in the PLS field is ignored. Reading to this bit
// returns to 0.
#define FTUSB_PORTSC0_LWS_BIT          16
#define FTUSB_PORTSC0_LWS_LEN          1
#define FTUSB_PORTSC0_LWS_MASK         0x00010000
// Field       : CSC
// Access      : W1C
// Connect Status Change. This flag indicates a change has occurred in
// Current Connect Status (CCS) of a port. 1 = Change in CCS. 0 = No
// change. XHC sets this bit to 1 for all changes to the port device
// connect status, even if system software has not cleared an existing
// Connect Status Change. Software clears this bit by writing 1 to it.
// Note: This flag shall not be set if the CCS transition was due to
// software setting PP to 0.
#define FTUSB_PORTSC0_CSC_BIT          17
#define FTUSB_PORTSC0_CSC_LEN          1
#define FTUSB_PORTSC0_CSC_MASK         0x00020000
// Field       : PEC
// Access      : W1C
// Port Enabled/Disabled Change. For a USB2 protocol port, this bit shall
// be set to 1 only when the port is disabled due to the appropriate
// conditions existing at the EOF2 point. For a USB3 protocol port, this
// bit is always 0. Software clears this bit by writing 1 to it. Note:
// This flag shall not be set if the PED transition was due to software
// setting PP to 0.
#define FTUSB_PORTSC0_PEC_BIT          18
#define FTUSB_PORTSC0_PEC_LEN          1
#define FTUSB_PORTSC0_PEC_MASK         0x00040000
// Field       : WRC
// Access      : W1C
// Warm Port Reset Change This bit is set when Warm Reset processing on
// this port completes. 0 = No change. 1 = Warm Reset complete. Software
// clears this bit by writing 1 to it. Notes: 1. This flag shall not be
// set to 1 if the Warm Reset process was forced to termination due to
// software clearing PP or PED to 0. 2. This flag is valid only for USB3
// protocol ports. For USB2 protocol ports, this bit is be Reserved.
#define FTUSB_PORTSC0_WRC_BIT          19
#define FTUSB_PORTSC0_WRC_LEN          1
#define FTUSB_PORTSC0_WRC_MASK         0x00080000
// Field       : OCC
// Access      : W1C
// Over-current Change. This bit shall be set to 1 when 1-to-0 or from
// 0-to-1 transition of Over-Current Active (OCA) occurs. Software clears
// this bit by writing 1 to it.
#define FTUSB_PORTSC0_OCC_BIT          20
#define FTUSB_PORTSC0_OCC_LEN          1
#define FTUSB_PORTSC0_OCC_MASK         0x00100000
// Field       : PRC
// Access      : W1C
// Port Reset Change. This flag is set to 1 during a 1-to-0 transition of
// Port Reset (PR) when any processing reset (Warm or Hot) on this port
// completes. Note: This flag shall not be set to 1 when the reset
// process was forced to termination caused by software of clearing PP or
// PED to 0. Software clears this bit by writing a 1 to it.
#define FTUSB_PORTSC0_PRC_BIT          21
#define FTUSB_PORTSC0_PRC_LEN          1
#define FTUSB_PORTSC0_PRC_MASK         0x00200000
// Field       : PLC
// Access      : W1C
// Port Link State Change. Set to 1 when the following state transitions
// occur. U3 > Resume Wakeup signaling from a device. Resume > Recovery >
// U0 Software Resume complete (USB3 only). U3 -> U0 Software Resume
// complete (USB2 only). U2 -> U0 L1 Resume complete (USB2 only). U0 ->
// U0 L1 Entry Reject (USB2 only). Any state -> Inactive Error (USB3
// only).
#define FTUSB_PORTSC0_PLC_BIT          22
#define FTUSB_PORTSC0_PLC_LEN          1
#define FTUSB_PORTSC0_PLC_MASK         0x00400000
// Field       : CEC
// Access      : W1C
// Port Config Error Change. This flag indicates that the port failed to
// configure the link partner. 1 = Port Config Error detected. Software
// clears this bit by writing 1 to it. Note: This flag is valid only for
// USB3 protocol ports. For USB2 protocol ports, this bit is Reserved.
#define FTUSB_PORTSC0_CEC_BIT          23
#define FTUSB_PORTSC0_CEC_LEN          1
#define FTUSB_PORTSC0_CEC_MASK         0x00800000
// Field       : CAS
// Access      : RO
// Cold Attach Status. = Far-end receiver terminations were detected at
// the disconnected state and the root hub port state machine was unable
// advance to the Enable state. The design does not support this feature.
#define FTUSB_PORTSC0_CAS_BIT          24
#define FTUSB_PORTSC0_CAS_LEN          1
#define FTUSB_PORTSC0_CAS_MASK         0x01000000
// Field       : WCE
// Access      : RW
// Wake on Connect Enable. The design does not support this feature.
#define FTUSB_PORTSC0_WCE_BIT          25
#define FTUSB_PORTSC0_WCE_LEN          1
#define FTUSB_PORTSC0_WCE_MASK         0x02000000
// Field       : WDE
// Access      : RW
// Wake on Disconnect Enable. The design does not support this feature.
#define FTUSB_PORTSC0_WDE_BIT          26
#define FTUSB_PORTSC0_WDE_LEN          1
#define FTUSB_PORTSC0_WDE_MASK         0x04000000
// Field       : WOE
// Access      : RW
// Wake on Over-current Enable. The design does nto support this feature.
#define FTUSB_PORTSC0_WOE_BIT          27
#define FTUSB_PORTSC0_WOE_LEN          1
#define FTUSB_PORTSC0_WOE_MASK         0x08000000
// Field       : DR
// Access      : RW
// Device Removable. This flag indicates that this port has an attached
// removable device. 1 = Device is non-removable. 0 = Device is
// removable.
#define FTUSB_PORTSC0_DR_BIT           30
#define FTUSB_PORTSC0_DR_LEN           1
#define FTUSB_PORTSC0_DR_MASK          0x40000000
// Field       : WPR
// Access      : W1S
// Warm Port Reset. When software writes 1 to this bit, the Warm Reset
// sequence will be initiated and the PR flag will be set to 1. Once
// initiated, the PR, PRC, and WRC flags shall reflect the progress of
// the Warm Reset sequence. This flag shall always return to 0 when read.
// This flag only applies to USB3 protocol ports. For USB2 protocol
// ports, it shall be Reserved.
#define FTUSB_PORTSC0_WPR_BIT          31
#define FTUSB_PORTSC0_WPR_LEN          1
#define FTUSB_PORTSC0_WPR_MASK         0x80000000
// ----------------------------------------------------------------------
// Register    : Port PM Status and Control Register
// This register is part of the Host Controller Operational Register set.
// There is one PORTPMSC register for every port attached to the root
// hub. The addresses are determined as 0x424 + (0x10 * (n-1) where n is
// the Root Hub Port Index. This is the register description when the
// port is operating in USB3 mode.
#define FTUSB_PORTPMSC_ADDR            0x10300424
// Field       : U1T
// Access      : RW
// U1 Timeout. When the link has been active this amount of time the port
// will enter the U1 state. 0: Port will immediately enter U1 after
// inactivity detected. 1-254: n * 1us, 255: Inifinite timeout period.
// The port will not enter U1 unless SW directs it.
#define FTUSB_PORTPMSC_U1T_BIT         0
#define FTUSB_PORTPMSC_U1T_LEN         8
#define FTUSB_PORTPMSC_U1T_MASK        0x000000ff
// Field       : U2T
// Access      : RW
// U2 Timeout. When the link has been active this amount of time the port
// will enter the U2 state. 0: Port will immediately enter U2 after
// inactivity detected. 1-127: n * 256us, 255: Inifinite timeout period.
// The port will not enter U2 unless SW directs it.
#define FTUSB_PORTPMSC_U2T_BIT         8
#define FTUSB_PORTPMSC_U2T_LEN         8
#define FTUSB_PORTPMSC_U2T_MASK        0x0000ff00
// Field       : FLA
// Access      : RW
// Force Link PM Accept When this bit is set to 1, the port shall
// generate a Set Link Function LMP with the asserted Force_LinkPM_Accept
// bit. This flag shall be set to 0 by the asserting PR to 1 or when CCS
// = transitions from 0 to 1. Writing to this flag have no effect if PP =
// 0. The Set Link Function LMP is sent by XHC to the device connected on
// this port when this bit transitions from 0 to 1. Improper use of the
// SS Force_LinkPM_Accept function can impact the performance of the link
// significantly. This bit shall only be used for compliance and testing
// purposes. Software shall ensure that there are no pending packets at
// the link level before setting this bit. This flag is 0 if PP is 0.
#define FTUSB_PORTPMSC_FLA_BIT         16
#define FTUSB_PORTPMSC_FLA_LEN         1
#define FTUSB_PORTPMSC_FLA_MASK        0x00010000
// ----------------------------------------------------------------------
// Register    : Port Link Info Register
// This register is part of the Host Controller Operational Register set.
// There is one PORTLI register for every port attached to the root hub.
// The addresses are determined as 0x428 + (0x10 * (n-1) where n is the
// Root Hub Port Index. This is the register description when the port is
// operating in USB3 mode.
#define FTUSB_PORTLI_ADDR              0x10300428
// Field       : LEC
// Access      : RO
// Link Error Count.
#define FTUSB_PORTLI_LEC_BIT           0
#define FTUSB_PORTLI_LEC_LEN           16
#define FTUSB_PORTLI_LEC_MASK          0x0000ffff
// ----------------------------------------------------------------------
// Register    : XHCI Supported U3 Protocol Capability Register 1
// This register is part of the XHCI Extended Cability Register set.
#define FTUSB_U3SPC1_ADDR              0x10300500
// Field       : CID
// Access      : RO
// Capability ID.
#define FTUSB_U3SPC1_CID_BIT           0
#define FTUSB_U3SPC1_CID_LEN           8
#define FTUSB_U3SPC1_CID_MASK          0x000000ff
// Field       : PTR
// Access      : RO
// Next Capability Pointer.
#define FTUSB_U3SPC1_PTR_BIT           8
#define FTUSB_U3SPC1_PTR_LEN           8
#define FTUSB_U3SPC1_PTR_MASK          0x0000ff00
// Field       : MINOR_VER
// Access      : RO
// Minor version number
#define FTUSB_U3SPC1_MINOR_VER_BIT     16
#define FTUSB_U3SPC1_MINOR_VER_LEN     8
#define FTUSB_U3SPC1_MINOR_VER_MASK    0x00ff0000
// Field       : MAJOR_VER
// Access      : RO
// Major version number
#define FTUSB_U3SPC1_MAJOR_VER_BIT     24
#define FTUSB_U3SPC1_MAJOR_VER_LEN     8
#define FTUSB_U3SPC1_MAJOR_VER_MASK    0xff000000
// ----------------------------------------------------------------------
// Register    : XHCI Supported U2 Protocol Capability Register 2
// This register is part of the XHCI Extended Cability Register set.
#define FTUSB_U3SPC2_ADDR              0x10300504
// Field       : NAME
// Access      : RO
// This field is a mnemonic name string that references the specification
// with which XHCI is compliant.
#define FTUSB_U3SPC2_NAME_BIT          0
#define FTUSB_U3SPC2_NAME_LEN          32
#define FTUSB_U3SPC2_NAME_MASK         0xffffffff
// ----------------------------------------------------------------------
// Register    : XHCI Supported U2 Protocol Capability Register 3
// This register is part of the XHCI Extended Cability Register set.
#define FTUSB_U3SPC3_ADDR              0x10300508
// Field       : CPORTOFF
// Access      : RO
// Compatible Port Offset. This field specifies the starting number of
// root hub ports that support this protocol. Valid value is ranging from
// 1 to MaxPorts.
#define FTUSB_U3SPC3_CPORTOFF_BIT      0
#define FTUSB_U3SPC3_CPORTOFF_LEN      8
#define FTUSB_U3SPC3_CPORTOFF_MASK     0x000000ff
// Field       : CPORTCNT
// Access      : RO
// Compatible Port Count. This field identifies the number of consecutive
// root hub ports (Starting at the Compatible Port Offset) that support
// this protocol. Valid value is ranging from 1 to MaxPorts.
#define FTUSB_U3SPC3_CPORTCNT_BIT      8
#define FTUSB_U3SPC3_CPORTCNT_LEN      8
#define FTUSB_U3SPC3_CPORTCNT_MASK     0x0000ff00
// Field       : PROTOCOL
// Access      : RO
// Protocol Defined. Reserved field.
#define FTUSB_U3SPC3_PROTOCOL_BIT      16
#define FTUSB_U3SPC3_PROTOCOL_LEN      8
#define FTUSB_U3SPC3_PROTOCOL_MASK     0x00ff0000
// Field       : PSIC
// Access      : RO
// Protocol Speed ID Count. This field indicates the number of Protocol
// Speed ID (PSI) Dwords that the XHCI supported Protocol Capability data
// structure contains. This field is set to 0 only when the default
// SuperSpeed bit rate is supported.
#define FTUSB_U3SPC3_PSIC_BIT          24
#define FTUSB_U3SPC3_PSIC_LEN          8
#define FTUSB_U3SPC3_PSIC_MASK         0xff000000
// ----------------------------------------------------------------------
// Register    : XHCI Supported U3 Protocol Capability Register 4
// This register is part of the XHCI Extended Cability Register set.
#define FTUSB_U3SPC4_ADDR              0x1030050c
// Field       : RESERVED
// Access      : RO
// This field is reserved.
#define FTUSB_U3SPC4_RESERVED_BIT      0
#define FTUSB_U3SPC4_RESERVED_LEN      32
#define FTUSB_U3SPC4_RESERVED_MASK     0xffffffff
// ----------------------------------------------------------------------
// Register    : XHCI Supported U2 Protocol Capability Register 1
// This register is part of the XHCI Extended Cability Register set.
#define FTUSB_U2SPC1_ADDR              0x10300510
// Field       : CID
// Access      : RO
// Capability ID.
#define FTUSB_U2SPC1_CID_BIT           0
#define FTUSB_U2SPC1_CID_LEN           8
#define FTUSB_U2SPC1_CID_MASK          0x000000ff
// Field       : PTR
// Access      : RO
// Next Capability Pointer.
#define FTUSB_U2SPC1_PTR_BIT           8
#define FTUSB_U2SPC1_PTR_LEN           8
#define FTUSB_U2SPC1_PTR_MASK          0x0000ff00
// Field       : MINOR_VER
// Access      : RO
// Minor version number
#define FTUSB_U2SPC1_MINOR_VER_BIT     16
#define FTUSB_U2SPC1_MINOR_VER_LEN     8
#define FTUSB_U2SPC1_MINOR_VER_MASK    0x00ff0000
// Field       : MAJOR_VER
// Access      : RO
// Major version number
#define FTUSB_U2SPC1_MAJOR_VER_BIT     24
#define FTUSB_U2SPC1_MAJOR_VER_LEN     8
#define FTUSB_U2SPC1_MAJOR_VER_MASK    0xff000000
// ----------------------------------------------------------------------
// Register    : XHCI Supported U2 Protocol Capability Register 2
// This register is part of the XHCI Extended Cability Register set.
#define FTUSB_U2SPC2_ADDR              0x10300514
// Field       : NAME
// Access      : RO
// This field is a mnemonic name string that references the specification
// with which XHCI is compliant.
#define FTUSB_U2SPC2_NAME_BIT          0
#define FTUSB_U2SPC2_NAME_LEN          32
#define FTUSB_U2SPC2_NAME_MASK         0xffffffff
// ----------------------------------------------------------------------
// Register    : XHCI Supported U2 Protocol Capability Register 3
// This register is part of the XHCI Extended Cability Register set.
#define FTUSB_U2SPC3_ADDR              0x10300518
// Field       : CPORTOFF
// Access      : RO
// Compatible Port Offset. This field specifies the starting number of
// root hub ports that support this protocol. Valid value is ranging from
// 1 to MaxPorts.
#define FTUSB_U2SPC3_CPORTOFF_BIT      0
#define FTUSB_U2SPC3_CPORTOFF_LEN      8
#define FTUSB_U2SPC3_CPORTOFF_MASK     0x000000ff
// Field       : CPORTCNT
// Access      : RO
// Compatible Port Count. This field identifies the number of consecutive
// root hub ports (Starting at the Compatible Port Offset) that support
// this protocol. Valid value is ranging from 1 to MaxPorts.
#define FTUSB_U2SPC3_CPORTCNT_BIT      8
#define FTUSB_U2SPC3_CPORTCNT_LEN      8
#define FTUSB_U2SPC3_CPORTCNT_MASK     0x0000ff00
// Field       : HSO
// Access      : RO
// This field only applies to the USB2 protocol. If this bit is set to 0,
// the USB2 ports described by this capability are Low-Speed, Full-Speed,
// and High-Speed capable. If this bit is set to 1, the USB2 ports
// described by this capability are High-Speed capable.
#define FTUSB_U2SPC3_HSO_BIT           17
#define FTUSB_U2SPC3_HSO_LEN           1
#define FTUSB_U2SPC3_HSO_MASK          0x00020000
// Field       : IHI
// Access      : RO
// Integrated Hub. If this bit is set, this IP supports integrated hub
// between root hub and external XHCI port for USB2 protocol.
#define FTUSB_U2SPC3_IHI_BIT           18
#define FTUSB_U2SPC3_IHI_LEN           1
#define FTUSB_U2SPC3_IHI_MASK          0x00040000
// Field       : HLC
// Access      : RO
// If this bit set, the ports described by the XHCI supported Protocol
// Capability support hardware controlled USB2 Link Power Management.
#define FTUSB_U2SPC3_HLC_BIT           19
#define FTUSB_U2SPC3_HLC_LEN           1
