#define FTUSB_IMAN_IE_BIT              1
#define FTUSB_IMAN_IE_LEN              1
#define FTUSB_IMAN_IE_MASK             0x00000002
// ----------------------------------------------------------------------
// Register    : Interrupt Moderation Register
