// not empty, IE and IP flags = 1, and EHB = 0.
#define FTUSB_IMOD_IMODC_BIT           16
#define FTUSB_IMOD_IMODC_LEN           1
#define FTUSB_IMOD_IMODC_MASK          0x00010000
