// Register    : Event Ring Segment Table Base Address Register
// This register is part of the XHCI Runtime Registers set.
#define FTUSB_ERSTBAL_ADDR             0x10300630
// Field       : BASE
// Access      : RW
// Event Ring Segment Table Base Address. This field defines bits 31:6 of
// the start address of Event Ring Segment Table. Writing this register
// sets the Event Ring State Machine: EREP Advancement to the Start
// state. This field should not be modified if HCHalted (HCH) = 0.
#define FTUSB_ERSTBAL_BASE_BIT         6
#define FTUSB_ERSTBAL_BASE_LEN         26
#define FTUSB_ERSTBAL_BASE_MASK        0xffffffc0
// ----------------------------------------------------------------------
// Register    : Event Ring Segment Table Base Address Register
// This register is part of the XHCI Runtime Registers set.
#define FTUSB_ERSTBAU_ADDR             0x10300634
// Field       : BASE
// Access      : RW
// Event Ring Segment Table Base Address. Upper 32 bits of 64 bit
// address.
#define FTUSB_ERSTBAU_BASE_BIT         0
#define FTUSB_ERSTBAU_BASE_LEN         31
#define FTUSB_ERSTBAU_BASE_MASK        0x7fffffff
// ----------------------------------------------------------------------
// Register    : Event Ring Dequeue Pointer Register
// This register is part of the XHCI Runtime Registers set.
#define FTUSB_ERDPL_ADDR               0x10300638
