#define FTUSB_ERDPL_ERDP_BIT           4
#define FTUSB_ERDPL_ERDP_LEN           28
#define FTUSB_ERDPL_ERDP_MASK          0xfffffff0
// ----------------------------------------------------------------------
// Register    : Event Ring Dequeue Pointer Register
// This register is part of the XHCI Runtime Registers set.
#define FTUSB_ERDPU_ADDR               0x1030063c
// Field       : ERDP
// Access      : RW
// Event Ring Dequeue Pointer. Upper 32 bits of 64 bit address.
#define FTUSB_ERDPU_ERDP_BIT           0
#define FTUSB_ERDPU_ERDP_LEN           32
#define FTUSB_ERDPU_ERDP_MASK          0xffffffff
