// Register    : Doorbell Register
// This register is part of the XHCI Runtime Registers set. There is one
// DB register for every port attached to the root hub. The addresses are
// determined as 0x800 + (4 * (DBINDEX-1).
#define FTUSB_DB_ADDR                  0x10300800
// Field       : TARGET
// Access      : RW
// DB Target. This field defines the target of the doorbell reference.
// The table below defines the XHCI notification that is generated by
// ringing the doorbell. Please note that Doorbell Register 0 is
// dedicated to Command Ring and decodes this field differently than
// other Doorbell registers. 0: Reserved, 1: Control EP0 Enqueue Pointer
// Update, 2: EP1 OUT Enqueue Pointer Update, 3: EP1 IN Enqueue Pointer
// Update, 4: EP2 OUT Enqueue Pointer Update, EP2 IN Enqueue Pointer
// Update ... 30: EP15 OUT Enqueue Pointer Update, 31: EP15 IN Enqueue
// Pointer Update, 32-247: Reserved, 248-255: Vendor Defined.   Host
// Controller Doorbell (0) is encoded as 0: HC Command, 1;247: Reserved,
// 248-255: Vendor Defined. This field returns to 0 when read and should
// be treated as undefined by software.
#define FTUSB_DB_TARGET_BIT            0
#define FTUSB_DB_TARGET_LEN            8
#define FTUSB_DB_TARGET_MASK           0x000000ff
