// ignored. This field only applies to Device Context Doorbells and shall
// be cleared to 0 for the host controller commands.
#define FTUSB_DB_STREAMID_BIT          16
#define FTUSB_DB_STREAMID_LEN          16
#define FTUSB_DB_STREAMID_MASK         0xffff0000
