#define FTUSB_FSEOFOFF_RSV_BYTECNT_BIT 0
#define FTUSB_FSEOFOFF_RSV_BYTECNT_LEN 8
#define FTUSB_FSEOFOFF_RSV_BYTECNT_MASK 0x000000ff
// Field       : EOF1_OFF
// Access      : RW
// End of Frame (EOF) 1 offset. This register is used to configure the
