#define FTUSB_CICOMSET_AWPROT_BIT      10
#define FTUSB_CICOMSET_AWPROT_LEN      3
#define FTUSB_CICOMSET_AWPROT_MASK     0x00001c00
// Field       : AWCACHE
// Access      : RW
// AXI transaction cache setting for writes
#define FTUSB_CICOMSET_AWCACHE_BIT     13
#define FTUSB_CICOMSET_AWCACHE_LEN     4
#define FTUSB_CICOMSET_AWCACHE_MASK    0x0001e000
// Field       : AWLOCK
// Access      : RW
// AXI transaction lock setting for writes
#define FTUSB_CICOMSET_AWLOCK_BIT      17
#define FTUSB_CICOMSET_AWLOCK_LEN      2
#define FTUSB_CICOMSET_AWLOCK_MASK     0x00060000
