#define FTUSB_APBWOH1_AP_HS_BW_OH_BIT  0
#define FTUSB_APBWOH1_AP_HS_BW_OH_LEN  13
#define FTUSB_APBWOH1_AP_HS_BW_OH_MASK 0x00001fff
// Field       : AP_SS_BW_OH
// Access      : RW
