// Field       : AP_LS_BW_OH
// Access      : RW
// AP Low-Speed Bandwidth Overhead. Bytes/Uframe is up to 8'h15.
#define FTUSB_APBWOH2_AP_LS_BW_OH_BIT  0
#define FTUSB_APBWOH2_AP_LS_BW_OH_LEN  8
#define FTUSB_APBWOH2_AP_LS_BW_OH_MASK 0x000000ff
// Field       : AP_FS_BW_OH
// Access      : RW
