#define FTUSB_APBWOH2_AP_FS_BW_OH_BIT  16
#define FTUSB_APBWOH2_AP_FS_BW_OH_LEN  11
#define FTUSB_APBWOH2_AP_FS_BW_OH_MASK 0x07ff0000
// Field       : SS_BW_INTR_CNSRV
// Access      : RW
