#define FTUSB_APBWOH2_SS_BW_INTR_CNSRV_BIT 27
#define FTUSB_APBWOH2_SS_BW_INTR_CNSRV_LEN 4
#define FTUSB_APBWOH2_SS_BW_INTR_CNSRV_MASK 0x78000000
