#define FTUSB_TPBAL_ADDR_BIT           2
#define FTUSB_TPBAL_ADDR_LEN           30
#define FTUSB_TPBAL_ADDR_MASK          0xfffffffc
// ----------------------------------------------------------------------
// Register    : Test Packet Base Address Register
// This register is part of the XHCI Special Purpose Registers set.
#define FTUSB_TPBAU_ADDR               0x10300e4c
// Field       : ADDR
// Access      : RW
// USB2 Test Packet Base Address. Upper 32 bits of 64 bit address.
#define FTUSB_TPBAU_ADDR_BIT           0
#define FTUSB_TPBAU_ADDR_LEN           32
#define FTUSB_TPBAU_ADDR_MASK          0xffffffff
// ----------------------------------------------------------------------
// Register    : Host USB3 Transaction Timeout Register
// This register is part of the XHCI Special Purpose Registers set.
#define FTUSB_HOSTTO_ADDR              0x10300e50
// Field       : TO
// Access      : RW
// Host USB3 Transaction timeout. Valid value is in a range between 1 and
