#define FTUSB_HOSTTO_TO_BIT            0
#define FTUSB_HOSTTO_TO_LEN            10
#define FTUSB_HOSTTO_TO_MASK           0x000003ff
// ----------------------------------------------------------------------
// Register    : USB3 Protocol Layer Control Register
