// controller. Software should not set this field when the Run/Stop bit
// in the USBCMD register is 1.
#define FTUSB_U3PLCNTRL_ISO_BURST_MODE_BIT 0
#define FTUSB_U3PLCNTRL_ISO_BURST_MODE_LEN 2
#define FTUSB_U3PLCNTRL_ISO_BURST_MODE_MASK 0x00000003
// Field       : BURST_EQ1
// Access      : RW
// None
#define FTUSB_U3PLCNTRL_BURST_EQ1_BIT  2
#define FTUSB_U3PLCNTRL_BURST_EQ1_LEN  1
#define FTUSB_U3PLCNTRL_BURST_EQ1_MASK 0x00000004
