#define FTUSB_U3PLCNTRL_IGNORE_CERR_LEN 1
#define FTUSB_U3PLCNTRL_IGNORE_CERR_MASK 0x00000008
// Field       : IGNORE_TO
// Access      : RW
// Do not assert so_done when a transaction timeout occurs.
#define FTUSB_U3PLCNTRL_IGNORE_TO_BIT  4
#define FTUSB_U3PLCNTRL_IGNORE_TO_LEN  1
#define FTUSB_U3PLCNTRL_IGNORE_TO_MASK 0x00000010
// ----------------------------------------------------------------------
