// This register is part of the XHCI Special Purpose Registers set.
#define FTUSB_TSTMOD_ADDR              0x10300e60
// Field       : TM
// Access      : RW
// Enable host turbo mode for simulation.
#define FTUSB_TSTMOD_TM_BIT            0
#define FTUSB_TSTMOD_TM_LEN            1
#define FTUSB_TSTMOD_TM_MASK           0x00000001
// ----------------------------------------------------------------------
// Register    : Over Current Switch Register Register
// This register is part of the XHCI Special Purpose Registers set.
#define FTUSB_OCAN_ADDR                0x10300e64
// Field       : OCAN
// Access      : RW
// Overcurrent Switch. 0: OC input is active high. 1: OC input is active
// low.
#define FTUSB_OCAN_OCAN_BIT            0
#define FTUSB_OCAN_OCAN_LEN            1
#define FTUSB_OCAN_OCAN_MASK           0x00000001
// Field       : OCA_MASK_TIME
// Access      : RW
// Overcurrent mask time. A timer will active when PP = 1 and OCA is
// masked before the timer counts to OCA_MASK_TIME. The unit of this
// timer is 100 us. SW can program the mask time as 0 us, 100 us, 200 us,
// ..., or 1.5 ms. When this field is programed to 0, no OCA mask during
// PP = 1.
#define FTUSB_OCAN_OCA_MASK_TIME_BIT   1
#define FTUSB_OCAN_OCA_MASK_TIME_LEN   4
#define FTUSB_OCAN_OCA_MASK_TIME_MASK  0x0000001e
// ----------------------------------------------------------------------
// Register    : Frame Length Adjustment Register
// This register is part of the XHCI Special Purpose Registers set.
#define FTUSB_FLADJ_ADDR               0x10300e70
// Field       : FLADJ
// Access      : RW
// Frame Length Timing Value. Each decimal value changing to this
// register corresponds to 16 high-speed bit times. The SOF cycle time is
// equal to 59488 + value in this field. The default value is decimal 32
// (20h), which gives a SOF cycle time of 60000. Frame Length (# HS bit
// times) FLADJ Value (decimal) (Decimal) 59488 0 (00h) 59504 1 (01h) ...
// 59984 31 (1Fh) 60000 32 (20h) ... 60480 62 (3Eh)
#define FTUSB_FLADJ_FLADJ_BIT          0
#define FTUSB_FLADJ_FLADJ_LEN          6
#define FTUSB_FLADJ_FLADJ_MASK         0x0000003f
