// Register    : USB3 Host Main Control Register
// This register is part of the XHCI Special Purpose Registers set. There
// is one U3HOSTCNTRL register for every port attached to the root hub.
// The addresses are determined as 0x1100 + (0x20 * (n-1) where n is the
// Root Hub Port Index.
#define FTUSB_U3HOSTCNTRL_ADDR         0x10301100
// Field       : WRST_PHY_EN
// Access      : RW
// Warm Reset To Do PIPE Reset. 1: Controller issues PIPE reset at the
// warm reset state. 0: Controller does not issue PIPE reset at the warm
// reset state.
#define FTUSB_U3HOSTCNTRL_WRST_PHY_EN_BIT 0
#define FTUSB_U3HOSTCNTRL_WRST_PHY_EN_LEN 1
#define FTUSB_U3HOSTCNTRL_WRST_PHY_EN_MASK 0x00000001
// Field       : WAKEUP_RST_PHY_EN
// Access      : RW
// Wakeup for PIPE reset. 1: Controller issues PIPE reset during wakeup
// from the U3 state. 0: Controller does not issue PIPE reset during
// wakeup from the U3 state.
#define FTUSB_U3HOSTCNTRL_WAKEUP_RST_PHY_EN_BIT 1
#define FTUSB_U3HOSTCNTRL_WAKEUP_RST_PHY_EN_LEN 1
#define FTUSB_U3HOSTCNTRL_WAKEUP_RST_PHY_EN_MASK 0x00000002
// Field       : TXDEEMPH_LEVEL
// Access      : RW
// Txdeemph level. This field indicates the level of Txdeemph. 0b00:
// -6.0-dB de-emphasis. 0b01: -3.5-dB de-emphasis. 0b10: No de-emphasis.
// 0b11: Reserved.
#define FTUSB_U3HOSTCNTRL_TXDEEMPH_LEVEL_BIT 2
#define FTUSB_U3HOSTCNTRL_TXDEEMPH_LEVEL_LEN 2
#define FTUSB_U3HOSTCNTRL_TXDEEMPH_LEVEL_MASK 0x0000000c
// Field       : SS_TX_SWING
// Access      : RW
// Tx swing control bit. This bit directly controls the output pin,
// mac_phy_tx_swing.
#define FTUSB_U3HOSTCNTRL_SS_TX_SWING_BIT 4
#define FTUSB_U3HOSTCNTRL_SS_TX_SWING_LEN 1
#define FTUSB_U3HOSTCNTRL_SS_TX_SWING_MASK 0x00000010
// ----------------------------------------------------------------------
// Register    : USB3 Port Controller Internal Error Register
// This register is part of the XHCI Special Purpose Registers set. There
// is one U3PCINTERR register for every port attached to the root hub.
// The addresses are determined as 0x1104 + (0x20 * (n-1) where n is the
// Root Hub Port Index.
#define FTUSB_U3PCINTERR_ADDR          0x10301104
// Field       : ARFIFO_OVERFLOW
// Access      : W1C
// ARFIFO overflow. An overflow of the asynchronous device response FIFO
// has occurred.
#define FTUSB_U3PCINTERR_ARFIFO_OVERFLOW_BIT 0
#define FTUSB_U3PCINTERR_ARFIFO_OVERFLOW_LEN 1
#define FTUSB_U3PCINTERR_ARFIFO_OVERFLOW_MASK 0x00000001
// ----------------------------------------------------------------------
// Register    : OTG Control Status Register
// This register is part of the OTG Registers set.
#define FTUSB_OTGCTRLSTS_ADDR          0x10301800
// Field       : ID
// Access      : RO
// Current ID pin status.
#define FTUSB_OTGCTRLSTS_ID_BIT        0
#define FTUSB_OTGCTRLSTS_ID_LEN        1
#define FTUSB_OTGCTRLSTS_ID_MASK       0x00000001
// Field       : ROLE
// Access      : RO
// Current Role. 0: Host, 1: Device.
#define FTUSB_OTGCTRLSTS_ROLE_BIT      1
#define FTUSB_OTGCTRLSTS_ROLE_LEN      1
#define FTUSB_OTGCTRLSTS_ROLE_MASK     0x00000002
// Field       : IDPULUP
// Access      : RW
// ID Pullup Polarity.
#define FTUSB_OTGCTRLSTS_IDPULUP_BIT   2
#define FTUSB_OTGCTRLSTS_IDPULUP_LEN   1
#define FTUSB_OTGCTRLSTS_IDPULUP_MASK  0x00000004
// ----------------------------------------------------------------------
// Register    : OTG Interrupt Status Register
// This register is part of the OTG Registers set.
#define FTUSB_OTGINTRSTS_ADDR          0x10301804
// Field       : IDCHG
// Access      : W1C
// ID Change. This bit will be set to 1 when the current ID of FOTG330
// changes. Writing 1 clears this bit while writing 0 has no effect.
#define FTUSB_OTGINTRSTS_IDCHG_BIT     0
#define FTUSB_OTGINTRSTS_IDCHG_LEN     1
#define FTUSB_OTGINTRSTS_IDCHG_MASK    0x00000001
// Field       : ROLECHG
// Access      : W1C
// Role Change. This bit will be set to 1 when the current role of
// FOTG330 changes. Writing 1 clears this bit while writing 0 has no
// effect.
#define FTUSB_OTGINTRSTS_ROLECHG_BIT   1
#define FTUSB_OTGINTRSTS_ROLECHG_LEN   1
#define FTUSB_OTGINTRSTS_ROLECHG_MASK  0x00000002
// ----------------------------------------------------------------------
// Register    : OTG Interrupt Enable Register
// This register is part of the OTG Registers set.
#define FTUSB_OTGINTREN_ADDR           0x10301808
// Field       : IDCHG_EN
// Access      : RW
// ID Change Enable.
#define FTUSB_OTGINTREN_IDCHG_EN_BIT   0
#define FTUSB_OTGINTREN_IDCHG_EN_LEN   1
#define FTUSB_OTGINTREN_IDCHG_EN_MASK  0x00000001
// Field       : ROLECHG_EN
// Access      : RW
// Role Change Enable.
#define FTUSB_OTGINTREN_ROLECHG_EN_BIT 1
#define FTUSB_OTGINTREN_ROLECHG_EN_LEN 1
#define FTUSB_OTGINTREN_ROLECHG_EN_MASK 0x00000002
// ----------------------------------------------------------------------
// Register    : Global Interrupt Enable Register
// This register is part of the OTG Registers set.
#define FTUSB_GLBINTREN_ADDR           0x1030180c
// Field       : OTGINTR_EN
// Access      : RW
// OTG interrupt enable.
#define FTUSB_GLBINTREN_OTGINTR_EN_BIT 0
#define FTUSB_GLBINTREN_OTGINTR_EN_LEN 1
#define FTUSB_GLBINTREN_OTGINTR_EN_MASK 0x00000001
// Field       : HOSTINTR_EN
// Access      : RW
// Host interrupt enable.
#define FTUSB_GLBINTREN_HOSTINTR_EN_BIT 1
#define FTUSB_GLBINTREN_HOSTINTR_EN_LEN 1
#define FTUSB_GLBINTREN_HOSTINTR_EN_MASK 0x00000002
// Field       : DEVINTR_EN
// Access      : RW
// Device interrupt enable.
#define FTUSB_GLBINTREN_DEVINTR_EN_BIT 2
#define FTUSB_GLBINTREN_DEVINTR_EN_LEN 1
#define FTUSB_GLBINTREN_DEVINTR_EN_MASK 0x00000004
// ----------------------------------------------------------------------
// Register    : Device Interrupt Status Register
// This register is part of the OTG Registers set.
#define FTUSB_DEVINTRSTS_ADDR          0x10301810
// Field       : DEVINTR0
// Access      : RO
// Device group0 interrupt. This signal indicates the occurrence of the
// GROUP0 interrupts. SW should read the Interrupt Group 0 Register
// (0x400) to check the cause of the interrupt event.
#define FTUSB_DEVINTRSTS_DEVINTR0_BIT  0
#define FTUSB_DEVINTRSTS_DEVINTR0_LEN  1
#define FTUSB_DEVINTRSTS_DEVINTR0_MASK 0x00000001
// Field       : DEVINTR1
// Access      : RO
// Device group1 interrupt. This signal indicates the occurrence of the
// GROUP1 interrupts. SW should read the Interrupt Group 1 Register
// (0x404) to check the cause of the interrupt event.
#define FTUSB_DEVINTRSTS_DEVINTR1_BIT  1
#define FTUSB_DEVINTRSTS_DEVINTR1_LEN  1
#define FTUSB_DEVINTRSTS_DEVINTR1_MASK 0x00000002
// ----------------------------------------------------------------------
// Register    : Global Control Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_GCR_ADDR                 0x10302000
// Field       : DEV_MODE
// Access      : RO
// Device Speed Status. 0: No link, 1: Super Speed, 2: High Speed, 3:
// Full Speed.
#define FTUSB_GCR_DEV_MODE_BIT         0
#define FTUSB_GCR_DEV_MODE_LEN         2
#define FTUSB_GCR_DEV_MODE_MASK        0x00000003
// Field       : FIFO_CLR
// Access      : RW
// FIFO clear. Write 1 to clear all FIFOs, except CX FIFO. This signal
// will be cleared automatically by hardware after the read/write pointer
// resets to the initial value or when receiving the interrupt of Set
// Address request. Please note that the bit shall be set when SW
// receives the interrupt of Set Address request.
#define FTUSB_GCR_FIFO_CLR_BIT         3
#define FTUSB_GCR_FIFO_CLR_LEN         1
#define FTUSB_GCR_FIFO_CLR_MASK        0x00000008
// Field       : SYNC_FIFO0_CLR
// Access      : RW
// SYNC-FIFO0 clear (For debugging usage only). Write 1 to clear SYNC-
// FIFO0. This signal will be cleared automatically by hardware after the
// read/write pointer resets to the initial value.
#define FTUSB_GCR_SYNC_FIFO0_CLR_BIT   4
#define FTUSB_GCR_SYNC_FIFO0_CLR_LEN   1
#define FTUSB_GCR_SYNC_FIFO0_CLR_MASK  0x00000010
// Field       : SYNC_FIFO1_CLR
// Access      : RW
// SYNC-FIFO1 clear (For debugging usage only). Write 1 to clear SYNC-
// FIFO1. This signal will be cleared automatically by hardware after the
// read/write pointer resets to the initial value.
#define FTUSB_GCR_SYNC_FIFO1_CLR_BIT   5
#define FTUSB_GCR_SYNC_FIFO1_CLR_LEN   1
#define FTUSB_GCR_SYNC_FIFO1_CLR_MASK  0x00000020
// Field       : USB3_LPMEN
// Access      : RW
// Force USB 3.0 EN. If lp_clk of FOTG330 directly comes from the Faraday
// USB 3.0 PHY, SW must write this bit to 1 to force the output pin,
// u_lpmen, to high. USB 3.0 PHY must guarantee that lp_clk will be kept
// alive during the sleeping state in the SS mode.
#define FTUSB_GCR_USB3_LPMEN_BIT       6
#define FTUSB_GCR_USB3_LPMEN_LEN       1
#define FTUSB_GCR_USB3_LPMEN_MASK      0x00000040
// Field       : VBUS_STATUS
// Access      : RO
// VBUS Status.
#define FTUSB_GCR_VBUS_STATUS_BIT      7
#define FTUSB_GCR_VBUS_STATUS_LEN      1
#define FTUSB_GCR_VBUS_STATUS_MASK     0x00000080
// Field       : SF_RST
// Access      : RW
// SW reset. The SW reset can reset FOTG330 and some registers to the
// initial values, as the behavior of the warm reset and hot reset in the
// SS mode and usb_rst in the HS/FS mode. This bit will be cleared
// automatically by hardware. Note: To reset the registers, please check
// the description of each register.
#define FTUSB_GCR_SF_RST_BIT           8
#define FTUSB_GCR_SF_RST_LEN           1
#define FTUSB_GCR_SF_RST_MASK          0x00000100
// Field       : POLL_TO_DIS_TMO
// Access      : RO
// Timemout of POLL_TO_DIS_CNT. This field informs that FOTG330 plugs
// into the SS host, but FOTG330 cannot build the SS link after retrying
// the POLL_TO_DIS_CNT times.
#define FTUSB_GCR_POLL_TO_DIS_TMO_BIT  9
#define FTUSB_GCR_POLL_TO_DIS_TMO_LEN  1
#define FTUSB_GCR_POLL_TO_DIS_TMO_MASK 0x00000200
// Field       : USB2_PLUG
// Access      : RW
// USB2 in the plug mode This bit will only effect when FOTG330_SS_EN is
// not defined. (FOTG330 was configured as USB2 only.) When USB2_PLUG is
// set to 0, the device controller will set PHY in the Non-Driving mode
// to emulate the detachment of a device even if it is really plugged.
// The USB host will not detect plugging of a device. Such an event is
// called soft-detachment. After hardware reset, the USB2_PLUG will be 0
// and the device is soft-detached. When the USB host detects the
// attachment of a device, the PHY must drive D+ and D- in the manner
// defined in USB specification. In order to let PHY drive D+ and D-, AP
// would set USB2_PLUG after the hardware reset. If the AP does not set
// USB2_PLUG bit, the device will be always soft-detached and the USB
// host will never detect the attachment of the device.
#define FTUSB_GCR_USB2_PLUG_BIT        10
#define FTUSB_GCR_USB2_PLUG_LEN        1
#define FTUSB_GCR_USB2_PLUG_MASK       0x00000400
// Field       : POLL_TO_DIS_CNT
// Access      : RW
// Counter of polling to disable. When the quality of signals on USB
// cable is very bad, FOTG330 may fail to connect with host for the SS
// link and start to try the HS link. This field indicates that FOTG330
// will try to re-build the SS connection until this counter is timeout.
#define FTUSB_GCR_POLL_TO_DIS_CNT_BIT  12
#define FTUSB_GCR_POLL_TO_DIS_CNT_LEN  4
#define FTUSB_GCR_POLL_TO_DIS_CNT_MASK 0x0000f000
// ----------------------------------------------------------------------
// Register    : Global Test Mode Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_GTM_ADDR                 0x10302004
// Field       : TST_MODE
// Access      : RW
// Turbo mode. This bit should only be set to 1 during a simulation. When
// this bit is set to 1, FOTG330 enters the turbo mode to shorten the
// simulation time.
#define FTUSB_GTM_TST_MODE_BIT         0
#define FTUSB_GTM_TST_MODE_LEN         1
#define FTUSB_GTM_TST_MODE_MASK        0x00000001
// Field       : TST_FIFO_DEG
// Access      : RW
// FIFO debug. After setting this bit, SW can access the context of FIFO
// without affecting the read/write pointer.
#define FTUSB_GTM_TST_FIFO_DEG_BIT     1
#define FTUSB_GTM_TST_FIFO_DEG_LEN     1
#define FTUSB_GTM_TST_FIFO_DEG_MASK    0x00000002
// Field       : TST_EP_NUM
// Access      : RW
// EP number in the debug mode. This field indicates that the context of
// Buffer Management Debug Table maps to the context of specified EP.
// This bit will be effective when TST_FIFO_DEG is set to 1.
#define FTUSB_GTM_TST_EP_NUM_BIT       4
#define FTUSB_GTM_TST_EP_NUM_LEN       4
#define FTUSB_GTM_TST_EP_NUM_MASK      0x000000f0
// Field       : TST_EP_ENTRY
// Access      : RO
// EP entry in the debug mode. This filed indicates that the context of
// Buffer Management Debug Table maps to the context of specified entry
// in specified EP number. This bit will be effective when TST_FIFO_DEG
// is set to 1.
#define FTUSB_GTM_TST_EP_ENTRY_BIT     8
#define FTUSB_GTM_TST_EP_ENTRY_LEN     4
#define FTUSB_GTM_TST_EP_ENTRY_MASK    0x00000f00
// Field       : TST_CUR_EP_ENTRY
// Access      : RW
// Number of current entries. This field indicates that the current
// operating entry in BFM for specified EP based on the value of
// TST_EP_NUM.
#define FTUSB_GTM_TST_CUR_EP_ENTRY_BIT 12
#define FTUSB_GTM_TST_CUR_EP_ENTRY_LEN 4
#define FTUSB_GTM_TST_CUR_EP_ENTRY_MASK 0x0000f000
// Field       : TST_DIS_SOFGEN
// Access      : RW
// Disable the generation of SOF. When this bit is set to 1, FOTG330
// disables the self-generate SOF in the HS/FS mode and uses SOF issued
// by the host.
#define FTUSB_GTM_TST_DIS_SOFGEN_BIT   16
#define FTUSB_GTM_TST_DIS_SOFGEN_LEN   1
#define FTUSB_GTM_TST_DIS_SOFGEN_MASK  0x00010000
// Field       : TST_FORCE_SS
// Access      : RW
// Force the SuperSpeed device. This bit informs FOTG330 to operate in
// the SuperSpeed mode. FOTG330 never operates in the HS/FS mode after
// the bit setting.
#define FTUSB_GTM_TST_FORCE_SS_BIT     17
#define FTUSB_GTM_TST_FORCE_SS_LEN     1
#define FTUSB_GTM_TST_FORCE_SS_MASK    0x00020000
// Field       : TST_FORCE_HS
// Access      : RW
// Force the High-Speed device. This bit informs FOTG330 to operate in
// the High-Speed/Full-Speed mode.
#define FTUSB_GTM_TST_FORCE_HS_BIT     18
#define FTUSB_GTM_TST_FORCE_HS_LEN     1
#define FTUSB_GTM_TST_FORCE_HS_MASK    0x00040000
// Field       : TST_FORCE_FS
// Access      : RW
// Force the Full-Speed device. This bit informs FOTG330 to operate in
// the Full-Speed mode.
#define FTUSB_GTM_TST_FORCE_FS_BIT     19
#define FTUSB_GTM_TST_FORCE_FS_LEN     1
#define FTUSB_GTM_TST_FORCE_FS_MASK    0x00080000
// ----------------------------------------------------------------------
// Register    : Device Address Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_DAR_ADDR                 0x10302008
// Field       : DEV_ADDR
// Access      : RW
// Device address. SW should set this field to the latest device address
// when the SET_ADDRESS request is successfully executed. This bit will
// be reset to 0 by the hot reset and warm reset in the SS mode and the
// bus reset in the HS/FS mode.
#define FTUSB_DAR_DEV_ADDR_BIT         0
#define FTUSB_DAR_DEV_ADDR_LEN         7
#define FTUSB_DAR_DEV_ADDR_MASK        0x0000007f
// Field       : SET_CONFIG
// Access      : RW
// SET_CONFIGURATION done. SW should set this bit when SET_CONFIGURATION
// is successfully executed. Before this bit is set, FOTG330 will not
// respond to any non-control transfer. This bit will be reset to 0 by
// the hot reset and warm reset in the SS mode, and the bus reset in the
// HS/FS mode.
#define FTUSB_DAR_SET_CONFIG_BIT       7
#define FTUSB_DAR_SET_CONFIG_LEN       1
#define FTUSB_DAR_SET_CONFIG_MASK      0x00000080
// ----------------------------------------------------------------------
// Register    : Control Transfer Configuration and Status Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_CX_CONFIG_STATUS_ADDR    0x1030200c
// Field       : DX_DONE
// Access      : RW
// Data transfer is done for control transfer. This bit should be set
// when all data for this control transfer is transferred. This bit is
// cleared automatically by hardware after ACK of Status stage is
// transmitted/received to/from the host. This bit will be reset to 0 by
// the hot reset and warm reset in the SS mode and the bus reset in the
// HS/FS mode. This bit will also be cleared by the interrupts of
// cx_cmdfail_int and cx_cmdabt_int.
#define FTUSB_CX_CONFIG_STATUS_DX_DONE_BIT 0
#define FTUSB_CX_CONFIG_STATUS_DX_DONE_LEN 1
#define FTUSB_CX_CONFIG_STATUS_DX_DONE_MASK 0x00000001
// Field       : CX_STL
// Access      : RW
// Stall CX. Writing 1 to this bit can stall EP0, and the CX FIFO will be
// cleared at the same time. Once CX_STL is set, SW cannot access CX FIFO
// until this bit is cleared. The bit will be cleared after the SETUP
// token is received. This bit will be reset to 0 by the hot reset and
// warm reset in the SS mode, and the bus reset in the HS/FS mode.
#define FTUSB_CX_CONFIG_STATUS_CX_STL_BIT 1
#define FTUSB_CX_CONFIG_STATUS_CX_STL_LEN 1
#define FTUSB_CX_CONFIG_STATUS_CX_STL_MASK 0x00000002
// Field       : CXF_CLR
// Access      : RW
// Clear CX FIFO data (For debugging usage only). Write 1 to clear the
// data in CX FIFO. This bit will be cleared automatically by hardware.
// Please note that when setting this bit, CX FIFO will be cleared no
// matter the previous SETUP, IN, or OUT transactions have completed or
// not.
#define FTUSB_CX_CONFIG_STATUS_CXF_CLR_BIT 2
#define FTUSB_CX_CONFIG_STATUS_CXF_CLR_LEN 1
#define FTUSB_CX_CONFIG_STATUS_CXF_CLR_MASK 0x00000004
// Field       : CXF_FUL
// Access      : RO
// CX FIFO is full. 1 indicates that the CX FIFO is full.
#define FTUSB_CX_CONFIG_STATUS_CXF_FUL_BIT 3
#define FTUSB_CX_CONFIG_STATUS_CXF_FUL_LEN 1
#define FTUSB_CX_CONFIG_STATUS_CXF_FUL_MASK 0x00000008
// Field       : CXF_EMP
// Access      : RO
// CX FIFO is empty. 1 indicates that the CX FIFO is empty.
#define FTUSB_CX_CONFIG_STATUS_CXF_EMP_BIT 4
#define FTUSB_CX_CONFIG_STATUS_CXF_EMP_LEN 1
#define FTUSB_CX_CONFIG_STATUS_CXF_EMP_MASK 0x00000010
// Field       : CXF_LEN
// Access      : RW
// Data length of CX FIFO. For the OUT transaction, this field indicates
// the byte count of data in CX_FIFO that SW should read out. For the IN
// transaction, this field indicates the byte count of total data that SW
// should write to CX_FIFO. SW should program this field after decoding
// the 8-byte command of the SETUP transfer. After writing the total
// data, CX_DONE of SW must be set. This field will be reset to 0 by the
// hot reset and warm reset in the SS mode, and the bus reset in the
// HS/FS mode.
#define FTUSB_CX_CONFIG_STATUS_CXF_LEN_BIT 8
#define FTUSB_CX_CONFIG_STATUS_CXF_LEN_LEN 16
#define FTUSB_CX_CONFIG_STATUS_CXF_LEN_MASK 0x00ffff00
// ----------------------------------------------------------------------
// Register    : Control Trnasfer Data Port Register
// This register is part of the Device Special Purpose Registers set. SW
// can access the data in CX FIFO through the fixed address, 0x2010, or
// the burst address, 0x2010 ~ 0x201C.
#define FTUSB_CX_PORT0_ADDR            0x10302010
// Field       : CDP
// Access      : RW
// iThe Data Port of Control Transfer. SW can access the data to control
// the transfer through the data port.
#define FTUSB_CX_PORT0_CDP_BIT         0
#define FTUSB_CX_PORT0_CDP_LEN         32
#define FTUSB_CX_PORT0_CDP_MASK        0xffffffff
// ----------------------------------------------------------------------
// Register    : Control Trnasfer Data Port Register
// This register is part of the Device Special Purpose Registers set. SW
// can access the data in CX FIFO through the fixed address, 0x2010, or
// the burst address, 0x2010 ~ 0x201C.
#define FTUSB_CX_PORT1_ADDR            0x10302014
// Field       : CDP
// Access      : RW
// iThe Data Port of Control Transfer. SW can access the data to control
// the transfer through the data port.
#define FTUSB_CX_PORT1_CDP_BIT         0
#define FTUSB_CX_PORT1_CDP_LEN         32
#define FTUSB_CX_PORT1_CDP_MASK        0xffffffff
// ----------------------------------------------------------------------
// Register    : Control Trnasfer Data Port Register
// This register is part of the Device Special Purpose Registers set. SW
// can access the data in CX FIFO through the fixed address, 0x2010, or
// the burst address, 0x2010 ~ 0x201C.
#define FTUSB_CX_PORT2_ADDR            0x10302018
// Field       : CDP
// Access      : RW
// iThe Data Port of Control Transfer. SW can access the data to control
// the transfer through the data port.
#define FTUSB_CX_PORT2_CDP_BIT         0
#define FTUSB_CX_PORT2_CDP_LEN         32
#define FTUSB_CX_PORT2_CDP_MASK        0xffffffff
// ----------------------------------------------------------------------
// Register    : Control Trnasfer Data Port Register
// This register is part of the Device Special Purpose Registers set. SW
// can access the data in CX FIFO through the fixed address, 0x2010, or
// the burst address, 0x2010 ~ 0x201C.
#define FTUSB_CX_PORT3_ADDR            0x1030201c
// Field       : CDP
// Access      : RW
// iThe Data Port of Control Transfer. SW can access the data to control
// the transfer through the data port.
#define FTUSB_CX_PORT3_CDP_BIT         0
#define FTUSB_CX_PORT3_CDP_LEN         32
#define FTUSB_CX_PORT3_CDP_MASK        0xffffffff
// ----------------------------------------------------------------------
// Register    : EP0 Setting 0 Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_EP0_SET0_ADDR            0x10302020
// Field       : EP_STL
// Access      : RW
// EPn Stall. This bit will be reset to 0 by the hot reset and warm reset
// in the SS mode, the bus reset in the HS/FS mode, and the interrupt of
// VBUS_chg_int. SW must clear the stall bit of the corresponding EP when
// receiving the command of CLEAR_FEATURE. This bit can be cleared with
// setting EPn_STL_CLR. 1: Stall this EPn 0: Not stall this EPn Note:
// Before setting this bit, SW must check if SYNC FIFO is empty for IN
// EP. It is to confirm that all data have been written to BFM. Note: For
// OUT EP, SW shall confirm if internal DMA is complete before setting
// the bit.
#define FTUSB_EP0_SET0_EP_STL_BIT      0
#define FTUSB_EP0_SET0_EP_STL_LEN      1
#define FTUSB_EP0_SET0_EP_STL_MASK     0x00000001
// Field       : EP_CLR_SEQNUM
// Access      : RW
// Reset Sequence/Toggle bit of EP. SW resets the sequence number of EP
// by writing a 1 to this bit. This bit is immediately cleared by
// hardware. When SW receives the Set Configuration, Set Interface or
// ClearFeature (ENDPOINT_HALT) command, SW must reset the
// sequence/toggle bit.
#define FTUSB_EP0_SET0_EP_CLR_SEQNUM_BIT 1
#define FTUSB_EP0_SET0_EP_CLR_SEQNUM_LEN 1
#define FTUSB_EP0_SET0_EP_CLR_SEQNUM_MASK 0x00000002
// Field       : EP_STL_CLR
// Access      : RW
// EPn Stall Clear. Writing 1 to clear the register, EPn_STL. This bit is
// immediately cleared by hardware. SW writes this bit to 1 with
// receiving the command, CLEAR_FEATURE (ENDPOINT_HALT). If EPn_STL is 1,
// SW sets EPn_STL_CLR and EPn_CLR_SEQNUM must be set at the same time.
// If EPn_STL is 0, SW sets EPn_STL_CLR and EPn_CLR_SEQNUM must be set
// after 2.5 us.
#define FTUSB_EP0_SET0_EP_STL_CLR_BIT  3
#define FTUSB_EP0_SET0_EP_STL_CLR_LEN  1
#define FTUSB_EP0_SET0_EP_STL_CLR_MASK 0x00000008
// ----------------------------------------------------------------------
// Register    : EP0 Setting 1 Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_EP0_SET1_ADDR            0x10302024
// Field       : EP_ACTIVE
// Access      : RW
// EPn active. 0: Disable EPn. 1: Enable EPn. When the USB host accesses
// the disabled EPn, no response will be returned.
#define FTUSB_EP0_SET1_EP_ACTIVE_BIT   0
#define FTUSB_EP0_SET1_EP_ACTIVE_LEN   1
#define FTUSB_EP0_SET1_EP_ACTIVE_MASK  0x00000001
// Field       : EP_DIR
// Access      : RW
// EPn direction. 0: OUT EP. 1: IN EP.
#define FTUSB_EP0_SET1_EP_DIR_BIT      1
#define FTUSB_EP0_SET1_EP_DIR_LEN      1
#define FTUSB_EP0_SET1_EP_DIR_MASK     0x00000002
// Field       : EP_TYPE
// Access      : RW
// Transfer type. 00: Reserved 01: Isochronous 10: Bulk 11: Interrupt
#define FTUSB_EP0_SET1_EP_TYPE_BIT     2
#define FTUSB_EP0_SET1_EP_TYPE_LEN     2
#define FTUSB_EP0_SET1_EP_TYPE_MASK    0x0000000c
// Field       : EP_BW_NUM
// Access      : RW
// Transaction number for the High-Speed ISO bandwidth. In the HS mode,
// this field indicates that the number of transactions that EP can
// service during one micro-frame.
#define FTUSB_EP0_SET1_EP_BW_NUM_BIT   4
#define FTUSB_EP0_SET1_EP_BW_NUM_LEN   2
#define FTUSB_EP0_SET1_EP_BW_NUM_MASK  0x00000030
// Field       : EP_ISO_IN_PKTNUM
// Access      : RW
// The number of packets for ISO IN during each service interval in the
// SS mode. This filed indicates that the total number of packets for ISO
// IN EP will be transmitted during each service interval. This value
// should be less than 48 and the application must provide sufficient
// bandwidth for total packets during each service interval.
#define FTUSB_EP0_SET1_EP_ISO_IN_PKTNUM_BIT 6
#define FTUSB_EP0_SET1_EP_ISO_IN_PKTNUM_LEN 6
#define FTUSB_EP0_SET1_EP_ISO_IN_PKTNUM_MASK 0x00000fc0
// Field       : EP_FIFO_ENTRY
// Access      : RW
// The number of the FIFO entries for EPn to store the data. For the SS
// mode, the value of this field should be equal to the burst number. For
// the HS/FS mode, the value of this field should be 1, 2, or 3 for
// single, double, or triple FIFOs, respectively.
#define FTUSB_EP0_SET1_EP_FIFO_ENTRY_BIT 12
#define FTUSB_EP0_SET1_EP_FIFO_ENTRY_LEN 5
#define FTUSB_EP0_SET1_EP_FIFO_ENTRY_MASK 0x0001f000
// Field       : EP_START_FIFO_ENTRY
// Access      : RW
// The first index of the EP FIFO entry. This field indicates the first
// FIFO entry, and EPn starts to store the data. The formula is:
// EPn_START_FIFO_ENTRY = EPn-1_START_FIFO_ENTRY + EPn-1_FIFO_ENTRY
// Please note that the value of this field for the minimum active EP
// must be 0.
#define FTUSB_EP0_SET1_EP_START_FIFO_ENTRY_BIT 24
#define FTUSB_EP0_SET1_EP_START_FIFO_ENTRY_LEN 8
#define FTUSB_EP0_SET1_EP_START_FIFO_ENTRY_MASK 0xff000000
// ----------------------------------------------------------------------
// Register    : EP0 Setting 2 Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_EP0_SET2_ADDR            0x10302028
// Field       : EP_MPS
// Access      : RW
// Max Packet Size of EPn. Maximum packet size of EPn is capable of
// sending or receiving data of less than or equal to this size.
#define FTUSB_EP0_SET2_EP_MPS_BIT      0
#define FTUSB_EP0_SET2_EP_MPS_LEN      11
#define FTUSB_EP0_SET2_EP_MPS_MASK     0x000007ff
// Field       : EP_FF_ADDR_OFS
// Access      : RW
// EPn Base FIFO address offset. This field indicates that EPn maps to
// the FIFO index. The formula is EPn_FF_ADDR_OFS = ((EPn-1_MPS[10:3] +
// (EPn-1_MPS[2:0] ? 1:0)) * EPn-1_FIFO_ENTRY) + EPn-1_FF_ADDR_OFS.
// Please note that the value of this field for the minimum active EP
// must be 0.
#define FTUSB_EP0_SET2_EP_FF_ADDR_OFS_BIT 16
#define FTUSB_EP0_SET2_EP_FF_ADDR_OFS_LEN 15
#define FTUSB_EP0_SET2_EP_FF_ADDR_OFS_MASK 0x7fff0000
// ----------------------------------------------------------------------
// Register    : EP0 FIFO Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_EP0_FFR_ADDR             0x1030202c
// Field       : EP_FF_BYCNT
// Access      : RW
// EPn Transfer Byte Count. For OUT, this field indicates how many data
// in the FIFO. This field only shows the byte count of one packet. For
// IN, SW must set the field to inform FOTG330 that the total byte counts
// are sent in this transfer.
#define FTUSB_EP0_FFR_EP_FF_BYCNT_BIT  0
#define FTUSB_EP0_FFR_EP_FF_BYCNT_LEN  21
#define FTUSB_EP0_FFR_EP_FF_BYCNT_MASK 0x001fffff
