// Access      : RO
// EPn FIFO full.
#define FTUSB_EP0_FFR_EP_FF_FULL_BIT   30
#define FTUSB_EP0_FFR_EP_FF_FULL_LEN   1
#define FTUSB_EP0_FFR_EP_FF_FULL_MASK  0x40000000
