#define FTUSB_EP0_STR_ID_EP_STR_ID_LEN 16
#define FTUSB_EP0_STR_ID_EP_STR_ID_MASK 0x0000ffff
// Field       : EP_STR_EN
// Access      : RW
// EPn Stream ID Enable. This bit activates the FOTG330 proposal,
// EPn_STR_ID, to host. This bit will be cleared by hardware once FOTG330
// sends out ERDY with EPn_STR_ID. This bit will be reset to 0 by the hot
// reset and the warm reset in the SS mode and the bus is reset in the
// HS/FS mode.
#define FTUSB_EP0_STR_ID_EP_STR_EN_BIT 16
#define FTUSB_EP0_STR_ID_EP_STR_EN_LEN 1
#define FTUSB_EP0_STR_ID_EP_STR_EN_MASK 0x00010000
