// sequence/toggle bit.
#define FTUSB_EP1_SET0_EP_CLR_SEQNUM_BIT 1
#define FTUSB_EP1_SET0_EP_CLR_SEQNUM_LEN 1
#define FTUSB_EP1_SET0_EP_CLR_SEQNUM_MASK 0x00000002
