// Access      : RW
// Transfer type. 00: Reserved 01: Isochronous 10: Bulk 11: Interrupt
#define FTUSB_EP11_SET1_EP_TYPE_BIT    2
#define FTUSB_EP11_SET1_EP_TYPE_LEN    2
#define FTUSB_EP11_SET1_EP_TYPE_MASK   0x0000000c
