// Access      : RW
// The number of packets for ISO IN during each service interval in the
// SS mode. This filed indicates that the total number of packets for ISO
// IN EP will be transmitted during each service interval. This value
// should be less than 48 and the application must provide sufficient
// bandwidth for total packets during each service interval.
#define FTUSB_EP11_SET1_EP_ISO_IN_PKTNUM_BIT 6
#define FTUSB_EP11_SET1_EP_ISO_IN_PKTNUM_LEN 6
#define FTUSB_EP11_SET1_EP_ISO_IN_PKTNUM_MASK 0x00000fc0
