#define FTUSB_EP11_FFR_EP_FF_EMPTY_LEN 1
#define FTUSB_EP11_FFR_EP_FF_EMPTY_MASK 0x20000000
// Field       : EP_FF_FULL
// Access      : RO
// EPn FIFO full.
#define FTUSB_EP11_FFR_EP_FF_FULL_BIT  30
#define FTUSB_EP11_FFR_EP_FF_FULL_LEN  1
#define FTUSB_EP11_FFR_EP_FF_FULL_MASK 0x40000000
