// receives the interrupt of Set Address request.
#define FTUSB_EP11_FFR_EP_FF_RST_BIT   31
#define FTUSB_EP11_FFR_EP_FF_RST_LEN   1
#define FTUSB_EP11_FFR_EP_FF_RST_MASK  0x80000000
