#define FTUSB_EP15_SET0_EP_CLR_SEQNUM_BIT 1
#define FTUSB_EP15_SET0_EP_CLR_SEQNUM_LEN 1
#define FTUSB_EP15_SET0_EP_CLR_SEQNUM_MASK 0x00000002
// Field       : EP_STL_CLR
// Access      : RW
// EPn Stall Clear. Writing 1 to clear the register, EPn_STL. This bit is
// immediately cleared by hardware. SW writes this bit to 1 with
// receiving the command, CLEAR_FEATURE (ENDPOINT_HALT). If EPn_STL is 1,
