#define FTUSB_EP15_SET0_EP_STL_CLR_LEN 1
#define FTUSB_EP15_SET0_EP_STL_CLR_MASK 0x00000008
// ----------------------------------------------------------------------
// Register    : EP15 Setting 1 Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_EP15_SET1_ADDR           0x103022f4
// Field       : EP_ACTIVE
// Access      : RW
// EPn active. 0: Disable EPn. 1: Enable EPn. When the USB host accesses
// the disabled EPn, no response will be returned.
#define FTUSB_EP15_SET1_EP_ACTIVE_BIT  0
#define FTUSB_EP15_SET1_EP_ACTIVE_LEN  1
#define FTUSB_EP15_SET1_EP_ACTIVE_MASK 0x00000001
// Field       : EP_DIR
// Access      : RW
// EPn direction. 0: OUT EP. 1: IN EP.
#define FTUSB_EP15_SET1_EP_DIR_BIT     1
#define FTUSB_EP15_SET1_EP_DIR_LEN     1
#define FTUSB_EP15_SET1_EP_DIR_MASK    0x00000002
// Field       : EP_TYPE
// Access      : RW
// Transfer type. 00: Reserved 01: Isochronous 10: Bulk 11: Interrupt
#define FTUSB_EP15_SET1_EP_TYPE_BIT    2
#define FTUSB_EP15_SET1_EP_TYPE_LEN    2
#define FTUSB_EP15_SET1_EP_TYPE_MASK   0x0000000c
// Field       : EP_BW_NUM
// Access      : RW
// Transaction number for the High-Speed ISO bandwidth. In the HS mode,
// this field indicates that the number of transactions that EP can
// service during one micro-frame.
#define FTUSB_EP15_SET1_EP_BW_NUM_BIT  4
#define FTUSB_EP15_SET1_EP_BW_NUM_LEN  2
#define FTUSB_EP15_SET1_EP_BW_NUM_MASK 0x00000030
// Field       : EP_ISO_IN_PKTNUM
// Access      : RW
// The number of packets for ISO IN during each service interval in the
// SS mode. This filed indicates that the total number of packets for ISO
// IN EP will be transmitted during each service interval. This value
// should be less than 48 and the application must provide sufficient
// bandwidth for total packets during each service interval.
#define FTUSB_EP15_SET1_EP_ISO_IN_PKTNUM_BIT 6
#define FTUSB_EP15_SET1_EP_ISO_IN_PKTNUM_LEN 6
#define FTUSB_EP15_SET1_EP_ISO_IN_PKTNUM_MASK 0x00000fc0
// Field       : EP_FIFO_ENTRY
// Access      : RW
// The number of the FIFO entries for EPn to store the data. For the SS
// mode, the value of this field should be equal to the burst number. For
// the HS/FS mode, the value of this field should be 1, 2, or 3 for
// single, double, or triple FIFOs, respectively.
#define FTUSB_EP15_SET1_EP_FIFO_ENTRY_BIT 12
#define FTUSB_EP15_SET1_EP_FIFO_ENTRY_LEN 5
#define FTUSB_EP15_SET1_EP_FIFO_ENTRY_MASK 0x0001f000
// Field       : EP_START_FIFO_ENTRY
// Access      : RW
// The first index of the EP FIFO entry. This field indicates the first
// FIFO entry, and EPn starts to store the data. The formula is:
// EPn_START_FIFO_ENTRY = EPn-1_START_FIFO_ENTRY + EPn-1_FIFO_ENTRY
// Please note that the value of this field for the minimum active EP
// must be 0.
#define FTUSB_EP15_SET1_EP_START_FIFO_ENTRY_BIT 24
#define FTUSB_EP15_SET1_EP_START_FIFO_ENTRY_LEN 8
#define FTUSB_EP15_SET1_EP_START_FIFO_ENTRY_MASK 0xff000000
// ----------------------------------------------------------------------
// Register    : EP15 Setting 2 Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_EP15_SET2_ADDR           0x103022f8
// Field       : EP_MPS
// Access      : RW
// Max Packet Size of EPn. Maximum packet size of EPn is capable of
// sending or receiving data of less than or equal to this size.
#define FTUSB_EP15_SET2_EP_MPS_BIT     0
#define FTUSB_EP15_SET2_EP_MPS_LEN     11
#define FTUSB_EP15_SET2_EP_MPS_MASK    0x000007ff
// Field       : EP_FF_ADDR_OFS
// Access      : RW
// EPn Base FIFO address offset. This field indicates that EPn maps to
// the FIFO index. The formula is EPn_FF_ADDR_OFS = ((EPn-1_MPS[10:3] +
// (EPn-1_MPS[2:0] ? 1:0)) * EPn-1_FIFO_ENTRY) + EPn-1_FF_ADDR_OFS.
// Please note that the value of this field for the minimum active EP
// must be 0.
#define FTUSB_EP15_SET2_EP_FF_ADDR_OFS_BIT 16
#define FTUSB_EP15_SET2_EP_FF_ADDR_OFS_LEN 15
#define FTUSB_EP15_SET2_EP_FF_ADDR_OFS_MASK 0x7fff0000
// ----------------------------------------------------------------------
// Register    : EP15 FIFO Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_EP15_FFR_ADDR            0x103022fc
// Field       : EP_FF_BYCNT
// Access      : RW
// EPn Transfer Byte Count. For OUT, this field indicates how many data
// in the FIFO. This field only shows the byte count of one packet. For
// IN, SW must set the field to inform FOTG330 that the total byte counts
// are sent in this transfer.
#define FTUSB_EP15_FFR_EP_FF_BYCNT_BIT 0
#define FTUSB_EP15_FFR_EP_FF_BYCNT_LEN 21
#define FTUSB_EP15_FFR_EP_FF_BYCNT_MASK 0x001fffff
// Field       : EP_TX0BYTE
// Access      : RW
// EPn Transfer 0 Byte. SW set this bit to 1 to inform FOTG330 to
// transmit the zero-length data packet. This bit will be cleared by
// hardware once the data packet is sent out. This bit will be reset to 0
// by the hot reset and warm reset in the SS mode, the bus reset in the
// HS/FS mode, and the interrupt of VBUS_chg_int.
#define FTUSB_EP15_FFR_EP_TX0BYTE_BIT  28
#define FTUSB_EP15_FFR_EP_TX0BYTE_LEN  1
#define FTUSB_EP15_FFR_EP_TX0BYTE_MASK 0x10000000
// Field       : EP_FF_EMPTY
// Access      : RO
// EPn FIFO empty.
#define FTUSB_EP15_FFR_EP_FF_EMPTY_BIT 29
#define FTUSB_EP15_FFR_EP_FF_EMPTY_LEN 1
#define FTUSB_EP15_FFR_EP_FF_EMPTY_MASK 0x20000000
// Field       : EP_FF_FULL
// Access      : RO
// EPn FIFO full.
#define FTUSB_EP15_FFR_EP_FF_FULL_BIT  30
#define FTUSB_EP15_FFR_EP_FF_FULL_LEN  1
#define FTUSB_EP15_FFR_EP_FF_FULL_MASK 0x40000000
// Field       : EP_FF_RST
// Access      : RW
// EPn FIFO reset. Writing 1 will reset all read/write pointers of EPn
// FIFO. Please note the bit of all active EPs shall be set when SW
// receives the interrupt of Set Address request.
#define FTUSB_EP15_FFR_EP_FF_RST_BIT   31
#define FTUSB_EP15_FFR_EP_FF_RST_LEN   1
#define FTUSB_EP15_FFR_EP_FF_RST_MASK  0x80000000
// ----------------------------------------------------------------------
// Register    : HS PHY Test Mode Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_HS_PTM_ADDR              0x10302300
// Field       : TST_JSTA
// Access      : RW
// Writing 1 to this bit, D+/D- is set to the High-Speed J state.
// Programming Sequence for Test_J 1. Received SET_FEATURE (Test_J)
// request. 2. SW must set TST_JSTA after receiving SET_FEATURE (Test_J)
// request. Set CX_DONE. This bit shall set before setting CX_DONE for
// the Control request with TEST_MODE set.
#define FTUSB_HS_PTM_TST_JSTA_BIT      0
#define FTUSB_HS_PTM_TST_JSTA_LEN      1
#define FTUSB_HS_PTM_TST_JSTA_MASK     0x00000001
// Field       : TST_KSTA
// Access      : RW
// Writing 1 to this bit, D+/D- is set to the High-Speed K state.
// Programming sequence for Test_K is as follows: 1. Received SET_FEATURE
// (Test_K) request. 2. SW must set TST_KSTA after receiving SET_FEATURE
// (Test_K) request. Set CX_DONE. This bit shall set before setting
// CX_DONE for the Control request with TEST_MODE set.
#define FTUSB_HS_PTM_TST_KSTA_BIT      1
#define FTUSB_HS_PTM_TST_KSTA_LEN      1
#define FTUSB_HS_PTM_TST_KSTA_MASK     0x00000002
// Field       : TST_SE0NAK
// Access      : RW
// Writing 1 to this bit, the D+/D- lines will be set to HS at the
// quiescent state. The device only responds to a valid HS IN token and
// always responds to the IN token with NAK. Programming sequence for
// Test_SE0_NAK is as follows: Receive SET_FEATURE(Test_SE0_NAK) request
// SW must set TST_SE0NAK after receiving SET_FEATURE (Test_SE0_NAK)
// request. Set CX_DONE This bit shall set before setting CX_DONE for the
// Control request with TEST_MODE set.
#define FTUSB_HS_PTM_TST_SE0NAK_BIT    2
#define FTUSB_HS_PTM_TST_SE0NAK_LEN    1
#define FTUSB_HS_PTM_TST_SE0NAK_MASK   0x00000004
// Field       : TST_PKT
// Access      : RW
// Test mode for packet. Writing 1 to this bit, FOTG330 will repeatedly
// send the packet defined in the UTMI specification to the transceiver.
// Programming sequence for Test_Packet is as follows: 1. Device shall be
// at the configured state by bus enumeration. 2. SW must set the bit
// after receiving SET_FEATURE (Test_Packet) request. 3. Set CX_DONE
// Software shall prepare the data payload of test packet and write to
// CX_FIFO. After the SET_FEATURE command shows the test mode and the
// Test_Packet index is decoded, SW must program this bit to 1. This bit
// shall be set before setting CX_DONE for the Control request with
// TEST_MODE set. Software shall prepare the data payload of test packet
// and write to CX_FIFO after setting the bit and CX_DONE.
#define FTUSB_HS_PTM_TST_PKT_BIT       3
#define FTUSB_HS_PTM_TST_PKT_LEN       1
#define FTUSB_HS_PTM_TST_PKT_MASK      0x00000008
// ----------------------------------------------------------------------
// Register    : HS Control Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_HS_CR_ADDR               0x10302304
// Field       : IDLE_CNT
// Access      : RW
// This bit controls the timing delay from the time indicated in the
// HS_GOSUSP bit to the time when FOTG330 enters a suspend mode. For
// reference, the delay is denoted as tsusp_delay in the list below:
// 0b000: tsusp_delay = 0 ms 0b001: tsusp_delay = 1.0 ms 0b010:
// tsusp_delay = 2.0 ms 0b011: tsusp_delay = 3.0 ms 0b100: tsusp_delay =
// 4.0 ms 0b101: tsusp_delay = 5.0 ms 0b110: tsusp_delay = 6.0 ms 0b111:
// tsusp_delay = 7.0 ms Please note that the USB 2.0 specification
// defines T2SUSP to mandate that the device should enter the suspend
// mode no later than 10 ms after D+/D- is continuously at the idle state
// for more than 3.0 ms. SW programmer should be cautious when
// programming the value of tsusp_delay.
#define FTUSB_HS_CR_IDLE_CNT_BIT       0
#define FTUSB_HS_CR_IDLE_CNT_LEN       3
#define FTUSB_HS_CR_IDLE_CNT_MASK      0x00000007
// Field       : CAP_RMWKUP
// Access      : RW
// Remote Wake-up Capability. Writing 1 to this bit indicates that
// FOTG330 can be woken up by HS_GORMWKUP. SW programs this bit after
// receiving the SET_FEATURE command when the Feature Selector is
// DEVICE_REMOTE_WAKEUP.
#define FTUSB_HS_CR_CAP_RMWKUP_BIT     3
#define FTUSB_HS_CR_CAP_RMWKUP_LEN     1
#define FTUSB_HS_CR_CAP_RMWKUP_MASK    0x00000008
// Field       : HS_GORMWKUP
// Access      : RW
// HS Go Remote Wake-up. Writing 1 to this bit activates FOTG330 to
// remote wakeup from the suspend state and this bit is effective when
// CAP_RMWKUP is active. This bit will be cleared automatically after
// FOTG330 has been woken up from suspend. This bit will be reset to 0 by
// the bus reset in the HS/FS mode.
#define FTUSB_HS_CR_HS_GORMWKUP_BIT    4
#define FTUSB_HS_CR_HS_GORMWKUP_LEN    1
#define FTUSB_HS_CR_HS_GORMWKUP_MASK   0x00000010
// Field       : HS_GOSUSP
// Access      : RW
// HS Go Suspend. Writing 1 to this bit activates the suspend mode. This
// bit will be cleared automatically after FOTG330 has been woken up from
// suspend. This bit will be reset to 0 by the bus reset in the HS/FS
// mode.
#define FTUSB_HS_CR_HS_GOSUSP_BIT      5
#define FTUSB_HS_CR_HS_GOSUSP_LEN      1
#define FTUSB_HS_CR_HS_GOSUSP_MASK     0x00000020
// Field       : CAP_LPM_RMWKUP
// Access      : RW
// Capability of Remote Wake-up from LPM. This bit is set by host with
// the LPM token. SW can check this bit whether the host permits the
// device to the initial remote wakeup.
#define FTUSB_HS_CR_CAP_LPM_RMWKUP_BIT 6
#define FTUSB_HS_CR_CAP_LPM_RMWKUP_LEN 1
#define FTUSB_HS_CR_CAP_LPM_RMWKUP_MASK 0x00000040
// Field       : HS_LPM_RMWKUP
// Access      : RW
// Remote Wake-up from LPM. Writing 1 to this bit activates FOTG330 to
// remove the wakeup from the LPM state and this bit is effective when
// CAP_LPM_RMWKUP is active. This bit will be automatically cleared after
// FOTG330 has been woken up from LPM. This bit will be reset to ?0? by
// the bus reset in the HS/FS mode.
#define FTUSB_HS_CR_HS_LPM_RMWKUP_BIT  7
#define FTUSB_HS_CR_HS_LPM_RMWKUP_LEN  1
#define FTUSB_HS_CR_HS_LPM_RMWKUP_MASK 0x00000080
// Field       : HS_LPM_PERMIT
// Access      : RW
// HS LPM Permission. 1 permits FOTG330 to respond ACK based on whether
// BFM has pending data or not. 0 indicates FOTG330 always responds NYET
// for the LPM request of the host.
#define FTUSB_HS_CR_HS_LPM_PERMIT_BIT  8
#define FTUSB_HS_CR_HS_LPM_PERMIT_LEN  1
#define FTUSB_HS_CR_HS_LPM_PERMIT_MASK 0x00000100
// Field       : LPM_BESL
// Access      : RO
// HS LPM BESL. Upon FOTG330 response ACK for LPM Token, this value will
// be updated with receiving LPM Token BESL field.
#define FTUSB_HS_CR_LPM_BESL_BIT       9
#define FTUSB_HS_CR_LPM_BESL_LEN       4
#define FTUSB_HS_CR_LPM_BESL_MASK      0x00001e00
// Field       : LPM_BESL_PERMIT_MINT
// Access      : RW
// Minimum BESL for LPM Permission. If LPM BESL is smaller than this
// field, FOTG330 will response NYET to reject the LPM request. LPM
// permit condition: HS_LPM_PERMIT = 1 and (LPM_BESL_PERMIT_MIN <
// LPM_BESL < LPM_BESL_PERMIT_MAX).
#define FTUSB_HS_CR_LPM_BESL_PERMIT_MINT_BIT 13
#define FTUSB_HS_CR_LPM_BESL_PERMIT_MINT_LEN 4
#define FTUSB_HS_CR_LPM_BESL_PERMIT_MINT_MASK 0x0001e000
// Field       : LPSM_BESL_PERMIT_MAX
// Access      : RW
// Maximum BESL for LPM Permission. If LPM BESL is larger than this
// field, FOTG330 will response NYET to reject the LPM request. LPM
// permit condition: HS_LPM_PERMIT = 1 and (LPM_BESL_PERMIT_MIN <
// LPM_BESL < LPM_BESL_PERMIT_MAX)
#define FTUSB_HS_CR_LPSM_BESL_PERMIT_MAX_BIT 17
#define FTUSB_HS_CR_LPSM_BESL_PERMIT_MAX_LEN 4
#define FTUSB_HS_CR_LPSM_BESL_PERMIT_MAX_MASK 0x001e0000
// Field       : HW_LPM_RMWKUP_IN
// Access      : RW
// Enable Hardware LPM remote wakeup for IN transfer. If in transfer is
// in the flow control and this bit is 1, FOTG330 will issue remote
// wakeup to leave LPM state when IN traffic is ready and CAP_LPM_RMWKUP
// is active.
#define FTUSB_HS_CR_HW_LPM_RMWKUP_IN_BIT 21
#define FTUSB_HS_CR_HW_LPM_RMWKUP_IN_LEN 1
#define FTUSB_HS_CR_HW_LPM_RMWKUP_IN_MASK 0x00200000
// Field       : HW_LPM_RMWKUP_OUT
// Access      : RW
// Enable Hardware LPM remote wakeup for OUT transfer. If out transfer is
// in the flow control and this bit is 1, FOTG330 will issue remote
// wakeup to leave LPM state when OUT buffer is ready and CAP_LPM_RMWKUP
// is active.
#define FTUSB_HS_CR_HW_LPM_RMWKUP_OUT_BIT 22
#define FTUSB_HS_CR_HW_LPM_RMWKUP_OUT_LEN 1
#define FTUSB_HS_CR_HW_LPM_RMWKUP_OUT_MASK 0x00400000
// Field       : HW_LPM_RMWKUP_CX
// Access      : RW
// Enable Hardware LPM remote wakeup for Control Status Stage. If control
// transfer is in the flow control and this bit is 1, FOTG330 will issue
// remote wakeup to leave LPM state when CX_DONE and CAP_LPM_RMWKUP are
// active.
#define FTUSB_HS_CR_HW_LPM_RMWKUP_CX_BIT 23
#define FTUSB_HS_CR_HW_LPM_RMWKUP_CX_LEN 1
#define FTUSB_HS_CR_HW_LPM_RMWKUP_CX_MASK 0x00800000
// Field       : HW_LPM_REJECT_IN
// Access      : RW
// Enable HW LPM reject for IN transfer. If this bit is 1, FOTG330 will
// response NYET to reject LPM request if there is no flow control during
// IN transfer. When SW sets one bit of the bit[26:24], other bits shall
// be set simultaneously.
#define FTUSB_HS_CR_HW_LPM_REJECT_IN_BIT 24
#define FTUSB_HS_CR_HW_LPM_REJECT_IN_LEN 1
#define FTUSB_HS_CR_HW_LPM_REJECT_IN_MASK 0x01000000
// Field       : HW_LPM_REJECT_OUT
// Access      : RW
// Enable HW LPM reject for OUT transfer. If this bit is 1, FOTG330 will
// response NYET to reject LPM request if there is no flow control during
// OUT transfer. When SW sets one bit of the bit[26:24], other bits shall
// be set simultaneously.
#define FTUSB_HS_CR_HW_LPM_REJECT_OUT_BIT 25
#define FTUSB_HS_CR_HW_LPM_REJECT_OUT_LEN 1
#define FTUSB_HS_CR_HW_LPM_REJECT_OUT_MASK 0x02000000
// Field       : HW_LPM_REJECT_CX
// Access      : RW
// Enable HW LPM reject for Control Status Stage. If this bit is 1,
// FOTG330 will response NYET to reject LPM request if there is no flow
// control during command done. Please note that when SW sets one bit of
// the bit[26:24], , other bits shall be set simultaneously.
#define FTUSB_HS_CR_HW_LPM_REJECT_CX_BIT 26
#define FTUSB_HS_CR_HW_LPM_REJECT_CX_LEN 1
#define FTUSB_HS_CR_HW_LPM_REJECT_CX_MASK 0x04000000
// ----------------------------------------------------------------------
// Register    : SS Control Register 0
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_SS_CR0_ADDR              0x10302308
// Field       : U1_FUN_EN
// Access      : RW
// U1 Function Enable. AP must program this bit when AP receives the EP0
// SET_FEATURE command with U1_ENABLE. This bit will enable
// U1_TIMEOUT_TIMER. Once U1_TIMEOUT_TIMER is time out, FOTG330 will
// actively initiate LGO_U1 to the link partner. This bit will be reset
// to 0 by the hot reset or warm reset in the SS mode.
#define FTUSB_SS_CR0_U1_FUN_EN_BIT     0
#define FTUSB_SS_CR0_U1_FUN_EN_LEN     1
#define FTUSB_SS_CR0_U1_FUN_EN_MASK    0x00000001
// Field       : U2_FUN_EN
// Access      : RW
// U2 Function Enable. AP must program this bit when AP receives the EP0
// SET_FEATURE command with U2_ENABLE. This bit will enable
// U2_TIMEOUT_TIMER. Once U2_TIMEOUT_TIMER is time out, FOTG330 will
// actively initiate LGO_U2 to the link partner. This bit will be reset
// to 0 by the hot reset or warm reset in the SS mode.
#define FTUSB_SS_CR0_U2_FUN_EN_BIT     1
#define FTUSB_SS_CR0_U2_FUN_EN_LEN     1
#define FTUSB_SS_CR0_U2_FUN_EN_MASK    0x00000002
// Field       : MAX_SINT
// Access      : RW
// Maximum Service Interval. This field indicates the maximum service
// interval between each ISO EP.
#define FTUSB_SS_CR0_MAX_SINT_BIT      4
#define FTUSB_SS_CR0_MAX_SINT_LEN      3
#define FTUSB_SS_CR0_MAX_SINT_MASK     0x00000070
// Field       : SSI_EN
// Access      : RW
// Support Smart ISO Enable. The field indicates whether FOTG330 performs
// SSI or not. All SSI contexts sent from host are ignored if the bit is
// set to 0. Please note that transiting the bit from 1 to 0 makes
// FOTG330 to automatically clear all SSI information received before. 0:
// Disable SSI 1: Enable SSI
#define FTUSB_SS_CR0_SSI_EN_BIT        7
#define FTUSB_SS_CR0_SSI_EN_LEN        1
#define FTUSB_SS_CR0_SSI_EN_MASK       0x00000080
// Field       : SSI_WAKEUP_DELAY
// Access      : RW
// This field indicates that the time FOTG330 needs to wake up from U2 to
// U0. The unit is a bus-interval (125 us). Please note that the wake-up
// time is related to the characteristics of PHY. 0b00: Zero bus-
// interval. 0b01: One bus-interval (125 us). 0b10: Two bus-intervals
// (250 us). 0b11: Three bus-intervals (375 us).
#define FTUSB_SS_CR0_SSI_WAKEUP_DELAY_BIT 8
#define FTUSB_SS_CR0_SSI_WAKEUP_DELAY_LEN 2
#define FTUSB_SS_CR0_SSI_WAKEUP_DELAY_MASK 0x00000300
// ----------------------------------------------------------------------
// Register    : SS Control Register 1
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_SS_CR1_ADDR              0x1030230c
// Field       : U1_ENTRY_EN
// Access      : RW
// Device Active U1 Entry Enable. When this bit is set, the device will
// actively send out the LGO_U1 command to request the link partner to
// enter to the U1 state. The value is effective no matter U1_FUN_EN sets
// to 1 or not. This bit is cleared by hardware when the interrupt of
// U1_ENTRY_INT is set. This bit will be reset to 0 by the hot reset or
// warm reset in the SS mode.
#define FTUSB_SS_CR1_U1_ENTRY_EN_BIT   0
#define FTUSB_SS_CR1_U1_ENTRY_EN_LEN   1
#define FTUSB_SS_CR1_U1_ENTRY_EN_MASK  0x00000001
// Field       : U2_ENTRY_EN
// Access      : RW
// Device Active U2 Entry Enable. When this bit is set, the device will
// actively send out the LGO_U2 command to request the link partner to
// enter to the U2 state. The value is effective no matter U2_FUN_EN sets
// to 1 or not. This bit is cleared by hardware when the interrupt of
// U2_ENTRY_INT is set. This bit will be reset to 0 by the hot reset or
// warm reset in the SS mode.
#define FTUSB_SS_CR1_U2_ENTRY_EN_BIT   1
#define FTUSB_SS_CR1_U2_ENTRY_EN_LEN   1
#define FTUSB_SS_CR1_U2_ENTRY_EN_MASK  0x00000002
// Field       : U1_EXIT_EN
// Access      : RW
// Device Active U1 Exit Enable. When this bit is set, the device will
// actively assert U1 Exit LFPS. This bit is cleared by hardware when the
// interrupt of U1_EXIT_INT or U1_EXIT_FAIL_INT is set. This bit is also
// reset to 0 by the hot reset or warm reset in the SS mode.
#define FTUSB_SS_CR1_U1_EXIT_EN_BIT    2
#define FTUSB_SS_CR1_U1_EXIT_EN_LEN    1
#define FTUSB_SS_CR1_U1_EXIT_EN_MASK   0x00000004
// Field       : U2_EXIT_EN
// Access      : RW
// Device Active U2 Exit Enable. When this bit is set, the device will
// actively assert U2 Exit LFPS. This bit is cleared by hardware when the
// interrupt of U2_EXIT_INT or U2_EXIT_FAIL_INT is set. This bit is also
// reset to 0 by the hot reset or warm reset in the SS mode.
#define FTUSB_SS_CR1_U2_EXIT_EN_BIT    3
#define FTUSB_SS_CR1_U2_EXIT_EN_LEN    1
#define FTUSB_SS_CR1_U2_EXIT_EN_MASK   0x00000008
// Field       : U3_WAKEUP_EN
// Access      : RW
// Device actively U3 Wake-up Enable. When this bit is set, the device
// will actively assert the U3 wakeup LFPS. This bit is cleared by
// hardware when the interrupt of U3_EXIT_INT or U3_EXIT_FAIL_INT is set.
// This bit is also reset to 0 by the hot reset or warm reset in the SS
// mode.
#define FTUSB_SS_CR1_U3_WAKEUP_EN_BIT  4
#define FTUSB_SS_CR1_U3_WAKEUP_EN_LEN  1
#define FTUSB_SS_CR1_U3_WAKEUP_EN_MASK 0x00000010
// Field       : FORCE_RECOVERY
// Access      : RW
// Force Entry Recovery State. When this bit is set, FOTG330 will
// immediately force LTSSM from U0 to Recovery.
#define FTUSB_SS_CR1_FORCE_RECOVERY_BIT 5
#define FTUSB_SS_CR1_FORCE_RECOVERY_LEN 1
#define FTUSB_SS_CR1_FORCE_RECOVERY_MASK 0x00000020
// Field       : DIS_SCRMB
// Access      : RW
// Scramble Disable. When this bit is set, FOTG330 will disable the
// descramble and scramble functions.
#define FTUSB_SS_CR1_DIS_SCRMB_BIT     6
#define FTUSB_SS_CR1_DIS_SCRMB_LEN     1
#define FTUSB_SS_CR1_DIS_SCRMB_MASK    0x00000040
// Field       : GO_U3_DONE
// Access      : RW
// Go U3 Done. This bit is used by SW to inform FOTG330 that the
// application has fully entered the power-saving mode and does not
// access BFM before wake-up. FOTG330 will gate the clock of BFM to save
// the power assumption. After FOTG330 fully enters the U3 state, this
// bit will be cleared automatically. This bit is reset to ?0? by the hot
// reset or warm reset in the SS mode.
#define FTUSB_SS_CR1_GO_U3_DONE_BIT    8
#define FTUSB_SS_CR1_GO_U3_DONE_LEN    1
#define FTUSB_SS_CR1_GO_U3_DONE_MASK   0x00000100
// Field       : TXDEEMPH_LEVEL
// Access      : RW
// Txdeemph Level. This field indicates the level of Txdeemph. 0b00:
// -6.0-dB de-emphasis. 0b01: -3.5-dB de-emphasis. 0b10: No de-emphasis.
// 0b11: Reserved.
#define FTUSB_SS_CR1_TXDEEMPH_LEVEL_BIT 9
#define FTUSB_SS_CR1_TXDEEMPH_LEVEL_LEN 2
#define FTUSB_SS_CR1_TXDEEMPH_LEVEL_MASK 0x00000600
// ----------------------------------------------------------------------
// Register    : SS Control Register 2
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_SS_CR2_ADDR              0x10302310
// Field       : U2_TIMEOUT
// Access      : RW
// Timer Initial U2 Entry. The timer is active once SW programs the
// value, except 0x00 or 0xFF. The unit of this timer is 256 us. The
// device will also reject LGO_U2 when this field is set to 0x00. Please
// note that FOTG330 does not send LGO_U2 with the value of this field to
// be 0x00 or 0xFF.
#define FTUSB_SS_CR2_U2_TIMEOUT_BIT    0
#define FTUSB_SS_CR2_U2_TIMEOUT_LEN    8
#define FTUSB_SS_CR2_U2_TIMEOUT_MASK   0x000000ff
// Field       : U1_TIMEOUT
// Access      : RW
// Timer Initial U1 Entry. The timer will be active once SW programs the
// value, except 0x00 or 0xFF. The unit of this timer is 1 us. FOTG330
// will reject LGO_U1 when this field is set to 0x00. Please note that
// FOTG330 will not send LGO_U1 with the value of this field to be 0x00
// or 0uFF.
#define FTUSB_SS_CR2_U1_TIMEOUT_BIT    8
#define FTUSB_SS_CR2_U1_TIMEOUT_LEN    8
#define FTUSB_SS_CR2_U1_TIMEOUT_MASK   0x0000ff00
// Field       : U2_INACT_TIMEOUT
// Access      : RO
// U2 Inactivity Timeout. FOTG330 will update this bit when receiving a
// U2 Inactivity Timeout LMP.
#define FTUSB_SS_CR2_U2_INACT_TIMEOUT_BIT 16
#define FTUSB_SS_CR2_U2_INACT_TIMEOUT_LEN 8
#define FTUSB_SS_CR2_U2_INACT_TIMEOUT_MASK 0x00ff0000
// Field       : FORCE_LINKPM_ACCEPT
// Access      : RW
// Force LinkPM Accept. FOTG330 will update this bit when receiving a Set
// Link Function LMP.
#define FTUSB_SS_CR2_FORCE_LINKPM_ACCEPT_BIT 24
#define FTUSB_SS_CR2_FORCE_LINKPM_ACCEPT_LEN 1
#define FTUSB_SS_CR2_FORCE_LINKPM_ACCEPT_MASK 0x01000000
// Field       : SS_TX_SWING
// Access      : RW
// Tx Swing Control. This bit directly controls the output pin,
// mac_phy_tx_swing.
#define FTUSB_SS_CR2_SS_TX_SWING_BIT   25
#define FTUSB_SS_CR2_SS_TX_SWING_LEN   1
#define FTUSB_SS_CR2_SS_TX_SWING_MASK  0x02000000
// ----------------------------------------------------------------------
// Register    : SS Device Notification Control Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_SS_DEV_NOTF_ADDR         0x10302314
// Field       : NOTF_TYPE
// Access      : RW
// Notification Type of Packet. Setting the field with the non-zero value
// will trigger FOTG330 to send the DEV_NOTIFICATION (DEV_NOTF)
// transaction packet. This field will be cleared automatically when the
// DEV_NOTF packet is sent out. Users must set NOTF_CONTEXT0 and
// NOTF_CONTEXT1 before setting this field. 0b0000: DEV_NOTF disable.
// 0b0001: FUNCTION_WAKE. 0b0010: LATENCY_TOLERANCE. 0b0011:
// BUS_INTERVAL_ADJUSTMENT_MESSAGE. 0b0100 ~ 4?b1111: Reserved.
#define FTUSB_SS_DEV_NOTF_NOTF_TYPE_BIT 0
#define FTUSB_SS_DEV_NOTF_NOTF_TYPE_LEN 4
#define FTUSB_SS_DEV_NOTF_NOTF_TYPE_MASK 0x0000000f
// Field       : NOTF_CONTEXT0
// Access      : RW
// This field indicates the context of NOTF_CONTEXT0 in the
// DEV_NOTIFICATION packet as shown in the upper table.
#define FTUSB_SS_DEV_NOTF_NOTF_CONTEXT0_BIT 8
#define FTUSB_SS_DEV_NOTF_NOTF_CONTEXT0_LEN 24
#define FTUSB_SS_DEV_NOTF_NOTF_CONTEXT0_MASK 0xffffff00
// ----------------------------------------------------------------------
// Register    : SS_Device Notification Context Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_SS_DEV_NOTF_CONTEXT_ADDR 0x10302318
// Field       : CONTEXT
// Access      : RW
// This field indicates the context of NOTF_CONTEXT in the
// DEV_NOTIFICATION package.
#define FTUSB_SS_DEV_NOTF_CONTEXT_CONTEXT_BIT 0
#define FTUSB_SS_DEV_NOTF_CONTEXT_CONTEXT_LEN 32
#define FTUSB_SS_DEV_NOTF_CONTEXT_CONTEXT_MASK 0xffffffff
// ----------------------------------------------------------------------
// Register    : BFM Arbiter Priority Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_BFM_ARB_ADDR             0x1030231c
// Field       : ARB_S0
// Access      : RW
// This bit ndicates the priority of Slave0. The priority of value 1 is
// higher than the priority of value 0. The same value uses the same
// round-robin sequence.
#define FTUSB_BFM_ARB_ARB_S0_BIT       0
#define FTUSB_BFM_ARB_ARB_S0_LEN       1
#define FTUSB_BFM_ARB_ARB_S0_MASK      0x00000001
// Field       : ARB_M0
// Access      : RW
// This bit indicates the priority of Master0. The priority of value 1 is
// higher than the priority of value 0. The same value uses the same
// round-robin sequence.
#define FTUSB_BFM_ARB_ARB_M0_BIT       2
#define FTUSB_BFM_ARB_ARB_M0_LEN       1
#define FTUSB_BFM_ARB_ARB_M0_MASK      0x00000004
// ----------------------------------------------------------------------
// Register    : Vendor Specific Control Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_VSIO_CR_ADDR             0x10302320
// Field       : VCTL
// Access      : RW
// Vendor-specific Test Mode Control. The programmed value is delivered
// to PHY via output, u_vctl.
#define FTUSB_VSIO_CR_VCTL_BIT         0
#define FTUSB_VSIO_CR_VCTL_LEN         6
#define FTUSB_VSIO_CR_VCTL_MASK        0x0000003f
// Field       : VCTLOAD_N
// Access      : RW
// Vendor-specific Test Mode Control Load. This bit controls the active-
// low u_vctload_n output to PHY. 1 in this bit sets the u_vctload_n
// output to 1. When this bit is cleared, u_vctload_n outputs a 0.
#define FTUSB_VSIO_CR_VCTLOAD_N_BIT    8
#define FTUSB_VSIO_CR_VCTLOAD_N_LEN    1
#define FTUSB_VSIO_CR_VCTLOAD_N_MASK   0x00000100
// ----------------------------------------------------------------------
// Register    : SOF Mask Timer Register
// This register is part of the Device Special Purpose Registers set. If
// the timing of the SOF packet sent by the host exceeds the boundary of
// the micro frame, FOTG330 will automatically generate the
// FOTG330_itp_sof output signal and mask the SOF packet sent by the host
// within the time of SOFTM.
#define FTUSB_SOF_MTR_ADDR             0x10302324
// Field       : SOFTM
// Access      : RW
// SOF Mask Timer. Time from the last SOF in numbers of the 30-MHz clock
// cycles.
#define FTUSB_SOF_MTR_SOFTM_BIT        0
#define FTUSB_SOF_MTR_SOFTM_LEN        16
#define FTUSB_SOF_MTR_SOFTM_MASK       0x0000ffff
// ----------------------------------------------------------------------
// Register    : Miscellaneous Control Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_MISC_CR_ADDR             0x10302328
// Field       : VBUS_DEBOUNCE_TIME
// Access      : RW
// VBUS debounce time. The time is for VBUS debounce, and the timer unit
// is 409.6 us for 10-MHz lp_clk. If VBUS_DEBOUNCE_TIME = 10'h3FF, it
// will always gating vbus to evaluate the un-plug behavior.
#define FTUSB_MISC_CR_VBUS_DEBOUNCE_TIME_BIT 0
#define FTUSB_MISC_CR_VBUS_DEBOUNCE_TIME_LEN 10
#define FTUSB_MISC_CR_VBUS_DEBOUNCE_TIME_MASK 0x000003ff
// ----------------------------------------------------------------------
// Register    : LTM Control Register
// This register is part of the Device Special Purpose Registers set.
#define FTUSB_LTM_CR_ADDR              0x1030232c
// Field       : LTM_EN
// Access      : RW
// LTM Function Enable.
#define FTUSB_LTM_CR_LTM_EN_BIT        0
#define FTUSB_LTM_CR_LTM_EN_LEN        1
#define FTUSB_LTM_CR_LTM_EN_MASK       0x00000001
// Field       : PP_EN
// Access      : RW
// PP Enable.
#define FTUSB_LTM_CR_PP_EN_BIT         1
#define FTUSB_LTM_CR_PP_EN_LEN         1
#define FTUSB_LTM_CR_PP_EN_MASK        0x00000002
// Field       : NRDY_TIMEOUT
// Access      : RW
// NRDY Timeout Value in increments of 16 us.
#define FTUSB_LTM_CR_NRDY_TIMEOUT_BIT  2
#define FTUSB_LTM_CR_NRDY_TIMEOUT_LEN  6
#define FTUSB_LTM_CR_NRDY_TIMEOUT_MASK 0x000000fc
// Field       : MIN_BELT
// Access      : RW
// Minimum BELT. Device will send LTM with MIN_BELT when the LT state is
// changed from Idle to Active. Must < 500 ms (tERDYtimeout) [9:0]
// Latency value (ns) [11:10] Latency scale 0: Reserved, 1: x1024, 2:
// x32768, 3: x1048576.
#define FTUSB_LTM_CR_MIN_BELT_BIT      8
#define FTUSB_LTM_CR_MIN_BELT_LEN      12
#define FTUSB_LTM_CR_MIN_BELT_MASK     0x000fff00
// Field       : MAX_BELT
// Access      : RW
// Maximum BELT. Device will send LTM with MAX_BELT when the LT state is
// changed from Idle to Active. [9:0] Latency value (ns) [11:10] Latency
// scale 0: Reserved, 1: x1024, 2: x32768, 3: x1048576.
#define FTUSB_LTM_CR_MAX_BELT_BIT      20
#define FTUSB_LTM_CR_MAX_BELT_LEN      12
#define FTUSB_LTM_CR_MAX_BELT_MASK     0xfff00000
// ----------------------------------------------------------------------
// Register    : Interrupt Group 0 Register
// This register is part of the Interrupt Source Registers set.
#define FTUSB_IGR0_ADDR                0x10302400
// Field       : EPN_FIFO_INT
// Access      : W1C
// FIFO of EPn is ready to be accessed. For IN EP, this bit indicates
// that FIFO is ready to write data. After asserting this bit, there will
// be at least one empty space with the maximum packet size. For OUT EP,
// this bit indicates that FIFO is ready to read data. SW should check
// EPn_FF_BYCNT so that the length can be read out.
#define FTUSB_IGR0_EPN_FIFO_INT_BIT    1
#define FTUSB_IGR0_EPN_FIFO_INT_LEN    15
#define FTUSB_IGR0_EPN_FIFO_INT_MASK   0x0000fffe
// Field       : EPN_PRD_INT
// Access      : W1C
// When this bit is set to 1, it indicates that DMA finishes EPn PRD by
// setting the I bit to 1.
#define FTUSB_IGR0_EPN_PRD_INT_BIT     17
#define FTUSB_IGR0_EPN_PRD_INT_LEN     15
#define FTUSB_IGR0_EPN_PRD_INT_MASK    0xfffe0000
// ----------------------------------------------------------------------
// Register    : Interrupt Group 1 Register
// This register is part of the Interrupt Source Registers set.
#define FTUSB_IGR1_ADDR                0x10302404
// Field       : INT_GRP2
// Access      : RO
// Some interrupts occurred in the Interrupt Group 2 Register.
#define FTUSB_IGR1_INT_GRP2_BIT        0
#define FTUSB_IGR1_INT_GRP2_LEN        1
#define FTUSB_IGR1_INT_GRP2_MASK       0x00000001
// Field       : INT_GRP3
// Access      : RO
// Some interrupts occurred in the Interrupt Group 3 Register.
#define FTUSB_IGR1_INT_GRP3_BIT        1
#define FTUSB_IGR1_INT_GRP3_LEN        1
#define FTUSB_IGR1_INT_GRP3_MASK       0x00000002
// Field       : INT_GRP4
// Access      : RO
// Some interrupts occurred in the Interrupt Group 4 Register.
#define FTUSB_IGR1_INT_GRP4_BIT        2
#define FTUSB_IGR1_INT_GRP4_LEN        1
#define FTUSB_IGR1_INT_GRP4_MASK       0x00000004
// Field       : CX_SETUP_INT
// Access      : RO
// This bit indicates that FOTG330 successfully receives the SETUP packet
// and SW can read eight-byte command from CXF. This bit will remain
// asserted until SW starts to read data from the control transfer FIFO
// (CXF) of FOTG330.
#define FTUSB_IGR1_CX_SETUP_INT_BIT    3
#define FTUSB_IGR1_CX_SETUP_INT_LEN    1
#define FTUSB_IGR1_CX_SETUP_INT_MASK   0x00000008
// Field       : CX_IN_INT
// Access      : RO
// This bit indicates that SW should write data for the control-read
// transfer to the control transfer FIFO. For a control-read with length
// less than, or equal to the maximum packet size of EP0, this bit will
// never be asserted. SW will decode the 8-byte data sent in the SETUP
// stage of the control transfer and directly write the first data
// payload into the control transfer FIFO This bit will be asserted only
// when the length of the control-read transfer is longer than 64
// bytes/512 bytes basedon HS/SS and USB host has successfully received
// the data of the previous packet. For example: For a 65-byte control-
// read transfer for HS, SW should automatically write the first 64 bytes
// after decoding eight bytes of the SETUP data. SW will be interrupted
// to write the 65th byte when the USB host ACKs to the first 64 bytes.
// For a 513-byte control-read transfer for SS, SW should automatically
// write the first 512-byte and will be interrupted to write the 513th
// byte when the USB host ACKs to the first 512 bytes. This bit will
// remain asserted until SW starts to write data into the control
// transfer FIFO (CXF) of FOTG330. For the stall condition, this bit will
// be cleared after SW sets the CX_STL bit of the CX_Config_Status
// register.
#define FTUSB_IGR1_CX_IN_INT_BIT       4
#define FTUSB_IGR1_CX_IN_INT_LEN       1
#define FTUSB_IGR1_CX_IN_INT_MASK      0x00000010
// Field       : CX_OUT_INT
// Access      : RO
// This bit indicates that the control transfer contains valid data for
// the control-write transfers. This bit will remain asserted until SW
// starts to read the data from the control transfer FIFO (CXF) of
// FOTG330. For the stall condition, this bit will be cleared after SW
// sets the CX_STL bit of the CX_Config_Status register.
#define FTUSB_IGR1_CX_OUT_INT_BIT      5
#define FTUSB_IGR1_CX_OUT_INT_LEN      1
#define FTUSB_IGR1_CX_OUT_INT_MASK     0x00000020
// Field       : CX_CMDEND_INT
// Access      : RO
// This bit indicates that the control transfer has entered the status
// stage. This bit will remain asserted until SW sets the CX_DONE bit or
// CX_STL bit of the CX CX_Config_Status register.
#define FTUSB_IGR1_CX_CMDEND_INT_BIT   6
#define FTUSB_IGR1_CX_CMDEND_INT_LEN   1
#define FTUSB_IGR1_CX_CMDEND_INT_MASK  0x00000040
// Field       : CX_CMDFAIL_INT
// Access      : RO
// This bit indicates that the control transfer has terminated
// abnormally. This bit will be asserted when FOTG330 receives an extra
// IN/OUT token, comparing the wLength in packet and the real length of
// packet, at the control data stage of a transfer. Once this bit is
// asserted, it will be kept at 1 before the SW sets the CX_STL bit of
// the CX_Config_Status register or receives new SETUP packet.
// CX_COMFAIL_INT and CX_FIFO will be both cleared automatically by HW
// after SW sets CX_STL.
#define FTUSB_IGR1_CX_CMDFAIL_INT_BIT  7
#define FTUSB_IGR1_CX_CMDFAIL_INT_LEN  1
#define FTUSB_IGR1_CX_CMDFAIL_INT_MASK 0x00000080
// Field       : CX_CMDABT_INT
// Access      : W1C
// This bit indicates that a command abort event has occurred. For the
// interrupts recorded in this source register, the command abort
// interrupt should be recognized as the highest priority. This bit will
// be accompanied by CX_SETUP_INT. Because CX FIFO is frozen for access
// when CX_COMABT_INT remains at 1, SW should serve CX_COMABT_INT and
// clear it before CX_SETUP_INT. For the 8-byte SETUP leads to command an
// abort, SW must clear CX_COMABT_INT first.
#define FTUSB_IGR1_CX_CMDABT_INT_BIT   8
#define FTUSB_IGR1_CX_CMDABT_INT_LEN   1
#define FTUSB_IGR1_CX_CMDABT_INT_MASK  0x00000100
// Field       : DEV_MODE_CHG_INT
// Access      : W1C
// Device Mode Change interrupt. This bit indicates that the device
// operating speed has been changed. SW can check the register
// (Bits[1:0], offset = 0x00) to check the speed that the device
// operates.
#define FTUSB_IGR1_DEV_MODE_CHG_INT_BIT 9
#define FTUSB_IGR1_DEV_MODE_CHG_INT_LEN 1
#define FTUSB_IGR1_DEV_MODE_CHG_INT_MASK 0x00000200
// Field       : LINK_IN_TEST_MODE_INT
// Access      : W1C
// LTSSM in Electrical Test Mode Interrupt. LTSSM in compliance or
// loopback mode.
#define FTUSB_IGR1_LINK_IN_TEST_MODE_INT_BIT 10
#define FTUSB_IGR1_LINK_IN_TEST_MODE_INT_LEN 1
#define FTUSB_IGR1_LINK_IN_TEST_MODE_INT_MASK 0x00000400
// Field       : HS_RST_INT
// Access      : W1C
// USB Reset Interrupt. When the device detects a USB HS/FS bus reset
// from host, SE0 longer than 2.5 us, this bit will be set. When the AP
// has served the interrupt request, this bit must be cleared by SW.
#define FTUSB_IGR1_HS_RST_INT_BIT      11
#define FTUSB_IGR1_HS_RST_INT_LEN      1
#define FTUSB_IGR1_HS_RST_INT_MASK     0x00000800
// Field       : HS_LPM_INT
// Access      : W1C
// USB LPM Interrupt. When FOTG330 responses ACK for the LPM packet and
// enters the L1 state, this bit will be set. This bit must be cleared by
// SW. It is also cleared by hardware when the HS/FS USB bus resets or a
// resume occurs. When this interrupt was triggered, SW can read LPM_BESL
// to get the BESL value of XHCI receiving LPM Token
#define FTUSB_IGR1_HS_LPM_INT_BIT      12
#define FTUSB_IGR1_HS_LPM_INT_LEN      1
#define FTUSB_IGR1_HS_LPM_INT_MASK     0x00001000
