// Access      : W1C
// Suspend Interrupt. When the HS/FS bus remains in an idle state for
// over 3 ms, this bit will be set. This bit must be cleared before SW
// sets ?HS_GOSUSP?. This bit will also be cleared when the HS/FS USB bus
// resets or a resume occurs.
#define FTUSB_IGR1_HS_SUSP_INT_BIT     13
#define FTUSB_IGR1_HS_SUSP_INT_LEN     1
#define FTUSB_IGR1_HS_SUSP_INT_MASK    0x00002000
// Field       : HS_RESM_INT
// Access      : W1C
// Resume Interrupt. This bit indicates that FOTG330 has resumed from the
// suspend/LPM state. After SW has served the interrupt request, this bit
// must be cleared by SW. When a HS/FS USB bus reset occurs, it will also
// be cleared.
#define FTUSB_IGR1_HS_RESM_INT_BIT     14
#define FTUSB_IGR1_HS_RESM_INT_LEN     1
#define FTUSB_IGR1_HS_RESM_INT_MASK    0x00004000
// Field       : WARM_RST_INT
// Access      : W1C
// SS warm reset received.
#define FTUSB_IGR1_WARM_RST_INT_BIT    15
#define FTUSB_IGR1_WARM_RST_INT_LEN    1
#define FTUSB_IGR1_WARM_RST_INT_MASK   0x00008000
// Field       : HOT_RST_INT
// Access      : W1C
// SS hot reset received
#define FTUSB_IGR1_HOT_RST_INT_BIT     16
#define FTUSB_IGR1_HOT_RST_INT_LEN     1
#define FTUSB_IGR1_HOT_RST_INT_MASK    0x00010000
