#define FTUSB_DMA_APR_ADDR             0x10302510
// Field       : DMA_ARB_EPN
// Access      : RW
// This bit indicates the arbitration priority of EPn. The value of 1 has
// higher priority than the value of 0. The same value uses the same
// round-robin sequence. Obviously if all bits are set to 1 then all will
// have the same priority.
#define FTUSB_DMA_APR_DMA_ARB_EPN_BIT  1
#define FTUSB_DMA_APR_DMA_ARB_EPN_LEN  15
#define FTUSB_DMA_APR_DMA_ARB_EPN_MASK 0x0000fffe
