// Access      : RW
// Byte Transfer Count. This field indicates how many data or space for
// this PRD link. SW must prepare BTC with four-byte alignment. For the
// OUT transfer, iDMA updates the remaining byte counts to this field
// after finishing accessing this PRD. SW can check this field to know
// how many data iDMA writes to this data buffer.
#define FTUSB_EP0_PRD_TABLE0_BTC_BIT   0
#define FTUSB_EP0_PRD_TABLE0_BTC_LEN   24
#define FTUSB_EP0_PRD_TABLE0_BTC_MASK  0x00ffffff
