#define FTUSB_FEATURE1_TOTAL_EP_LEN    5
#define FTUSB_FEATURE1_TOTAL_EP_MASK   0x000001f0
// Field       : EPN_STR
// Access      : RO
// EP with Streaming Enabled.
#define FTUSB_FEATURE1_EPN_STR_BIT     17
#define FTUSB_FEATURE1_EPN_STR_LEN     15
#define FTUSB_FEATURE1_EPN_STR_MASK    0xfffe0000
// ----------------------------------------------------------------------
// Register    : Feature 2 Configuration Information Register
// This register is part of the Interrupt Source Registers set.
#define FTUSB_FEATURE2_ADDR            0x10302618
// Field       : SFIFO_DEPTH
// Access      : RO
// SYNC FIFO Depth.
#define FTUSB_FEATURE2_SFIFO_DEPTH_BIT 0
#define FTUSB_FEATURE2_SFIFO_DEPTH_LEN 4
#define FTUSB_FEATURE2_SFIFO_DEPTH_MASK 0x0000000f
// Field       : TOTAL_ENTRY
// Access      : RO
// 60K Bytes  in FIFO.
#define FTUSB_FEATURE2_TOTAL_ENTRY_BIT 4
#define FTUSB_FEATURE2_TOTAL_ENTRY_LEN 8
#define FTUSB_FEATURE2_TOTAL_ENTRY_MASK 0x00000ff0
// Field       : LP_CLK_FREQ
// Access      : RO
// Low Power Clock Frequency - 12 MHz.
#define FTUSB_FEATURE2_LP_CLK_FREQ_BIT 16
#define FTUSB_FEATURE2_LP_CLK_FREQ_LEN 4
#define FTUSB_FEATURE2_LP_CLK_FREQ_MASK 0x000f0000
// ----------------------------------------------------------------------
// Memory      : Buffer Management Debug Table
//
#define FTUSB_BMDT_START_ADDR          0x10302800
#define FTUSB_BMDT_WORDS               0x00000100
#define FTUSB_BMDT_WIDTH               0x00000020
// ----------------------------------------------------------------------
// Memory      : EP Data Port
//
#define FTUSB_EP_DATA_PORT_START_ADDR  0x10303010
#define FTUSB_EP_DATA_PORT_WORDS       0x0000003c
#define FTUSB_EP_DATA_PORT_WIDTH       0x00000020


// ======================================================================
// Module      : PCIe Core Registers
// Base Address: 0x10400000
// PCIe Core registers can be accessed through the AXI DBI slave. It
// gives the on chip CPU the ability to program the PCIe core config and
// other registers. The EchoNous PCIe Endpoint supports only one Physical
// Function and does not support any Virtual Functions.
// ----------------------------------------------------------------------
// Register    : Device ID and Vendor ID Register
// PF0 Type 0 Header Register.
#define DBI_IDR_ADDR                   0x10400000
// Field       : VENDOR_ID
// Access      : RO
// Faraday Vendor ID. RW if DBI_RO_WR_EN=1.
#define DBI_IDR_VENDOR_ID_BIT          0
#define DBI_IDR_VENDOR_ID_LEN          16
#define DBI_IDR_VENDOR_ID_MASK         0x0000ffff
// Field       : DEV_ID
// Access      : RO
// Device ID. RW if DBI_RO_WR_EN=1.
#define DBI_IDR_DEV_ID_BIT             16
#define DBI_IDR_DEV_ID_LEN             16
#define DBI_IDR_DEV_ID_MASK            0xffff0000
// ----------------------------------------------------------------------
// Register    : Status Command Register
// PF0 Type 0 Header Register.
#define DBI_SCR_ADDR                   0x10400004
// Field       : IO_EN
// Access      : RO
// Enables IO Access Response.
#define DBI_SCR_IO_EN_BIT              0
#define DBI_SCR_IO_EN_LEN              1
#define DBI_SCR_IO_EN_MASK             0x00000001
// Field       : MEM_EN
// Access      : RW
// Enables Memory Access Response.
#define DBI_SCR_MEM_EN_BIT             1
#define DBI_SCR_MEM_EN_LEN             1
#define DBI_SCR_MEM_EN_MASK            0x00000002
// Field       : BME
// Access      : RW
// Bus Master Enable.
#define DBI_SCR_BME_BIT                2
#define DBI_SCR_BME_LEN                1
#define DBI_SCR_BME_MASK               0x00000004
// Field       : SCE
// Access      : RO
// Spcecial Cycle.
#define DBI_SCR_SCE_BIT                3
#define DBI_SCR_SCE_LEN                1
#define DBI_SCR_SCE_MASK               0x00000008
// Field       : MWI_EN
// Access      : RO
// Memory Write and Invalidate.
#define DBI_SCR_MWI_EN_BIT             4
#define DBI_SCR_MWI_EN_LEN             1
#define DBI_SCR_MWI_EN_MASK            0x00000010
// Field       : VSE
// Access      : RO
// VGA Palette Snoop.
#define DBI_SCR_VSE_BIT                5
#define DBI_SCR_VSE_LEN                1
#define DBI_SCR_VSE_MASK               0x00000020
// Field       : PERR_EN
// Access      : RW
// Parity Error Enable.
#define DBI_SCR_PERR_EN_BIT            6
#define DBI_SCR_PERR_EN_LEN            1
#define DBI_SCR_PERR_EN_MASK           0x00000040
// Field       : IDSEL_STEP
// Access      : RO
// ID Select Stepping.
#define DBI_SCR_IDSEL_STEP_BIT         7
#define DBI_SCR_IDSEL_STEP_LEN         1
#define DBI_SCR_IDSEL_STEP_MASK        0x00000080
// Field       : SERR_EN
// Access      : RW
// Error Reporting Enable.
#define DBI_SCR_SERR_EN_BIT            8
#define DBI_SCR_SERR_EN_LEN            1
#define DBI_SCR_SERR_EN_MASK           0x00000100
// Field       : INT_EN
// Access      : RW
// Interrupt Generation Enable.
#define DBI_SCR_INT_EN_BIT             10
#define DBI_SCR_INT_EN_LEN             1
#define DBI_SCR_INT_EN_MASK            0x00000400
// Field       : INT_STATUS
// Access      : RO
// Interrupt Pending.
#define DBI_SCR_INT_STATUS_BIT         19
#define DBI_SCR_INT_STATUS_LEN         1
#define DBI_SCR_INT_STATUS_MASK        0x00080000
// Field       : CAP_LIST
// Access      : RO
// Extended Capability exists.
#define DBI_SCR_CAP_LIST_BIT           20
#define DBI_SCR_CAP_LIST_LEN           1
#define DBI_SCR_CAP_LIST_MASK          0x00100000
// Field       : FAST_66
// Access      : RO
// PCI 66 MHz. Legacy PCI feature. Does not apply to PCIe.
#define DBI_SCR_FAST_66_BIT            21
#define DBI_SCR_FAST_66_LEN            1
#define DBI_SCR_FAST_66_MASK           0x00200000
// Field       : FAST_B2B
// Access      : RO
// Fast Back Back Transaction Capable and Enable. Legacy PCI feature.
// Does not apply to PCIe.
#define DBI_SCR_FAST_B2B_BIT           23
#define DBI_SCR_FAST_B2B_LEN           1
#define DBI_SCR_FAST_B2B_MASK          0x00800000
// Field       : MDPE
// Access      : RW
// Master DPE. Controls poisoned completion and rqeuest error reporting.
#define DBI_SCR_MDPE_BIT               24
#define DBI_SCR_MDPE_LEN               1
#define DBI_SCR_MDPE_MASK              0x01000000
// Field       : DST
// Access      : RO
// Device Select Timing.
#define DBI_SCR_DST_BIT                25
#define DBI_SCR_DST_LEN                2
#define DBI_SCR_DST_MASK               0x06000000
// Field       : STA
// Access      : RW
// Signaled Target Abort. Completer abort had an error.
#define DBI_SCR_STA_BIT                27
#define DBI_SCR_STA_LEN                1
#define DBI_SCR_STA_MASK               0x08000000
// Field       : RTA
// Access      : RW
// Received Target Abort. Completer abort received.
#define DBI_SCR_RTA_BIT                28
#define DBI_SCR_RTA_LEN                1
#define DBI_SCR_RTA_MASK               0x10000000
// Field       : RMA
// Access      : RW
// Received Master Abort. Unuspported request completion status received.
#define DBI_SCR_RMA_BIT                29
#define DBI_SCR_RMA_LEN                1
#define DBI_SCR_RMA_MASK               0x20000000
// Field       : SSE
// Access      : RW
// Signaled System Error. Fatal or non-fatal error message sent by
// function.
#define DBI_SCR_SSE_BIT                30
#define DBI_SCR_SSE_LEN                1
#define DBI_SCR_SSE_MASK               0x40000000
// Field       : PERR
// Access      : RW
// Detected Parity Error. Poisoned TLP received by function.
#define DBI_SCR_PERR_BIT               31
#define DBI_SCR_PERR_LEN               1
#define DBI_SCR_PERR_MASK              0x80000000
