// Register    : Class Code Revision ID Register
// PF0 Type 0 Header Register.
#define DBI_CCR_ADDR                   0x10400008
// Field       : REV_ID
// Access      : RO
// Vendor chosen Revision ID. RW if DBI_RO_WR_EN=1.
#define DBI_CCR_REV_ID_BIT             0
#define DBI_CCR_REV_ID_LEN             8
#define DBI_CCR_REV_ID_MASK            0x000000ff
