// Access      : RO
// Class Code. RW if DBI_RO_WR_EN=1.
#define DBI_CCR_CLASS_BIT              24
#define DBI_CCR_CLASS_LEN              8
#define DBI_CCR_CLASS_MASK             0xff000000
