#define DBI_BCLR_CLS_LEN               8
#define DBI_BCLR_CLS_MASK              0x000000ff
// Field       : LMT
// Access      : RO
// Latency Master Timer. Legacy PCI function. Does not apply to PCIe.
#define DBI_BCLR_LMT_BIT               8
#define DBI_BCLR_LMT_LEN               8
#define DBI_BCLR_LMT_MASK              0x0000ff00
// Field       : HT
