// Access      : RO
// MSI Multi-Message Capable. RW if DI_RO_WR_EN=1.
#define DBI_MSI_MMMC_BIT               17
#define DBI_MSI_MMMC_LEN               3
#define DBI_MSI_MMMC_MASK              0x000e0000
// Field       : MMME
// Access      : RW
// MSI Multi-Message Enable.
#define DBI_MSI_MMME_BIT               20
#define DBI_MSI_MMME_LEN               3
#define DBI_MSI_MMME_MASK              0x00700000
// Field       : B64
// Access      : RO
// 64 Bit Address Capable. RW if DI_RO_WR_EN=1.
#define DBI_MSI_B64_BIT                23
#define DBI_MSI_B64_LEN                1
#define DBI_MSI_B64_MASK               0x00800000
// Field       : PVM
// Access      : RO
// Per Vector Masking Capable.
