// Access      : RO
// MSI Extended Data Capable. RW if DI_RO_WR_EN=1.
#define DBI_MSI_MEDC_BIT               25
#define DBI_MSI_MEDC_LEN               1
#define DBI_MSI_MEDC_MASK              0x02000000
// Field       : MEDE
// Access      : RW
// MSI Extended Data Enable.
#define DBI_MSI_MEDE_BIT               26
#define DBI_MSI_MEDE_LEN               1
#define DBI_MSI_MEDE_MASK              0x04000000
// ----------------------------------------------------------------------
// Register    : MSI Address Low Word
// The PCIe endpoint writes to this address when it signals an interrupt.
// HW on the PCIe Root Complex detects a write to the address and
// forwards an interrupt to the CPU system.
#define DBI_MSIA0_ADDR                 0x10400054
// Field       : RESERVE
// Access      : RO
#define DBI_MSIA0_RESERVE_BIT          0
#define DBI_MSIA0_RESERVE_LEN          2
#define DBI_MSIA0_RESERVE_MASK         0x00000003
// Field       : ADDR
// Access      : RW
#define DBI_MSIA0_ADDR_BIT             2
#define DBI_MSIA0_ADDR_LEN             30
#define DBI_MSIA0_ADDR_MASK            0xfffffffc
// ----------------------------------------------------------------------
// Register    : MSI Address Upper Word
// The PCIe endpoint writes to this address when it signals an interrupt.
// HW on the PCIe Root Complex detects a write to the address and
// forwards an interrupt to the CPU system.
#define DBI_MSIA1_ADDR                 0x10400058
// Field       : DUMMY
// Access      : RW
#define DBI_MSIA1_BIT                  0
#define DBI_MSIA1_LEN                  32
#define DBI_MSIA1_MASK                 0xffffffff
// ----------------------------------------------------------------------
// Register    : MSI Message Data
// The PCIe endpoint writes this data message to the MSI address when it
// signals an interrupt. The low bits are modified using the interrupt
// vector being signaled. The low log2(vectors) bits of the message
// should be set to 0 by the PCIe driver. The endpoint then encodes the
// vector being signaled into the field. For example, if 8 vectors are
// enabled, the low 3 bits of the MSI data message should be 0. If the
// endpoint signals interrupt vector 4 it will set the low bits to a
// encoded value of 4. The HW supports up to 32 vectors.
#define DBI_MSID_ADDR                  0x1040005c
// Field       : DUMMY
// Access      : RW
#define DBI_MSID_BIT                   0
#define DBI_MSID_LEN                   32
#define DBI_MSID_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : MSI Mask
// PCIe driver SW can enable or disable individual vectors by writing to
// this field. Writing a 1 to a bit disables the corresponding vector.
// The HW supports up to 32 vectors.
#define DBI_MSIM_ADDR                  0x10400060
// Field       : DUMMY
// Access      : RW
#define DBI_MSIM_BIT                   0
#define DBI_MSIM_LEN                   32
#define DBI_MSIM_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : MSI Pending
// The status of each vector is reflected in the bits of this register.
#define DBI_MSIP_ADDR                  0x10400064
// Field       : DUMMY
// Access      : RO
#define DBI_MSIP_BIT                   0
#define DBI_MSIP_LEN                   32
#define DBI_MSIP_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : PCIe Capabilities List Register
// PCIe Capabilities Registers
#define DBI_PCLR_ADDR                  0x10400070
// Field       : CAP_ID
// Access      : RO
// Capability ID.
#define DBI_PCLR_CAP_ID_BIT            0
#define DBI_PCLR_CAP_ID_LEN            8
#define DBI_PCLR_CAP_ID_MASK           0x000000ff
// Field       : CAP_PTR
// Access      : RO
// Next capabliity offset. RW if DBI_RO_WR_EN=1.
#define DBI_PCLR_CAP_PTR_BIT           8
#define DBI_PCLR_CAP_PTR_LEN           8
#define DBI_PCLR_CAP_PTR_MASK          0x0000ff00
// Field       : CAP_VER
// Access      : RO
// Capability version.
#define DBI_PCLR_CAP_VER_BIT           16
#define DBI_PCLR_CAP_VER_LEN           4
#define DBI_PCLR_CAP_VER_MASK          0x000f0000
// Field       : TYPE
// Access      : RO
// PCIe Device Type/Port. Indicates the specific type of this PCI Express
