// being connected to a system-integrated device or being disabled). RW
// if DBI_RO_WR_EN=1.
#define DBI_PCLR_SLOT_BIT              24
#define DBI_PCLR_SLOT_LEN              1
#define DBI_PCLR_SLOT_MASK             0x01000000
