// Access      : RO
// For MSI, the value in this field indicates the offset between the base
// Message Data and the interrupt message that is generated. Hardware is
// required to update this field so that it is correct if the number of
// MSI Messages assigned to the Function changes when software writes to
// the Multiple Message Enable field in the MSI Message Control register.
// RW if DBI_RO_WR_EN=1.
#define DBI_PCLR_INTMSGN_BIT           25
#define DBI_PCLR_INTMSGN_LEN           5
#define DBI_PCLR_INTMSGN_MASK          0x3e000000
// ----------------------------------------------------------------------
// Register    : PCIe Device Capabilities Register
// PCIe Capabilities Registers
#define DBI_PDCR_ADDR                  0x10400074
// Field       : MPS
// Access      : RO
// Max Payload Size. Bytes = 128 << mps. Maximum 4096 bytes. 128 or 256
// is best for most root complexes. RW if DBI_RO_WR_EN=1.
#define DBI_PDCR_MPS_BIT               0
#define DBI_PDCR_MPS_LEN               3
#define DBI_PDCR_MPS_MASK              0x00000007
// Field       : PFS
// Access      : RO
// Phantom functions supported. This field indicates the support for use
// of unclaimed Function Numbers to extend the number of outstanding
// transactions allowed by logically combining unclaimed Function Numbers
// RW if DBI_RO_WR_EN=1.
#define DBI_PDCR_PFS_BIT               3
#define DBI_PDCR_PFS_LEN               2
#define DBI_PDCR_PFS_MASK              0x00000018
// Field       : ETS
// Access      : RO
// Extended tag field support. 0: 5 bit Tag field. 1: 8 bit Tag field. RW
// if DBI_RO_WR_EN=1.
#define DBI_PDCR_ETS_BIT               5
#define DBI_PDCR_ETS_LEN               1
#define DBI_PDCR_ETS_MASK              0x00000020
