// Endpoint's internal buffering. RW if DBI_RO_WR_EN=1.
#define DBI_PDCR_L0S_LAT_BIT           6
#define DBI_PDCR_L0S_LAT_LEN           3
#define DBI_PDCR_L0S_LAT_MASK          0x000001c0
// Field       : L1S_LAT
// Access      : RO
// L1S acceptable latency. This field indicates the acceptable latency
