// internal buffering. RW if DBI_RO_WR_EN=1.
#define DBI_PDCR_L1S_LAT_BIT           9
#define DBI_PDCR_L1S_LAT_LEN           3
#define DBI_PDCR_L1S_LAT_MASK          0x00000e00
// Field       : RBER
// Access      : RO
// Role based error reporting implemented. RW if DBI_RO_WR_EN=1.
#define DBI_PDCR_RBER_BIT              15
#define DBI_PDCR_RBER_LEN              1
#define DBI_PDCR_RBER_MASK             0x00008000
// Field       : SPLV
// Access      : RO
// Captured slot power limit value.
#define DBI_PDCR_SPLV_BIT              18
#define DBI_PDCR_SPLV_LEN              8
#define DBI_PDCR_SPLV_MASK             0x03fc0000
// Field       : SPLS
// Access      : RO
// Captured slot power limit scale.
#define DBI_PDCR_SPLS_BIT              26
#define DBI_PDCR_SPLS_LEN              2
#define DBI_PDCR_SPLS_MASK             0x0c000000
// Field       : FLR
// Access      : RO
// Function level reset supported. RW if DBI_RO_WR_EN=1.
#define DBI_PDCR_FLR_BIT               28
#define DBI_PDCR_FLR_LEN               1
#define DBI_PDCR_FLR_MASK              0x10000000
// ----------------------------------------------------------------------
// Register    : Device Control and Status Register
// PCIe Capabilities Registers
#define DBI_DCSR_ADDR                  0x10400078
// Field       : CER_EN
// Access      : RW
// Correctable error reporting enable.
#define DBI_DCSR_CER_EN_BIT            0
#define DBI_DCSR_CER_EN_LEN            1
#define DBI_DCSR_CER_EN_MASK           0x00000001
