#define DBI_DCSR_MPS_BIT               5
#define DBI_DCSR_MPS_LEN               3
#define DBI_DCSR_MPS_MASK              0x000000e0
// Field       : ET_EN
// Access      : RW
// Extended tag enable.
#define DBI_DCSR_ET_EN_BIT             8
#define DBI_DCSR_ET_EN_LEN             1
#define DBI_DCSR_ET_EN_MASK            0x00000100
// Field       : PHF_EN
// Access      : RW
// Phantom function enable.
#define DBI_DCSR_PHF_EN_BIT            9
#define DBI_DCSR_PHF_EN_LEN            1
#define DBI_DCSR_PHF_EN_MASK           0x00000200
// Field       : AUXP_EN
// Access      : RW
// Auxiliary Power, Power Management enable. The design does not support
