#define DBI_DCSR_CED_LEN               1
#define DBI_DCSR_CED_MASK              0x00010000
// Field       : NFED
// Access      : RW
// Non-fatal error detected.
#define DBI_DCSR_NFED_BIT              17
#define DBI_DCSR_NFED_LEN              1
#define DBI_DCSR_NFED_MASK             0x00020000
// Field       : FED
// Access      : RW
// Fatal error detected.
#define DBI_DCSR_FED_BIT               18
#define DBI_DCSR_FED_LEN               1
#define DBI_DCSR_FED_MASK              0x00040000
// Field       : URD
