// Max Link Speed. RW if DBI_RO_WR_EN=1.
#define DBI_LINK_CAP_SPD_BIT           0
#define DBI_LINK_CAP_SPD_LEN           4
#define DBI_LINK_CAP_SPD_MASK          0x0000000f
// Field       : WIDTH
