// ----------------------------------------------------------------------
// Register    : Link Control and Status Register
// PCIe Capabilities Registers
#define DBI_LCSR_ADDR                  0x10400080
// Field       : ASPM
// Access      : RW
// Active State Power Management (ASPM) Control. This field controls the
// level of ASPM enabled on the given PCI Express Link. Defined encodings
// are: 0: Disabled, 1: L0s Entry Enabled, 2: L1 Entry Enabled, 3: L0s
// and L1 Entry Enabled. Note: L0s Entry Enabled enables the Transmitter
// to enter L0s. If L0s is supported, the Receiver must be capable of
// entering L0s even when the Transmitter is disabled from entering L0s
// (00b or 10b). ASPM L1 must be enabled by software in the Upstream
// component on a Link prior to enabling ASPM L1 in the Downstream
// component on that Link. When disabling ASPM L1, software must disable
// ASPM L1 in the Downstream component on a Link prior to disabling ASPM
// L1 in the Upstream component on that Link. ASPM L1 must only be
// enabled on the Downstream component if both components on a Link
// support ASPM L1.
#define DBI_LCSR_ASPM_BIT              0
#define DBI_LCSR_ASPM_LEN              2
#define DBI_LCSR_ASPM_MASK             0x00000003
