#define DBI_LCSR_CCC_LEN               1
#define DBI_LCSR_CCC_MASK              0x00000040
// Field       : EXT_SYNC
// Access      : RW
// Extended sync.
#define DBI_LCSR_EXT_SYNC_BIT          7
#define DBI_LCSR_EXT_SYNC_LEN          1
#define DBI_LCSR_EXT_SYNC_MASK         0x00000080
