#define DBI_LCSR_LBWMI_EN_LEN          1
#define DBI_LCSR_LBWMI_EN_MASK         0x00000400
// Field       : LABWI_EN
// Access      : RW
// Link Auto BW Interrupt Enable.
#define DBI_LCSR_LABWI_EN_BIT          11
#define DBI_LCSR_LABWI_EN_LEN          1
#define DBI_LCSR_LABWI_EN_MASK         0x00000800
// Field       : DRSC
