// enables the controller to perform the RxStandby/RxStandbyStatus
// handshake. [0]: Rx EIOS and subsequent T TX-IDLE-MIN. [1]: Rate
// Change. [2]: Inactive lane for upconfigure/downconfigure. [3]:
// PowerDown=P1orP2. [4]: RxL0s.Idle. [5]: EI Infer in L0. [6]: Execute
// RxStandby/RxStandbyStatus Handshake.
#define DBI_PICO_RXSTANDBY_CONTROL_BIT 0
#define DBI_PICO_RXSTANDBY_CONTROL_LEN 7
#define DBI_PICO_RXSTANDBY_CONTROL_MASK 0x0000007f
