#define DBI_TCLDEO_ADDR                0x104008c8
// Field       : DELETE_EN
// Access      : RW
// This is a one-shot bit. A '1' write to this bit triggers the deletion
// of the target completion LUT entry that is specified in the LOOK_UP_ID
// field. This is a self-clearing register field. Reading from this
// register field always returns a '0'.
#define DBI_TCLDEO_DELETE_EN_BIT       31
#define DBI_TCLDEO_DELETE_EN_LEN       1
#define DBI_TCLDEO_DELETE_EN_MASK      0x80000000
