// on the wire and used to avoid AXI RAR and WAW hazards at the remote
// link partner. For more details, see the "Optional Serialization of AXI
// Slave Non-posted Requests" section in the AXI chapter of the Databook.
#define DBI_AOCO_AX_SNP_EN_BIT         1
#define DBI_AOCO_AX_SNP_EN_LEN         1
#define DBI_AOCO_AX_SNP_EN_MASK        0x00000002
