#define DBI_IRC2OII31_REGION_EN_MASK   0x80000000
// Field       : MATCH_MODE
// Access      : RW
// Match Mode. Determines Inbound matching mode for TLPs. The mode
// depends on the type of TLP that is received as follows:
#define DBI_IRC2OII31_MATCH_MODE_BIT   30
#define DBI_IRC2OII31_MATCH_MODE_LEN   1
#define DBI_IRC2OII31_MATCH_MODE_MASK  0x40000000
// Field       : INVERT_MODE
// Access      : RW
// Invert Mode. When set the address matching region is inverted.
// Therefore, an address match occurs when the untranslated address is in
// the region outside the defined range (Base Address to Limit Address).
#define DBI_IRC2OII31_INVERT_MODE_BIT  29
#define DBI_IRC2OII31_INVERT_MODE_LEN  1
#define DBI_IRC2OII31_INVERT_MODE_MASK 0x20000000
// Field       : CFG_SHIFT_MODE
// Access      : RW
// CFG Shift Mode. This is useful for CFG transactions where the PCIe
// configuration mechanism maps bits [27:12] of the address to the
// bus/device and function number. This allows a CFG configuration space
// to be located in any 256MB window of your application memory space
// using a 28-bit effective address. Shifts bits [31:16] of the
// untranslated address to form bits [27:12] of the translated address.
#define DBI_IRC2OII31_CFG_SHIFT_MODE_BIT 28
#define DBI_IRC2OII31_CFG_SHIFT_MODE_LEN 1
#define DBI_IRC2OII31_CFG_SHIFT_MODE_MASK 0x10000000
// Field       : FUZZY_TYPE_MATCH_CODE
// Access      : RW
// Fuzzy Type Match Mode. When enabled, the iATU relaxes the matching of
// the TLP TYPE field against the expected TYPE field so that
#define DBI_IRC2OII31_FUZZY_TYPE_MATCH_CODE_BIT 27
#define DBI_IRC2OII31_FUZZY_TYPE_MATCH_CODE_LEN 1
#define DBI_IRC2OII31_FUZZY_TYPE_MATCH_CODE_MASK 0x08000000
// Field       : RESPONSE_CODE
// Access      : RW
// Response Code. Defines the type of response to give for accesses
// matching this region. This overrides the normal RADM filter response.
// Note that this feature is not available for any region where Single
// Address Location Translate is enabled.
#define DBI_IRC2OII31_RESPONSE_CODE_BIT 24
#define DBI_IRC2OII31_RESPONSE_CODE_LEN 2
#define DBI_IRC2OII31_RESPONSE_CODE_MASK 0x03000000
// Field       : SINGLE_ADDR_LOC_TRANS_EN
// Access      : RW
// Single Address Location Translate Enable.
#define DBI_IRC2OII31_SINGLE_ADDR_LOC_TRANS_EN_BIT 23
#define DBI_IRC2OII31_SINGLE_ADDR_LOC_TRANS_EN_LEN 1
#define DBI_IRC2OII31_SINGLE_ADDR_LOC_TRANS_EN_MASK 0x00800000
// Field       : MSG_CODE_MATCH_EN
// Access      : RW
// Message Code Match Enable (Msg TLPS). Ensures that a successful
// message Code TLP field comparison match (see Message Code field of the
// "iATU Control 2 Register") occurs (in MSG transactions) for address
// translation to proceed.
#define DBI_IRC2OII31_MSG_CODE_MATCH_EN_BIT 21
#define DBI_IRC2OII31_MSG_CODE_MATCH_EN_LEN 1
#define DBI_IRC2OII31_MSG_CODE_MATCH_EN_MASK 0x00200000
// Field       : FUNC_NUM_MATCH_EN
// Access      : RW
// Function Number Match Enable. Ensures that a successful Function
// Number TLP field comparison match (see Function Number field of the
// "iATU Control 1 Register") occurs (in MEM-I/O and CFG0/CFG1
// transactions) for address translation to proceed.
#define DBI_IRC2OII31_FUNC_NUM_MATCH_EN_BIT 19
#define DBI_IRC2OII31_FUNC_NUM_MATCH_EN_LEN 1
#define DBI_IRC2OII31_FUNC_NUM_MATCH_EN_MASK 0x00080000
// Field       : ATTR_MATCH_EN
// Access      : RW
// ATTR Match Enable. Ensures that a successful ATTR TLP field comparison
// match (see ATTR field of the "iATU Control 1 Register") occurs for
// address translation to proceed.
#define DBI_IRC2OII31_ATTR_MATCH_EN_BIT 16
#define DBI_IRC2OII31_ATTR_MATCH_EN_LEN 1
#define DBI_IRC2OII31_ATTR_MATCH_EN_MASK 0x00010000
// Field       : TD_MATCH_EN
// Access      : RW
// TD Match Enable. Ensures that a successful TD TLP field comparison
// match (see TD field of the "iATU Control 1 Register") occurs for
// address translation to proceed.
#define DBI_IRC2OII31_TD_MATCH_EN_BIT  15
#define DBI_IRC2OII31_TD_MATCH_EN_LEN  1
#define DBI_IRC2OII31_TD_MATCH_EN_MASK 0x00008000
// Field       : TC_MATCH_EN
// Access      : RW
// TC Match Enable. Ensures that a successful TC TLP field comparison
// match (see TC field of the "iATU Control 1 Register") occurs for
// address translation to proceed.
#define DBI_IRC2OII31_TC_MATCH_EN_BIT  14
#define DBI_IRC2OII31_TC_MATCH_EN_LEN  1
#define DBI_IRC2OII31_TC_MATCH_EN_MASK 0x00004000
