#define DBI_IRC2OII31_MSG_TYPE_MATCH_MODE_LEN 1
#define DBI_IRC2OII31_MSG_TYPE_MATCH_MODE_MASK 0x00002000
// Field       : BAR_NUM
// Access      : RW
// BAR Number. When the BAR number of an inbound MEM or IO TLP " that is
// matched by the normal internal BAR address matching mechanism " is the
// same as this field, address translation proceeds (when all other
// enabled field-matches are successful). This check is only performed if
// the "Match Mode" bit of the "iATU Control 2 Register" is set.
