#define SYS_INT0_UART_RX_BIT           0
#define SYS_INT0_UART_RX_LEN           1
#define SYS_INT0_UART_RX_MASK          0x00000001
// Field       : UART_TX
// Access      : W1C
// Set when data has been transmitted on the UART.
#define SYS_INT0_UART_TX_BIT           1
#define SYS_INT0_UART_TX_LEN           1
#define SYS_INT0_UART_TX_MASK          0x00000002
