// Field       : DT4
// Access      : RW
#define SYS_MSI1_DT4_BIT               0
#define SYS_MSI1_DT4_LEN               5
#define SYS_MSI1_DT4_MASK              0x0000001f
// Field       : DT5
// Access      : RW
#define SYS_MSI1_DT5_BIT               8
#define SYS_MSI1_DT5_LEN               5
#define SYS_MSI1_DT5_MASK              0x00001f00
// Field       : DT6
// Access      : RW
#define SYS_MSI1_DT6_BIT               16
#define SYS_MSI1_DT6_LEN               5
#define SYS_MSI1_DT6_MASK              0x001f0000
// Field       : DT7
// Access      : RW
#define SYS_MSI1_DT7_BIT               24
#define SYS_MSI1_DT7_LEN               5
#define SYS_MSI1_DT7_MASK              0x1f000000
// ----------------------------------------------------------------------
// Register    : MSI Vector Register Other
// All other interrupts use the MSI vector in this register. SW must
// ensure that the vector is within the range allocatec to the PCIe
// endpoint device.
#define SYS_MSI2_ADDR                  0x10a00058
// Field       : OTHER
// Access      : RW
#define SYS_MSI2_OTHER_BIT             0
#define SYS_MSI2_OTHER_LEN             5
#define SYS_MSI2_OTHER_MASK            0x0000001f
// ----------------------------------------------------------------------
// Register    : GPIO Write Register
// The GPIO Write Register values will be written to the GPIO pins when
// the direction of each corresponding bit is set to out. NOTE: Bit 0 is
// no longer usable. The pin was taken for the tx_clk_en pin.
#define SYS_GPIOW_ADDR                 0x10a00080
// Field       : GPIO
// Access      : RW
#define SYS_GPIOW_GPIO_BIT             0
#define SYS_GPIOW_GPIO_LEN             16
#define SYS_GPIOW_GPIO_MASK            0x0000ffff
// ----------------------------------------------------------------------
// Register    : GPIO Read Register
// This is the raw value on each GPIO pin.
#define SYS_GPIOR_ADDR                 0x10a00084
// Field       : GPIO
// Access      : RO
#define SYS_GPIOR_GPIO_BIT             0
#define SYS_GPIOR_GPIO_LEN             16
#define SYS_GPIOR_GPIO_MASK            0x0000ffff
// ----------------------------------------------------------------------
// Register    : GPIO Direction Register
// When a bit of this register is set to zero the value of the
// corresponding bit in the GPIO Write Register will be driven onto the
// corresponding GPIO pin. The default is all GPIO pins in the IN
// direction.
#define SYS_GPIOD_ADDR                 0x10a00088
// Field       : GPIO
// Access      : RW
#define SYS_GPIOD_GPIO_BIT             0
#define SYS_GPIOD_GPIO_LEN             16
#define SYS_GPIOD_GPIO_MASK            0x0000ffff
// ----------------------------------------------------------------------
// Register    : GPIO Interrupt Polarity Register
// When a bit is set the polarity of the corresponding bit is active lo
// for generation of interrupts.
#define SYS_GPIOP_ADDR                 0x10a0008c
// Field       : GPIO
// Access      : RW
#define SYS_GPIOP_GPIO_BIT             0
#define SYS_GPIOP_GPIO_LEN             16
#define SYS_GPIOP_GPIO_MASK            0x0000ffff
// ----------------------------------------------------------------------
// Register    : GPIO Alternate Function Register
// When a bit of this register is set to one the correspond GPIO pin is
// performing a special function as outlined below.
#define SYS_GPIOF_ADDR                 0x10a00090
// Field       : GPIO
// Access      : RW
#define SYS_GPIOF_GPIO_BIT             0
#define SYS_GPIOF_GPIO_LEN             10
#define SYS_GPIOF_GPIO_MASK            0x000003ff
// Field       : BF_PS
// Access      : RW
#define SYS_GPIOF_BF_PS_BIT            10
#define SYS_GPIOF_BF_PS_LEN            4
#define SYS_GPIOF_BF_PS_MASK           0x00003c00
// Field       : BFLAG0
// Access      : RW
#define SYS_GPIOF_BFLAG0_BIT           14
#define SYS_GPIOF_BFLAG0_LEN           1
#define SYS_GPIOF_BFLAG0_MASK          0x00004000
// Field       : BFLAG1
// Access      : RW
#define SYS_GPIOF_BFLAG1_BIT           15
#define SYS_GPIOF_BFLAG1_LEN           1
#define SYS_GPIOF_BFLAG1_MASK          0x00008000
