// Register    : GPIO Set Register
// Bits in the corresponding CPU data write that are one will result in
// the register bit being set to one. Other bits in the register will
// remain in their current state.
#define SYS_GPIO_SET_ADDR              0x10a00094
// Field       : GPIO
// Access      : RW
#define SYS_GPIO_SET_GPIO_BIT          0
#define SYS_GPIO_SET_GPIO_LEN          16
#define SYS_GPIO_SET_GPIO_MASK         0x0000ffff
// ----------------------------------------------------------------------
// Register    : GPIO Reset Register
// Bits in the corresponding CPU data write that are one will result in
// the register bit being set to zero. Other bits in the register will
// remain in their current state.
#define SYS_GPIO_RESET_ADDR            0x10a00098
// Field       : GPIO
// Access      : RW
#define SYS_GPIO_RESET_GPIO_BIT        0
#define SYS_GPIO_RESET_GPIO_LEN        16
#define SYS_GPIO_RESET_GPIO_MASK       0x0000ffff
// ----------------------------------------------------------------------
// Register    : Test Control Register
//
#define SYS_TCTL_ADDR                  0x10a00100
// Field       : LED
// Access      : RW
// LED Selection. {0: System, 1: Beam Former}
#define SYS_TCTL_LED_BIT               0
#define SYS_TCTL_LED_LEN               1
#define SYS_TCTL_LED_MASK              0x00000001
// Field       : TP
// Access      : RW
// Test Point Selection
// Value      | Setting
// _________________________________________________________________
// 0          | Beam Former Probe Mux
// 1          | System Probe Mux
//
#define SYS_TCTL_TP_BIT                1
#define SYS_TCTL_TP_LEN                1
#define SYS_TCTL_TP_MASK               0x00000002
// Field       : PRBMX
// Access      : RW
// Probe mux selection.
// Value      | Bits 10:8 Select
// _________________________________________________________________
// 0          | PCI Probe Mux
// 1          | Interrupts and LED - {bf_intr led}
// 2          | MSI Sys Clock Domain - {1'b0, sys_msi_vec, sys_msi_gnt,
// sys_msi_req}
// 3          | MSI PCI Clock Domain - {1'b0, ven_msi_vector,
// ven_msi_grant, ven_msi_req}
// 4          | Sequencer Probe Mux
// 5          | Streaming Engine Probe Mux
// 6          | MSI Probe Mux
//
// Value      | Bits 15:13 Select the MSI Probe Mux
// _________________________________________________________________
// 0          | msi_to_send
// 1          | msi_pend
// 2          | msi_int_mask
// 3          | msi_pend_map
// 4          | msi_pending
// 5          | msi_vec_mask
// 6          | {msi_sel, msi_pend_map[8], msi_int_mask[8], msi_pend[8],
// msi_to_send[8]}
// 7          | {msi_pending[8], state, wdma_msi_data[6:2]}
//
#define SYS_TCTL_PRBMX_BIT             8
#define SYS_TCTL_PRBMX_LEN             8
#define SYS_TCTL_PRBMX_MASK            0x0000ff00
// ----------------------------------------------------------------------
