// Field       : DUMMY
// Access      : RW
#define SYS_TEST_BIT                   0
#define SYS_TEST_LEN                   32
#define SYS_TEST_MASK                  0xffffffff


// ======================================================================
// Module      : UART Controller Registers
// Base Address: 0x10a01000
// By default the UART runs at 19200 BAUD with 1 stop, no parity bits and
// no hardware flow control. The UART can act as a slave to an external
// device or as a master to an external device. By default the UART acts
// as a slave.  In this mode the UART receives instructions to initiate
// SMP bus transactions. The external entity sends a command byte, a 4
// byte address, and for a write 4 bytes of data. The UART responds with
// 4 bytes of data for a read and a status command byte.  Master mode is
// enabled by setting the cpu_mode bit in the ctl register. In this mode
// the UART can send and receive one byte at a time under CPU control.
// ----------------------------------------------------------------------
// Register    : Status Register
//
#define UART_ST_ADDR                   0x10a01000
// Field       : RX_DONE
// Access      : RO
// Set when a byte is received on the UART. An interrupt can be triggered
// if enabled. Self-clearing.
#define UART_ST_RX_DONE_BIT            0
#define UART_ST_RX_DONE_LEN            1
#define UART_ST_RX_DONE_MASK           0x00000001
// Field       : TX_DONE
// Access      : RO
// Set when a byte is transmitted on the UART. An interrupt can be
// triggered if enabled. Self-clearing.
#define UART_ST_TX_DONE_BIT            1
#define UART_ST_TX_DONE_LEN            1
#define UART_ST_TX_DONE_MASK           0x00000002
// Field       : BUSY
// Access      : RO
// Valid only when the UART is acting as a slave device to an external
// device. Set when the UART is busy transmitting or receiving. Self-
// clearing.
#define UART_ST_BUSY_BIT               2
#define UART_ST_BUSY_LEN               1
#define UART_ST_BUSY_MASK              0x00000004
// Field       : RX_BUSY
// Access      : RO
// Set when the UART transceiver is busy receiving a byte.
#define UART_ST_RX_BUSY_BIT            3
#define UART_ST_RX_BUSY_LEN            1
#define UART_ST_RX_BUSY_MASK           0x00000008
// Field       : TX_BUSY
// Access      : RO
// Set when the UART transceiver is busy transmitting a byte.
#define UART_ST_TX_BUSY_BIT            4
#define UART_ST_TX_BUSY_LEN            1
#define UART_ST_TX_BUSY_MASK           0x00000010
// Field       : SMP_ERR
// Access      : WC
// Set when a CPU write to a register that does not exist occurs.
#define UART_ST_SMP_ERR_BIT            5
#define UART_ST_SMP_ERR_LEN            1
#define UART_ST_SMP_ERR_MASK           0x00000020
// ----------------------------------------------------------------------
// Register    : Control Register
//
#define UART_CTL_ADDR                  0x10a01004
// Field       : CPU_MODE
// Access      : RW
// When set the CPU is in control of the UART. However, there is nothing
// preventing the entity on the other end of the UART link from
// transitting whenever it feels like, but it will prevent it from
// initiating any SMP bus transactions.
#define UART_CTL_CPU_MODE_BIT          0
#define UART_CTL_CPU_MODE_LEN          1
#define UART_CTL_CPU_MODE_MASK         0x00000001
// Field       : RESET
// Access      : RW
// Resets the UART control state machines. Does not reset any other
// registers.
#define UART_CTL_RESET_BIT             1
#define UART_CTL_RESET_LEN             1
#define UART_CTL_RESET_MASK            0x00000002
// ----------------------------------------------------------------------
// Register    : UART BAUD Rate Register
//
#define UART_BAUD_ADDR                 0x10a01008
// Field       : DIVISOR
// Access      : RW
// Sets the UART clock rate divisor to this formula: Divisor = int(100e6
// / BAUD / 16. The default is 19200 BAUD.
#define UART_BAUD_DIVISOR_BIT          0
#define UART_BAUD_DIVISOR_LEN          16
#define UART_BAUD_DIVISOR_MASK         0x0000ffff
// ----------------------------------------------------------------------
// Register    : Tx Register
//
#define UART_TX_ADDR                   0x10a0100c
// Field       : BYTE
// Access      : RW
// Byte to transmit.
#define UART_TX_BYTE_BIT               0
#define UART_TX_BYTE_LEN               8
#define UART_TX_BYTE_MASK              0x000000ff
// ----------------------------------------------------------------------
// Register    : Rx Register
//
#define UART_RX_ADDR                   0x10a01010
// Field       : BYTE
// Access      : RO
// Byte received.
#define UART_RX_BYTE_BIT               0
#define UART_RX_BYTE_LEN               8
#define UART_RX_BYTE_MASK              0x000000ff


