// ======================================================================
// Module      : Write DMA Engine Registers
// Base Address: 0x10a03000
//
// ----------------------------------------------------------------------
// Register    : Status Register
//
#define WDMA_ST_ADDR                   0x10a03000
// Field       : SMP_ERR
// Access      : WC
// Set when a CPU write to a register that does not exist occurs.
#define WDMA_ST_SMP_ERR_BIT            0
#define WDMA_ST_SMP_ERR_LEN            1
#define WDMA_ST_SMP_ERR_MASK           0x00000001
// Field       : PCIE_LBOUND_ERR
// Access      : WC
// Set when a DMA operation occurs outside of SW programmed boundaryies.
// The address and byte count that triggered the error are in the BERRAL,
// BERRAH and BERRB registers.
#define WDMA_ST_PCIE_LBOUND_ERR_BIT    1
#define WDMA_ST_PCIE_LBOUND_ERR_LEN    1
#define WDMA_ST_PCIE_LBOUND_ERR_MASK   0x00000002
// Field       : PCIE_UBOUND_ERR
// Access      : WC
// Set when a DMA operation occurs outside of SW programmed boundaryies.
// The address and byte count that triggered the error are in the BERRAL,
// BERRAH and BERRB registers.
#define WDMA_ST_PCIE_UBOUND_ERR_BIT    2
#define WDMA_ST_PCIE_UBOUND_ERR_LEN    1
#define WDMA_ST_PCIE_UBOUND_ERR_MASK   0x00000004
// Field       : STATE
// Access      : RO
// WDMA state.
#define WDMA_ST_STATE_BIT              4
#define WDMA_ST_STATE_LEN              4
#define WDMA_ST_STATE_MASK             0x000000f0
// ----------------------------------------------------------------------
// Register    : WDMA Control Register
//
#define WDMA_CTL_ADDR                  0x10a03004
// Field       : RESET
// Access      : RW
// Soft reset of WDMA.
#define WDMA_CTL_RESET_BIT             0
#define WDMA_CTL_RESET_LEN             1
#define WDMA_CTL_RESET_MASK            0x00000001
// ----------------------------------------------------------------------
// Register    : Lower Boundary Address Register
// WDMA Memory Region Lower Boundary. The DMA engine cannot initiate DMA
// transactions outside of the designated Memory Region. The default is
// the entire PCIe system memory address range (0x2000_0000).
#define WDMA_BNDL_ADDR                 0x10a03010
// Field       : ADDR
// Access      : RW
// Forced to double word alignment.
#define WDMA_BNDL_ADDR_BIT             3
#define WDMA_BNDL_ADDR_LEN             27
#define WDMA_BNDL_ADDR_MASK            0x3ffffff8
// ----------------------------------------------------------------------
// Register    : Higher Boundary Address Register
// WDMA Memory Region Upper Boundary.
#define WDMA_BNDH_ADDR                 0x10a03014
// Field       : ADDR
// Access      : RW
// Forced to double word alignment.
#define WDMA_BNDH_ADDR_BIT             3
#define WDMA_BNDH_ADDR_LEN             27
#define WDMA_BNDH_ADDR_MASK            0x3ffffff8
// ----------------------------------------------------------------------
// Register    : Boundary Error Address Register
// Address that was outside of WDMA Memory Region.
#define WDMA_BERRAL_ADDR               0x10a03020
// Field       : DUMMY
// Access      : RO
#define WDMA_BERRAL_BIT                0
#define WDMA_BERRAL_LEN                32
#define WDMA_BERRAL_MASK               0xffffffff
// ----------------------------------------------------------------------
// Register    : Boundary Error DWord Count Register
// Word count of AXI operation that resulted in a transaction outside of
// the designated WDMA Memory Region. Words are 8 bytes.
#define WDMA_BERRB_ADDR                0x10a03024
// Field       : DUMMY
// Access      : RO
#define WDMA_BERRB_BIT                 0
#define WDMA_BERRB_LEN                 32
#define WDMA_BERRB_MASK                0xffffffff


// ======================================================================
// Module      : Sequencer Registers
// Base Address: 0x10a04000
//
// ----------------------------------------------------------------------
// Register    : Status Register
//
#define SEQ_ST_ADDR                    0x10a04000
// Field       : BUSY
// Access      : RO
// When set indicates the sequencer is currently active.
#define SEQ_ST_BUSY_BIT                0
#define SEQ_ST_BUSY_LEN                1
#define SEQ_ST_BUSY_MASK               0x00000001
// Field       : WAITBB
// Access      : RO
// When set indicates the sequencer is currently waiting on a Beam
// Boundary.
#define SEQ_ST_WAITBB_BIT              1
#define SEQ_ST_WAITBB_LEN              1
#define SEQ_ST_WAITBB_MASK             0x00000002
// Field       : WAITFB
// Access      : RO
// When set indicates the sequencer is currently waiting on a Frame
// Boundary.
#define SEQ_ST_WAITFB_BIT              2
#define SEQ_ST_WAITFB_LEN              1
#define SEQ_ST_WAITFB_MASK             0x00000004
// Field       : WAITTB
// Access      : RO
// When set indicates the sequencer is currently waiting on a Timer
// Boundary.
#define SEQ_ST_WAITTB_BIT              3
#define SEQ_ST_WAITTB_LEN              1
#define SEQ_ST_WAITTB_MASK             0x00000008
// Field       : WAITSB
// Access      : RO
// When set indicates the sequencer is currently waiting on a Sequencer
// Boundary.
#define SEQ_ST_WAITSB_BIT              4
#define SEQ_ST_WAITSB_LEN              1
#define SEQ_ST_WAITSB_MASK             0x00000010
// Field       : SMP_ERR
// Access      : WC
// Set when a CPU write to a register that does not exist occurs.
#define SEQ_ST_SMP_ERR_BIT             5
#define SEQ_ST_SMP_ERR_LEN             1
#define SEQ_ST_SMP_ERR_MASK            0x00000020
// Field       : ERR_PRI
// Access      : WC
// Set when a PRI Sync occurs at an unexpected time. An unexpected PRI
// Sync is one that occurs when the sequencer is not waiting on a
// boundary. This will trigger an interrupt if enabled.
#define SEQ_ST_ERR_PRI_BIT             6
#define SEQ_ST_ERR_PRI_LEN             1
#define SEQ_ST_ERR_PRI_MASK            0x00000040
// Field       : ERR_LLE
// Access      : WC
// Set when an invalid LLE is received. Validity is determined by
// checking the magic number in the LLE against the Magic Check Value
// Register. This will trigger an interrupt if enabled.
#define SEQ_ST_ERR_LLE_BIT             7
#define SEQ_ST_ERR_LLE_LEN             1
#define SEQ_ST_ERR_LLE_MASK            0x00000080
// Field       : ERR_PLD
// Access      : WC
// Set when an error occurs on a Payload write. This will trigger an
// interrupt if enabled.
#define SEQ_ST_ERR_PLD_BIT             8
#define SEQ_ST_ERR_PLD_LEN             1
#define SEQ_ST_ERR_PLD_MASK            0x00000100
// Field       : FSM
// Access      : RO
// Current Sequencer FSM State.
// Value      | State
// _________________________________________________________________
// 0          | IDLE
// 1          | FAIL
// 2          | START
// 3          | WAKE0
// 4          | WAKE1
// 5          | LLE_READ
// 6          | LLE_RDAT
// 7          | LLE_CHK
// 8          | LLE_PROC
// 9          | B_WAIT
// 10         | PYLD_CHK
// 11         | PYLD
// 12         | ACTION
// 13         | JUMP
// 14         | STOP
//
#define SEQ_ST_FSM_BIT                 12
#define SEQ_ST_FSM_LEN                 4
#define SEQ_ST_FSM_MASK                0x0000f000
// Field       : FSM_ERR
// Access      : WC
// Sequencer FSM State when a err_pri or err_lle is encountered.
#define SEQ_ST_FSM_ERR_BIT             16
#define SEQ_ST_FSM_ERR_LEN             4
#define SEQ_ST_FSM_ERR_MASK            0x000f0000
// Field       : WEST
// Access      : WC
// Sequencer Write Engine State.
#define SEQ_ST_WEST_BIT                24
#define SEQ_ST_WEST_LEN                5
#define SEQ_ST_WEST_MASK               0x1f000000
// ----------------------------------------------------------------------
// Register    : Control Register
//
#define SEQ_CTL_ADDR                   0x10a04004
// Field       : RESET
// Access      : RW
// Reset the state and state machines.
#define SEQ_CTL_RESET_BIT              0
#define SEQ_CTL_RESET_LEN              1
#define SEQ_CTL_RESET_MASK             0x00000001
// Field       : NOSLEEP
// Access      : RW
// Prevent local RAM from entering sleep state. Bits 0 to 3 control
// Payload memory banks 0 to 3. Bit 4 controls the LLE RAM.
#define SEQ_CTL_NOSLEEP_BIT            8
#define SEQ_CTL_NOSLEEP_LEN            5
#define SEQ_CTL_NOSLEEP_MASK           0x00001f00
// ----------------------------------------------------------------------
// Register    : Command Register
//
#define SEQ_CMD_ADDR                   0x10a04008
// Field       : GO
// Access      : RW
// When this bit is set the sequencer will begin fetching LLE from the
// location pointed to by the Jump Address Registers. If the sequencer
// halts SW must clear and set this bit again to restart the sequencer.
#define SEQ_CMD_GO_BIT                 0
#define SEQ_CMD_GO_LEN                 1
#define SEQ_CMD_GO_MASK                0x00000001
// ----------------------------------------------------------------------
// Register    : Beam Boundary Action Register
//
#define SEQ_BB_ADDR                    0x10a0400c
// Field       : ACT
// Access      : RW
// This setting determines what action the sequencer will take when
// waiting for this boundary. This field uses the seq_action encoded
// values.
#define SEQ_BB_ACT_BIT                 0
#define SEQ_BB_ACT_LEN                 2
#define SEQ_BB_ACT_MASK                0x00000003
// ----------------------------------------------------------------------
// Register    : Frame Boundary Action Register
//
#define SEQ_FB_ADDR                    0x10a04010
// Field       : ACT
// Access      : RW
// This setting determines what action the sequencer will take when
// waiting for this boundary. This field uses the seq_action encoded
// values.
#define SEQ_FB_ACT_BIT                 0
#define SEQ_FB_ACT_LEN                 2
#define SEQ_FB_ACT_MASK                0x00000003
// ----------------------------------------------------------------------
// Register    : Timer Boundary Action Register
//
#define SEQ_TB_ADDR                    0x10a04014
// Field       : ACT
// Access      : RW
// This setting determines what action the sequencer will take when
// waiting for this boundary. This field uses the seq_action encoded
// values.
#define SEQ_TB_ACT_BIT                 0
#define SEQ_TB_ACT_LEN                 2
#define SEQ_TB_ACT_MASK                0x00000003
// ----------------------------------------------------------------------
// Register    : Sequence Boundary Action Register
//
#define SEQ_SB_ADDR                    0x10a04018
// Field       : ACT
// Access      : RW
// This setting determines what action the sequencer will take when
// waiting for this boundary. This field uses the seq_action encoded
// values.
#define SEQ_SB_ACT_BIT                 0
#define SEQ_SB_ACT_LEN                 2
#define SEQ_SB_ACT_MASK                0x00000003
// ----------------------------------------------------------------------
// Register    : Index Action Register
//
#define SEQ_INDEX_ADDR                 0x10a0401c
// Field       : ACTION_ON_INDEX
// Access      : RW
// When set the sequencer will execute the action if it encounters a LLE
// matching the index set in the Index field.
#define SEQ_INDEX_ACTION_ON_INDEX_BIT  0
#define SEQ_INDEX_ACTION_ON_INDEX_LEN  2
#define SEQ_INDEX_ACTION_ON_INDEX_MASK 0x00000003
// Field       : ACTION_INDEX
// Access      : RW
// When action_on_index is set sequencer will perform the action on the
// LLE whose index matches this field.
#define SEQ_INDEX_ACTION_INDEX_BIT     16
#define SEQ_INDEX_ACTION_INDEX_LEN     10
#define SEQ_INDEX_ACTION_INDEX_MASK    0x03ff0000
// ----------------------------------------------------------------------
// Register    : Jump Address Register
// When the Go bit in the cmd register is written the sequencer will
// begin fetching LLE from this address.
#define SEQ_JMP_ADDR                   0x10a04020
// Field       : ADR
// Access      : RW
#define SEQ_JMP_ADR_BIT                0
#define SEQ_JMP_ADR_LEN                10
#define SEQ_JMP_ADR_MASK               0x000003ff
// ----------------------------------------------------------------------
// Register    : Magic Check Value Register
//
#define SEQ_MAGIC_ADDR                 0x10a04028
// Field       : NUMBER
// Access      : RO
// This value is checked against the Magic number field of a LLE to
// determine if it is valid.
#define SEQ_MAGIC_NUMBER_BIT           0
#define SEQ_MAGIC_NUMBER_LEN           16
#define SEQ_MAGIC_NUMBER_MASK          0x0000ffff
// ----------------------------------------------------------------------
// Register    : Current LLE Word 0 Register
// Bits 31:0 of the current LLE being processed.
#define SEQ_LLE0_ADDR                  0x10a04030
// Field       : DUMMY
// Access      : RO
#define SEQ_LLE0_BIT                   0
#define SEQ_LLE0_LEN                   32
#define SEQ_LLE0_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : Current LLE Word 1 Register
// Bits 63:32 of the current LLE being processed.
#define SEQ_LLE1_ADDR                  0x10a04034
// Field       : DUMMY
// Access      : RO
#define SEQ_LLE1_BIT                   0
#define SEQ_LLE1_LEN                   32
#define SEQ_LLE1_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : Current LLE Word 2 Register
// Bits 95:64 of the current LLE being processed.
#define SEQ_LLE2_ADDR                  0x10a04038
// Field       : DUMMY
// Access      : RO
#define SEQ_LLE2_BIT                   0
#define SEQ_LLE2_LEN                   32
#define SEQ_LLE2_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : Current LLE Word 3 Register
// Bits 127:96 of the current LLE being processed.
#define SEQ_LLE3_ADDR                  0x10a0403c
// Field       : DUMMY
// Access      : RO
#define SEQ_LLE3_BIT                   0
#define SEQ_LLE3_LEN                   32
#define SEQ_LLE3_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : Current Payload Destination Register
// Payload desination address and word count of LLE being processed.
#define SEQ_PYLD_ADDR                  0x10a04040
// Field       : ADR
// Access      : RO
// Payload destination address.
#define SEQ_PYLD_ADR_BIT               0
#define SEQ_PYLD_ADR_LEN               24
#define SEQ_PYLD_ADR_MASK              0x00ffffff
// Field       : WDS
// Access      : RO
// Payload word count.
#define SEQ_PYLD_WDS_BIT               24
#define SEQ_PYLD_WDS_LEN               8
#define SEQ_PYLD_WDS_MASK              0xff000000
// ----------------------------------------------------------------------
// Register    : Debug Control Register
//
#define SEQ_DEBUG_ADDR                 0x10a04050
// Field       : TRIGGER
// Access      : RW
// If the sequencer is waiting at a boundary force the trigger condition.
// Clear and set to force again.
#define SEQ_DEBUG_TRIGGER_BIT          0
#define SEQ_DEBUG_TRIGGER_LEN          1
#define SEQ_DEBUG_TRIGGER_MASK         0x00000001
// Field       : PRBMX_SEL
// Access      : RW
// Sequencer probe mux selects.
// Value      | Setting
// _________________________________________________________________
// 0          | {sb_wait, tb_wait, fb_wait, bb_wait, state}
// 1          | {clr_status, pri_eos, pri_eof, pri_sync, state}
// 2          | {sb_jump, tb_jump, fb_jump, bb_jump, state}
// 3          | {sb_stop, tb_stop, fb_stop, bb_stop, state}
// 4          | {sb_wait, tb_wait, fb_wait, bb_wait, pri_eos, timer_done,
// pri_eof, pri_sync}
// 5          | {pyld_last, pyld_strt, pyld_done, pyld_state}
// 6          | {pyld_last, pyld_words}
// 7          | {lle_sleep, lle_sleep_fsm, lle_sleep_cpu, no_sleep}
//
#define SEQ_DEBUG_PRBMX_SEL_BIT        8
#define SEQ_DEBUG_PRBMX_SEL_LEN        3
#define SEQ_DEBUG_PRBMX_SEL_MASK       0x00000700


// ======================================================================
// Module      : Streaming Engine Registers
// Base Address: 0x10a05000
//
// ----------------------------------------------------------------------
// Register    : Status Register
//
#define SE_ST_ADDR                     0x10a05000
// Field       : SMP_ERR
// Access      : WC
// Set when a CPU write to a register that does not exist occurs.
#define SE_ST_SMP_ERR_BIT              0
#define SE_ST_SMP_ERR_LEN              1
#define SE_ST_SMP_ERR_MASK             0x00000001
// Field       : CPL_ST
