#define SE_ST_CPL_ST_BIT               1
#define SE_ST_CPL_ST_LEN               2
#define SE_ST_CPL_ST_MASK              0x00000006
// Field       : BOF
// Access      : WC
// Buffer overflow. Indicates a buffer with data from a previous line was
// overwritten with a new line.
#define SE_ST_BOF_BIT                  8
#define SE_ST_BOF_LEN                  8
#define SE_ST_BOF_MASK                 0x0000ff00
// Field       : DOF
// Access      : WC
// Data overflow. Indicates the line was longer than the maximum buffer
// size of 2048 words.
#define SE_ST_DOF_BIT                  16
#define SE_ST_DOF_LEN                  8
#define SE_ST_DOF_MASK                 0x00ff0000
// Field       : PS
// Access      : WC
// PRI Sync Error. Another PRI sync was received before the current line
// was finished being received. PRF is too high.
#define SE_ST_PS_BIT                   24
#define SE_ST_PS_LEN                   8
#define SE_ST_PS_MASK                  0xff000000
// ----------------------------------------------------------------------
// Register    : Control Register
//
#define SE_CTL_ADDR                    0x10a05004
// Field       : RESET
// Access      : RW
// Reset the streaming engine state and state machine.
#define SE_CTL_RESET_BIT               0
#define SE_CTL_RESET_LEN               1
#define SE_CTL_RESET_MASK              0x00000001
// Field       : SLAVE
// Access      : RW
// The Streaming Engine is operating as a AXI slave for USB. This is
// necessary to prevent the SE sending DMA commands to PCIe when in USB
// mode.
#define SE_CTL_SLAVE_BIT               1
#define SE_CTL_SLAVE_LEN               1
#define SE_CTL_SLAVE_MASK              0x00000002
// Field       : L1
// Access      : RW
// Enable SE to control when PCIe enters the L1 power managment state.
#define SE_CTL_L1_BIT                  2
#define SE_CTL_L1_LEN                  1
#define SE_CTL_L1_MASK                 0x00000004
// Field       : FAXP
// Access      : RW
// Force app_xfer_pending to 1.
#define SE_CTL_FAXP_BIT                3
#define SE_CTL_FAXP_LEN                1
#define SE_CTL_FAXP_MASK               0x00000008
// Field       : NOSLEEP
// Access      : RW
// Prevent memory bank N from entering the sleep state.
#define SE_CTL_NOSLEEP_BIT             4
#define SE_CTL_NOSLEEP_LEN             4
#define SE_CTL_NOSLEEP_MASK            0x000000f0
// Field       : RESET_E
// Access      : RW
// Per engine soft reset. Bit 8: BeamFormer. Bit 9: CW, Bit 10: Sensor.
#define SE_CTL_RESET_E_BIT             8
#define SE_CTL_RESET_E_LEN             3
#define SE_CTL_RESET_E_MASK            0x00000700
// Field       : PRBMX_SEL
// Access      : WO
// Streaming engine probe mux selects.
// Value      | Setting
// _________________________________________________________________
// 0          | {bif.dv, bif.start, bif.enable, bif.eof, tp_sof_bf,
// tp_state_bf}
// 1          | {cif.dv, cif.start, cif.enable, cif.eof, tp_sof_cw,
// tp_state_cw}
// 2          | {sif.dv, sif.start, sif.enable, sif.eof, tp_sof_ss,
// tp_state_ss}
// 3          | {cif.dv, cif.rdy, sif.dv, sif.rdy, 4'b0}
// 4          | {dma_d.vld, dma_d.rdy, dma_d.dt, dma_d.cb}
// 5          | {dma_d.vld, dma_d.rdy, dma_d.intr, dma_cpl.vld,
// dma_cpl.dt, dma_cpl.status}
// 6          | {dma_cpl.vld, dma_cpl.dt, dma_cpl.cb, 1'b0}
// 7          | {sys_flush_req, sys_xfer_pending, active, 3'b0}
//
#define SE_CTL_PRBMX_SEL_BIT           12
#define SE_CTL_PRBMX_SEL_LEN           3
#define SE_CTL_PRBMX_SEL_MASK          0x00007000
// Field       : FLUSH
