// ======================================================================
// Module      : I2S Registers
// Base Address: 0x10a06000
//
// ----------------------------------------------------------------------
// Register    : Streaming engine packets Configuration Register.
//
#define I2S_I2SFRAMECFG_ADDR           0x10a06000
// Field       : FRAMESIZE
// Access      : RW
// Indicates, number of samples per frame.
#define I2S_I2SFRAMECFG_FRAMESIZE_BIT  0
#define I2S_I2SFRAMECFG_FRAMESIZE_LEN  16
#define I2S_I2SFRAMECFG_FRAMESIZE_MASK 0x0000ffff
// Field       : SAMPLESIZE
// Access      : RW
// Indicates, number of words per sample. Per cycle I2S received data
// from left, right channel.. 2 words, keep this as multiple of 2. Valid
// range 0-31. 0 means 1 ... similarly 31 means 32 words.
#define I2S_I2SFRAMECFG_SAMPLESIZE_BIT 16
#define I2S_I2SFRAMECFG_SAMPLESIZE_LEN 8
#define I2S_I2SFRAMECFG_SAMPLESIZE_MASK 0x00ff0000
// ----------------------------------------------------------------------
// Register    : I2S Start Configuration Register
//
#define I2S_START_ADDR                 0x10a06004
// Field       : CWSTART
// Access      : RW
// Must be set to 1 during entire I2S active period, to kick-off I2S
// activity.
#define I2S_START_CWSTART_BIT          0
#define I2S_START_CWSTART_LEN          1
#define I2S_START_CWSTART_MASK         0x00000001
// ----------------------------------------------------------------------
// Register    : I2S clock dividers
//
#define I2S_I2SCLKDIV_ADDR             0x10a06008
// Field       : LRCLKDIV
// Access      : RW
// LRCLK Divider(N), lrclk = SCLK/(N+1); must be set in Master mode. N
// should be minimum:63
#define I2S_I2SCLKDIV_LRCLKDIV_BIT     0
#define I2S_I2SCLKDIV_LRCLKDIV_LEN     8
#define I2S_I2SCLKDIV_LRCLKDIV_MASK    0x000000ff
// Field       : MCLKDIV
// Access      : RW
// MCLK Divider(N), mclk = sysbus_clock/(N+1)
#define I2S_I2SCLKDIV_MCLKDIV_BIT      8
#define I2S_I2SCLKDIV_MCLKDIV_LEN      8
#define I2S_I2SCLKDIV_MCLKDIV_MASK     0x0000ff00
// Field       : SCLKDIV
// Access      : RW
// SCLK Divider(N), sclk = sysbus_clock/(N+1); must be set in Master mode
#define I2S_I2SCLKDIV_SCLKDIV_BIT      16
#define I2S_I2SCLKDIV_SCLKDIV_LEN      8
#define I2S_I2SCLKDIV_SCLKDIV_MASK     0x00ff0000
// ----------------------------------------------------------------------
// Register    : I2S configuration register
//
#define I2S_I2SCONFIG_ADDR             0x10a0600c
// Field       : I2SMODE
// Access      : RW
// 1: Master Mode; 0: Slave mode
#define I2S_I2SCONFIG_I2SMODE_BIT      0
#define I2S_I2SCONFIG_I2SMODE_LEN      1
#define I2S_I2SCONFIG_I2SMODE_MASK     0x00000001
// Field       : I2SENABLE
// Access      : RW
// 1: I2S/LJ is enabled; 0: Disabled
#define I2S_I2SCONFIG_I2SENABLE_BIT    1
#define I2S_I2SCONFIG_I2SENABLE_LEN    1
#define I2S_I2SCONFIG_I2SENABLE_MASK   0x00000002
// Field       : I2SLJ
// Access      : RW
// 1: I2S Mode; 0: LJ mode
#define I2S_I2SCONFIG_I2SLJ_BIT        2
#define I2S_I2SCONFIG_I2SLJ_LEN        1
#define I2S_I2SCONFIG_I2SLJ_MASK       0x00000004
// Field       : DASTLRCK
// Access      : RW
// 1: Acquire start on rising edge of LRCK; 0: Acquire start on falling
// edge of LRCK.
#define I2S_I2SCONFIG_DASTLRCK_BIT     3
#define I2S_I2SCONFIG_DASTLRCK_LEN     1
#define I2S_I2SCONFIG_DASTLRCK_MASK    0x00000008
// Field       : I2SCORERESET
// Access      : RW
// 1: Bit clock Core logic gets reset; 0: no reset; logic must be reset
// before enabling I2S/LJ
#define I2S_I2SCONFIG_I2SCORERESET_BIT 31
#define I2S_I2SCONFIG_I2SCORERESET_LEN 1
#define I2S_I2SCONFIG_I2SCORERESET_MASK 0x80000000
// ----------------------------------------------------------------------
// Register    : I2S Received Data
//
#define I2S_I2SDATARCVD_ADDR           0x10a06010
// Field       : I2SDATA
// Access      : RO
// Received channel data.
#define I2S_I2SDATARCVD_I2SDATA_BIT    0
#define I2S_I2SDATARCVD_I2SDATA_LEN    24
#define I2S_I2SDATARCVD_I2SDATA_MASK   0x00ffffff
// Field       : I2SCHANNEL
// Access      : RO
// 0-> Right Channel; 1-> Left Channel
#define I2S_I2SDATARCVD_I2SCHANNEL_BIT 24
#define I2S_I2SDATARCVD_I2SCHANNEL_LEN 1
#define I2S_I2SDATARCVD_I2SCHANNEL_MASK 0x01000000
// ----------------------------------------------------------------------
// Register    : I2S Status
//
#define I2S_I2SST_ADDR                 0x10a06014
// Field       : I2SDATARDY
// Access      : W1C
// 1-> Channel data is ready. If not cleared then it will stay high
// forever. Debug status bit...
#define I2S_I2SST_I2SDATARDY_BIT       0
#define I2S_I2SST_I2SDATARDY_LEN       1
#define I2S_I2SST_I2SDATARDY_MASK      0x00000001


// ======================================================================
// Module      : System Monitor and Sensor Registers
// Base Address: 0x10a07000
// Sensor engine to manage I2C, SPI and DA/EKG sensors.
// ----------------------------------------------------------------------
// Register    : Status Register
//
#define SENSOR_ST_ADDR                 0x10a07400
// Field       : BUSY
// Access      : RO
// 1 --> Either I2C or SPI engine are busy. Useful when running manual
// mode single channel data acquisition
#define SENSOR_ST_BUSY_BIT             0
#define SENSOR_ST_BUSY_LEN             1
#define SENSOR_ST_BUSY_MASK            0x00000001
// ----------------------------------------------------------------------
// Register    : Control Register
// Reserved: not implemented in design.
#define SENSOR_CTL_ADDR                0x10a07404
// Field       : RESET
// Access      : RW
// Reserved: Ignore CTL register: The sysmon module is not reset when the
// external system reset is asserted.  This is to allow for continous
// temperature monitoring even while the system is in reset. To reset the
// sysmon module write a one to this bit.
#define SENSOR_CTL_RESET_BIT           0
#define SENSOR_CTL_RESET_LEN           1
#define SENSOR_CTL_RESET_MASK          0x00000001
// ----------------------------------------------------------------------
// Register    : SPI Manual configuration Register
//
#define SENSOR_SPIMCFG_ADDR            0x10a07000
// Field       : SPIGO
// Access      : WO
// Start SPI transfer in Manual mode. Self cleared
#define SENSOR_SPIMCFG_SPIGO_BIT       0
#define SENSOR_SPIMCFG_SPIGO_LEN       1
#define SENSOR_SPIMCFG_SPIGO_MASK      0x00000001
// Field       : SPIDEV
// Access      : RW
// Target SPI Device in Manual mode.
#define SENSOR_SPIMCFG_SPIDEV_BIT      1
#define SENSOR_SPIMCFG_SPIDEV_LEN      2
#define SENSOR_SPIMCFG_SPIDEV_MASK     0x00000006
// Field       : SPIRESET
// Access      : RW
// 1-> Resets SPI-CORE, Clear it after to bring SPI to normal mode.
#define SENSOR_SPIMCFG_SPIRESET_BIT    3
#define SENSOR_SPIMCFG_SPIRESET_LEN    1
#define SENSOR_SPIMCFG_SPIRESET_MASK   0x00000008
// ----------------------------------------------------------------------
// Register    : I2C Manual configuration Register
//
#define SENSOR_I2CMCFG_ADDR            0x10a07004
// Field       : I2CGO
// Access      : WO
// Start I2C transfer in Manual mode. Self cleared
#define SENSOR_I2CMCFG_I2CGO_BIT       0
#define SENSOR_I2CMCFG_I2CGO_LEN       1
#define SENSOR_I2CMCFG_I2CGO_MASK      0x00000001
// Field       : I2CDEV
// Access      : RW
// Target I2C Device in Manual mode.
#define SENSOR_I2CMCFG_I2CDEV_BIT      1
#define SENSOR_I2CMCFG_I2CDEV_LEN      2
#define SENSOR_I2CMCFG_I2CDEV_MASK     0x00000006
// Field       : I2CRESET
// Access      : RW
// Reset I2C
#define SENSOR_I2CMCFG_I2CRESET_BIT    3
#define SENSOR_I2CMCFG_I2CRESET_LEN    1
#define SENSOR_I2CMCFG_I2CRESET_MASK   0x00000008
