// RDAT register in Little Endian order. That is, starting with the LSB.
#define SENSOR_I2CRDAT0_ADDR           0x10a07190
// Field       : DUMMY
// Access      : RO
#define SENSOR_I2CRDAT0_BIT            0
#define SENSOR_I2CRDAT0_LEN            32
#define SENSOR_I2CRDAT0_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Read Data Register
// Data read in an I2C read operation. Data from I2C is placed in the
// RDAT register in Little Endian order. That is, starting with the LSB.
#define SENSOR_I2CRDAT1_ADDR           0x10a07194
// Field       : DUMMY
// Access      : RO
#define SENSOR_I2CRDAT1_BIT            0
#define SENSOR_I2CRDAT1_LEN            32
#define SENSOR_I2CRDAT1_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Read Data Register
// Data read in an I2C read operation. Data from I2C is placed in the
// RDAT register in Little Endian order. That is, starting with the LSB.
#define SENSOR_I2CRDAT2_ADDR           0x10a07198
// Field       : DUMMY
// Access      : RO
#define SENSOR_I2CRDAT2_BIT            0
#define SENSOR_I2CRDAT2_LEN            32
#define SENSOR_I2CRDAT2_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Read Data Register
// Data read in an I2C read operation. Data from I2C is placed in the
// RDAT register in Little Endian order. That is, starting with the LSB.
#define SENSOR_I2CRDAT3_ADDR           0x10a0719c
// Field       : DUMMY
// Access      : RO
#define SENSOR_I2CRDAT3_BIT            0
#define SENSOR_I2CRDAT3_LEN            32
#define SENSOR_I2CRDAT3_MASK           0xffffffff
// ----------------------------------------------------------------------
// Register    : Configuration Register
// Adc0 Configuration register bits.
#define SENSOR_ADC0CFG_ADDR            0x10a07200
// Field       : XTEMP
// Access      : RW
// 1-> temperature mode; 0->voltage mode.
#define SENSOR_ADC0CFG_XTEMP_BIT       0
#define SENSOR_ADC0CFG_XTEMP_LEN       1
#define SENSOR_ADC0CFG_XTEMP_MASK      0x00000001
// Field       : XRST
// Access      : RW
// 1->resets data bits to 0; 0->normal operation.
#define SENSOR_ADC0CFG_XRST_BIT        1
#define SENSOR_ADC0CFG_XRST_LEN        1
#define SENSOR_ADC0CFG_XRST_MASK       0x00000002
// Field       : XPWDB
// Access      : RW
// 1->normal mode; 0->power-down mode.
#define SENSOR_ADC0CFG_XPWDB_BIT       2
#define SENSOR_ADC0CFG_XPWDB_LEN       1
#define SENSOR_ADC0CFG_XPWDB_MASK      0x00000004
// Field       : XIBC
// Access      : RW
// Bias current control.
#define SENSOR_ADC0CFG_XIBC_BIT        3
#define SENSOR_ADC0CFG_XIBC_LEN        1
#define SENSOR_ADC0CFG_XIBC_MASK       0x00000008
// Field       : XTCP1
// Access      : RW
// Bias current control.
#define SENSOR_ADC0CFG_XTCP1_BIT       4
#define SENSOR_ADC0CFG_XTCP1_LEN       1
#define SENSOR_ADC0CFG_XTCP1_MASK      0x00000010
// Field       : XVREFEN
// Access      : RW
// XVRT enable control.
#define SENSOR_ADC0CFG_XVREFEN_BIT     5
#define SENSOR_ADC0CFG_XVREFEN_LEN     1
#define SENSOR_ADC0CFG_XVREFEN_MASK    0x00000020
// Field       : XDSC
// Access      : RW
// 00-> Single-ended SAR 01->Differential SAR 11->Differential SAR for
// temperature mode 10-> forbidden.
#define SENSOR_ADC0CFG_XDSC_BIT        6
#define SENSOR_ADC0CFG_XDSC_LEN        2
#define SENSOR_ADC0CFG_XDSC_MASK       0x000000c0
// Field       : XSAMPSEL
// Access      : RW
// 1->Select external sampling clock(xsampclk); 0->Select internal
// sampling clock.
#define SENSOR_ADC0CFG_XSAMPSEL_BIT    8
#define SENSOR_ADC0CFG_XSAMPSEL_LEN    1
#define SENSOR_ADC0CFG_XSAMPSEL_MASK   0x00000100
// Field       : ADCAUTOGO
// Access      : RW
// 1-> Kicks off auto mode Acquisition of data from selected ADC channels
// at acqrate rate; 0 -> no acquisition in auto mode.
#define SENSOR_ADC0CFG_ADCAUTOGO_BIT   12
#define SENSOR_ADC0CFG_ADCAUTOGO_LEN   1
#define SENSOR_ADC0CFG_ADCAUTOGO_MASK  0x00001000
// Field       : ADCMANUALGO
// Access      : WO
// 0 --> 1 transition does manual ADC conversions on all enabled
// channels; auto cleared. Recent channel data is available at Adc0RdDat.
#define SENSOR_ADC0CFG_ADCMANUALGO_BIT 13
#define SENSOR_ADC0CFG_ADCMANUALGO_LEN 1
#define SENSOR_ADC0CFG_ADCMANUALGO_MASK 0x00002000
// Field       : ADCMODE
// Access      : RW
// 0 --> manual mode, trigger comes from adcmanual; 1 --> Auto mode
// trigger due to adcautogo and acqrate; ADC conversions on all enabled
// channels; recent channel data is available at Adc0RdDat.
#define SENSOR_ADC0CFG_ADCMODE_BIT     14
#define SENSOR_ADC0CFG_ADCMODE_LEN     1
#define SENSOR_ADC0CFG_ADCMODE_MASK    0x00004000
// Field       : XAINSEL
// Access      : RW
// Analog input channel select enables
#define SENSOR_ADC0CFG_XAINSEL_BIT     16
#define SENSOR_ADC0CFG_XAINSEL_LEN     8
#define SENSOR_ADC0CFG_XAINSEL_MASK    0x00ff0000
// Field       : SSFRXMCLK
// Access      : RW
// 0 --> XMCLK runs when ADC accessed. 1 --> XMCLK is free-running clock.
#define SENSOR_ADC0CFG_SSFRXMCLK_BIT   31
#define SENSOR_ADC0CFG_SSFRXMCLK_LEN   1
#define SENSOR_ADC0CFG_SSFRXMCLK_MASK  0x80000000
// ----------------------------------------------------------------------
// Register    : Configuration Register
// Adc0 clock dividers to generate mclk, sampclk clocks.
#define SENSOR_ADC0CLKDIVS_ADDR        0x10a07204
// Field       : XMCLK_DIV
// Access      : RW
// xmclk = sys_clk / (xmclk_div+1)
#define SENSOR_ADC0CLKDIVS_XMCLK_DIV_BIT 0
#define SENSOR_ADC0CLKDIVS_XMCLK_DIV_LEN 8
#define SENSOR_ADC0CLKDIVS_XMCLK_DIV_MASK 0x000000ff
// Field       : ACQRATE
// Access      : RW
// Data acquire rate = sys_clk / (acqrate+1)
#define SENSOR_ADC0CLKDIVS_ACQRATE_BIT 16
#define SENSOR_ADC0CLKDIVS_ACQRATE_LEN 16
#define SENSOR_ADC0CLKDIVS_ACQRATE_MASK 0xffff0000
// ----------------------------------------------------------------------
// Register    : Read Data Register
// Data read in an I2C read operation. Data from I2C is placed in the
// RDAT register in Little Endian order. That is, starting with the LSB.
#define SENSOR_ADC0RDDAT_ADDR          0x10a07208
// Field       : DUMMY
// Access      : RO
#define SENSOR_ADC0RDDAT_BIT           0
#define SENSOR_ADC0RDDAT_LEN           32
#define SENSOR_ADC0RDDAT_MASK          0xffffffff
// ----------------------------------------------------------------------
// Register    : ADC0 Status
// Provides current status of ADC(Busy or Idle).
#define SENSOR_ADC0ST_ADDR             0x10a0720c
// Field       : ADCBUSY
// Access      : RO
// 1-> Busy; 0-> Idle; Useful in manual mode
#define SENSOR_ADC0ST_ADCBUSY_BIT      0
#define SENSOR_ADC0ST_ADCBUSY_LEN      1
#define SENSOR_ADC0ST_ADCBUSY_MASK     0x00000001
// ----------------------------------------------------------------------
// Register    : Auto Mode SPI/I2C/ADC engines status Register
// Auto Mode SPI/I2C/ADC data acquisition engines status Register.
#define SENSOR_AUTOST_ADDR             0x10a07210
// Field       : I2CAUTOBUSY
// Access      : RO
// 1: I2C engine is busy in Auto mode, 0: I2C Engine is in Idle state.
#define SENSOR_AUTOST_I2CAUTOBUSY_BIT  0
#define SENSOR_AUTOST_I2CAUTOBUSY_LEN  1
#define SENSOR_AUTOST_I2CAUTOBUSY_MASK 0x00000001
// Field       : SPIAUTOBUSY
// Access      : RO
// 1: SPI engine is busy in Auto mode, 0: SPI Engine is in Idle state.
#define SENSOR_AUTOST_SPIAUTOBUSY_BIT  1
#define SENSOR_AUTOST_SPIAUTOBUSY_LEN  1
#define SENSOR_AUTOST_SPIAUTOBUSY_MASK 0x00000002
// Field       : ADCAUTOBUSY
// Access      : RO
// 1: ADC data acquire engine is busy in Auto mode, 0: ADC data acquire
// Engine is in Idle state.
#define SENSOR_AUTOST_ADCAUTOBUSY_BIT  2
#define SENSOR_AUTOST_ADCAUTOBUSY_LEN  1
#define SENSOR_AUTOST_ADCAUTOBUSY_MASK 0x00000004
// ----------------------------------------------------------------------
// Register    : Number of DaEkg samples per Frame Configuration Register
// Configure number of samples acquired per frame.
#define SENSOR_DAEKGFRAMESIZE_ADDR     0x10a07300
// Field       : DAEKGFRAMESIZE
// Access      : RW
// number DAEKG samples. load N-1 to acquire N samples.
#define SENSOR_DAEKGFRAMESIZE_DAEKGFRAMESIZE_BIT 0
#define SENSOR_DAEKGFRAMESIZE_DAEKGFRAMESIZE_LEN 16
#define SENSOR_DAEKGFRAMESIZE_DAEKGFRAMESIZE_MASK 0x0000ffff
// ----------------------------------------------------------------------
// Register    : Number of I2C samples per Frame Configuration Register
// Configure number of samples acquired per frame.
#define SENSOR_I2CFRAMESIZE_ADDR       0x10a07308
// Field       : I2CSAMPLES
// Access      : RW
// number I2C samples. load N-1 to acquire N samples.
#define SENSOR_I2CFRAMESIZE_I2CSAMPLES_BIT 0
#define SENSOR_I2CFRAMESIZE_I2CSAMPLES_LEN 16
#define SENSOR_I2CFRAMESIZE_I2CSAMPLES_MASK 0x0000ffff
// ----------------------------------------------------------------------
// Register    : Number of SPI samples per Frame Configuration Register
// Configure number of samples acquired per frame.
#define SENSOR_SPIFRAMESIZE_ADDR       0x10a07310
// Field       : SPISAMPLES
// Access      : RW
// number SPI samples. load N-1 to acquire N samples.
#define SENSOR_SPIFRAMESIZE_SPISAMPLES_BIT 0
#define SENSOR_SPIFRAMESIZE_SPISAMPLES_LEN 16
#define SENSOR_SPIFRAMESIZE_SPISAMPLES_MASK 0x0000ffff
// ----------------------------------------------------------------------
// Register    : Number of Data words per Sample Configuration Register
// Configure number of words per sample in each data type. Don't change
// this register contents during data acquisition.
#define SENSOR_SAMPLESIZE_ADDR         0x10a07320
// Field       : DAEKGDSIZE
// Access      : RW
// number DAEKG words per sample. load N-1 to send N words. Set to number
// of ADC channels enabled(1,2,3,4,5,6,7,8 are valid configurations).
#define SENSOR_SAMPLESIZE_DAEKGDSIZE_BIT 0
#define SENSOR_SAMPLESIZE_DAEKGDSIZE_LEN 8
#define SENSOR_SAMPLESIZE_DAEKGDSIZE_MASK 0x000000ff
// Field       : I2CDSIZE
// Access      : RW
// number I2C words per sample. load N-1 to send N words. Set to 4x
// enabled I2C devices(4,8,12,16 are valid configurations).
#define SENSOR_SAMPLESIZE_I2CDSIZE_BIT 8
#define SENSOR_SAMPLESIZE_I2CDSIZE_LEN 8
#define SENSOR_SAMPLESIZE_I2CDSIZE_MASK 0x0000ff00
// Field       : SPIDSIZE
// Access      : RW
// number SPI words per sample. load N-1 to send N words. Set to 4x
// enabled SPI devices(4,8,12,16 are valid configurations).
#define SENSOR_SAMPLESIZE_SPIDSIZE_BIT 16
#define SENSOR_SAMPLESIZE_SPIDSIZE_LEN 8
#define SENSOR_SAMPLESIZE_SPIDSIZE_MASK 0x00ff0000


