#define PMONCTRL_PWRCONFIG_PWRSYSENABLE_BIT 0
#define PMONCTRL_PWRCONFIG_PWRSYSENABLE_LEN 1
#define PMONCTRL_PWRCONFIG_PWRSYSENABLE_MASK 0x00000001
// Field       : HV2DISABLE
// Access      : RW
// Reserved: Hv2 Disable for power saving.
#define PMONCTRL_PWRCONFIG_HV2DISABLE_BIT 1
#define PMONCTRL_PWRCONFIG_HV2DISABLE_LEN 1
#define PMONCTRL_PWRCONFIG_HV2DISABLE_MASK 0x00000002
// Field       : AUTOACQ
// Access      : RW
// Power Monitoring ADC Enable, this also kicks of auto mode ADC data
// acquire.
#define PMONCTRL_PWRCONFIG_AUTOACQ_BIT 2
#define PMONCTRL_PWRCONFIG_AUTOACQ_LEN 1
#define PMONCTRL_PWRCONFIG_AUTOACQ_MASK 0x00000004
// Field       : CONTMODE
// Access      : RW
// Monitor Power in Continuous Mode; ADC data acquire continuosuly.
#define PMONCTRL_PWRCONFIG_CONTMODE_BIT 3
#define PMONCTRL_PWRCONFIG_CONTMODE_LEN 1
#define PMONCTRL_PWRCONFIG_CONTMODE_MASK 0x00000008
// Field       : AUTOACQALLTIME
// Access      : RW
// Normal mode Power-saving option. when set, ADC continuously acquires
// data as long as pmon_enable is asserted, although it uses configured
// number of samples for calculating pmon average from pmon_start rising-
// edge. Default value is 0, acquires configured number of samples and
// waits for next rising-edge on pmon_start. This bit matters only in
// auto mode, not in continuous mode.
#define PMONCTRL_PWRCONFIG_AUTOACQALLTIME_BIT 4
#define PMONCTRL_PWRCONFIG_AUTOACQALLTIME_LEN 1
#define PMONCTRL_PWRCONFIG_AUTOACQALLTIME_MASK 0x00000010
// ----------------------------------------------------------------------
// Register    : Power Supplies Status Register
// Live status in bits[7:0], changes status frame to frame; Sticky bits
// [11:8],[23:16]; All get cleared on writing some data to PwrStatus
// register.
#define PMONCTRL_PWRSTATUS_ADDR        0x10a08064
// Field       : HVPOUTUPLIMIT
// Access      : WC
// Power Hvp is above upper limit.
#define PMONCTRL_PWRSTATUS_HVPOUTUPLIMIT_BIT 0
#define PMONCTRL_PWRSTATUS_HVPOUTUPLIMIT_LEN 1
#define PMONCTRL_PWRSTATUS_HVPOUTUPLIMIT_MASK 0x00000001
// Field       : HVPOUTLWRLIMIT
// Access      : WC
// Power Hvp is below lower limit.
#define PMONCTRL_PWRSTATUS_HVPOUTLWRLIMIT_BIT 1
#define PMONCTRL_PWRSTATUS_HVPOUTLWRLIMIT_LEN 1
#define PMONCTRL_PWRSTATUS_HVPOUTLWRLIMIT_MASK 0x00000002
// Field       : HVNIOUTUPLIMIT
// Access      : WC
// Power Hvni is above upper limit.
#define PMONCTRL_PWRSTATUS_HVNIOUTUPLIMIT_BIT 2
#define PMONCTRL_PWRSTATUS_HVNIOUTUPLIMIT_LEN 1
#define PMONCTRL_PWRSTATUS_HVNIOUTUPLIMIT_MASK 0x00000004
// Field       : HVNIOUTLWRLIMIT
// Access      : WC
// Power Hvni is below lower limit.
#define PMONCTRL_PWRSTATUS_HVNIOUTLWRLIMIT_BIT 3
#define PMONCTRL_PWRSTATUS_HVNIOUTLWRLIMIT_LEN 1
#define PMONCTRL_PWRSTATUS_HVNIOUTLWRLIMIT_MASK 0x00000008
// Field       : HVNOUTUPLIMIT
