// ======================================================================
// Module      : Beam Former Core
// Base Address: 0x10c00000
// Beam former registers are described elsewhere. Here lie monsters.
// ----------------------------------------------------------------------
// Register    : beam former resets configuration/control Register
// Errata. An issue was found late in the design cycle where some
// registers were not getting reset properly the first time. The issue
// was resolved by resetting tr_swrst twice. SW should set tr_swrst and
// clear it and then set and clear it again.
#define BF_TR0_ADDR                    0x10c00000
// Field       : TR_SWRST
// Access      : RW
// Top level SW reset of beamformer signal processing and control logic.
// Other resets controled by following bits. This bit will not reset the
// top, beam parameter, or diagnostic register files.
#define BF_TR0_TR_SWRST_BIT            0
#define BF_TR0_TR_SWRST_LEN            1
#define BF_TR0_TR_SWRST_MASK           0x00000001
// Field       : TR_SPI_SWRST
// Access      : RW
// AFE5832 SPI interface SW reset.
#define BF_TR0_TR_SPI_SWRST_BIT        1
#define BF_TR0_TR_SPI_SWRST_LEN        1
#define BF_TR0_TR_SPI_SWRST_MASK       0x00000002
// Field       : TR_AFEIO_SWRST
// Access      : RW
// AFE5832 input interface SW reset.
#define BF_TR0_TR_AFEIO_SWRST_BIT      2
#define BF_TR0_TR_AFEIO_SWRST_LEN      1
#define BF_TR0_TR_AFEIO_SWRST_MASK     0x00000004
// Field       : TR_AFE_SWRST
// Access      : RW
// AFE5832 SW reset.
#define BF_TR0_TR_AFE_SWRST_BIT        3
#define BF_TR0_TR_AFE_SWRST_LEN        1
#define BF_TR0_TR_AFE_SWRST_MASK       0x00000008
// Field       : TR_TX_SWRST
// Access      : RW
// STHV1600 reset.
#define BF_TR0_TR_TX_SWRST_BIT         4
#define BF_TR0_TR_TX_SWRST_LEN         1
#define BF_TR0_TR_TX_SWRST_MASK        0x00000010
// Field       : TR_PSV_SWRST
// Access      : RW
// Reset of HV power supply voltage control PWM signals. Both HV+ and HV-
// pulse width modulation signals will be forced to the de- asserted
// state as defined in register HVPS0.
#define BF_TR0_TR_PSV_SWRST_BIT        5
#define BF_TR0_TR_PSV_SWRST_LEN        1
#define BF_TR0_TR_PSV_SWRST_MASK       0x00000020
// Field       : HV_FAULT_SWRST
// Access      : RW
// Clear HV disable due to hv fault input from power monitor.
#define BF_TR0_HV_FAULT_SWRST_BIT      8
#define BF_TR0_HV_FAULT_SWRST_LEN      1
#define BF_TR0_HV_FAULT_SWRST_MASK     0x00000100
// Field       : HV_INT_SWRST
// Access      : RW
// Clear HV disable due to interrupt from HV pulsers.
#define BF_TR0_HV_INT_SWRST_BIT        9
#define BF_TR0_HV_INT_SWRST_LEN        1
#define BF_TR0_HV_INT_SWRST_MASK       0x00000200
// ----------------------------------------------------------------------
// Register    : beam former resets configuration/control Register
//
#define BF_LS0_ADDR                    0x10c00004
// Field       : TR_LS_EN
// Access      : RW
// PRI timer enable.
#define BF_LS0_TR_LS_EN_BIT            0
#define BF_LS0_TR_LS_EN_LEN            1
#define BF_LS0_TR_LS_EN_MASK           0x00000001
// ----------------------------------------------------------------------
// Register    : beam former resets configuration/control Register
//
#define BF_EN0_ADDR                    0x10c00008
// Field       : TR_TX_EN
// Access      : RW
// Top level transmit (TX) enable. 0 = TX is disabled. 1 = TX determined
// by beam parameter.
#define BF_EN0_TR_TX_EN_BIT            0
#define BF_EN0_TR_TX_EN_LEN            1
#define BF_EN0_TR_TX_EN_MASK           0x00000001
// Field       : TR_RX_EN
// Access      : RW
// Top level receive (RX) enable. RX is defined as input from the AF5832
// and write to delay memory. 0 = RX disabled. 1 = RX determined by beam
// parameter.
#define BF_EN0_TR_RX_EN_BIT            1
#define BF_EN0_TR_RX_EN_LEN            1
#define BF_EN0_TR_RX_EN_MASK           0x00000002
// Field       : TR_BF_EN
// Access      : RW
// Top level beamforming (BF) enable. 0 = BF disabled. 1 = BF defined by
// beam parameters.
#define BF_EN0_TR_BF_EN_BIT            2
#define BF_EN0_TR_BF_EN_LEN            1
#define BF_EN0_TR_BF_EN_MASK           0x00000004
// Field       : TR_AFE_AUTO_RST_EN
// Access      : RW
// Enable automatic reset of AFE5832 parts after transition from power
// down to standby or full power. The time of the actual reset is defined
// by a delay from the start of AFE power up.
#define BF_EN0_TR_AFE_AUTO_RST_EN_BIT  5
#define BF_EN0_TR_AFE_AUTO_RST_EN_LEN  1
#define BF_EN0_TR_AFE_AUTO_RST_EN_MASK 0x00000020
// Field       : TR_AFEIO_AUTO_RST_EN
// Access      : RW
// AFE interface auto-reset enable. Enables automatic reset of the
// AFE5832 input interface on transition from power down to standby or
// full power. The time of the actual reset is defined by a delay from
// the start of AFE power up.
#define BF_EN0_TR_AFEIO_AUTO_RST_EN_BIT 6
#define BF_EN0_TR_AFEIO_AUTO_RST_EN_LEN 1
#define BF_EN0_TR_AFEIO_AUTO_RST_EN_MASK 0x00000040
// Field       : TR_AFEIO_CONFIG_EN
// Access      : RW
// AFE auto config enable. Enables a set of SPI write commands initiated
// after the AFE auto reset. This set of initialization commands is
// stored in a seperate LUT from the normal write queue.
#define BF_EN0_TR_AFEIO_CONFIG_EN_BIT  7
#define BF_EN0_TR_AFEIO_CONFIG_EN_LEN  1
#define BF_EN0_TR_AFEIO_CONFIG_EN_MASK 0x00000080
// Field       : TR_THSD
// Access      : RW
// Transmit pulser shutdown (STHV800) 0=Normal operation, 1=Force
// shutdown of TX pulser parts.
#define BF_EN0_TR_THSD_BIT             8
#define BF_EN0_TR_THSD_LEN             1
#define BF_EN0_TR_THSD_MASK            0x00000100
// Field       : AFE0_SLOPE_EN
// Access      : RW
// AFE0 TGC_SLOPE pulse enable: 0 = TGC_SLOPE pulse disabled 1 =
// TGC_SLOPE pulse enable.
#define BF_EN0_AFE0_SLOPE_EN_BIT       16
#define BF_EN0_AFE0_SLOPE_EN_LEN       1
#define BF_EN0_AFE0_SLOPE_EN_MASK      0x00010000
// Field       : AFE1_SLOPE_EN
// Access      : RW
// AFE1 TGC_SLOPE pulse enable: 0 = TGC_SLOPE pulse disabled 1 =
// TGC_SLOPE pulse enable.
#define BF_EN0_AFE1_SLOPE_EN_BIT       17
#define BF_EN0_AFE1_SLOPE_EN_LEN       1
#define BF_EN0_AFE1_SLOPE_EN_MASK      0x00020000
// Field       : AFE0_UPDN_EN
// Access      : RW
// AFE0 TGC_UPDN pulse enable: 0 = TGC_UPDN pulse disabled 1 = TGC_UPDN
// pulse enable.
#define BF_EN0_AFE0_UPDN_EN_BIT        18
#define BF_EN0_AFE0_UPDN_EN_LEN        1
#define BF_EN0_AFE0_UPDN_EN_MASK       0x00040000
// Field       : AFE1_UPDN_EN
// Access      : RW
