// reset, if enabled. Value is SPI writes-1. The number of write commands
// is TBD.
#define BF_AFE0_AFE_INIT_COMMANDS_BIT  8
#define BF_AFE0_AFE_INIT_COMMANDS_LEN  8
#define BF_AFE0_AFE_INIT_COMMANDS_MASK 0x0000ff00
// Field       : AFE_WRITE_MODE
// Access      : RW
// Selects mode of processing for writes to real time SPI command queue,
// not the init command LUT. 0 = Enable AFE SPI writes whenever queue is
// not empty. SPI commands will be exectued ASAP until queue is empty. 1
// = Start AFE SPI writes on LS and continue until queue is empty.
#define BF_AFE0_AFE_WRITE_MODE_BIT     16
#define BF_AFE0_AFE_WRITE_MODE_LEN     1
#define BF_AFE0_AFE_WRITE_MODE_MASK    0x00010000
// ----------------------------------------------------------------------
// Register    : Afe configuration/control Register-1
//
#define BF_AFE1_ADDR                   0x10c00020
// Field       : AFE_PDGBL_DEL
// Access      : RW
// AFE global power up time. Units are cycles of Fs. This value is
// subtracted from the current PRI in order to determine when to start
// the power up process during a power management line. Units are Fs
// (25Mhz) cycles.
#define BF_AFE1_AFE_PDGBL_DEL_BIT      0
#define BF_AFE1_AFE_PDGBL_DEL_LEN      32
#define BF_AFE1_AFE_PDGBL_DEL_MASK     0xffffffff
// ----------------------------------------------------------------------
// Register    : Afe configuration/control Register-2
//
#define BF_AFE2_ADDR                   0x10c00024
// Field       : AFEIO_RST_DEL
// Access      : RW
// Delay from the start of AFE global power up to the automatic reset of
// the AFE interface controller (re-lock). This value must include the
// full power up time and must be AFTER afe_rst_del. Units are Fs (25Mhz)
// cycles.
#define BF_AFE2_AFEIO_RST_DEL_BIT      0
#define BF_AFE2_AFEIO_RST_DEL_LEN      16
#define BF_AFE2_AFEIO_RST_DEL_MASK     0x0000ffff
// Field       : AFE_RST_DEL
// Access      : RW
// Delay from the start of AFE global power up to the automatic AFE
// reset, if enabled. This value must include the full power up time.
// Units are Fs (25Mhz) cycles.
#define BF_AFE2_AFE_RST_DEL_BIT        16
#define BF_AFE2_AFE_RST_DEL_LEN        16
#define BF_AFE2_AFE_RST_DEL_MASK       0xffff0000
// ----------------------------------------------------------------------
// Register    : Afe configuration/control Register-3
//
#define BF_AFE3_ADDR                   0x10c00028
// Field       : DIE_SEL
// Access      : RW
// AFE die select mode: 0 = Normal mode. Die selected by bit field in
// write queue. 1 = Die select by bits in following fields.
#define BF_AFE3_DIE_SEL_BIT            0
#define BF_AFE3_DIE_SEL_LEN            1
#define BF_AFE3_DIE_SEL_MASK           0x00000001
// Field       : SELB0
// Access      : RW
// AFE0 bottom analog die select.
#define BF_AFE3_SELB0_BIT              1
#define BF_AFE3_SELB0_LEN              1
#define BF_AFE3_SELB0_MASK             0x00000002
// Field       : SELB1
// Access      : RW
// AFE1 bottom analog die select.
#define BF_AFE3_SELB1_BIT              2
#define BF_AFE3_SELB1_LEN              1
#define BF_AFE3_SELB1_MASK             0x00000004
// Field       : SELT0
// Access      : RW
// AFE0 top analog die select.
#define BF_AFE3_SELT0_BIT              3
#define BF_AFE3_SELT0_LEN              1
#define BF_AFE3_SELT0_MASK             0x00000008
// Field       : SELT1
// Access      : RW
// AFE1 top analog die select.
#define BF_AFE3_SELT1_BIT              4
#define BF_AFE3_SELT1_LEN              1
#define BF_AFE3_SELT1_MASK             0x00000010
// Field       : SELD0
// Access      : RW
// AFE0 digital die select.
#define BF_AFE3_SELD0_BIT              5
#define BF_AFE3_SELD0_LEN              1
#define BF_AFE3_SELD0_MASK             0x00000020
// Field       : SELD1
// Access      : RW
// AFE1 digital die select.
#define BF_AFE3_SELD1_BIT              6
#define BF_AFE3_SELD1_LEN              1
#define BF_AFE3_SELD1_MASK             0x00000040
// Field       : DIGDIE_SEL
// Access      : RW
// AFE Digital die select mode: 0 = Normal mode. Die selected by bit
// field in write queue. 1 = Die select by bits seld0, seld1 fields.
#define BF_AFE3_DIGDIE_SEL_BIT         8
#define BF_AFE3_DIGDIE_SEL_LEN         1
#define BF_AFE3_DIGDIE_SEL_MASK        0x00000100
// ----------------------------------------------------------------------
// Register    : Afe configuration/control Register-4
//
#define BF_AFE4_ADDR                   0x10c0002c
// Field       : AFE_SLOPE_DEL
// Access      : RW
// Delay from PRI to output of TGC_SLOPE pulse to AFEs in units of 4*Fs
// (100Mhz) cycles.
#define BF_AFE4_AFE_SLOPE_DEL_BIT      0
#define BF_AFE4_AFE_SLOPE_DEL_LEN      16
#define BF_AFE4_AFE_SLOPE_DEL_MASK     0x0000ffff
// Field       : AFE_UPDN_DEL
// Access      : RW
// Delay from PRI to output of TGC_UPDN pulse to AFEs in units of 4*Fs
// (100Mhz) cycles. The TGC_UPDN pulse is normally not enabled since it
// is not needed for the internl non-uniform TGC mode.
#define BF_AFE4_AFE_UPDN_DEL_BIT       16
#define BF_AFE4_AFE_UPDN_DEL_LEN       16
#define BF_AFE4_AFE_UPDN_DEL_MASK      0xffff0000
// ----------------------------------------------------------------------
// Register    : Afe configuration/control Register-5
//
#define BF_AFE5_ADDR                   0x10c00030
// Field       : AFE_TRIG_DEL
// Access      : RW
// Delay from PRI to output of TX_TRIG pulse to AFEs in units of 4*Fs
// (100Mhz).
#define BF_AFE5_AFE_TRIG_DEL_BIT       0
#define BF_AFE5_AFE_TRIG_DEL_LEN       16
#define BF_AFE5_AFE_TRIG_DEL_MASK      0x0000ffff
// ----------------------------------------------------------------------
// Register    : 0 word offset from base.
//
#define BF_BP0_ADDR                    0x10c04000
// Field       : ADC_S
// Access      : RW
// Number of ADC samples received for beam -1 Defines the total number of
// ADC samples stored in the delay memory circular buffer.
#define BF_BP0_ADC_S_BIT               0
#define BF_BP0_ADC_S_LEN               13
#define BF_BP0_ADC_S_MASK              0x00001fff
// Field       : ADC_S_PRE
// Access      : RW
// Number of ADC stamples stored in delay memory prior to start of
// beamforming -1
#define BF_BP0_ADC_S_PRE_BIT           16
#define BF_BP0_ADC_S_PRE_LEN           10
#define BF_BP0_ADC_S_PRE_MASK          0x03ff0000
// ----------------------------------------------------------------------
// Register    : Focal Point Params
//
#define BF_FPS_ADDR                    0x10c04004
// Field       : FP_S
// Access      : RW
// Number of calculated focal points -1 Defines the total number of focal
// points calculate from TX/RX time of flight. This value is choses as a
// function of imaging depth, required delay accuracy, and any applied
// focal point correction.
#define BF_FPS_FP_S_BIT                0
#define BF_FPS_FP_S_LEN                14
#define BF_FPS_FP_S_MASK               0x00003fff
// Field       : DM_START
// Access      : RW
// Delay memory start address. This value is used for C beams when the
// top of the color ROI is below the skin line. The delay calculations
// are absolute so if data capture starts after the skin line then the
// write address must represent the correct sample address as if starting
// from the skin line. With Rs is the range from the origin to the top of
// the color ROI.
#define BF_FPS_DM_START_BIT            16
#define BF_FPS_DM_START_LEN            10
#define BF_FPS_DM_START_MASK           0x03ff0000
// Field       : DEL_SCALE
// Access      : RW
// Delay calculation scale. Defines scaling of calculated delays prior to
// interpolation. Used when focal points and element postions are scaled
// by a power of two in order to trade delay range for accuracy. 0x0= 1
// 0x1 = 1/2 0x2 = 1/4 0x3 = 1/8 others = 1
#define BF_FPS_DEL_SCALE_BIT           28
#define BF_FPS_DEL_SCALE_LEN           3
#define BF_FPS_DEL_SCALE_MASK          0x70000000
// ----------------------------------------------------------------------
// Register    : Beam Param Samples
//
#define BF_BPS_ADDR                    0x10c04008
// Field       : BF_S
// Access      : RW
// Total number of generated delays -1 Defines the total number of delay
// and apodization weights calculated after interpolation.
#define BF_BPS_BF_S_BIT                0
#define BF_BPS_BF_S_LEN                14
#define BF_BPS_BF_S_MASK               0x00003fff
// Field       : BFOUT_S
// Access      : RW
//  Beamformer output words B -1 Defines the total number of 32 bit
// output words for PRI. Value depends on data type: B mode: B samples -1
// C mode: Color flow processing samples*4 -1 (N,D,P,U words for each
// color sample) IQ data: Sample*4-1 (One 32 bit I/Q word per sample per
// beam)
#define BF_BPS_BFOUT_S_BIT             16
#define BF_BPS_BFOUT_S_LEN             11
#define BF_BPS_BFOUT_S_MASK            0x07ff0000
// ----------------------------------------------------------------------
// Register    : FPLUT
//
#define BF_FPLUT_ADDR                  0x10c0400c
// Field       : HV_CLKEN_OFF
// Access      : RW
// Time from LS to optional disable of HV PS and voltage control PWM
// signals in units of 16 ADC samples. This time should be set after TX
// waveform genertion is complete. Top level parameter hvps_gate_en must
// be '1' to enable timed gating of the clock
#define BF_FPLUT_HV_CLKEN_OFF_BIT      0
#define BF_FPLUT_HV_CLKEN_OFF_LEN      16
#define BF_FPLUT_HV_CLKEN_OFF_MASK     0x0000ffff
// Field       : HV_CLKEN_ON
// Access      : RW
// Time from LS to enable of HV PS and voltage control PWM signals in
// units of 16 ADC samples This time should be set according to the time
// required for the HV supply to charge up in advance of transmit.
#define BF_FPLUT_HV_CLKEN_ON_BIT       16
#define BF_FPLUT_HV_CLKEN_ON_LEN       16
#define BF_FPLUT_HV_CLKEN_ON_MASK      0xffff0000
// ----------------------------------------------------------------------
// Register    : BF Enables Configuration Register
//
#define BF_BENABLE_ADDR                0x10c04010
// Field       : BX_TX_EN
// Access      : RW
// Beam transmit enable. The top level register bit tx_en must also be
// set to enable transmit pulse generation.
#define BF_BENABLE_BX_TX_EN_BIT        0
#define BF_BENABLE_BX_TX_EN_LEN        1
#define BF_BENABLE_BX_TX_EN_MASK       0x00000001
// Field       : BX_RX_EN
// Access      : RW
// Beam RX enable. The top level register bit rx_en must also be set to
// enable RX.
#define BF_BENABLE_BX_RX_EN_BIT        1
#define BF_BENABLE_BX_RX_EN_LEN        1
#define BF_BENABLE_BX_RX_EN_MASK       0x00000002
// Field       : BP_BF_EN
// Access      : RW
// Beamforming enable. The top level register bit bf_en must also be set
// to enable beam processing.
#define BF_BENABLE_BP_BF_EN_BIT        2
#define BF_BENABLE_BP_BF_EN_LEN        1
#define BF_BENABLE_BP_BF_EN_MASK       0x00000004
// Field       : BP_OUT_EN
// Access      : RW
// Enable output from beamformer to DMA controller for streaming to CPU
// memory.
#define BF_BENABLE_BP_OUT_EN_BIT       3
#define BF_BENABLE_BP_OUT_EN_LEN       1
#define BF_BENABLE_BP_OUT_EN_MASK      0x00000008
// Field       : OUT_TYPE
// Access      : RW
// Select output data type. 0x0= B; 0x1= C; 0x2= PW; 0x3 = M; 0x4 = CW;
// 0x5 = AC.
#define BF_BENABLE_OUT_TYPE_BIT        4
#define BF_BENABLE_OUT_TYPE_LEN        3
#define BF_BENABLE_OUT_TYPE_MASK       0x00000070
// Field       : OUT_IQ_TYPE
// Access      : RW
// Select color output mode:0 = Coherent compounding block output. 1 =
// Autocorreleation block N,D,P,U output.
#define BF_BENABLE_OUT_IQ_TYPE_BIT     8
#define BF_BENABLE_OUT_IQ_TYPE_LEN     2
#define BF_BENABLE_OUT_IQ_TYPE_MASK    0x00000300
// Field       : CTB_WRITE_EN
// Access      : RW
// Enable write to corner turn buffer.
#define BF_BENABLE_CTB_WRITE_EN_BIT    10
#define BF_BENABLE_CTB_WRITE_EN_LEN    1
#define BF_BENABLE_CTB_WRITE_EN_MASK   0x00000400
// Field       : CFP_EN
// Access      : RW
// Color flow processing enable.
#define BF_BENABLE_CFP_EN_BIT          11
#define BF_BENABLE_CFP_EN_LEN          1
#define BF_BENABLE_CFP_EN_MASK         0x00000800
// Field       : AFE_SPI_EN
// Access      : RW
// Enable AFE SPI writes on specific beams. Used when the top level bit
// afe_write_mode = 1. Otherwise with afe_write_mode=0 the SPI writes are
// done any time the queue is not empty.0 = AFE SPI writes not enabled
// for beam. 1 = AFE SPI writes done until queue empy.
#define BF_BENABLE_AFE_SPI_EN_BIT      12
#define BF_BENABLE_AFE_SPI_EN_LEN      1
#define BF_BENABLE_AFE_SPI_EN_MASK     0x00001000
// Field       : BP_FLAG0
// Access      : RW
// Generic beam parameter 0 for ASIC output pin.
#define BF_BENABLE_BP_FLAG0_BIT        13
#define BF_BENABLE_BP_FLAG0_LEN        1
#define BF_BENABLE_BP_FLAG0_MASK       0x00002000
// Field       : BP_FLAG1
// Access      : RW
// Generic beam parameter 1 for ASIC output pin.
#define BF_BENABLE_BP_FLAG1_BIT        14
#define BF_BENABLE_BP_FLAG1_LEN        1
#define BF_BENABLE_BP_FLAG1_MASK       0x00004000
// Field       : B_EOF
// Access      : RW
// B mode end of frame flag.
#define BF_BENABLE_B_EOF_BIT           16
#define BF_BENABLE_B_EOF_LEN           1
#define BF_BENABLE_B_EOF_MASK          0x00010000
// Field       : C_EOF
// Access      : RW
// C mode end of frame flag.
#define BF_BENABLE_C_EOF_BIT           17
#define BF_BENABLE_C_EOF_LEN           1
#define BF_BENABLE_C_EOF_MASK          0x00020000
// Field       : EOS
// Access      : RW
// End of sequence flag.
#define BF_BENABLE_EOS_BIT             18
#define BF_BENABLE_EOS_LEN             1
#define BF_BENABLE_EOS_MASK            0x00040000
// Field       : BP_SLOPE_EN
// Access      : RW
// 0 = AFE slope pulse disable. 1 = AFE slope pulse enable.
#define BF_BENABLE_BP_SLOPE_EN_BIT     19
#define BF_BENABLE_BP_SLOPE_EN_LEN     1
#define BF_BENABLE_BP_SLOPE_EN_MASK    0x00080000
// Field       : BP_PRI_TX_TRIG_EN
// Access      : RW
// Enable AFE tx_trig pulse at PRI; 0 = tx_trig pulse generation
// disabled.1 = Normal mode with tx_trig pulse enabled.
#define BF_BENABLE_BP_PRI_TX_TRIG_EN_BIT 20
#define BF_BENABLE_BP_PRI_TX_TRIG_EN_LEN 1
#define BF_BENABLE_BP_PRI_TX_TRIG_EN_MASK 0x00100000
// Field       : BP_PRI_AFEIO_RST_EN
// Access      : RW
// Enable AFEIO reset (relock) at PRI 0 = Normal mode; 1 = Reserved
#define BF_BENABLE_BP_PRI_AFEIO_RST_EN_BIT 21
#define BF_BENABLE_BP_PRI_AFEIO_RST_EN_LEN 1
#define BF_BENABLE_BP_PRI_AFEIO_RST_EN_MASK 0x00200000
// Field       : STHV_WAKEUP_EN
// Access      : RW
// 0 = No wakeup tx_trigger prior to SPI writes 1 = Enable pulse on
// tx_trigger to wake up device from power down mode prior to SPI writes.
#define BF_BENABLE_STHV_WAKEUP_EN_BIT  22
#define BF_BENABLE_STHV_WAKEUP_EN_LEN  1
#define BF_BENABLE_STHV_WAKEUP_EN_MASK 0x00400000
// Field       : STHV_TRIG_HOLD
// Access      : RW
// 0 = Normal mode 1 = tx_trigger de-asserted for whole beam time
#define BF_BENABLE_STHV_TRIG_HOLD_BIT  23
#define BF_BENABLE_STHV_TRIG_HOLD_LEN  1
#define BF_BENABLE_STHV_TRIG_HOLD_MASK 0x00800000
// Field       : PMON_EN
// Access      : RW
// 0 = Power monitor not enabled for PRI. This will prevent samples of
// voltage/current for the current PRI interval from being used to
// calculate an average.1 = Power monitor enabled for this PRI.
#define BF_BENABLE_PMON_EN_BIT         24
#define BF_BENABLE_PMON_EN_LEN         1
#define BF_BENABLE_PMON_EN_MASK        0x01000000
// Field       : BP_HV_FAULT_DIS_MODE
// Access      : RW
// 0 = HV fault from power monitor will not force HV off 1 = HV fault
// will force HV off if top level register bit hv_fault_dis_mode is also
// 1.
#define BF_BENABLE_BP_HV_FAULT_DIS_MODE_BIT 25
#define BF_BENABLE_BP_HV_FAULT_DIS_MODE_LEN 1
#define BF_BENABLE_BP_HV_FAULT_DIS_MODE_MASK 0x02000000
// Field       : BP_INT_FAULT_DIS_MODE
// Access      : RW
// 0 = TX part interrupt will not force HV off; 1 = TX part interrupt
// will force HV off if top level register bit hv_int_dis_mode is also 1.
#define BF_BENABLE_BP_INT_FAULT_DIS_MODE_BIT 26
#define BF_BENABLE_BP_INT_FAULT_DIS_MODE_LEN 1
#define BF_BENABLE_BP_INT_FAULT_DIS_MODE_MASK 0x04000000
// Field       : BP_HV_WAKEUP_EN
// Access      : RW
// 0 = Normal mode 1 = Assert tx_trigger for one cycle prior to normal
// programm and tx_trigger sequence
#define BF_BENABLE_BP_HV_WAKEUP_EN_BIT 27
#define BF_BENABLE_BP_HV_WAKEUP_EN_LEN 1
#define BF_BENABLE_BP_HV_WAKEUP_EN_MASK 0x08000000
// Field       : BP_ALT_HV_CONFIG
// Access      : RW
// 0 = Normal mode 1 = Use alternate HV voltage setting
#define BF_BENABLE_BP_ALT_HV_CONFIG_BIT 28
#define BF_BENABLE_BP_ALT_HV_CONFIG_LEN 1
#define BF_BENABLE_BP_ALT_HV_CONFIG_MASK 0x10000000
// Field       : BP_HVPS_BURST_EN
// Access      : RW
// HV Burst Mode.  0 = Normal HV PS clock.  1 = Enable burst mode for HV
// PS clock. On/off cycles of burst sequence defined in HVPS2 and HVPS3.
#define BF_BENABLE_BP_HVPS_BURST_EN_BIT 29
#define BF_BENABLE_BP_HVPS_BURST_EN_LEN 1
#define BF_BENABLE_BP_HVPS_BURST_EN_MASK 0x20000000
// Field       : PMON_START
// Access      : RW
// Set for first line of power monitor sequence
#define BF_BENABLE_PMON_START_BIT      30
#define BF_BENABLE_PMON_START_LEN      1
#define BF_BENABLE_PMON_START_MASK     0x40000000
// ----------------------------------------------------------------------
// Register    : Power management Register
//
#define BF_BPWR_ADDR                   0x10c04014
// Field       : PM_AFE_PWR_ON
// Access      : RW
// AFE power on control. 0 = Normal power management for PDN_FAST and
// PDN_GBL. 1 = Force AFE power to full on.
#define BF_BPWR_PM_AFE_PWR_ON_BIT      1
#define BF_BPWR_PM_AFE_PWR_ON_LEN      1
#define BF_BPWR_PM_AFE_PWR_ON_MASK     0x00000002
// Field       : PM_AFE_PWR_OFF
// Access      : RW
// AFE power off control. 0 = Normal power management mode for PDN_FAST
// and PDN_GBL. 1 = Force AFE power to off.
#define BF_BPWR_PM_AFE_PWR_OFF_BIT     2
#define BF_BPWR_PM_AFE_PWR_OFF_LEN     1
#define BF_BPWR_PM_AFE_PWR_OFF_MASK    0x00000004
// Field       : PM_AFE_PWR_SB
// Access      : RW
// AFE standby control. 0 = Normal power management mode for PDN_FAST and
// PDN_GBL. 1 = Force AFE to standby power.
#define BF_BPWR_PM_AFE_PWR_SB_BIT      3
#define BF_BPWR_PM_AFE_PWR_SB_LEN      1
#define BF_BPWR_PM_AFE_PWR_SB_MASK     0x00000008
// Field       : PM_AFE_GBL_TIMER
// Access      : RW
// Enable timer control of AFE PDN_GBL pin. 0 = AFE power on if
// pm_afe_pwr_on is '1' 1 = Timer used for AFE PDN_GBL pin control.
#define BF_BPWR_PM_AFE_GBL_TIMER_BIT   4
#define BF_BPWR_PM_AFE_GBL_TIMER_LEN   1
#define BF_BPWR_PM_AFE_GBL_TIMER_MASK  0x00000010
// Field       : PM_AFE_SB_TIMER
// Access      : RW
// Enable timer control of AFE PDN_FAST pin. 0 = Standby mode not used. 1
// = Timer control of AFE PDN_FAST pin.
#define BF_BPWR_PM_AFE_SB_TIMER_BIT    5
#define BF_BPWR_PM_AFE_SB_TIMER_LEN    1
#define BF_BPWR_PM_AFE_SB_TIMER_MASK   0x00000020
// Field       : PM_DIG_CH_PM
// Access      : RW
// Enable per channel power management per RX aperture for delay ,
// apodization, and rf filter sections. 0 = All digital processing
// enable. 1 = Digital processing disabled for channels not in current RX
// aperture.
#define BF_BPWR_PM_DIG_CH_PM_BIT       6
#define BF_BPWR_PM_DIG_CH_PM_LEN       1
#define BF_BPWR_PM_DIG_CH_PM_MASK      0x00000040
// ----------------------------------------------------------------------
// Register    : Transmit SPI LUT Register
//
#define BF_TXLUT_ADDR                  0x10c04018
// Field       : TXD_SPI_PTR
// Access      : RW
// TX configuration SPI command start pointer. Defines a starting
// location in the STHV1600 SPI command LUT. Starting with this address a
// set of N SPI write frames (address or data) define the required
// register writes to configure the TX parts for a particular beam angle.
#define BF_TXLUT_TXD_SPI_PTR_BIT       0
#define BF_TXLUT_TXD_SPI_PTR_LEN       13
#define BF_TXLUT_TXD_SPI_PTR_MASK      0x00001fff
// Field       : TXD_W_C
// Access      : RW
// TX configuration SPI command sequence length. Defines the number of
// SPI write frames. A value of zero is invalid.
#define BF_TXLUT_TXD_W_C_BIT           16
#define BF_TXLUT_TXD_W_C_LEN           12
#define BF_TXLUT_TXD_W_C_MASK          0x0fff0000
// ----------------------------------------------------------------------
// Register    : Transmit Length Register
//
#define BF_TXLEN_ADDR                  0x10c0401c
// Field       : TXLEN
// Access      : RW
// Defines the number of cycles of 4*Fs that the TX clock will be enabled
// after TX_START. This value must include the full TX waveform time. If
// TX clock power management is enabled (CK0 bit 2) then the TX clock
// will be enabled on LS and remain so until the TX_START time plus the
// number of cycles defined by txlen[15:0].
#define BF_TXLEN_TXLEN_BIT             0
#define BF_TXLEN_TXLEN_LEN             14
#define BF_TXLEN_TXLEN_MASK            0x00003fff
// ----------------------------------------------------------------------
// Register    : Receive Element Enable Register Low
// RX element [31:0] enable. rxap_low(n) = 0 RX disabled for element n.
// Delay memory read data forced to zero. rxap_low(n) = 1 RX enabled for
// element n.
#define BF_RXAP_LOW_ADDR               0x10c04028
// Field       : DUMMY
// Access      : RW
#define BF_RXAP_LOW_BIT                0
#define BF_RXAP_LOW_LEN                32
#define BF_RXAP_LOW_MASK               0xffffffff
// ----------------------------------------------------------------------
// Register    : Receive Element Enable Register High
// RX element [63:32] enable. rxap_low(n) = 0 RX disabled for element n.
// Delay memory read data forced to zero. rxap_low(n) = 1 RX enabled for
// element n.
#define BF_RXAP_HIGH_ADDR              0x10c0402c
// Field       : DUMMY
// Access      : RW
#define BF_RXAP_HIGH_BIT               0
#define BF_RXAP_HIGH_LEN               32
#define BF_RXAP_HIGH_MASK              0xffffffff
// ----------------------------------------------------------------------
// Register    : Beam PRI Register
// Beam PRI. Defines the exact beam time in cycles of Fs. However, an
// overtime feature will extend the beam time long enough to complete all
// processing. In this case the extra cycles of Fs required are stored in
// a read only register available to the system.
#define BF_BPRI_ADDR                   0x10c04030
// Field       : DUMMY
// Access      : RW
#define BF_BPRI_BIT                    0
#define BF_BPRI_LEN                    32
#define BF_BPRI_MASK                   0xffffffff
// ----------------------------------------------------------------------
// Register    : Transmit and Receive Start
//
#define BF_TXRXT_ADDR                  0x10c04034
// Field       : TX_START
// Access      : RW
// TX start delay. Defines the start of TX pulse generation from the
// start of the beam in cycles of Fs. The actual pulse delay for a
// particular element is this value plus the programmed delay for the
// element. For all but the FPGA v1 build this value must account for the
// total time needed for the STHV1600 SPI writes. If not, the write data
// will be corrupted when LVDS power management is enabled for the SPI
// port.
#define BF_TXRXT_TX_START_BIT          0
#define BF_TXRXT_TX_START_LEN          16
#define BF_TXRXT_TX_START_MASK         0x0000ffff
// Field       : RX_START
// Access      : RW
// RX start delay. Defines the start of ADC samples stored in delay
// memory from the start of the beam in cycles of Fs. This value must
// include several factors. See the architecture slide set for details.
#define BF_TXRXT_RX_START_BIT          16
#define BF_TXRXT_RX_START_LEN          16
#define BF_TXRXT_RX_START_MASK         0xffff0000
// ----------------------------------------------------------------------
// Register    : afetr
//
#define BF_AFETR_ADDR                  0x10c04038
// Field       : AFE_TR_EN
// Access      : RW
// AFE TR_EN pin assert delay.  Defines time from beam start to when the
// AFE5832 TR_EN pin is asserted, if enabled.
#define BF_AFETR_AFE_TR_EN_BIT         0
#define BF_AFETR_AFE_TR_EN_LEN         16
#define BF_AFETR_AFE_TR_EN_MASK        0x0000ffff
// Field       : TX_PING
// Access      : RW
// Reserved. Used as index to select specific beams for RF data capture.
#define BF_AFETR_TX_PING_BIT           16
#define BF_AFETR_TX_PING_LEN           8
#define BF_AFETR_TX_PING_MASK          0x00ff0000
// ----------------------------------------------------------------------
// Register    : bprf
//
#define BF_BPRF_ADDR                   0x10c0403c
// Field       : BPT_SPARE_ON
// Access      : RW
// ASIC: Spare beam timer output on time in units of Fs/16 or 16 ADC
// samples. Used to define a spare signal that is asserted for a defined
// range of the PRI time and routed to the spare ASIC pin bf_flag1.
#define BF_BPRF_BPT_SPARE_ON_BIT       0
#define BF_BPRF_BPT_SPARE_ON_LEN       16
#define BF_BPRF_BPT_SPARE_ON_MASK      0x0000ffff
// Field       : BPT_SPARE_OFF
// Access      : RW
// Off time in units of Fs/16.
#define BF_BPRF_BPT_SPARE_OFF_BIT      16
#define BF_BPRF_BPT_SPARE_OFF_LEN      16
#define BF_BPRF_BPT_SPARE_OFF_MASK     0xffff0000
// ----------------------------------------------------------------------
// Register    : Band Pass Filter Params 0
//
#define BF_BPF0_ADDR                   0x10c04040
// Field       : VBP_FC
// Access      : RW
// Bandpass filter (BPF) count: 0 = One filter result calculated per
// output sample. 1 = Two filter results calculated per output sample.
// Used for example for frequency compounding.
#define BF_BPF0_VBP_FC_BIT             0
#define BF_BPF0_VBP_FC_LEN             1
#define BF_BPF0_VBP_FC_MASK            0x00000001
// Field       : VBP_PR
// Access      : RW
// BPF phase resolution. Defines the number of decimation rate fractional
// bits. 0 = 3 fractional bits of decimation rate, 8 filter phases. 1 = 4
// fractional bits of decimation rate, 16 filter phases.
#define BF_BPF0_VBP_PR_BIT             1
#define BF_BPF0_VBP_PR_LEN             1
#define BF_BPF0_VBP_PR_MASK            0x00000002
// Field       : VBP_PLC
// Access      : RW
// BPF preload count. Defines the number of samples written to the kernal
// circular buffer prior to the start of output sample calculation. The
// typical value is 64
#define BF_BPF0_VBP_PLC_BIT            8
#define BF_BPF0_VBP_PLC_LEN            8
#define BF_BPF0_VBP_PLC_MASK           0x0000ff00
// Field       : VBP_FL
// Access      : RW
// BPF Filter length. Selects the number of filter taps. The maximum
// filter length depends on the decimation rate and the parameters vbp_pr
// and vbp_fc. These factors determine the number of multiply/accumulate
// cycles can be used for each output sample while matching the average
// rate of input samples Fs. vbp_fl[7:0] = (Taps/2)-1 In single filter 8
// phase mode (vbp_fc=0,vbp_pr=0): Taps (max) = min(16*floor(D),128) In
// two filter 8 phase mode (vbp_fc=1,vbp_pr=0): Taps (max) =
// min(8*floor(D),128) In single filter 16 phase mode
// (vbp_fc=0,vbp_pr=1): Taps (max) = min(16*floor(D),64) In two filter 16
// phase mode (vbp_fc=1,vbp_pr=0): Taps (max) = min(8*floor(D),64)
#define BF_BPF0_VBP_FL_BIT             16
#define BF_BPF0_VBP_FL_LEN             8
#define BF_BPF0_VBP_FL_MASK            0x00ff0000
// Field       : VBP_FS
// Access      : RW
// BPF filter select. Selects filters for one or two filters per sample
// depending on vbp_fc.
#define BF_BPF0_VBP_FS_BIT             24
#define BF_BPF0_VBP_FS_LEN             2
#define BF_BPF0_VBP_FS_MASK            0x03000000
// Field       : VBP_OSCALE
// Access      : RW
// BPF output scale. Selects a scale factor applied to the filter output
// prior to rounding. scale factor is 2^-(vbp_oscale). Filter
// coefficients may be scaled by a power of 2 by as much as possible
// while avoiding coefficient overflow in order to reduce quantization
// errors. Then vbp_oscale is set to the same factor. The maximum scale
// factor is a function of the maximum I and Q coef over all filter
// phases. 0 = 1.0 1 = 1/2 2 = 1/4 3 = 1/8 4 = 1/16 5 = 1/32 6 = 1/64 7 =
// 1/128
#define BF_BPF0_VBP_OSCALE_BIT         28
#define BF_BPF0_VBP_OSCALE_LEN         3
#define BF_BPF0_VBP_OSCALE_MASK        0x70000000
// ----------------------------------------------------------------------
// Register    : Band Pass Filter Params 1
//
#define BF_BPF1_ADDR                   0x10c04044
// Field       : VBP_PINC0
// Access      : RW
// BPF pointer increment 0. This is one of two increments used by the HW
// to decimate the input vector. vbp_pinc0[7:0] = floor(D)
#define BF_BPF1_VBP_PINC0_BIT          0
#define BF_BPF1_VBP_PINC0_LEN          8
#define BF_BPF1_VBP_PINC0_MASK         0x000000ff
// Field       : VBP_PINC1
// Access      : RW
// BPF pointer increment 1. This is one of two increments used by the HW
// to decimate the input vector. vbp_pinc1[7:0] = ceil(D)
#define BF_BPF1_VBP_PINC1_BIT          8
#define BF_BPF1_VBP_PINC1_LEN          8
#define BF_BPF1_VBP_PINC1_MASK         0x0000ff00
// Field       : VBP_WC0
// Access      : RW
// BPF wait count 0. This parameter is one of two counts used to control
// the delay between the start of filter calculations. The purpose is
// match the filter output rate with the sample input rate (Fs), avoiding
// the need to track the number of samples available in the filter kernel
// circular buffer. For single filter mode when vbp_fc = '0':
// vbp_wc0[7:0] = vbp_pinc0*8-2 For two filter mode when vbp_fc = '1':
// vbp_wc0[7:0] = vbp_pinc0*4-2
#define BF_BPF1_VBP_WC0_BIT            16
#define BF_BPF1_VBP_WC0_LEN            8
#define BF_BPF1_VBP_WC0_MASK           0x00ff0000
// Field       : VBP_WC1
// Access      : RW
// BPF wait count 1. For single filter mode when vbp_fc = '0':
// vbp_wc1[7:0] = vbp_pinc1*8-2 For two filter mode when vbp_fc = '1':
// vbp_wc1[7:0] = vbp_pinc1*4-2
#define BF_BPF1_VBP_WC1_BIT            24
#define BF_BPF1_VBP_WC1_LEN            8
#define BF_BPF1_VBP_WC1_MASK           0xff000000
// ----------------------------------------------------------------------
// Register    : Band Pass Filter Params 2
//
#define BF_BPF2_ADDR                   0x10c04048
// Field       : VBP_PHASE_INC
// Access      : RW
// U5.3, U4.4, BPF filter phase increment. With vbp_pr = 0: vbp_phase_inc
// = D*8 With vbp_pr = 1 : vbp_phase_inc = D*16
#define BF_BPF2_VBP_PHASE_INC_BIT      0
#define BF_BPF2_VBP_PHASE_INC_LEN      8
#define BF_BPF2_VBP_PHASE_INC_MASK     0x000000ff
// Field       : VBP_W_C
// Access      : RW
// BPF output word count. vbp_w_c[13:0] = O_S-1
#define BF_BPF2_VBP_W_C_BIT            16
#define BF_BPF2_VBP_W_C_LEN            14
#define BF_BPF2_VBP_W_C_MASK           0x3fff0000
// ----------------------------------------------------------------------
// Register    : Band Pass Filter Params 3
//
#define BF_BPF3_ADDR                   0x10c0404c
// Field       : VBP_I_C
// Access      : RW
// BPF input word count. vbp_i_c[13:0] = BF_C-1
#define BF_BPF3_VBP_I_C_BIT            0
#define BF_BPF3_VBP_I_C_LEN            14
#define BF_BPF3_VBP_I_C_MASK           0x00003fff
// Field       : VBP_DSEQ
// Access      : RW
// BPF decimation sequence. This parameter is a function of the
// fractional portion of the decimation rate Df Df = D-floor(D):
// vbp_dseq[15:0] is defined below for each possible Df: 0.0 = 0x0000
// 0.0625 = 0x8000 0.125 = 0x8080 0.1875 = 0x8420 0.25 = 0x8888 0.3125 =
// 0x9248 0.375 = 0xA4A4 0.4375 = 0xAA54 0.5 = 0xAAAA 0.5625 = 0xD5AA
// 0.625 = 0xDADA 0.6875 = 0xEDB6 0.75 = 0xEEEE 0.8125 = 0xFBDE 0.875 =
// 0xFEFE 0.9375 = 0xFFFE
#define BF_BPF3_VBP_DSEQ_BIT           16
#define BF_BPF3_VBP_DSEQ_LEN           16
#define BF_BPF3_VBP_DSEQ_MASK          0xffff0000
// ----------------------------------------------------------------------
// Register    : Apodization Params 0
//
#define BF_APOD0_ADDR                  0x10c04050
// Field       : APOD_OFFSET
// Access      : RW
// Format S8.8. Apod element position offset. Used to define beam origin
// for linear configuration. This value is added to the apodization
// element positions prior to scaling. Apod element positions are defined
// as 64 pairs with each element pair using the same weight. With the
// apod element pointer set to zero, the channel inputs are from physical
// elements 0 to 63, the first half of the array. With apod_offset set to
// zero these elements will map to the first 32 apod element pairs
// defined at positions (-31.5, -30.5, ... -0.5]. If, for example the
// actual RX beam origin (set of four) is centered at between elements 31
// and 32 then this is between apod element pairs 15 and 16 with
// positions -16.5 and -15.5. The value apot_offset is set to 16 so that
// after adding this to the LUT values the apodization curve is centered
// betwen elements 31 and 32.
#define BF_APOD0_APOD_OFFSET_BIT       0
#define BF_APOD0_APOD_OFFSET_LEN       16
#define BF_APOD0_APOD_OFFSET_MASK      0x0000ffff
// Field       : APOD_SCALE
// Access      : RW
// Format 8.8. This is the fixed, non range dependent scale factor
// applied to apod element positions. The typical value is 1.0
#define BF_APOD0_APOD_SCALE_BIT        16
#define BF_APOD0_APOD_SCALE_LEN        16
#define BF_APOD0_APOD_SCALE_MASK       0xffff0000
// ----------------------------------------------------------------------
// Register    : Apodization Params 1
//
#define BF_APOD1_ADDR                  0x10c04054
// Field       : APOD_FLAT
// Access      : RW
// Force apodization weights to 1.0 0 = Normal apodization weights used 1
// = All weights forced to 1.0
#define BF_APOD1_APOD_FLAT_BIT         0
#define BF_APOD1_APOD_FLAT_LEN         1
#define BF_APOD1_APOD_FLAT_MASK        0x00000001
// ----------------------------------------------------------------------
// Register    : Depth Time Gain Control 0
//
#define BF_DTGC0_ADDR                  0x10c0405c
// Field       : TGC0_LGC
// Access      : RW
// Beam 0 lateral gain. Depth independent lateral gain applied after
// depth dependent gain
#define BF_DTGC0_TGC0_LGC_BIT          0
#define BF_DTGC0_TGC0_LGC_LEN          24
#define BF_DTGC0_TGC0_LGC_MASK         0x00ffffff
// Field       : TGC0_FLAT
// Access      : RW
// Beam 0 tgc flat gain enable. 0 = Use lateral and depth dependent gain
// 1 = Use only lateral gain
#define BF_DTGC0_TGC0_FLAT_BIT         24
#define BF_DTGC0_TGC0_FLAT_LEN         1
#define BF_DTGC0_TGC0_FLAT_MASK        0x01000000
// Field       : BGPTR
// Access      : RW
// Beam gain pointer. Selects one of 32 sets of depth dependent gain
// curves per each parallel beam.
#define BF_DTGC0_BGPTR_BIT             25
#define BF_DTGC0_BGPTR_LEN             5
#define BF_DTGC0_BGPTR_MASK            0x3e000000
// ----------------------------------------------------------------------
// Register    : Depth Time Gain Control 1
//
#define BF_DTGC1_ADDR                  0x10c04060
// Field       : TGC1_LGC
// Access      : RW
// Beam 1 lateral gain. Depth independent lateral gain applied after
// depth dependent gain
#define BF_DTGC1_TGC1_LGC_BIT          0
#define BF_DTGC1_TGC1_LGC_LEN          24
#define BF_DTGC1_TGC1_LGC_MASK         0x00ffffff
// Field       : TGC1_FLAT
// Access      : RW
// Beam 1 tgc flat gain enable. 0 = Use lateral and depth dependent gain
// 1 = Use only lateral gain
#define BF_DTGC1_TGC1_FLAT_BIT         24
#define BF_DTGC1_TGC1_FLAT_LEN         1
#define BF_DTGC1_TGC1_FLAT_MASK        0x01000000
// Field       : BG_R_C
// Access      : RW
// Depth dependent gain breakpoints -1 The minimum number of breakpoints
// is 9. Defines the number of gain breakpoints used for the beam range.
// A gain value in dB units will be defined for each breakpoint. Linear
// interpolation will be used to generate the gain (dB) for each beam
// sample. The gains in dB will be converted to linear using a LUT.
#define BF_DTGC1_BG_R_C_BIT            25
#define BF_DTGC1_BG_R_C_LEN            5
#define BF_DTGC1_BG_R_C_MASK           0x3e000000
// Field       : TGC_FLIP
// Access      : RW
// Flip depth dependent gains. Used to share depth dependent gain curves
// for symmetrical beam angles. 0 = Gain curves 0,1,2,3 applied to beams
// 0,1,2,3 1 = Gain curves 0,1,2,3 applied to beams 3,2,1,0
#define BF_DTGC1_TGC_FLIP_BIT          30
#define BF_DTGC1_TGC_FLIP_LEN          1
#define BF_DTGC1_TGC_FLIP_MASK         0x40000000
// ----------------------------------------------------------------------
// Register    : Depth Time Gain Control 2
//
#define BF_DTGC2_ADDR                  0x10c04064
// Field       : TGC2_LGC
// Access      : RW
// Beam 2 lateral gain. Depth independent lateral gain applied after
// depth dependent gain
#define BF_DTGC2_TGC2_LGC_BIT          0
#define BF_DTGC2_TGC2_LGC_LEN          24
#define BF_DTGC2_TGC2_LGC_MASK         0x00ffffff
// Field       : TGC2_FLAT
// Access      : RW
// Beam 2 tgc flat gain enable. 0 = Use lateral and depth dependent gain
// 1 = Use only lateral gain
#define BF_DTGC2_TGC2_FLAT_BIT         24
#define BF_DTGC2_TGC2_FLAT_LEN         1
#define BF_DTGC2_TGC2_FLAT_MASK        0x01000000
// ----------------------------------------------------------------------
// Register    : Depth Time Gain Control 3
//
#define BF_DTGC3_ADDR                  0x10c04068
// Field       : TGC3_LGC
// Access      : RW
// Beam 3 lateral gain. Depth independent lateral gain applied after
// depth dependent gain
#define BF_DTGC3_TGC3_LGC_BIT          0
#define BF_DTGC3_TGC3_LGC_LEN          24
#define BF_DTGC3_TGC3_LGC_MASK         0x00ffffff
// Field       : TGC3_FLAT
// Access      : RW
// Beam 3 tgc flat gain enable. 0 = Use lateral and depth dependent gain
// 1 = Use only lateral gain
#define BF_DTGC3_TGC3_FLAT_BIT         24
#define BF_DTGC3_TGC3_FLAT_LEN         1
#define BF_DTGC3_TGC3_FLAT_MASK        0x01000000
// ----------------------------------------------------------------------
// Register    : Depth Time Gain Control 4
//
#define BF_DTGC4_ADDR                  0x10c0406c
// Field       : TGCIR_LOW
// Access      : RW
// Depth dependent gain interpolation rates for breakpoints 0 to 15. Two
// bits per breakpoint starting with the LSBs '00' = 4:1 '01' = 16:1 '10'
// = 64:1 '11' = 256:1
#define BF_DTGC4_TGCIR_LOW_BIT         0
#define BF_DTGC4_TGCIR_LOW_LEN         32
#define BF_DTGC4_TGCIR_LOW_MASK        0xffffffff
// ----------------------------------------------------------------------
// Register    : Depth Time Gain Control 5
//
#define BF_DTGC5_ADDR                  0x10c04070
// Field       : TGCIR_HIGH
// Access      : RW
// Depth dependent gain interpolation rates for breakpoints 16 to 31. Two
// bits per breakpoint starting with the LSBs '00' = 4:1 '01' = 16:1 '10'
// = 64:1 '11' = 256:1
#define BF_DTGC5_TGCIR_HIGH_BIT        0
#define BF_DTGC5_TGCIR_HIGH_LEN        32
#define BF_DTGC5_TGCIR_HIGH_MASK       0xffffffff
// ----------------------------------------------------------------------
// Register    : Coherency Compounding Params
//
#define BF_CCOMP_ADDR                  0x10c04074
// Field       : CC_PTR
// Access      : RW
// Coherent compounding (CC) coef LUT pointer.
#define BF_CCOMP_CC_PTR_BIT            0
#define BF_CCOMP_CC_PTR_LEN            10
#define BF_CCOMP_CC_PTR_MASK           0x000003ff
// Field       : CC_OUTEN
// Access      : RW
// CC output enable. 0 = CC output not enabled. 1 = CC output enabled.
#define BF_CCOMP_CC_OUTEN_BIT          16
#define BF_CCOMP_CC_OUTEN_LEN          1
#define BF_CCOMP_CC_OUTEN_MASK         0x00010000
// Field       : CC_WE
// Access      : RW
// CC buffer write enable. 0 = Compounding buffer write disabled. 1 =
// Compounding buffer write enabled.
#define BF_CCOMP_CC_WE_BIT             17
#define BF_CCOMP_CC_WE_LEN             1
#define BF_CCOMP_CC_WE_MASK            0x00020000
// Field       : CC_SUM
// Access      : RW
// CC summation enable. 0 = Buffer write data is weighted input data. 1 =
// Buffer write data is current buffer + weighted input data.
#define BF_CCOMP_CC_SUM_BIT            18
#define BF_CCOMP_CC_SUM_LEN            1
#define BF_CCOMP_CC_SUM_MASK           0x00040000
// Field       : CC_ONE
// Access      : RW
// CC force weight of 1.0 0 = Use weight from LUT 1 = Use weight of 1.0
#define BF_CCOMP_CC_ONE_BIT            19
#define BF_CCOMP_CC_ONE_LEN            1
#define BF_CCOMP_CC_ONE_MASK           0x00080000
// Field       : CC_INV
// Access      : RW
// CC invert weight 0 = Use LUT value for weight. 1 = Use (1-LUT value)
// for weight.
#define BF_CCOMP_CC_INV_BIT            20
#define BF_CCOMP_CC_INV_LEN            1
#define BF_CCOMP_CC_INV_MASK           0x00100000
// Field       : CC_OUTMODE
// Access      : RW
// CC output mode 0 = Output sum result. 1 = Output sum result and
// current input data.
#define BF_CCOMP_CC_OUTMODE_BIT        21
#define BF_CCOMP_CC_OUTMODE_LEN        1
#define BF_CCOMP_CC_OUTMODE_MASK       0x00200000
// ----------------------------------------------------------------------
// Register    : Corner Turn Buffer Register 3
//
#define BF_CF3_ADDR                    0x10c040e8
// Field       : CTBR_RPTR
// Access      : RW
// Outer loop base pointer. This pointer is the CTB address divided by 2
// with an implied zero for the LSB. The actual CTB address must be even.
#define BF_CF3_CTBR_RPTR_BIT           0
#define BF_CF3_CTBR_RPTR_LEN           16
#define BF_CF3_CTBR_RPTR_MASK          0x0000ffff
// Field       : CTBR_IPTR
// Access      : RW
// Inner loop base pointer. This pointer is the required increment
// divided by two with an implied zero for the LSB. The first write
// address will be ctbw_rptr+ctbw_iptr
#define BF_CF3_CTBR_IPTR_BIT           16
#define BF_CF3_CTBR_IPTR_LEN           16
#define BF_CF3_CTBR_IPTR_MASK          0xffff0000
// ----------------------------------------------------------------------
// Register    : Corner Turn Buffer Register 4
//
#define BF_CF4_ADDR                    0x10c040ec
// Field       : CTBR_RI
// Access      : RW
// Outer loop increment. The current outer loop pointer will be
// incremented by this value at the end of each inner loop.
#define BF_CF4_CTBR_RI_BIT             0
#define BF_CF4_CTBR_RI_LEN             14
#define BF_CF4_CTBR_RI_MASK            0x00003fff
// Field       : CTBR_II
// Access      : RW
// Inner loop increment. The current inner loop pointer will be
// incremented by this value for each output sample.
#define BF_CF4_CTBR_II_BIT             16
#define BF_CF4_CTBR_II_LEN             14
#define BF_CF4_CTBR_II_MASK            0x3fff0000
// ----------------------------------------------------------------------
// Register    : Corner Turn Buffer Register 5
//
#define BF_CF5_ADDR                    0x10c040f0
// Field       : CTBR_R_C
// Access      : RW
// Outer loop count -1. Defines the number of inner loops.
#define BF_CF5_CTBR_R_C_BIT            0
#define BF_CF5_CTBR_R_C_LEN            14
#define BF_CF5_CTBR_R_C_MASK           0x00003fff
// Field       : CTBR_I_C
// Access      : RW
// Inner loop count -1. Defines the number of samples per inner loop.
#define BF_CF5_CTBR_I_C_BIT            16
#define BF_CF5_CTBR_I_C_LEN            14
#define BF_CF5_CTBR_I_C_MASK           0x3fff0000
// ----------------------------------------------------------------------
// Register    : Corner Turn Buffer Register 6
//
#define BF_CF6_ADDR                    0x10c040f4
// Field       : CF_ENS
// Access      : RW
// Ensemble size - 1.
#define BF_CF6_CF_ENS_BIT              0
#define BF_CF6_CF_ENS_LEN              5
#define BF_CF6_CF_ENS_MASK             0x0000001f
// Field       : CF_R_C
// Access      : RW
// Wall filter output samples - 1.
#define BF_CF6_CF_R_C_BIT              16
#define BF_CF6_CF_R_C_LEN              9
#define BF_CF6_CF_R_C_MASK             0x01ff0000
// ----------------------------------------------------------------------
// Register    : Software line sync trigger
// Trigger registers are used to cause one time events by way of a
// register write with the write data not used. Each write to the
// register will cause the correspoding actions. The registers are write
// only and the data is unused. These registers are expected to be used
// primarilly for verification.
#define BF_TRIG0_ADDR                  0x10c0c000
// Field       : SWLS
// Access      : WO
// his trigger will cause the generation of on internal line sync LS
// event. The beamformer actions will depend on the state of the top
// level and beam dependent parameters at the time of the tirgger
#define BF_TRIG0_SWLS_BIT              0
#define BF_TRIG0_SWLS_LEN              1
#define BF_TRIG0_SWLS_MASK             0x00000001
// ----------------------------------------------------------------------
// Register    : Tx Trigger
// Generate pulse on AFE tx_trig pin.
#define BF_TRIG1_ADDR                  0x10c0c004
// Field       : DUMMY
// Access      : WO
#define BF_TRIG1_BIT                   0
#define BF_TRIG1_LEN                   32
#define BF_TRIG1_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : Tx Slope
// Generate pulse on AFE tx_slope pin.
#define BF_TRIG2_ADDR                  0x10c0c008
// Field       : DUMMY
// Access      : WO
#define BF_TRIG2_BIT                   0
#define BF_TRIG2_LEN                   32
#define BF_TRIG2_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : AFE updn
// Generate pulse on AFE updn pin. FPGA only.
#define BF_TRIG3_ADDR                  0x10c0c00c
// Field       : DUMMY
// Access      : WO
#define BF_TRIG3_BIT                   0
#define BF_TRIG3_LEN                   32
#define BF_TRIG3_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : Tx delay generation
// Proto V1: Force TX delay configuration and waveform generation.
#define BF_TRIG4_ADDR                  0x10c0c010
// Field       : DUMMY
// Access      : WO
#define BF_TRIG4_BIT                   0
#define BF_TRIG4_LEN                   32
#define BF_TRIG4_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : STVH1600 Enable
// Enable configuration of STHV1600.
#define BF_TRIG5_ADDR                  0x10c0c014
// Field       : DUMMY
// Access      : WO
#define BF_TRIG5_BIT                   0
#define BF_TRIG5_LEN                   32
#define BF_TRIG5_MASK                  0xffffffff
// ----------------------------------------------------------------------
// Register    : Debug Register-0
//
#define BF_DP0_ADDR                    0x10c10000
// Field       : PRI_TP_ON
