#define BF_ROID_ADDR                   0x10c08000
// Field       : ID
// Access      : RO
// 0x00000000 Proto v1; 0x11111111 Proto v1p, v2; 0x22222222 AX ASIC.
#define BF_ROID_ID_BIT                 0
#define BF_ROID_ID_LEN                 32
#define BF_ROID_ID_MASK                0xffffffff
// ----------------------------------------------------------------------
// Register    : AFE Status Register
//
#define BF_ROAFE_ADDR                  0x10c08004
// Field       : AFE0_LOCK
// Access      : RO
// Lock status for AFE0 input interface 0 = Unlocked 1 = Locked.
#define BF_ROAFE_AFE0_LOCK_BIT         0
#define BF_ROAFE_AFE0_LOCK_LEN         1
#define BF_ROAFE_AFE0_LOCK_MASK        0x00000001
// Field       : AFE1_LOCK
// Access      : RO
// Lock status for AFE1 input interface 0 = Unlocked 1 = Locked.
#define BF_ROAFE_AFE1_LOCK_BIT         1
#define BF_ROAFE_AFE1_LOCK_LEN         1
#define BF_ROAFE_AFE1_LOCK_MASK        0x00000002
// Field       : AFEWQ_DV
// Access      : RO
// AFE SPI write queue data valid. Used to indicate if the SPI write
// queue is not empty. 0 = Write queue empty 1 = Write queue not empty.
#define BF_ROAFE_AFEWQ_DV_BIT          2
#define BF_ROAFE_AFEWQ_DV_LEN          1
#define BF_ROAFE_AFEWQ_DV_MASK         0x00000004
// Field       : AFE0_SPI_BUSY
// Access      : RO
// Busy status of AFE0 SPI write controller 0 = SPI interface idle 1 =
// SPI interface busy.
#define BF_ROAFE_AFE0_SPI_BUSY_BIT     4
#define BF_ROAFE_AFE0_SPI_BUSY_LEN     1
#define BF_ROAFE_AFE0_SPI_BUSY_MASK    0x00000010
// Field       : AFE1_SPI_BUSY
// Access      : RO
// Busy status of AFE1 SPI write controller 0 = SPI interface idle 1 =
// SPI interface busy.
#define BF_ROAFE_AFE1_SPI_BUSY_BIT     5
#define BF_ROAFE_AFE1_SPI_BUSY_LEN     1
#define BF_ROAFE_AFE1_SPI_BUSY_MASK    0x00000020
// Field       : TP1
// Access      : RO
// Status of SMA1 test point output determined by the mux selection
// register DP17[7:0].
#define BF_ROAFE_TP1_BIT               6
#define BF_ROAFE_TP1_LEN               1
#define BF_ROAFE_TP1_MASK              0x00000040
// Field       : TP2
// Access      : RO
// Status of SMA2 test point output determined by the mux selection
// register DP17[15:8].
#define BF_ROAFE_TP2_BIT               7
#define BF_ROAFE_TP2_LEN               1
#define BF_ROAFE_TP2_MASK              0x00000080
// Field       : TXSPI_BUSY
// Access      : RO
// Busy status of TX SPI write controller 0 = TX SPI interface idle 1 =
// TX SPI interface busy.
#define BF_ROAFE_TXSPI_BUSY_BIT        8
#define BF_ROAFE_TXSPI_BUSY_LEN        1
#define BF_ROAFE_TXSPI_BUSY_MASK       0x00000100
// Field       : TXSPIWQ_BUSY
// Access      : RO
// TX SPI write queue data valid. Used to indicate if the SPI write queue
// is not empty. 0 = Write queue empty 1 = Write queue not empty.
#define BF_ROAFE_TXSPIWQ_BUSY_BIT      9
#define BF_ROAFE_TXSPIWQ_BUSY_LEN      1
#define BF_ROAFE_TXSPIWQ_BUSY_MASK     0x00000200
// ----------------------------------------------------------------------
// Register    : Read Only Transmit Status Register
//
#define BF_ROTX_ADDR                   0x10c08008
// Field       : TX_SHUTDOWN
// Access      : RW
// FPGA proto v1: Status of thermal shutdown pin from transmit chip.
#define BF_ROTX_TX_SHUTDOWN_BIT        0
#define BF_ROTX_TX_SHUTDOWN_LEN        1
#define BF_ROTX_TX_SHUTDOWN_MASK       0x00000001
// Field       : TX_INT
// Access      : RW
// Status of STHV1600 interrupt pin. Active low wired OR of all four TX
// parts.
#define BF_ROTX_TX_INT_BIT             1
#define BF_ROTX_TX_INT_LEN             1
#define BF_ROTX_TX_INT_MASK            0x00000002
// Field       : TX_HV_FAULT_FLAG
// Access      : RW
// Status of hv fault shutdown flag. {0 = Normal. 1 = HV has been shut
// down due to HV fault from power monitor}.
#define BF_ROTX_TX_HV_FAULT_FLAG_BIT   2
#define BF_ROTX_TX_HV_FAULT_FLAG_LEN   1
#define BF_ROTX_TX_HV_FAULT_FLAG_MASK  0x00000004
// Field       : TX_HV_INT_FLAG
// Access      : RW
// {0 = Normal. 1 = HV has been shut down due to interrupt from TX
// components.}
#define BF_ROTX_TX_HV_INT_FLAG_BIT     3
#define BF_ROTX_TX_HV_INT_FLAG_LEN     1
#define BF_ROTX_TX_HV_INT_FLAG_MASK    0x00000008
// ----------------------------------------------------------------------
// Register    : HV SPI Read Data Register
//
#define BF_ROHVSPI_ADDR                0x10c08024
// Field       : HV_SPI_READ
// Access      : RO
// Data from SPI readback of STHV1600 parts.
#define BF_ROHVSPI_HV_SPI_READ_BIT     0
#define BF_ROHVSPI_HV_SPI_READ_LEN     16
#define BF_ROHVSPI_HV_SPI_READ_MASK    0x0000ffff
// ----------------------------------------------------------------------
// Register    : AFE0 Write Data Register
//
#define BF_AFE0_WDATA_ADDR             0x10c14400
// Field       : AFE0_WDATA
// Access      : RW
// Write data for AFE0.
#define BF_AFE0_WDATA_AFE0_WDATA_BIT   0
#define BF_AFE0_WDATA_AFE0_WDATA_LEN   16
#define BF_AFE0_WDATA_AFE0_WDATA_MASK  0x0000ffff
// ----------------------------------------------------------------------
// Register    : AFE0 Read Data Register
//
#define BF_AFE0_RDATA_ADDR             0x10c14404
// Field       : AFE0_RDATA
// Access      : RO
// Read data for AFE0.
#define BF_AFE0_RDATA_AFE0_RDATA_BIT   0
#define BF_AFE0_RDATA_AFE0_RDATA_LEN   16
#define BF_AFE0_RDATA_AFE0_RDATA_MASK  0x0000ffff
// ----------------------------------------------------------------------
// Register    : AFE0 Status Register
//
#define BF_AFE0_STATUS_ADDR            0x10c14408
// Field       : AFE0_SPI_BUSY
// Access      : RO
// 0 = SPI port ready 1 = SPI port busy.
#define BF_AFE0_STATUS_AFE0_SPI_BUSY_BIT 0
#define BF_AFE0_STATUS_AFE0_SPI_BUSY_LEN 1
#define BF_AFE0_STATUS_AFE0_SPI_BUSY_MASK 0x00000001
// ----------------------------------------------------------------------
// Register    : AFE0 Clock Divide Register
//
#define BF_AFE0_CLKDIV_ADDR            0x10c1440c
// Field       : AFE0_CLKDIV
// Access      : RW
// Defines SPI bit clock rate. If Divider value is afe0_clkdiv, then SPI
// clk speed = clk4x/((afe0_clkdiv+1)*2); Default value of afe0_clkdiv=2.
#define BF_AFE0_CLKDIV_AFE0_CLKDIV_BIT 0
#define BF_AFE0_CLKDIV_AFE0_CLKDIV_LEN 8
#define BF_AFE0_CLKDIV_AFE0_CLKDIV_MASK 0x000000ff
// ----------------------------------------------------------------------
// Register    : AFE1 Write Data Register
//
#define BF_AFE1_WDATA_ADDR             0x10c14800
// Field       : AFE1_WDATA
// Access      : RW
// Write data for AFE1.
#define BF_AFE1_WDATA_AFE1_WDATA_BIT   0
#define BF_AFE1_WDATA_AFE1_WDATA_LEN   16
#define BF_AFE1_WDATA_AFE1_WDATA_MASK  0x0000ffff
// ----------------------------------------------------------------------
// Register    : AFE1 Read Data Register
//
#define BF_AFE1_RDATA_ADDR             0x10c14804
// Field       : AFE1_RDATA
// Access      : RO
// Read data for AFE1.
#define BF_AFE1_RDATA_AFE1_RDATA_BIT   0
#define BF_AFE1_RDATA_AFE1_RDATA_LEN   16
#define BF_AFE1_RDATA_AFE1_RDATA_MASK  0x0000ffff
// ----------------------------------------------------------------------
// Register    : AFE1 Status Register
//
#define BF_AFE1_STATUS_ADDR            0x10c14808
// Field       : AFE1_SPI_BUSY
// Access      : RO
// 0 = SPI port ready 1 = SPI port busy.
#define BF_AFE1_STATUS_AFE1_SPI_BUSY_BIT 0
#define BF_AFE1_STATUS_AFE1_SPI_BUSY_LEN 1
#define BF_AFE1_STATUS_AFE1_SPI_BUSY_MASK 0x00000001
// ----------------------------------------------------------------------
// Register    : AFE1 Clock Divide Register
//
#define BF_AFE1_CLKDIV_ADDR            0x10c1480c
// Field       : AFE1_CLKDIV
// Access      : RW
// Defines SPI bit clock rate. If Divider value is afe1_clkdiv, then SPI
// clk speed = clk4x/((afe1_clkdiv+1)*2); Default value of afe1_clkdiv=2.
#define BF_AFE1_CLKDIV_AFE1_CLKDIV_BIT 0
#define BF_AFE1_CLKDIV_AFE1_CLKDIV_LEN 8
#define BF_AFE1_CLKDIV_AFE1_CLKDIV_MASK 0x000000ff
// ----------------------------------------------------------------------
// Memory      : Tx config SPI Command LUT
//
#define BF_MSSTTXC_START_ADDR          0x10c80000
#define BF_MSSTTXC_WORDS               0x00002000
#define BF_MSSTTXC_WIDTH               0x00000017
// ----------------------------------------------------------------------
// Memory      : Interpolation rate LUT
//
#define BF_MSDIS_START_ADDR            0x10e88000
#define BF_MSDIS_WORDS                 0x00000080
#define BF_MSDIS_WIDTH                 0x00000020
// ----------------------------------------------------------------------
// Memory      : Wall Filter Coefficients
//
#define BF_MSWFC_START_ADDR            0x10ef6000
#define BF_MSWFC_WORDS                 0x00000100
#define BF_MSWFC_WIDTH                 0x00000020
// ----------------------------------------------------------------------
// Memory      : Corner Turn Buffer
//
#define BF_MSCTB_START_ADDR            0x10ef8000
#define BF_MSCTB_WORDS                 0x00000800
#define BF_MSCTB_WIDTH                 0x00000020
// ----------------------------------------------------------------------
// Memory      : AFE SPI Init command RAM Memory
//
#define BF_MSAFEINIT_START_ADDR        0x10f00400
#define BF_MSAFEINIT_WORDS             0x00000100
#define BF_MSAFEINIT_WIDTH             0x00000020


// ======================================================================
// Module      : BeamFormer Delay Memory Buffer
// Base Address: 0x10e00000
//
// ----------------------------------------------------------------------
// Memory      : Beam Former Delay Buffer Memory
//
#define BF_DMEM_MEM_START_ADDR         0x10e00000
#define BF_DMEM_MEM_WORDS              0x00008000
#define BF_DMEM_MEM_WIDTH              0x00000020


// ======================================================================
// Module      : PCIe core memory map to PCIe wire.
// Base Address: 0x20000000
//
// ----------------------------------------------------------------------
// Memory      : PCIe Memory Map to PCIe wire
//
#define PCIE_MMAP_MEM_START_ADDR       0x20000000
#define PCIE_MMAP_MEM_WORDS            0x08000000
#define PCIE_MMAP_MEM_WIDTH            0x00000020




